def _leo_move_class(value) -> str:
    if pd.notna(value):
        if float(value) > 0:
            return "up"
        if float(value) < 0:
            return "down"
    return "flat"


def _leo_signal_class(signal: str) -> str:
    raw = str(signal or "").upper()
    if raw == "BUY":
        return "up"
    if raw == "SELL":
        return "down"
    return "flat"


def _leo_news_class(label: str) -> str:
    lowered = str(label or "").lower()
    if "bullish" in lowered:
        return "up"
    if "bearish" in lowered:
        return "down"
    return "flat"


