def render_thematic_supply_chain_sections(lens_meta: dict | None = None) -> None:
    if get_language() != "zh_TW":
        return
    ensure_supply_chain_panels_default_closed()
    for config_key in SUPPLY_CHAIN_FOCUS_ORDER:
        render_supply_chain_focus_section(config_key, lens_meta=lens_meta)


def render_supply_chain_focus_section(config_key: str, lens_meta: dict | None = None) -> None:
    if get_language() != "zh_TW":
        return

    config = SUPPLY_CHAIN_FOCUS_CONFIGS.get(config_key)
    if not config:
        return

    inject_low_orbit_supply_chain_css()
    inject_supply_chain_focus_css()

    catalog = config["catalog"]
    cached_snapshot = peek_supply_chain_focus_snapshot(config_key, lens_meta=lens_meta)
    collapsed_preview_html = build_supply_chain_panel_preview_html(cached_snapshot)
    panel_open = render_dashboard_section_panel(
        config["title"],
        config["panel_section"],
        item_count=len(catalog),
        helper_base=config["copy"],
        expanded=False,
        panel_key=config["panel_key"],
        collapsed_preview_html=collapsed_preview_html,
    )
    if not panel_open:
        return

    snapshot_cols = st.columns([3, 1])
    with snapshot_cols[1]:
        refresh_clicked = st.button(
            f"↻ 刷新 {config['title']}",
            key=f"supply_chain_refresh::{config_key}",
            use_container_width=True,
        )

    snapshot_missing = not isinstance(cached_snapshot, dict)
    if refresh_clicked:
        with st.spinner(f"正在更新 {config['title']} 快照…"):
            snapshot = get_supply_chain_focus_snapshot(config_key, lens_meta=lens_meta, force_refresh=True)
        try:
            st.toast(f"{config['title']} 快照已更新")
        except Exception:
            st.success(f"{config['title']} 快照已更新")
    elif snapshot_missing:
        with st.spinner(f"正在建立 {config['title']} 初始快照…"):
            snapshot = get_supply_chain_focus_snapshot(config_key, lens_meta=lens_meta, force_refresh=False)
    else:
        snapshot = cached_snapshot

    if not isinstance(snapshot, dict):
        st.info(config["empty_note"])
        return

    fetched_at_text = format_supply_chain_snapshot_fetched_at(snapshot.get("fetched_at"))
    last_sync_text = str(snapshot.get("last_sync_text") or "—")
    lens_title = str(snapshot.get("lens_title", "") or (lens_meta or {}).get("title", DEFAULT_TREND_LENS))
    with snapshot_cols[0]:
        st.caption(f"快照建立：{fetched_at_text} · 市價基準：{last_sync_text} · Lens：{lens_title} · 本區只在你按右側刷新時才重抓")

    if str(snapshot.get("status", "ready")) != "ready":
        st.info(config["empty_note"])
        return

    top_rows = _deserialize_supply_chain_rows(snapshot.get("top_rows", []))
    summary_cards = [
        (
            str(card.get("label", "")).strip(),
            str(card.get("value", "")).strip() or "—",
            str(card.get("note", "")).strip(),
        )
        for card in snapshot.get("summary_cards", [])
        if isinstance(card, dict)
    ]
    if not top_rows:
        st.info(config["empty_note"])
        return

    cards_html = "".join(
        f'''
        <div class="leo-summary-card">
            <div class="leo-summary-label">{escape(label)}</div>
            <div class="leo-summary-value">{escape(value)}</div>
            <div class="leo-summary-note">{escape(note)}</div>
        </div>
        '''
        for label, value, note in summary_cards
    )

    head_html = "".join(f'<div class="sc-head-cell">{escape(str(column.get("label", "")))}</div>' for column in config["columns"])
    row_html_parts = []
    for row in top_rows:
        cells = "".join(_render_supply_chain_focus_cell_html(column, row, config["lead_story_fallback"]) for column in config["columns"])
        row_html_parts.append(f'<div class="sc-table-row" style="grid-template-columns:{config["grid_template"]};">{cells}</div>')

    chips = [config["selection_note"]]
    driver_note = str(config.get("driver_note", "") or "").strip()
    if driver_note:
        chips.append(driver_note)
    chips.append(f'{config["table_title"]} · Top {len(top_rows)}')
    chip_html = "".join(f'<span class="explorer-nav-chip">{escape(chip)}</span>' for chip in chips if str(chip).strip())

    render_html_block(
        f'''
        <div class="guide-shell leo-shell">
            <div class="leo-kicker">{escape(config["topline"])}</div>
            <div class="leo-title">{escape(config["title"])}</div>
            <div class="leo-copy">{escape(config["copy"])}</div>
            <div class="chip-row">{chip_html}</div>
            <div class="leo-summary-grid">{cards_html}</div>
            <div class="sc-table-shell">
                <div class="sc-table" style="min-width:{config["min_width"]};">
                    <div class="sc-table-head" style="grid-template-columns:{config["grid_template"]};">{head_html}</div>
                    {"".join(row_html_parts)}
                </div>
            </div>
            <div class="leo-rank-note">{escape(config["rank_note"])}</div>
        </div>
        '''
    )


def render_general_market_dashboard_layout(
    daily_data: pd.DataFrame,
    intraday_data: pd.DataFrame | None,
    tickers: list[str],
    lens_meta: dict | None = None,
    layout_mode: str = "Advanced",
) -> None:
    # v1.4.6: render_global_market_indicator() used to be called inside three
    # tabs of this layout (Standard market_brief, Advanced overview, Expert
    # research_flow header). It has been promoted to generate_dashboard()
    # so it shows ABOVE the Decision Cockpit regardless of which tab is
    # active. We deliberately keep the global_indicator computation out of
    # this function -- it's now done once at the top level.
    lang_zh = get_lang() == "繁體中文"

    render_dashboard_layout_intro(layout_mode, "General Market", tickers)
    render_layout_flow_cards(layout_mode, "General Market")

    show_taiwan_macro = any(is_taiwan_ticker(ticker) for ticker in tickers)

    if layout_mode == "Standard":
        standard_sections = [
            "layout_standard_market_brief_tab",
            "layout_standard_compare_plan_tab",
            "layout_standard_single_workspace_tab",
        ]
        current_section = render_standard_step_navigator(
            standard_sections,
            state_key="dashboard_standard_general_section",
        )
        if current_section == "layout_standard_market_brief_tab":
            if show_taiwan_macro:
                render_taiwan_market_macro_strip(force_show=True)
            render_section_guide()
            render_active_trend_lens(lens_meta)
            render_stock_explorer_nav(tickers)
        elif current_section == "layout_standard_compare_plan_tab":
            render_global_scenario_planning_stack(daily_data, intraday_data, tickers, lens_meta=lens_meta)
            render_precomparison_target_and_brief_groups(daily_data, intraday_data, tickers, lens_meta=lens_meta)
            render_comparison_section(daily_data, intraday_data, tickers, lens_meta=lens_meta)
        else:
            render_standard_workspace_picker(daily_data, intraday_data, tickers, lens_meta=lens_meta)
    elif layout_mode == "Advanced":
        advanced_sections = [
            "layout_overview_tab",
            "layout_planning_tab",
            "layout_compare_tab",
            "layout_workspace_tab",
        ]
        current_section = render_lightweight_option_selector(
            advanced_sections,
            "dashboard_advanced_general_section",
            format_func=standard_layout_section_label,
            helper_text=(
                "這裡改成只載入你目前打開的站點，切換 Compare / Workspace 會順很多。"
                if lang_zh else
                "Only the active station is loaded now, so switching between Compare and Workspace stays much smoother."
            ),
            widget_label="dashboard-advanced-general-station",
        )
        if current_section == "layout_overview_tab":
            if show_taiwan_macro:
                render_taiwan_market_macro_strip(force_show=True)
            render_section_guide()
            render_active_trend_lens(lens_meta)
            render_stock_explorer_nav(tickers)
        elif current_section == "layout_planning_tab":
            render_global_scenario_planning_stack(daily_data, intraday_data, tickers, lens_meta=lens_meta)
            render_precomparison_target_and_brief_groups(daily_data, intraday_data, tickers, lens_meta=lens_meta)
        elif current_section == "layout_compare_tab":
            render_comparison_section(daily_data, intraday_data, tickers, lens_meta=lens_meta)
        else:
            render_ticker_workspace_tabs(daily_data, intraday_data, tickers, lens_meta=lens_meta)
    else:
        if show_taiwan_macro:
            render_taiwan_market_macro_strip(force_show=True)
        expert_sections = [
            "layout_research_flow_tab",
            "layout_comparison_desk_tab",
            "layout_ticker_desks_tab",
        ]
        current_section = render_lightweight_option_selector(
            expert_sections,
            "dashboard_expert_general_section",
            format_func=standard_layout_section_label,
            helper_text=(
                "Expert 模式現在也只渲染目前站點，避免比較區與工作台一起卡住。"
                if lang_zh else
                "Expert mode now renders only the active station so comparison and workspaces do not stall each other."
            ),
            widget_label="dashboard-expert-general-station",
        )
        if current_section == "layout_research_flow_tab":
            render_section_guide()
            render_active_trend_lens(lens_meta)
            render_stock_explorer_nav(tickers)
            render_global_scenario_planning_stack(daily_data, intraday_data, tickers, lens_meta=lens_meta)
            render_precomparison_target_and_brief_groups(daily_data, intraday_data, tickers, lens_meta=lens_meta)
        elif current_section == "layout_comparison_desk_tab":
            render_comparison_section(daily_data, intraday_data, tickers, lens_meta=lens_meta)
        else:
            render_ticker_workspace_tabs(daily_data, intraday_data, tickers, lens_meta=lens_meta)

    render_html_block(f'<div class="footer-note">{t("footer_note")}</div>')


def render_active_etf_pair_picker(active_etf_tickers: list[str]) -> tuple[str | None, str | None]:
    lang_zh = get_language() == "zh_TW"
    if len(active_etf_tickers) < 2:
        st.info("至少需要兩檔主動式 ETF 才能進行雙 ETF 比較。" if lang_zh else "Select at least two active ETFs to enable pair comparison.")
        return None, None

    pair_left_key = "active_etf_lab_pair_left"
    pair_right_key = "active_etf_lab_pair_right"

    if st.session_state.get(pair_left_key) not in active_etf_tickers:
        st.session_state[pair_left_key] = active_etf_tickers[0]
    if (
        st.session_state.get(pair_right_key) not in active_etf_tickers
        or st.session_state.get(pair_right_key) == st.session_state[pair_left_key]
    ):
        st.session_state[pair_right_key] = active_etf_tickers[1] if len(active_etf_tickers) > 1 else active_etf_tickers[0]

    left_col, right_col = st.columns(2)
    left_etf = left_col.selectbox(
        "比較 ETF A" if lang_zh else "Compare ETF A",
        options=active_etf_tickers,
        format_func=active_etf_selector_label,
        key=pair_left_key,
    )
    right_options = [ticker for ticker in active_etf_tickers if ticker != left_etf] or active_etf_tickers
    if st.session_state.get(pair_right_key) not in right_options:
        st.session_state[pair_right_key] = right_options[0]
    right_etf = right_col.selectbox(
        "比較 ETF B" if lang_zh else "Compare ETF B",
        options=right_options,
        format_func=active_etf_selector_label,
        key=pair_right_key,
    )
    return left_etf, right_etf


def _render_active_etf_workspace_station_body(
    selected_ticker: str,
    daily_data: pd.DataFrame | None,
    intraday_data: pd.DataFrame | None,
    tickers: list[str],
    lens_meta: dict | None = None,
) -> None:
    lang_zh = get_language() == "zh_TW"
    snapshot, snapshot_source = inspect_active_etf_workspace_snapshot(selected_ticker, lens_meta=lens_meta)
    refresh_key = f"active_etf_workspace_refresh_{re.sub(r'[^A-Za-z0-9_]+', '_', str(selected_ticker).upper())}"
    status_col, action_col = st.columns([4.5, 1.2], gap="small")
    with status_col:
        if snapshot is not None:
            fetched_at = format_active_etf_snapshot_fetched_at(snapshot.get("fetched_at"))
            source_labels_zh = {
                "remote_exact": "遠端 Prefetch 快照",
                "remote_fallback": "遠端 Prefetch 快照（最近成功版本）",
                "local_exact": "本機快照",
                "local_fallback": "本機快照（最近成功版本）",
            }
            source_labels_en = {
                "remote_exact": "remote prefetched snapshot",
                "remote_fallback": "remote prefetched snapshot (closest saved version)",
                "local_exact": "local snapshot cache",
                "local_fallback": "local snapshot cache (closest saved version)",
            }
            source_label = (
                source_labels_zh.get(snapshot_source, "已保存工作台快照")
                if lang_zh else
                source_labels_en.get(snapshot_source, "saved workspace snapshot")
            )
            matched_period = str((snapshot or {}).get("period", "—") or "—")
            matched_interval = str((snapshot or {}).get("interval", "—") or "—")
            matched_lens = str((snapshot or {}).get("lens_title", DEFAULT_TREND_LENS) or DEFAULT_TREND_LENS)
            st.caption(
                (
                    f"目前先顯示 {display_ticker_label(selected_ticker)} 的 {source_label}：{fetched_at}，"
                    f"鏡頭 {matched_lens} / {matched_period} / {matched_interval}。需要最新資料時，再按右側刷新。"
                    if lang_zh else
                    f"Showing the {source_label} for {display_ticker_label(selected_ticker)} from {fetched_at}, "
                    f"using {matched_lens} / {matched_period} / {matched_interval}. Refresh only when you want a newer build."
                )
            )
        else:
            st.info(
                (
                    f"{display_ticker_label(selected_ticker)} 尚未建立工作台快照；第一次建立會稍慢，之後會優先顯示最近一次成功版本。"
                    if lang_zh else
                    f"No saved workspace snapshot exists yet for {display_ticker_label(selected_ticker)}. The first build may take longer, then future opens will use the latest successful snapshot first."
                )
            )
    with action_col:
        refresh_now = st.button(
            "刷新工作台" if lang_zh else "Refresh workspace",
            key=refresh_key,
            use_container_width=True,
        )

    needs_build = refresh_now or snapshot is None
    if needs_build:
        with st.spinner("正在建立 ETF 工作台快照..." if lang_zh else "Building the ETF workspace snapshot..."):
            bundle, bundle_snapshot = load_active_etf_workspace_bundle(
                daily_data,
                intraday_data,
                selected_ticker,
                lens_meta=lens_meta,
                force_refresh=refresh_now,
            )
    else:
        bundle, bundle_snapshot = load_active_etf_workspace_bundle(
            daily_data,
            intraday_data,
            selected_ticker,
            lens_meta=lens_meta,
            force_refresh=False,
        )

    if bundle is None:
        st.warning(
            "目前無法建立這檔主動式 ETF 的工作台資料，請稍後再試。"
            if lang_zh else
            "The workspace snapshot could not be built for this active ETF right now. Please try again later."
        )
        return

    if refresh_now and _active_etf_lab_snapshot_ready(bundle_snapshot):
        refreshed_at = format_active_etf_snapshot_fetched_at(bundle_snapshot.get("fetched_at"))
        st.caption(
            (
                f"工作台快照已更新：{refreshed_at}"
                if lang_zh else
                f"Workspace snapshot refreshed at {refreshed_at}"
            )
        )

    render_ticker_bundle_page(bundle, lens_meta=lens_meta, selected_count=len(tickers))


def render_single_bundle_workspace_picker(
    tickers: list[str],
    daily_data: pd.DataFrame | None,
    intraday_data: pd.DataFrame | None,
    lens_meta: dict | None = None,
) -> None:
    if not tickers:
        return
    lang_zh = get_language() == "zh_TW"
    active_group = render_active_etf_group_buttons(
        tickers,
        state_key="active_etf_workspace_group",
    )
    visible_tickers = [
        ticker for ticker in tickers
        if not active_group or active_etf_group_key(ticker) == active_group
    ] or tickers
    default_ticker = st.session_state.get("dashboard_standard_focus_etf", visible_tickers[0])
    if default_ticker not in visible_tickers:
        default_ticker = visible_tickers[0]
    selected_ticker = st.selectbox(
        "選擇一檔 ETF 工作台" if lang_zh else "Choose one ETF workspace",
        options=visible_tickers,
        index=visible_tickers.index(default_ticker),
        format_func=active_etf_selector_label,
        key="dashboard_standard_focus_etf",
    )
    _render_active_etf_workspace_station_body(
        selected_ticker,
        daily_data,
        intraday_data,
        tickers,
        lens_meta=lens_meta,
    )


def render_bundle_workspace_tabs(
    tickers: list[str],
    daily_data: pd.DataFrame | None,
    intraday_data: pd.DataFrame | None,
    lens_meta: dict | None = None,
) -> None:
    if not tickers:
        return
    lang_zh = get_language() == "zh_TW"
    active_group = render_active_etf_group_buttons(
        tickers,
        state_key="active_etf_workspace_group",
    )
    visible_tickers = [
        ticker for ticker in tickers
        if not active_group or active_etf_group_key(ticker) == active_group
    ] or tickers
    selected_ticker = render_lightweight_option_selector(
        visible_tickers,
        "active_etf_workspace_focus_ticker",
        format_func=active_etf_selector_label,
        helper_text=(
            "工作台一次只載入一檔主動式 ETF，避免切換時整排頁面同時重算。"
            if lang_zh else
            "Only one active ETF workspace is loaded at a time, so switching does not recalculate the whole strip."
        ),
        widget_label="active-etf-workspaces-selector",
    )
    if not selected_ticker:
        return
    _render_active_etf_workspace_station_body(
        selected_ticker,
        daily_data,
        intraday_data,
        tickers,
        lens_meta=lens_meta,
    )


def _safe_secret(name: str, default: str = "") -> str:
    try:
        value = st.secrets.get(name, default)
    except Exception:
        value = default
    return str(value).strip()


