# v1.3.8.3: In-memory cache for the local snapshot JSON store. Without this,
# every peek/load call re-reads and re-parses the entire JSON file, which can
# accumulate to tens of MB once many ETFs are tracked. Keyed on file mtime so
# external writes (other reruns / sessions) invalidate the cache automatically.
_ACTIVE_ETF_LAB_STORE_CACHE: dict = {"mtime": 0.0, "items": None, "version": 0}


def _active_etf_lab_snapshot_store() -> dict:
    empty_store = {"version": ACTIVE_ETF_LAB_SNAPSHOT_VERSION, "items": {}}
    try:
        if not ACTIVE_ETF_LAB_SNAPSHOT_PATH.exists():
            return empty_store
        mtime = ACTIVE_ETF_LAB_SNAPSHOT_PATH.stat().st_mtime
    except Exception:
        return empty_store

    cache = _ACTIVE_ETF_LAB_STORE_CACHE
    cached_items = cache.get("items")
    if cache.get("mtime") == mtime and isinstance(cached_items, dict):
        # Fast path: file unchanged, reuse parsed items dict. We return a
        # fresh top-level wrapper so callers that do `store["items"] = ...`
        # don't accidentally rebind our cache entry, but we share the items
        # dict reference (callers always copy via `dict(store.get("items"))`
        # before mutating, so this is safe and avoids deep-copy overhead on
        # multi-MB stores).
        return {"version": cache.get("version") or ACTIVE_ETF_LAB_SNAPSHOT_VERSION, "items": cached_items}

    try:
        payload = json.loads(ACTIVE_ETF_LAB_SNAPSHOT_PATH.read_text(encoding="utf-8"))
    except Exception:
        return empty_store
    if not isinstance(payload, dict):
        return empty_store
    items = payload.get("items")
    if not isinstance(items, dict):
        items = {}
    version = int(payload.get("version", ACTIVE_ETF_LAB_SNAPSHOT_VERSION) or ACTIVE_ETF_LAB_SNAPSHOT_VERSION)
    cache["mtime"] = mtime
    cache["items"] = items
    cache["version"] = version
    return {"version": version, "items": items}


def _write_active_etf_lab_snapshot_store(store: dict) -> None:
    ACTIVE_ETF_LAB_SNAPSHOT_PATH.parent.mkdir(parents=True, exist_ok=True)
    items_payload = dict((store or {}).get("items", {}) or {})
    payload = {
        "version": ACTIVE_ETF_LAB_SNAPSHOT_VERSION,
        "items": items_payload,
    }
    try:
        ACTIVE_ETF_LAB_SNAPSHOT_PATH.write_text(
            json.dumps(payload, ensure_ascii=False, indent=2),
            encoding="utf-8",
        )
    except Exception:
        return
    # v1.3.8.3: Update the in-memory cache directly so the very next read
    # does not have to re-parse the file we just wrote.
    try:
        new_mtime = ACTIVE_ETF_LAB_SNAPSHOT_PATH.stat().st_mtime
    except Exception:
        new_mtime = 0.0
    cache = _ACTIVE_ETF_LAB_STORE_CACHE
    cache["mtime"] = new_mtime
    cache["items"] = items_payload
    cache["version"] = ACTIVE_ETF_LAB_SNAPSHOT_VERSION


def _active_etf_snapshot_as_of_date(snapshot: dict | None) -> str:
    ts = _normalize_tw_timestamp((snapshot or {}).get("fetched_at"))
    if ts is None:
        return _snapshot_today_string()
    return ts.date().isoformat()


def _supabase_active_etf_read_request(path: str) -> tuple[int, dict | list | str]:
    # v1.13.32: publishable key 可能因 RLS 讀到「HTTP 200 但 0 筆」(anon 角色
    # 無 SELECT policy)。原本只要 2xx 就回傳 → 回傳空清單、不 fallback。
    # 改為: publishable 讀到「成功且非空」才用; 否則 fallback 到 service key
    # (service 繞過 RLS, 讀得到資料)。
    if _supabase_is_configured():
        status, payload = _supabase_request("GET", path)
        if 200 <= status < 300 and isinstance(payload, list) and len(payload) > 0:
            return status, payload
    if _supabase_service_is_configured():
        return _supabase_service_request("GET", path)
    return 0, {"message": "Supabase is not configured."}


def _active_etf_supabase_row_from_snapshot(snapshot: dict) -> dict:
    ticker_key = _active_etf_snapshot_ticker_key(str(snapshot.get("ticker", "") or ""))
    payload = dict(snapshot or {})
    if ticker_key:
        payload["ticker"] = ticker_key
    return {
        "ticker": ticker_key,
        "as_of_date": _active_etf_snapshot_as_of_date(snapshot),
        "fetched_at": str(snapshot.get("fetched_at") or pd.Timestamp.now(tz=TW_TZ).isoformat()),
        "period": str(snapshot.get("period", DEFAULT_PERIOD) or DEFAULT_PERIOD),
        "interval": str(snapshot.get("interval", DEFAULT_INTERVAL) or DEFAULT_INTERVAL),
        "lens_title": str(snapshot.get("lens_title", DEFAULT_TREND_LENS) or DEFAULT_TREND_LENS),
        "status": str(snapshot.get("status", "ready") or "ready"),
        "snapshot_payload": _active_etf_lab_snapshot_safe(payload),
    }


def _active_etf_supabase_snapshot_from_row(row: dict | None) -> dict | None:
    if not isinstance(row, dict):
        return None
    payload = row.get("snapshot_payload", {})
    if isinstance(payload, str):
        try:
            payload = json.loads(payload)
        except Exception:
            payload = {}
    if not isinstance(payload, dict):
        payload = {}
    snapshot = dict(payload)
    snapshot.setdefault("ticker", str(row.get("ticker", "") or "").upper().strip())
    snapshot.setdefault("period", str(row.get("period", DEFAULT_PERIOD) or DEFAULT_PERIOD))
    snapshot.setdefault("interval", str(row.get("interval", DEFAULT_INTERVAL) or DEFAULT_INTERVAL))
    snapshot.setdefault("lens_title", str(row.get("lens_title", DEFAULT_TREND_LENS) or DEFAULT_TREND_LENS))
    snapshot.setdefault("status", str(row.get("status", "ready") or "ready"))
    snapshot.setdefault("fetched_at", str(row.get("fetched_at", "") or ""))
    return snapshot


@st.cache_data(ttl=1800, show_spinner=False)
def _load_supabase_active_etf_snapshot(
    ticker: str,
    lens_meta: dict | None = None,
    *,
    allow_any_lens: bool = False,
) -> dict | None:
    ticker_upper = _active_etf_snapshot_ticker_key(ticker)
    if not ticker_upper:
        return None
    raw_ticker_upper = str(ticker or "").upper().strip()
    ticker_candidates = dedupe_keep_order([ticker_upper, raw_ticker_upper])
    select_query = quote_plus("ticker,as_of_date,fetched_at,period,interval,lens_title,status,snapshot_payload")
    for candidate in ticker_candidates:
        if not candidate:
            continue
        filters = [f"ticker=eq.{quote_plus(candidate)}"]
        if lens_meta is not None and not allow_any_lens:
            filters.extend(
                [
                    f"period=eq.{quote_plus(str((lens_meta or {}).get('period', DEFAULT_PERIOD) or DEFAULT_PERIOD))}",
                    f"interval=eq.{quote_plus(str((lens_meta or {}).get('interval', DEFAULT_INTERVAL) or DEFAULT_INTERVAL))}",
                    f"lens_title=eq.{quote_plus(str((lens_meta or {}).get('title', DEFAULT_TREND_LENS) or DEFAULT_TREND_LENS))}",
                ]
            )
        path = (
            f"/rest/v1/{SUPABASE_ACTIVE_ETF_SNAPSHOT_TABLE}"
            f"?select={select_query}&{'&'.join(filters)}&order=as_of_date.desc,fetched_at.desc&limit=1"
        )
        status, payload = _supabase_active_etf_read_request(path)
        if 200 <= status < 300 and isinstance(payload, list) and payload:
            return _active_etf_supabase_snapshot_from_row(payload[0])
    return None


def _upsert_supabase_active_etf_snapshot(snapshot: dict) -> bool:
    ticker = str((snapshot or {}).get("ticker", "") or "").upper().strip()
    if not ticker or not _supabase_service_is_configured():
        return False
    row = _active_etf_supabase_row_from_snapshot(snapshot)
    path = (
        f"/rest/v1/{SUPABASE_ACTIVE_ETF_SNAPSHOT_TABLE}"
        f"?on_conflict={quote_plus('ticker,as_of_date,period,interval,lens_title')}"
    )
    status, _ = _supabase_service_request(
        "POST",
        path,
        payload=[row],
        extra_headers={"Prefer": "resolution=merge-duplicates,return=minimal"},
    )
    return 200 <= status < 300


# ---------------------------------------------------------------------------
# v1.3.7: Supabase persistence for pair compare snapshots.
# Reuses the existing active_etf_snapshot table by encoding the pair as a
# synthetic ticker key ("PAIR::<left>::<right>"), so no schema migration is
# needed. This lets prefetch jobs running in GitHub Actions warm up pair
# compares for the Streamlit Cloud runtime.
# ---------------------------------------------------------------------------
def _active_etf_pair_supabase_ticker_key(left_ticker: str, right_ticker: str) -> str:
    left = _active_etf_snapshot_ticker_key(left_ticker)
    right = _active_etf_snapshot_ticker_key(right_ticker)
    if not left or not right:
        return ""
    return f"PAIR::{left}::{right}"


def _active_etf_pair_supabase_row_from_snapshot(snapshot: dict) -> dict:
    """Convert a pair compare snapshot dict into a Supabase row.

    The pair-compare schema does not include period / interval / lens_title,
    so we slot in the defaults to satisfy the existing on_conflict constraint
    and keep the JSONB payload intact otherwise.
    """
    snapshot = dict(snapshot or {})
    left = _active_etf_snapshot_ticker_key(str(snapshot.get("left_ticker", "") or ""))
    right = _active_etf_snapshot_ticker_key(str(snapshot.get("right_ticker", "") or ""))
    pair_key = _active_etf_pair_supabase_ticker_key(left, right)
    payload = dict(snapshot)
    payload["ticker"] = pair_key
    payload.setdefault("kind", "compare")
    fetched_at = str(snapshot.get("fetched_at") or pd.Timestamp.now(tz=TW_TZ).isoformat())
    return {
        "ticker": pair_key,
        "as_of_date": _active_etf_snapshot_as_of_date(snapshot),
        "fetched_at": fetched_at,
        "period": DEFAULT_PERIOD,
        "interval": DEFAULT_INTERVAL,
        "lens_title": DEFAULT_TREND_LENS,
        "status": str(snapshot.get("status", "ready") or "ready"),
        "snapshot_payload": _active_etf_lab_snapshot_safe(payload),
    }


def _upsert_supabase_active_etf_pair_snapshot(snapshot: dict) -> bool:
    """Persist a pair compare snapshot to Supabase using the synthetic-ticker
    encoding. Returns True iff the upsert succeeded.
    """
    if not isinstance(snapshot, dict):
        return False
    if not _supabase_service_is_configured():
        return False
    left = _active_etf_snapshot_ticker_key(str(snapshot.get("left_ticker", "") or ""))
    right = _active_etf_snapshot_ticker_key(str(snapshot.get("right_ticker", "") or ""))
    if not left or not right:
        return False
    row = _active_etf_pair_supabase_row_from_snapshot(snapshot)
    path = (
        f"/rest/v1/{SUPABASE_ACTIVE_ETF_SNAPSHOT_TABLE}"
        f"?on_conflict={quote_plus('ticker,as_of_date,period,interval,lens_title')}"
    )
    try:
        status, _ = _supabase_service_request(
            "POST",
            path,
            payload=[row],
            extra_headers={"Prefer": "resolution=merge-duplicates,return=minimal"},
        )
    except Exception:
        return False
    return 200 <= status < 300


@st.cache_data(ttl=1800, show_spinner=False)
def _load_supabase_active_etf_pair_snapshot(left_ticker: str, right_ticker: str) -> dict | None:
    """Load a previously-persisted pair compare snapshot from Supabase.

    Returns ``None`` if Supabase is not configured, the row is missing, or the
    payload cannot be parsed. The 5-minute cache mirrors the workspace
    snapshot reader so refreshes propagate quickly without hammering Supabase.
    """
    pair_key = _active_etf_pair_supabase_ticker_key(left_ticker, right_ticker)
    if not pair_key:
        return None
    select_query = quote_plus("ticker,as_of_date,fetched_at,period,interval,lens_title,status,snapshot_payload")
    path = (
        f"/rest/v1/{SUPABASE_ACTIVE_ETF_SNAPSHOT_TABLE}"
        f"?select={select_query}&ticker=eq.{quote_plus(pair_key)}"
        f"&order=as_of_date.desc,fetched_at.desc&limit=1"
    )
    try:
        status, payload = _supabase_active_etf_read_request(path)
    except Exception:
        return None
    if not (200 <= status < 300) or not isinstance(payload, list) or not payload:
        return None
    row = payload[0]
    raw = row.get("snapshot_payload", {})
    if isinstance(raw, str):
        try:
            raw = json.loads(raw)
        except Exception:
            raw = {}
    if not isinstance(raw, dict):
        return None
    snapshot = dict(raw)
    snapshot.setdefault("kind", "compare")
    snapshot.setdefault("status", str(row.get("status", "ready") or "ready"))
    snapshot.setdefault("fetched_at", str(row.get("fetched_at", "") or ""))
    # Guard the ticker fields in case the JSONB blob lost them in transit.
    if not snapshot.get("left_ticker") or not snapshot.get("right_ticker"):
        ticker_field = str(row.get("ticker", "") or "")
        if ticker_field.startswith("PAIR::"):
            parts = ticker_field.split("::", 2)
            if len(parts) == 3:
                snapshot.setdefault("left_ticker", parts[1])
                snapshot.setdefault("right_ticker", parts[2])
    return snapshot


def _active_etf_lab_snapshot_safe(value):
    if value is None or value is pd.NA:
        return None
    if isinstance(value, (pd.Timestamp, datetime)):
        return value.isoformat()
    if isinstance(value, pd.DataFrame):
        if value.empty:
            return []
        try:
            return json.loads(value.to_json(orient="records", date_format="iso"))
        except Exception:
            return [
                {
                    str(column): _active_etf_lab_snapshot_safe(cell)
                    for column, cell in row.items()
                }
                for row in value.to_dict(orient="records")
            ]
    if isinstance(value, pd.Series):
        if value.empty:
            return {}
        return {
            str(key): _active_etf_lab_snapshot_safe(item)
            for key, item in value.to_dict().items()
        }
    if isinstance(value, np.ndarray):
        return [_active_etf_lab_snapshot_safe(item) for item in value.tolist()]
    if isinstance(value, np.generic):
        return _active_etf_lab_snapshot_safe(value.item())
    if isinstance(value, dict):
        return {
            str(key): _active_etf_lab_snapshot_safe(item)
            for key, item in value.items()
        }
    if isinstance(value, (list, tuple, set)):
        return [_active_etf_lab_snapshot_safe(item) for item in value]
    try:
        if pd.isna(value):
            return None
    except Exception:
        pass
    return value


def _serialize_active_etf_series(series: pd.Series | None) -> dict | None:
    if not isinstance(series, pd.Series) or series.empty:
        return None
    frame = series.to_frame(name=str(series.name or "value"))
    return {
        "series_name": str(series.name or frame.columns[0]),
        "frame": json.loads(frame.to_json(orient="split", date_format="iso")),
    }


def _deserialize_active_etf_series(payload: dict | None) -> pd.Series:
    if not isinstance(payload, dict):
        return pd.Series(dtype=float)
    frame_payload = payload.get("frame")
    if not isinstance(frame_payload, dict):
        return pd.Series(dtype=float)
    try:
        frame = pd.read_json(io.StringIO(json.dumps(frame_payload, ensure_ascii=False)), orient="split")
    except Exception:
        return pd.Series(dtype=float)
    if frame.empty:
        return pd.Series(dtype=float)
    series = frame.iloc[:, 0].copy()
    series.name = str(payload.get("series_name") or frame.columns[0] or "value")
    return series


def _serialize_active_etf_frame(frame: pd.DataFrame | None) -> dict | None:
    if not isinstance(frame, pd.DataFrame) or frame.empty:
        return None
    return json.loads(frame.to_json(orient="split", date_format="iso"))


def _deserialize_active_etf_frame(payload: dict | None) -> pd.DataFrame:
    if not isinstance(payload, dict):
        return pd.DataFrame()
    try:
        return pd.read_json(io.StringIO(json.dumps(payload, ensure_ascii=False)), orient="split")
    except Exception:
        return pd.DataFrame()


def _serialize_active_etf_bundle(bundle: dict | None) -> dict:
    bundle = dict(bundle or {})
    return {
        "ticker": str(bundle.get("ticker", "")).upper().strip(),
        "field_name": str(bundle.get("field_name", "") or "").strip(),
        "news_items": _active_etf_lab_snapshot_safe(bundle.get("news_items", [])),
        "news_error": str(bundle.get("news_error", "") or "").strip(),
        "intraday": _active_etf_lab_snapshot_safe(bundle.get("intraday", {})),
        "analysis": _active_etf_lab_snapshot_safe(bundle.get("analysis", {})),
        "price_series": _serialize_active_etf_series(bundle.get("price_series")),
        "volume_series": _serialize_active_etf_series(bundle.get("volume_series")),
        "daily_ohlc": _serialize_active_etf_frame(bundle.get("daily_ohlc")),
        "intraday_ohlc": _serialize_active_etf_frame(bundle.get("intraday_ohlc")),
    }


def _deserialize_active_etf_bundle(payload: dict | None) -> dict | None:
    if not isinstance(payload, dict):
        return None
    ticker = str(payload.get("ticker", "") or "").upper().strip()
    if not ticker:
        return None
    return {
        "ticker": ticker,
        "field_name": str(payload.get("field_name", "") or "").strip(),
        "news_items": list(payload.get("news_items", []) or []),
        "news_error": str(payload.get("news_error", "") or "").strip(),
        "intraday": dict(payload.get("intraday", {}) or {}),
        "analysis": dict(payload.get("analysis", {}) or {}),
        "price_series": _deserialize_active_etf_series(payload.get("price_series")),
        "volume_series": _deserialize_active_etf_series(payload.get("volume_series")),
        "daily_ohlc": _deserialize_active_etf_frame(payload.get("daily_ohlc")),
        "intraday_ohlc": _deserialize_active_etf_frame(payload.get("intraday_ohlc")),
    }


def _active_etf_snapshot_ticker_key(ticker: str) -> str:
    normalized = normalize_taiwan_active_etf_symbol(str(ticker or ""))
    return normalized or str(ticker or "").upper().strip()


def _active_etf_workspace_snapshot_key(ticker: str, lens_meta: dict | None = None) -> str:
    ticker_key = _active_etf_snapshot_ticker_key(ticker)
    period = str((lens_meta or {}).get("period", DEFAULT_PERIOD) or DEFAULT_PERIOD)
    interval = str((lens_meta or {}).get("interval", DEFAULT_INTERVAL) or DEFAULT_INTERVAL)
    lens_title = str((lens_meta or {}).get("title", DEFAULT_TREND_LENS) or DEFAULT_TREND_LENS)
    return f"workspace::{ticker_key}::{period}::{interval}::{lens_title}"


def _active_etf_pair_snapshot_key(left_ticker: str, right_ticker: str) -> str:
    return f"compare::{_active_etf_snapshot_ticker_key(left_ticker)}::{_active_etf_snapshot_ticker_key(right_ticker)}"


def _active_etf_lab_snapshot_ready(snapshot: dict | None) -> bool:
    return (
        isinstance(snapshot, dict)
        and int(snapshot.get("version", 0) or 0) == ACTIVE_ETF_LAB_SNAPSHOT_VERSION
        and str(snapshot.get("status", "") or "") == "ready"
    )


def format_active_etf_snapshot_fetched_at(value: object) -> str:
    ts = _normalize_tw_timestamp(value)
    if ts is None:
        return "—"
    return ts.strftime("%Y-%m-%d %H:%M")


def _active_etf_workspace_snapshot_candidates(ticker: str) -> list[dict]:
    ticker_upper = _active_etf_snapshot_ticker_key(ticker)
    if not ticker_upper:
        return []
    raw_ticker_upper = str(ticker or "").upper().strip()
    prefixes = [f"workspace::{candidate}::" for candidate in dedupe_keep_order([ticker_upper, raw_ticker_upper]) if candidate]
    items = dict((_active_etf_lab_snapshot_store().get("items", {}) or {}))
    matches: list[dict] = []
    for key, snapshot in items.items():
        if not any(str(key or "").startswith(prefix) for prefix in prefixes):
            continue
        if _active_etf_lab_snapshot_ready(snapshot):
            matches.append(dict(snapshot or {}))
    matches.sort(
        key=lambda item: _normalize_tw_timestamp((item or {}).get("fetched_at")) or pd.Timestamp.min.tz_localize(TW_TZ),
        reverse=True,
    )
    return matches


def _load_local_active_etf_snapshot(
    ticker: str,
    lens_meta: dict | None = None,
    *,
    allow_any_lens: bool = False,
) -> dict | None:
    ticker_upper = _active_etf_snapshot_ticker_key(ticker)
    if not ticker_upper:
        return None
    items = dict((_active_etf_lab_snapshot_store().get("items", {}) or {}))
    if lens_meta is not None and not allow_any_lens:
        snapshot = items.get(_active_etf_workspace_snapshot_key(ticker_upper, lens_meta))
        if _active_etf_lab_snapshot_ready(snapshot):
            return dict(snapshot or {})
        return None
    candidates = _active_etf_workspace_snapshot_candidates(ticker_upper)
    return candidates[0] if candidates else None


def inspect_active_etf_workspace_snapshot(ticker: str, lens_meta: dict | None = None) -> tuple[dict | None, str]:
    # v1.3.8.3: When lens_meta is None (the most common path -- peek and pair
    # compare both pass None), the "exact" and "any-lens" branches issue
    # IDENTICAL queries (no period/interval/lens_title filter to begin with),
    # so the second call is pure waste. The Supabase reader is wrapped with
    # @st.cache_data which keys on argument tuples, so even repeating the
    # nominally-identical pair returns triggers a second cache slot lookup,
    # paying the round trip again on cache miss. Skip the duplicate work.
    remote_snapshot = _load_supabase_active_etf_snapshot(ticker, lens_meta=lens_meta)
    if _active_etf_lab_snapshot_ready(remote_snapshot):
        return remote_snapshot, "remote_exact"
    if lens_meta is not None:
        fallback_remote_snapshot = _load_supabase_active_etf_snapshot(ticker, allow_any_lens=True)
        if _active_etf_lab_snapshot_ready(fallback_remote_snapshot):
            return fallback_remote_snapshot, "remote_fallback"
    local_snapshot = _load_local_active_etf_snapshot(ticker, lens_meta=lens_meta)
    if _active_etf_lab_snapshot_ready(local_snapshot):
        return local_snapshot, "local_exact"
    if lens_meta is not None:
        fallback_local_snapshot = _load_local_active_etf_snapshot(ticker, allow_any_lens=True)
        if _active_etf_lab_snapshot_ready(fallback_local_snapshot):
            return fallback_local_snapshot, "local_fallback"
    return None, "missing"


def peek_active_etf_workspace_snapshot(ticker: str, lens_meta: dict | None = None) -> dict | None:
    snapshot, _ = inspect_active_etf_workspace_snapshot(ticker, lens_meta=lens_meta)
    return snapshot


def _peek_active_etf_workspace_snapshot_exact(ticker: str, lens_meta: dict | None = None) -> dict | None:
    remote_snapshot = _load_supabase_active_etf_snapshot(ticker, lens_meta=lens_meta)
    if _active_etf_lab_snapshot_ready(remote_snapshot):
        return remote_snapshot
    return _load_local_active_etf_snapshot(ticker, lens_meta=lens_meta)


def peek_active_etf_pair_snapshot(left_ticker: str, right_ticker: str) -> dict | None:
    # v1.3.8.3: Path order changed to C -> B -> A so prefetch warm-ups land
    # the user on a single ~50-300ms cached Supabase read instead of paying
    # 2 workspace lookups + in-memory synthesis (typically 600-2000ms).
    #
    # Path C (FAST when prefetch ran): direct Supabase pair-compare lookup.
    # _load_supabase_active_etf_pair_snapshot is wrapped with @st.cache_data
    # (ttl=300s), so the second visit within 5 minutes is essentially free.
    try:
        remote = _load_supabase_active_etf_pair_snapshot(left_ticker, right_ticker)
    except Exception:
        remote = None
    if _active_etf_lab_snapshot_ready(remote):
        # Mirror to local for next-time speed; do NOT mirror back to Supabase
        # (we just READ from there, writing the same payload back is a wasted
        # round trip).
        try:
            return _persist_active_etf_pair_snapshot(remote, mirror_supabase=False)
        except Exception:
            return remote

    # Path B: a previous run already wrote a pair snapshot to the local JSON
    # store on this machine.
    store = _active_etf_lab_snapshot_store()
    snapshot = (store.get("items", {}) or {}).get(_active_etf_pair_snapshot_key(left_ticker, right_ticker))
    if _active_etf_lab_snapshot_ready(snapshot):
        return snapshot

    # Path A (most expensive): synthesize from the two workspace snapshots.
    # This is only reached when both Path C and Path B miss, e.g. a pair the
    # prefetch job has not been configured to warm up yet.
    left_snapshot = peek_active_etf_workspace_snapshot(left_ticker, lens_meta=None)
    right_snapshot = peek_active_etf_workspace_snapshot(right_ticker, lens_meta=None)
    if _active_etf_lab_snapshot_ready(left_snapshot) and _active_etf_lab_snapshot_ready(right_snapshot):
        synthesized = _build_active_etf_pair_compare_snapshot_from_workspace_snapshots(left_snapshot, right_snapshot)
        if _active_etf_lab_snapshot_ready(synthesized):
            return _persist_active_etf_pair_snapshot(synthesized, mirror_supabase=False)
    return None


def _clear_active_etf_lab_refresh_caches() -> None:
    try:
        _clear_supply_chain_refresh_caches()
    except Exception:
        pass
    cached_funcs = [
        fetch_daily_data,
        fetch_intraday_data,
        fetch_ticker_news,
        fetch_analyst_target_snapshot,
        fetch_asset_profile_snapshot,
        fetch_twse_valuation_snapshot,
        fetch_twse_stock_institutional_flow,
        fetch_monthly_revenue_snapshot,
        fetch_cbc_macro_snapshot,
        fetch_taifex_put_call_snapshot,
        fetch_active_etf_holdings_snapshot,
        fetch_twse_etf_institutional_flow,
        fetch_active_etf_underlying_signal,
    ]
    # v1.3.7: include the new official-data fetcher when it is defined.
    # Guarded by getattr so this file remains importable even if someone trims
    # the official-data block in the future.
    extra_func = globals().get("fetch_active_etf_official_payload")
    if extra_func is not None:
        cached_funcs.append(extra_func)
    pair_remote_loader = globals().get("_load_supabase_active_etf_pair_snapshot")
    if pair_remote_loader is not None:
        cached_funcs.append(pair_remote_loader)
    for cached_func in cached_funcs:
        try:
            cached_func.clear()
        except Exception:
            pass
    # v1.3.8.3: also reset the local store mtime cache so the next read is
    # forced to re-parse from disk. Important for force_refresh paths where
    # the user explicitly asked for fresh data.
    try:
        cache = globals().get("_ACTIVE_ETF_LAB_STORE_CACHE")
        if isinstance(cache, dict):
            cache["mtime"] = 0.0
            cache["items"] = None
            cache["version"] = 0
    except Exception:
        pass


# ---------------------------------------------------------------------------
# v1.3.7: Restore daily / intraday data from prefetched workspace snapshots.
# This avoids hitting yfinance during the first paint of Active ETF Lab.
# ---------------------------------------------------------------------------
def _restore_active_etf_market_data_from_snapshots(
    tickers: list[str],
    lens_meta: dict | None = None,
) -> tuple[pd.DataFrame | None, pd.DataFrame | None] | None:
    """Try to reconstruct yfinance-compatible MultiIndex frames from snapshots.

    Returns ``(daily_df, intraday_df)`` if every ticker has a ready workspace
    snapshot with a usable ``daily_ohlc`` payload. Returns ``None`` otherwise,
    so the caller can fall back to live ``fetch_daily_data`` / ``fetch_intraday_data``.

    Both frames use a ``(field, ticker)`` MultiIndex column layout, matching
    what ``yf.download(group_by='column')`` produces. The downstream readers
    (``get_series`` / ``get_price_series``) already understand this layout.

    Defensive throughout: any unexpected payload shape returns ``None`` so the
    UI never breaks, just falls back to live fetch.
    """
    try:
        normalized_tickers = [
            normalize_dashboard_ticker(t) or str(t or "").upper().strip()
            for t in (tickers or [])
        ]
        normalized_tickers = [t for t in normalized_tickers if t]
        if not normalized_tickers:
            return None

        daily_columns: dict[tuple[str, str], pd.Series] = {}
        intraday_columns: dict[tuple[str, str], pd.Series] = {}

        for ticker in normalized_tickers:
            snapshot, _ = inspect_active_etf_workspace_snapshot(ticker, lens_meta=lens_meta)
            if not _active_etf_lab_snapshot_ready(snapshot):
                return None
            bundle = _deserialize_active_etf_bundle(snapshot.get("bundle"))
            if not bundle:
                return None

            daily_ohlc = bundle.get("daily_ohlc")
            if not isinstance(daily_ohlc, pd.DataFrame) or daily_ohlc.empty:
                return None
            daily_ohlc = daily_ohlc.copy()
            try:
                daily_ohlc.index = pd.to_datetime(daily_ohlc.index, errors="coerce")
            except Exception:
                return None
            for column in daily_ohlc.columns:
                series = daily_ohlc[column]
                if isinstance(series, pd.DataFrame):
                    # Defensive: if a duplicate column name turned the slice
                    # into a frame, take the first column.
                    if series.empty:
                        continue
                    series = series.iloc[:, 0]
                daily_columns[(str(column), ticker)] = series

            intraday_ohlc = bundle.get("intraday_ohlc")
            if isinstance(intraday_ohlc, pd.DataFrame) and not intraday_ohlc.empty:
                intraday_ohlc = intraday_ohlc.copy()
                try:
                    intraday_ohlc.index = pd.to_datetime(intraday_ohlc.index, errors="coerce")
                except Exception:
                    intraday_ohlc = None
                if isinstance(intraday_ohlc, pd.DataFrame) and not intraday_ohlc.empty:
                    for column in intraday_ohlc.columns:
                        series = intraday_ohlc[column]
                        if isinstance(series, pd.DataFrame):
                            if series.empty:
                                continue
                            series = series.iloc[:, 0]
                        intraday_columns[(str(column), ticker)] = series

        if not daily_columns:
            return None

        daily_frame = pd.DataFrame(daily_columns)
        if daily_frame.empty:
            return None
        try:
            daily_frame = daily_frame.sort_index()
        except Exception:
            pass
        try:
            daily_frame.columns = pd.MultiIndex.from_tuples(daily_frame.columns)
        except Exception:
            pass

        intraday_frame: pd.DataFrame | None = None
        if intraday_columns:
            intraday_frame = pd.DataFrame(intraday_columns)
            try:
                intraday_frame = intraday_frame.sort_index()
            except Exception:
                pass
            try:
                intraday_frame.columns = pd.MultiIndex.from_tuples(intraday_frame.columns)
            except Exception:
                pass

        return daily_frame, intraday_frame
    except Exception:
        return None


def _build_active_etf_workspace_live_bundle(
    daily_data: pd.DataFrame | None,
    intraday_data: pd.DataFrame | None,
    ticker: str,
    lens_meta: dict | None = None,
    *,
    force_market_refresh: bool = False,
) -> dict | None:
    source_daily = daily_data
    source_intraday = intraday_data
    if force_market_refresh:
        period = str((lens_meta or {}).get("period", DEFAULT_PERIOD) or DEFAULT_PERIOD)
        interval = str((lens_meta or {}).get("interval", DEFAULT_INTERVAL) or DEFAULT_INTERVAL)
        try:
            fetch_daily_data.clear()
        except Exception:
            pass
        try:
            fetch_intraday_data.clear()
        except Exception:
            pass
        source_daily = fetch_daily_data([ticker], period, interval)
        source_intraday = fetch_intraday_data([ticker])
    return collect_ticker_context(source_daily, source_intraday, ticker, news_limit=8, lens_meta=lens_meta)


# ---------------------------------------------------------------------------
# v1.9.0: Taiwan general market universe — daily + intraday OHLC restore
# ---------------------------------------------------------------------------
# The General Market path was hitting yfinance live for every Taiwan ticker
# in the user's watchlist on first paint (5-12s daily + 2-5s intraday). The
# Active ETF Lab path solved this with per-ticker workspace snapshots; we
# do the analogous thing for general market by storing a single bulk
# universe payload (~95 curated Taiwan tickers) on the existing
# main_dashboard_snapshot row.
#
# Required prefetch_main_dashboard_job.py change:
#     payload = build_general_market_universe_payload("1y", "1d")
#     row["universe_market_data_payload"] = payload
#
# The universe payload structure:
#   {
#     "tickers": list[str],              # the universe at prefetch time
#     "period": "1y", "interval": "1d",  # so live render can verify match
#     "daily_frames":    {ticker: {orient="split" frame dict}},
#     "intraday_frames": {ticker: {orient="split" frame dict}},
#     "snapshot_at": ISO 8601 string,
#   }
def _build_taiwan_general_market_universe() -> list[str]:
    """Return the Taiwan ticker universe for prefetch (sorted, deduped).

    The universe constant TAIWAN_GENERAL_MARKET_UNIVERSE is assigned
    LATER in the module (right after merge_ticker_selection / the rest of
    the ticker-utility cluster) because this function depends on
    TAIWAN_WATCHLIST_GROUPS, WATCHLIST_PRESETS, normalize_dashboard_ticker,
    and is_taiwan_ticker — none of which exist yet at this line. Defining
    the function here (alongside the rest of the v1.9.0 universe restore
    helpers) is fine since Python resolves references inside function
    bodies at CALL time, not at definition time.
    """
    universe: set[str] = set()
    for group in TAIWAN_WATCHLIST_GROUPS:
        for tk in (WATCHLIST_PRESETS.get(group) or []):
            tk_norm = normalize_dashboard_ticker(tk)
            if tk_norm and is_taiwan_ticker(tk_norm):
                universe.add(tk_norm)
    # Include any Taiwan ticker that appears in DEFAULT_TICKERS too.
    for tk in DEFAULT_TICKERS:
        tk_norm = normalize_dashboard_ticker(tk)
        if tk_norm and is_taiwan_ticker(tk_norm):
            universe.add(tk_norm)
    return sorted(universe)


def _extract_ticker_ohlc_frame(
    multi_frame: "pd.DataFrame | None",
    ticker: str,
) -> "pd.DataFrame | None":
    """Slice a single ticker's OHLC dataframe out of yfinance's MultiIndex
    download result. yfinance with group_by='column' produces columns of
    (field, ticker) — but the orientation can vary across yfinance versions
    so we try both axes. Returns a single-ticker frame with simple column
    names [Open, High, Low, Close, Volume, Adj Close], or None if the
    ticker is missing / data is empty.
    """
    if not isinstance(multi_frame, pd.DataFrame) or multi_frame.empty:
        return None
    if isinstance(multi_frame.columns, pd.MultiIndex):
        # Try level=1 (assumes (field, ticker))
        for level in (1, 0):
            try:
                slice_frame = multi_frame.xs(ticker, axis=1, level=level, drop_level=True)
                if isinstance(slice_frame, pd.DataFrame) and not slice_frame.empty:
                    return slice_frame.copy()
            except (KeyError, ValueError):
                continue
        return None
    # Single-ticker download: columns are field names directly.
    return multi_frame.copy()


def build_general_market_universe_payload(
    period: str = DEFAULT_PERIOD,
    interval: str = DEFAULT_INTERVAL,
) -> dict | None:
    """Build the Taiwan universe payload for prefetch_main_dashboard_job.py.

    This function is the BUILDER half of the v1.9.0 speedup: prefetch calls
    it once per scheduled run, persists the returned dict into the
    main_dashboard_snapshot row's universe_market_data_payload column.
    Live render then short-circuits yfinance using
    _restore_general_market_data_from_snapshot.

    Returns None if the universe is empty or yfinance fetch fails entirely.
    Per-ticker errors are silently tolerated (those tickers will fall
    through to live fetch on the dashboard side).
    """
    universe = list(TAIWAN_GENERAL_MARKET_UNIVERSE)
    if not universe:
        return None
    try:
        daily_full = fetch_daily_data(universe, period, interval)
    except Exception:
        daily_full = None
    try:
        intraday_full = fetch_intraday_data(universe)
    except Exception:
        intraday_full = None

    daily_frames: dict[str, dict] = {}
    intraday_frames: dict[str, dict] = {}
    for ticker in universe:
        try:
            d_frame = _extract_ticker_ohlc_frame(daily_full, ticker)
            if d_frame is not None:
                serialized = _serialize_active_etf_frame(d_frame)
                if serialized:
                    daily_frames[ticker] = serialized
        except Exception:
            pass
        try:
            i_frame = _extract_ticker_ohlc_frame(intraday_full, ticker)
            if i_frame is not None:
                serialized = _serialize_active_etf_frame(i_frame)
                if serialized:
                    intraday_frames[ticker] = serialized
        except Exception:
            pass

    if not daily_frames:
        # Fetch failed across the board — let the dashboard fall back to
        # live fetch rather than serve an empty payload.
        return None

    return {
        "tickers": universe,
        "period": str(period),
        "interval": str(interval),
        "daily_frames": daily_frames,
        "intraday_frames": intraday_frames,
        "snapshot_at": _utc_now_iso(),
    }


def _restore_general_market_data_from_snapshot(
    tickers: list[str],
    payload: dict | None,
    *,
    period: str | None = None,
    interval: str | None = None,
) -> tuple["pd.DataFrame | None", "pd.DataFrame | None", list[str]]:
    """Restore daily + intraday MultiIndex frames from a universe payload.

    Returns (daily_frame, intraday_frame, missing_tickers):
      - daily_frame, intraday_frame: yfinance-compatible MultiIndex frames
        with columns of (field, ticker) for tickers found in the payload.
        intraday_frame may be None if no intraday data was prefetched.
        daily_frame is None when NO ticker was restored (caller falls
        back to full live fetch).
      - missing_tickers: tickers NOT covered by the payload. The caller
        is expected to fetch ONLY these from yfinance live and concat
        with the restored frames (hybrid restore).

    When period/interval are provided, the snapshot's stored period+interval
    must match — otherwise we return (None, None, all_input) so the caller
    falls back entirely. This protects users on a custom lens (5y/1wk etc.)
    from getting truncated 1y daily data.
    """
    normalized_input = [
        normalize_dashboard_ticker(t) or str(t or "").upper().strip()
        for t in (tickers or [])
    ]
    normalized_input = [t for t in normalized_input if t]
    if not isinstance(payload, dict):
        return None, None, normalized_input

    payload_period = str(payload.get("period") or "")
    payload_interval = str(payload.get("interval") or "")
    if period is not None and payload_period and str(period) != payload_period:
        return None, None, normalized_input
    if interval is not None and payload_interval and str(interval) != payload_interval:
        return None, None, normalized_input

    daily_frames_raw = payload.get("daily_frames") or {}
    intraday_frames_raw = payload.get("intraday_frames") or {}
    if not isinstance(daily_frames_raw, dict):
        return None, None, normalized_input

    daily_columns: dict[tuple[str, str], "pd.Series"] = {}
    intraday_columns: dict[tuple[str, str], "pd.Series"] = {}
    covered: list[str] = []
    missing: list[str] = []

    for ticker in normalized_input:
        daily_payload = daily_frames_raw.get(ticker)
        if not isinstance(daily_payload, dict):
            missing.append(ticker)
            continue
        try:
            d_frame = _deserialize_active_etf_frame(daily_payload)
        except Exception:
            missing.append(ticker)
            continue
        if not isinstance(d_frame, pd.DataFrame) or d_frame.empty:
            missing.append(ticker)
            continue
        try:
            d_frame.index = pd.to_datetime(d_frame.index, errors="coerce")
        except Exception:
            missing.append(ticker)
            continue
        for col in d_frame.columns:
            series = d_frame[col]
            if isinstance(series, pd.DataFrame):
                if series.empty:
                    continue
                series = series.iloc[:, 0]
            daily_columns[(str(col), ticker)] = series

        # Intraday is optional — restore if available, skip if not.
        intraday_payload = (
            intraday_frames_raw.get(ticker)
            if isinstance(intraday_frames_raw, dict) else None
        )
        if isinstance(intraday_payload, dict):
            try:
                i_frame = _deserialize_active_etf_frame(intraday_payload)
                if isinstance(i_frame, pd.DataFrame) and not i_frame.empty:
                    try:
                        i_frame.index = pd.to_datetime(i_frame.index, errors="coerce")
                    except Exception:
                        i_frame = None
                    if isinstance(i_frame, pd.DataFrame) and not i_frame.empty:
                        for col in i_frame.columns:
                            series = i_frame[col]
                            if isinstance(series, pd.DataFrame):
                                if series.empty:
                                    continue
                                series = series.iloc[:, 0]
                            intraday_columns[(str(col), ticker)] = series
            except Exception:
                pass
        covered.append(ticker)

    if not covered:
        return None, None, normalized_input

    daily_frame = pd.DataFrame(daily_columns) if daily_columns else None
    intraday_frame = pd.DataFrame(intraday_columns) if intraday_columns else None
    if daily_frame is not None:
        daily_frame.columns = pd.MultiIndex.from_tuples(daily_frame.columns)
        daily_frame = daily_frame.sort_index(axis=1)
    if intraday_frame is not None:
        intraday_frame.columns = pd.MultiIndex.from_tuples(intraday_frame.columns)
        intraday_frame = intraday_frame.sort_index(axis=1)

    return daily_frame, intraday_frame, missing


def _build_active_etf_workspace_snapshot(
    daily_data: pd.DataFrame | None,
    intraday_data: pd.DataFrame | None,
    ticker: str,
    lens_meta: dict | None = None,
    *,
    force_market_refresh: bool = False,
) -> dict:
    period = str((lens_meta or {}).get("period", DEFAULT_PERIOD) or DEFAULT_PERIOD)
    interval = str((lens_meta or {}).get("interval", DEFAULT_INTERVAL) or DEFAULT_INTERVAL)
    lens_title = str((lens_meta or {}).get("title", DEFAULT_TREND_LENS) or DEFAULT_TREND_LENS)
    bundle = _build_active_etf_workspace_live_bundle(
        daily_data,
        intraday_data,
        ticker,
        lens_meta=lens_meta,
        force_market_refresh=force_market_refresh,
    )
    if bundle is None:
        return {
            "version": ACTIVE_ETF_LAB_SNAPSHOT_VERSION,
            "kind": "workspace",
            "ticker": str(ticker or "").upper().strip(),
            "period": period,
            "interval": interval,
            "lens_title": lens_title,
            "fetched_at": pd.Timestamp.now(tz=TW_TZ).isoformat(),
            "status": "missing",
            "bundle": {},
        }
    holdings_payload = fetch_active_etf_holdings_snapshot(ticker, max_items=40)
    fast_prefetch_mode = str(os.environ.get("ACTIVE_ETF_PREFETCH_FAST_MODE", "") or "").strip() in {"1", "true", "TRUE", "yes", "YES"}
    etf_flow_payload = (
        {
            "date": None,
            "record": {},
            "source": "TWSE T86",
            "error": "Skipped during fast Prefetch; use manual refresh for the latest ETF institutional flow.",
            "status": "skipped",
            "tried": [],
        }
        if fast_prefetch_mode
        else fetch_twse_etf_institutional_flow(ticker)
    )
    # v1.3.7: New official ETF data block. Honours ACTIVE_ETF_PREFETCH_FAST_MODE
    # internally, so it is safe to call unconditionally.
    try:
        etf_official_payload = fetch_active_etf_official_payload(ticker)
    except Exception as exc:
        etf_official_payload = {
            "ticker": str(ticker or "").upper().strip(),
            "status": "missing",
            "errors": {"unhandled": str(exc)},
            "fetched_at": pd.Timestamp.now(tz=TW_TZ).isoformat(),
            "source": ACTIVE_ETF_OFFICIAL_SOURCE_LABEL,
        }
    # v1.3.7: Pure derivation off prefetched daily_data; no extra network call.
    try:
        turnover_summary = _compute_active_etf_turnover_summary(daily_data, ticker)
    except Exception:
        turnover_summary = {}
    if isinstance(etf_official_payload, dict):
        etf_official_payload = dict(etf_official_payload)
        etf_official_payload.setdefault("turnover", {})
        if isinstance(etf_official_payload["turnover"], dict):
            etf_official_payload["turnover"].update(turnover_summary or {})
        else:
            etf_official_payload["turnover"] = dict(turnover_summary or {})
    holdings_items = list((holdings_payload or {}).get("items", []) or [])
    holdings_map = _active_etf_holdings_compare_map(holdings_items, max_items=40) if holdings_items else {}
    signal_cache: dict[str, dict] = {}
    lookthrough_payload = (
        _active_etf_build_lookthrough_snapshot(
            holdings_map,
            signal_cache=signal_cache,
            allow_live_fetch=not fast_prefetch_mode,
        )
        if holdings_map
        else {}
    )
    strategy_profile = _active_etf_strategy_profile(holdings_map) if holdings_map else {}
    underlying_signals = {}
    for symbol, signal in dict(signal_cache or {}).items():
        if not str(symbol).strip():
            continue
        underlying_signals[str(symbol).upper().strip()] = {
            "news_score": _active_etf_lab_snapshot_safe(signal.get("news_score")),
            "foreign_net": _active_etf_lab_snapshot_safe(signal.get("foreign_net")),
            "dominant_catalyst": str(signal.get("dominant_catalyst", "Macro") or "Macro"),
        }
    return {
        "version": ACTIVE_ETF_LAB_SNAPSHOT_VERSION,
        "kind": "workspace",
        "ticker": str(ticker or "").upper().strip(),
        "period": period,
        "interval": interval,
        "lens_title": lens_title,
        "fetched_at": pd.Timestamp.now(tz=TW_TZ).isoformat(),
        "status": "ready",
        "bundle": _serialize_active_etf_bundle(bundle),
        "holdings_payload": _active_etf_lab_snapshot_safe(holdings_payload),
        "etf_flow_payload": _active_etf_lab_snapshot_safe(etf_flow_payload),
        "etf_official_payload": _active_etf_lab_snapshot_safe(etf_official_payload),
        "strategy_profile": _active_etf_lab_snapshot_safe(strategy_profile),
        "lookthrough_payload": _active_etf_clean_lookthrough_snapshot(lookthrough_payload) if lookthrough_payload else {},
        "underlying_signals": underlying_signals,
    }


def _persist_active_etf_workspace_snapshot(snapshot: dict) -> dict:
    ticker = _active_etf_snapshot_ticker_key(str((snapshot or {}).get("ticker", "") or ""))
    if not ticker:
        return snapshot
    safe_snapshot = _active_etf_lab_snapshot_safe(snapshot)
    if not isinstance(safe_snapshot, dict):
        safe_snapshot = dict(snapshot or {})
    safe_snapshot["ticker"] = ticker
    snapshot_key = _active_etf_workspace_snapshot_key(
        ticker,
        {
            "period": str(safe_snapshot.get("period", DEFAULT_PERIOD) or DEFAULT_PERIOD),
            "interval": str(safe_snapshot.get("interval", DEFAULT_INTERVAL) or DEFAULT_INTERVAL),
            "title": str(safe_snapshot.get("lens_title", DEFAULT_TREND_LENS) or DEFAULT_TREND_LENS),
        },
    )
    store = _active_etf_lab_snapshot_store()
    items = dict(store.get("items", {}) or {})
    items[snapshot_key] = safe_snapshot
    store["items"] = items
    _write_active_etf_lab_snapshot_store(store)
    _upsert_supabase_active_etf_snapshot(safe_snapshot)
    return safe_snapshot


def get_active_etf_workspace_bundle_snapshot(
    daily_data: pd.DataFrame | None,
    intraday_data: pd.DataFrame | None,
    ticker: str,
    lens_meta: dict | None = None,
    *,
    force_refresh: bool = False,
) -> dict:
    snapshot_key = _active_etf_workspace_snapshot_key(ticker, lens_meta)
    store = _active_etf_lab_snapshot_store()
    existing = (store.get("items", {}) or {}).get(snapshot_key)
    if not force_refresh and _active_etf_lab_snapshot_ready(existing):
        _upsert_supabase_active_etf_snapshot(existing)
        return existing
    if force_refresh:
        _clear_active_etf_lab_refresh_caches()
    snapshot = _build_active_etf_workspace_snapshot(
        daily_data,
        intraday_data,
        ticker,
        lens_meta=lens_meta,
        force_market_refresh=force_refresh,
    )
    return _persist_active_etf_workspace_snapshot(snapshot)


def load_active_etf_workspace_bundle(
    daily_data: pd.DataFrame | None,
    intraday_data: pd.DataFrame | None,
    ticker: str,
    lens_meta: dict | None = None,
    *,
    force_refresh: bool = False,
) -> tuple[dict | None, dict]:
    snapshot = None if force_refresh else peek_active_etf_workspace_snapshot(ticker, lens_meta=lens_meta)
    if snapshot is None:
        snapshot = get_active_etf_workspace_bundle_snapshot(
            daily_data,
            intraday_data,
            ticker,
            lens_meta=lens_meta,
            force_refresh=force_refresh,
        )
    bundle = _deserialize_active_etf_bundle(snapshot.get("bundle"))
    return bundle, snapshot


def parse_active_etf_snapshot_tickers(raw_value: str | None = None) -> list[str]:
    source_value = str(raw_value or os.environ.get("ACTIVE_ETF_SNAPSHOT_TICKERS", "")).strip()
    if source_value:
        tokens = re.split(r"[\s,;|]+", source_value)
        parsed: list[str] = []
        for token in tokens:
            raw_token = str(token or "").strip().upper().replace(" ", "")
            if not raw_token:
                continue
            if ACTIVE_ETF_SYMBOL_PATTERN.fullmatch(raw_token):
                if raw_token.endswith(".TW") or raw_token.endswith(".TWO"):
                    parsed.append(raw_token)
                    continue
                tw_candidate = f"{raw_token}.TW"
                two_candidate = f"{raw_token}.TWO"
                if tw_candidate in ACTIVE_ETF_METADATA:
                    parsed.append(tw_candidate)
                elif two_candidate in ACTIVE_ETF_METADATA:
                    parsed.append(two_candidate)
                else:
                    parsed.append(tw_candidate)
                continue
            parsed.append(normalize_dashboard_ticker(token))
        return [ticker for ticker in dedupe_keep_order(parsed) if is_taiwan_active_etf(ticker)]
    return [ticker for ticker in dedupe_keep_order(ACTIVE_ETF_QUICK_PICK_SYMBOLS) if is_taiwan_active_etf(ticker)]


def _normalize_prefetch_shard_value(value: object, default: int) -> int:
    try:
        parsed = int(str(value).strip())
    except Exception:
        parsed = default
    return parsed


def _slice_prefetch_shard(items: list[str], shard_index: int | None = None, shard_count: int | None = None) -> list[str]:
    values = list(items or [])
    resolved_shard_count = _normalize_prefetch_shard_value(
        shard_count if shard_count is not None else os.environ.get("PREFETCH_SHARD_COUNT", ""),
        1,
    )
    if resolved_shard_count <= 1:
        return values

    resolved_shard_index = _normalize_prefetch_shard_value(
        shard_index if shard_index is not None else os.environ.get("PREFETCH_SHARD_INDEX", ""),
        0,
    )
    if resolved_shard_index < 0 or resolved_shard_index >= resolved_shard_count:
        return values
    return [item for idx, item in enumerate(values) if idx % resolved_shard_count == resolved_shard_index]


def _active_etf_snapshot_is_fresh_for_today(snapshot: dict | None) -> bool:
    if not _active_etf_lab_snapshot_ready(snapshot):
        return False
    fetched_ts = _normalize_tw_timestamp((snapshot or {}).get("fetched_at"))
    if fetched_ts is None:
        return False
    return fetched_ts.date() == datetime.now(TW_TZ).date()


def prefetch_active_etf_snapshots_job(
    tickers: list[str] | None = None,
    *,
    lens_meta: dict | None = None,
    period: str | None = None,
    interval: str | None = None,
    shard_index: int | None = None,
    shard_count: int | None = None,
) -> dict:
    requested_tickers = [
        ticker for ticker in dedupe_keep_order(tickers or parse_active_etf_snapshot_tickers())
        if is_taiwan_active_etf(ticker)
    ]
    if not requested_tickers:
        return {"status": "skipped", "reason": "No active ETF tickers configured.", "tickers": []}

    selected_tickers: list[str] = []
    skipped_tickers: list[str] = []
    for ticker in requested_tickers:
        normalized = normalize_taiwan_active_etf_symbol(ticker) or str(ticker or "").upper().strip()
        if normalized and yahoo_symbol_has_history(normalized):
            selected_tickers.append(normalized)
        else:
            skipped_tickers.append(str(ticker or "").upper().strip())

    if not selected_tickers:
        return {
            "status": "skipped",
            "reason": "No active ETF tickers with Yahoo price history available.",
            "tickers": [],
            "requested_tickers": requested_tickers,
            "skipped_tickers": skipped_tickers,
        }

    if lens_meta is None:
        resolved_period = str(period or DEFAULT_PERIOD or "1y")
        resolved_interval = str(interval or DEFAULT_INTERVAL or "1d")
        lens_meta = {
            "period": resolved_period,
            "interval": resolved_interval,
            "title": DEFAULT_TREND_LENS,
        }

    sharded_tickers = _slice_prefetch_shard(selected_tickers, shard_index=shard_index, shard_count=shard_count)
    resolved_shard_count = _normalize_prefetch_shard_value(
        shard_count if shard_count is not None else os.environ.get("PREFETCH_SHARD_COUNT", ""),
        1,
    )
    resolved_shard_index = _normalize_prefetch_shard_value(
        shard_index if shard_index is not None else os.environ.get("PREFETCH_SHARD_INDEX", ""),
        0,
    )
    if not sharded_tickers:
        return {
            "status": "skipped",
            "reason": "No active ETF tickers assigned to this shard.",
            "tickers": [],
            "requested_tickers": requested_tickers,
            "selected_tickers": selected_tickers,
            "skipped_tickers": skipped_tickers,
            "shard_index": resolved_shard_index,
            "shard_count": resolved_shard_count,
        }

    fresh_skipped_rows: list[dict] = []
    build_tickers: list[str] = []
    for ticker in sharded_tickers:
        existing_snapshot = _peek_active_etf_workspace_snapshot_exact(ticker, lens_meta=lens_meta)
        if _active_etf_snapshot_is_fresh_for_today(existing_snapshot):
            fresh_skipped_rows.append(
                {
                    "ticker": ticker,
                    "status": "fresh_skip",
                    "fetched_at": str((existing_snapshot or {}).get("fetched_at", "") or ""),
                }
            )
            continue
        build_tickers.append(ticker)

    if not build_tickers:
        return {
            "status": "ok",
            "tickers": sharded_tickers,
            "requested_tickers": requested_tickers,
            "selected_tickers": selected_tickers,
            "skipped_tickers": skipped_tickers,
            "rows": fresh_skipped_rows,
            "fresh_skipped_tickers": [row["ticker"] for row in fresh_skipped_rows],
            "built_tickers": [],
            "fetched_at": pd.Timestamp.now(tz=TW_TZ).isoformat(),
            "lens_title": str(lens_meta.get("title", DEFAULT_TREND_LENS) or DEFAULT_TREND_LENS),
            "period": str(lens_meta.get("period", DEFAULT_PERIOD) or DEFAULT_PERIOD),
            "interval": str(lens_meta.get("interval", DEFAULT_INTERVAL) or DEFAULT_INTERVAL),
            "shard_index": resolved_shard_index,
            "shard_count": resolved_shard_count,
        }

    _clear_active_etf_lab_refresh_caches()
    daily_data = fetch_daily_data(build_tickers, str(lens_meta.get("period", DEFAULT_PERIOD) or DEFAULT_PERIOD), str(lens_meta.get("interval", DEFAULT_INTERVAL) or DEFAULT_INTERVAL))
    intraday_data = fetch_intraday_data(build_tickers)

    built_rows: list[dict] = list(fresh_skipped_rows)
    for ticker in build_tickers:
        snapshot = _build_active_etf_workspace_snapshot(daily_data, intraday_data, ticker, lens_meta=lens_meta, force_market_refresh=False)
        _persist_active_etf_workspace_snapshot(snapshot)
        built_rows.append(
            {
                "ticker": ticker,
                "status": str(snapshot.get("status", "missing") or "missing"),
                "fetched_at": str(snapshot.get("fetched_at", "") or ""),
            }
        )

    return {
        "status": "ok",
        "tickers": sharded_tickers,
        "requested_tickers": requested_tickers,
        "selected_tickers": selected_tickers,
        "skipped_tickers": skipped_tickers,
        "rows": built_rows,
        "fresh_skipped_tickers": [row["ticker"] for row in fresh_skipped_rows],
        "built_tickers": build_tickers,
        "fetched_at": pd.Timestamp.now(tz=TW_TZ).isoformat(),
        "lens_title": str(lens_meta.get("title", DEFAULT_TREND_LENS) or DEFAULT_TREND_LENS),
        "period": str(lens_meta.get("period", DEFAULT_PERIOD) or DEFAULT_PERIOD),
        "interval": str(lens_meta.get("interval", DEFAULT_INTERVAL) or DEFAULT_INTERVAL),
        "shard_index": resolved_shard_index,
        "shard_count": resolved_shard_count,
    }


# ---------------------------------------------------------------------------
# v1.3.7: Active ETF pair compare prefetch job
# Designed to run AFTER prefetch_active_etf_snapshots_job has populated the
# individual workspace snapshots. Synthesizes pair compares for the configured
# pair list (or for all combinations of the active ETF universe by default)
# and persists them to both the local store and Supabase.
# ---------------------------------------------------------------------------
def parse_active_etf_pair_snapshot_pairs(
    raw_value: str | None = None,
    *,
    fallback_tickers: list[str] | None = None,
    max_default_pairs: int | None = None,
) -> list[tuple[str, str]]:
    """Parse an environment variable describing which pair compares to prefetch.

    Accepted formats (any combination of separators):
        ACTIVE_ETF_SNAPSHOT_PAIRS="00982A.TW|00981A.TW, 00988A.TW|00981A.TW"
        ACTIVE_ETF_SNAPSHOT_PAIRS="00982A.TW>00981A.TW; 00988A.TW>00981A.TW"

    When no env var is provided, falls back to "all unordered combinations of
    the configured active ETF tickers", capped at ``max_default_pairs`` (default
    24, controllable via ``ACTIVE_ETF_PAIR_MAX_DEFAULT_PAIRS``).
    """
    source_value = str(raw_value or os.environ.get("ACTIVE_ETF_SNAPSHOT_PAIRS", "")).strip()
    pairs: list[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()

    def _add(left: str, right: str) -> None:
        left_norm = normalize_dashboard_ticker(left)
        right_norm = normalize_dashboard_ticker(right)
        if not left_norm or not right_norm or left_norm == right_norm:
            return
        if not is_taiwan_active_etf(left_norm) or not is_taiwan_active_etf(right_norm):
            return
        # Treat (A, B) and (B, A) as the same pair so we don't waste budget.
        key = tuple(sorted([left_norm, right_norm]))
        if key in seen:
            return
        seen.add(key)
        pairs.append((left_norm, right_norm))

    if source_value:
        for token in re.split(r"[,;]+", source_value):
            token = token.strip()
            if not token:
                continue
            sides = [piece.strip() for piece in re.split(r"[|>/]+", token) if piece.strip()]
            if len(sides) < 2:
                continue
            _add(sides[0], sides[1])
        return pairs

    base_tickers = list(fallback_tickers or [])
    if not base_tickers:
        base_tickers = parse_active_etf_snapshot_tickers()
    base_tickers = [t for t in dedupe_keep_order(base_tickers) if is_taiwan_active_etf(t)]

    if max_default_pairs is None:
        try:
            max_default_pairs = int(str(os.environ.get("ACTIVE_ETF_PAIR_MAX_DEFAULT_PAIRS", "24") or 24))
        except Exception:
            max_default_pairs = 24

    for i in range(len(base_tickers)):
        for j in range(i + 1, len(base_tickers)):
            _add(base_tickers[i], base_tickers[j])
            if max_default_pairs and len(pairs) >= max_default_pairs:
                return pairs
    return pairs


def _active_etf_pair_snapshot_is_fresh_for_today(snapshot: dict | None) -> bool:
    if not _active_etf_lab_snapshot_ready(snapshot):
        return False
    fetched_ts = _normalize_tw_timestamp((snapshot or {}).get("fetched_at"))
    if fetched_ts is None:
        return False
    return fetched_ts.date() == datetime.now(TW_TZ).date()


def prefetch_active_etf_pair_compare_snapshots_job(
    pairs: list[tuple[str, str]] | None = None,
    *,
    shard_index: int | None = None,
    shard_count: int | None = None,
) -> dict:
    """Prefetch pair compare snapshots for a configurable list of ETF pairs.

    Run this AFTER ``prefetch_active_etf_snapshots_job`` has populated the
    individual workspace snapshots. For each requested pair, this job:

      1. Looks up the latest workspace snapshot for each side.
      2. If both sides are ready, synthesizes the pair compare in-memory via
         ``_build_active_etf_pair_compare_snapshot_from_workspace_snapshots``.
      3. Persists the result to the local JSON store **and** Supabase using
         ``_persist_active_etf_pair_snapshot`` (so any runtime can read it
         back via ``peek_active_etf_pair_snapshot`` Path C).

    Pairs whose compare snapshot is already fresh today are skipped, so the
    job is idempotent and cheap to re-run.

    Returns a dict with per-pair status rows, suitable for logging in a
    GitHub Actions step summary.
    """
    requested_pairs: list[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()
    raw_pairs = pairs if pairs is not None else parse_active_etf_pair_snapshot_pairs()
    for left, right in raw_pairs or []:
        left_norm = normalize_dashboard_ticker(left)
        right_norm = normalize_dashboard_ticker(right)
        if not left_norm or not right_norm or left_norm == right_norm:
            continue
        key = tuple(sorted([left_norm, right_norm]))
        if key in seen:
            continue
        seen.add(key)
        requested_pairs.append((left_norm, right_norm))

    if not requested_pairs:
        return {"status": "skipped", "reason": "No active ETF pairs configured.", "pairs": []}

    # Shard support, mirroring prefetch_active_etf_snapshots_job
    resolved_shard_count = _normalize_prefetch_shard_value(
        shard_count if shard_count is not None else os.environ.get("PREFETCH_SHARD_COUNT", ""),
        1,
    )
    resolved_shard_index = _normalize_prefetch_shard_value(
        shard_index if shard_index is not None else os.environ.get("PREFETCH_SHARD_INDEX", ""),
        0,
    )
    if resolved_shard_count > 1 and 0 <= resolved_shard_index < resolved_shard_count:
        sharded_pairs = [
            pair for idx, pair in enumerate(requested_pairs)
            if idx % resolved_shard_count == resolved_shard_index
        ]
    else:
        sharded_pairs = list(requested_pairs)

    if not sharded_pairs:
        return {
            "status": "skipped",
            "reason": "No active ETF pairs assigned to this shard.",
            "pairs": [],
            "requested_pairs": [list(pair) for pair in requested_pairs],
            "shard_index": resolved_shard_index,
            "shard_count": resolved_shard_count,
        }

    fresh_skipped_rows: list[dict] = []
    build_pairs: list[tuple[str, str]] = []
    for left, right in sharded_pairs:
        # Only check the local store directly (NOT peek_active_etf_pair_snapshot,
        # which would re-synthesize even when fresh). This keeps the fresh-skip
        # check cheap and idempotent.
        store_items = (_active_etf_lab_snapshot_store().get("items", {}) or {})
        existing_local = store_items.get(_active_etf_pair_snapshot_key(left, right))
        existing = existing_local if _active_etf_lab_snapshot_ready(existing_local) else None
        if existing is None:
            try:
                existing = _load_supabase_active_etf_pair_snapshot(left, right)
            except Exception:
                existing = None
        if _active_etf_pair_snapshot_is_fresh_for_today(existing):
            fresh_skipped_rows.append(
                {
                    "left": left,
                    "right": right,
                    "status": "fresh_skip",
                    "fetched_at": str((existing or {}).get("fetched_at", "") or ""),
                }
            )
            continue
        build_pairs.append((left, right))

    built_rows: list[dict] = list(fresh_skipped_rows)
    if not build_pairs:
        return {
            "status": "ok",
            "pairs": [list(pair) for pair in sharded_pairs],
            "requested_pairs": [list(pair) for pair in requested_pairs],
            "rows": built_rows,
            "built_pairs": [],
            "fresh_skipped_pairs": [[row["left"], row["right"]] for row in fresh_skipped_rows],
            "fetched_at": pd.Timestamp.now(tz=TW_TZ).isoformat(),
            "shard_index": resolved_shard_index,
            "shard_count": resolved_shard_count,
        }

    for left, right in build_pairs:
        left_workspace = peek_active_etf_workspace_snapshot(left, lens_meta=None)
        right_workspace = peek_active_etf_workspace_snapshot(right, lens_meta=None)
        if not _active_etf_lab_snapshot_ready(left_workspace) or not _active_etf_lab_snapshot_ready(right_workspace):
            built_rows.append(
                {
                    "left": left,
                    "right": right,
                    "status": "missing_workspace",
                    "fetched_at": "",
                    "error": "Workspace snapshot missing for one or both ETFs. Run prefetch_active_etf_snapshots_job first.",
                }
            )
            continue
        try:
            synthesized = _build_active_etf_pair_compare_snapshot_from_workspace_snapshots(
                left_workspace, right_workspace
            )
        except Exception as exc:
            built_rows.append(
                {
                    "left": left,
                    "right": right,
                    "status": "error",
                    "fetched_at": "",
                    "error": f"Synthesis failed: {exc}",
                }
            )
            continue
        if not _active_etf_lab_snapshot_ready(synthesized):
            built_rows.append(
                {
                    "left": left,
                    "right": right,
                    "status": str((synthesized or {}).get("status", "missing") or "missing"),
                    "fetched_at": str((synthesized or {}).get("fetched_at", "") or ""),
                }
            )
            continue
        persisted = _persist_active_etf_pair_snapshot(synthesized)
        built_rows.append(
            {
                "left": left,
                "right": right,
                "status": str((persisted or {}).get("status", "ready") or "ready"),
                "fetched_at": str((persisted or {}).get("fetched_at", "") or ""),
            }
        )

    return {
        "status": "ok",
        "pairs": [list(pair) for pair in sharded_pairs],
        "requested_pairs": [list(pair) for pair in requested_pairs],
        "rows": built_rows,
        "built_pairs": [[left, right] for left, right in build_pairs],
        "fresh_skipped_pairs": [[row["left"], row["right"]] for row in fresh_skipped_rows],
        "fetched_at": pd.Timestamp.now(tz=TW_TZ).isoformat(),
        "shard_index": resolved_shard_index,
        "shard_count": resolved_shard_count,
    }


def _taiwan_official_snapshot_store() -> dict:
    empty_store = {"version": TAIWAN_OFFICIAL_SNAPSHOT_VERSION, "items": {}}
    try:
        if not TAIWAN_OFFICIAL_SNAPSHOT_PATH.exists():
            return empty_store
        payload = json.loads(TAIWAN_OFFICIAL_SNAPSHOT_PATH.read_text(encoding="utf-8"))
    except Exception:
        return empty_store
    if not isinstance(payload, dict):
        return empty_store
    items = payload.get("items")
    if not isinstance(items, dict):
        items = {}
    return {
        "version": int(payload.get("version", TAIWAN_OFFICIAL_SNAPSHOT_VERSION) or TAIWAN_OFFICIAL_SNAPSHOT_VERSION),
        "items": items,
    }


def _write_taiwan_official_snapshot_store(store: dict) -> None:
    TAIWAN_OFFICIAL_SNAPSHOT_PATH.parent.mkdir(parents=True, exist_ok=True)
    payload = {
        "version": TAIWAN_OFFICIAL_SNAPSHOT_VERSION,
        "items": dict((store or {}).get("items", {}) or {}),
    }
    try:
        TAIWAN_OFFICIAL_SNAPSHOT_PATH.write_text(
            json.dumps(payload, ensure_ascii=False, indent=2),
            encoding="utf-8",
        )
    except Exception:
        pass


def _taiwan_official_snapshot_target(snapshot_kind: str, ticker: str | None = None) -> str:
    kind = str(snapshot_kind or "ticker").strip().lower()
    if kind == "macro":
        return TAIWAN_OFFICIAL_SNAPSHOT_MARKET_KEY
    normalized = normalize_dashboard_ticker(ticker)
    return str(normalized or ticker or "").upper().strip()


def _taiwan_official_snapshot_key(snapshot_kind: str, ticker: str | None = None) -> str:
    kind = str(snapshot_kind or "ticker").strip().lower()
    return f"{kind}::{_taiwan_official_snapshot_target(kind, ticker)}"


def _taiwan_official_snapshot_as_of_date(snapshot: dict | None) -> str:
    ts = _normalize_tw_timestamp((snapshot or {}).get("fetched_at"))
    if ts is None:
        return _snapshot_today_string()
    return ts.date().isoformat()


def _supabase_taiwan_official_read_request(path: str) -> tuple[int, dict | list | str]:
    if _supabase_is_configured():
        status, payload = _supabase_request("GET", path)
        if 200 <= status < 300:
            return status, payload
    if _supabase_service_is_configured():
        return _supabase_service_request("GET", path)
    return 0, {"message": "Supabase is not configured."}


def _taiwan_official_supabase_row_from_snapshot(snapshot: dict) -> dict:
    snapshot_kind = str((snapshot or {}).get("snapshot_kind", "ticker") or "ticker").strip().lower()
    snapshot_ticker = _taiwan_official_snapshot_target(snapshot_kind, str((snapshot or {}).get("ticker", "") or ""))
    return {
        "snapshot_kind": snapshot_kind,
        "ticker": snapshot_ticker,
        "as_of_date": _taiwan_official_snapshot_as_of_date(snapshot),
        "fetched_at": str(snapshot.get("fetched_at") or pd.Timestamp.now(tz=TW_TZ).isoformat()),
        "status": str(snapshot.get("status", "ready") or "ready"),
        "snapshot_payload": _json_request_safe(snapshot),
    }


def _taiwan_official_supabase_snapshot_from_row(row: dict | None) -> dict | None:
    if not isinstance(row, dict):
        return None
    payload = row.get("snapshot_payload", {})
    if isinstance(payload, str):
        try:
            payload = json.loads(payload)
        except Exception:
            payload = {}
    if not isinstance(payload, dict):
        payload = {}
    snapshot = dict(payload)
    snapshot_kind = str(row.get("snapshot_kind", snapshot.get("snapshot_kind", "ticker")) or "ticker").strip().lower()
    snapshot_ticker = _taiwan_official_snapshot_target(snapshot_kind, str(row.get("ticker", snapshot.get("ticker", "")) or ""))
    snapshot.setdefault("version", TAIWAN_OFFICIAL_SNAPSHOT_VERSION)
    snapshot.setdefault("snapshot_kind", snapshot_kind)
    snapshot["ticker"] = snapshot_ticker if snapshot_kind == "macro" else str(snapshot.get("ticker", snapshot_ticker) or snapshot_ticker).upper().strip()
    snapshot.setdefault("status", str(row.get("status", "ready") or "ready"))
    snapshot.setdefault("fetched_at", str(row.get("fetched_at", "") or ""))
    return snapshot


def _load_supabase_taiwan_official_snapshot(snapshot_kind: str, ticker: str | None = None) -> dict | None:
    kind = str(snapshot_kind or "ticker").strip().lower()
    target = _taiwan_official_snapshot_target(kind, ticker)
    select_query = quote_plus("snapshot_kind,ticker,as_of_date,fetched_at,status,snapshot_payload")
    filters = [
        f"snapshot_kind=eq.{quote_plus(kind)}",
        f"ticker=eq.{quote_plus(target)}",
    ]
    path = (
        f"/rest/v1/{SUPABASE_TAIWAN_OFFICIAL_SNAPSHOT_TABLE}"
        f"?select={select_query}&{'&'.join(filters)}&order=as_of_date.desc,fetched_at.desc&limit=1"
    )
    status, payload = _supabase_taiwan_official_read_request(path)
    if not (200 <= status < 300) or not isinstance(payload, list) or not payload:
        return None
    return _taiwan_official_supabase_snapshot_from_row(payload[0])


def _upsert_supabase_taiwan_official_snapshot(snapshot: dict) -> bool:
    snapshot_kind = str((snapshot or {}).get("snapshot_kind", "ticker") or "ticker").strip().lower()
    target = _taiwan_official_snapshot_target(snapshot_kind, str((snapshot or {}).get("ticker", "") or ""))
    if not snapshot_kind or not target or not _supabase_service_is_configured():
        return False
    row = _taiwan_official_supabase_row_from_snapshot(snapshot)
    path = (
        f"/rest/v1/{SUPABASE_TAIWAN_OFFICIAL_SNAPSHOT_TABLE}"
        f"?on_conflict={quote_plus('snapshot_kind,ticker,as_of_date')}"
    )
    status, _ = _supabase_service_request(
        "POST",
        path,
        payload=[row],
        extra_headers={"Prefer": "resolution=merge-duplicates,return=minimal"},
    )
    return 200 <= status < 300


def _taiwan_official_snapshot_ready(snapshot: dict | None) -> bool:
    return (
        isinstance(snapshot, dict)
        and int(snapshot.get("version", 0) or 0) == TAIWAN_OFFICIAL_SNAPSHOT_VERSION
        and str(snapshot.get("status", "") or "") == "ready"
    )


def _taiwan_official_snapshot_has_retryable_errors(snapshot: dict | None) -> bool:
    if not isinstance(snapshot, dict):
        return False
    errors = dict((snapshot or {}).get("errors", {}) or {})
    if not errors:
        return False
    flow_error = str(errors.get("flow", "") or "").strip()
    revenue_error = str(errors.get("revenue", "") or "").strip()
    valuation_error = str(errors.get("valuation", "") or "").strip()
    foreign_error = str(errors.get("foreign_ownership", "") or "").strip()
    ticker = str((snapshot or {}).get("ticker", "") or "").upper().strip()
    if is_taiwan_active_etf(ticker):
        return bool(flow_error)
    return bool(flow_error or revenue_error or valuation_error or foreign_error)


def format_taiwan_official_snapshot_fetched_at(value: object) -> str:
    ts = _normalize_tw_timestamp(value)
    if ts is None:
        return "—"
    return ts.strftime("%Y-%m-%d %H:%M")


def _clear_taiwan_official_refresh_caches() -> None:
    for cached_func in (
        fetch_taiwan_official_dashboard_snapshot,
        fetch_twse_valuation_snapshot,
        fetch_twse_stock_institutional_flow,
        fetch_tpex_snapshot_bundle,
        fetch_monthly_revenue_snapshot,
        fetch_cbc_macro_snapshot,
        fetch_taifex_put_call_snapshot,
        fetch_twse_etf_institutional_flow,
    ):
        try:
            cached_func.clear()
        except Exception:
            pass


def _build_taiwan_official_macro_snapshot(*, force_refresh: bool = False) -> dict:
    if force_refresh:
        for cached_func in (fetch_cbc_macro_snapshot, fetch_taifex_put_call_snapshot):
            try:
                cached_func.clear()
            except Exception:
                pass
    macro = _json_request_safe(fetch_cbc_macro_snapshot())
    derivatives = _json_request_safe(fetch_taifex_put_call_snapshot())
    return {
        "version": TAIWAN_OFFICIAL_SNAPSHOT_VERSION,
        "snapshot_kind": "macro",
        "ticker": TAIWAN_OFFICIAL_SNAPSHOT_MARKET_KEY,
        "fetched_at": pd.Timestamp.now(tz=TW_TZ).isoformat(),
        "status": "ready",
        "macro": macro if isinstance(macro, dict) else {},
        "derivatives": derivatives if isinstance(derivatives, dict) else {},
        "errors": {
            "cbc_fx": str(((macro or {}).get("fx", {}) or {}).get("error", "")),
            "cbc_rate": str(((macro or {}).get("policy_rate", {}) or {}).get("error", "")),
            "taifex_pcr": str((derivatives or {}).get("error", "")),
        },
    }


def _build_taiwan_official_ticker_snapshot(
    ticker: str,
    *,
    macro_snapshot: dict | None = None,
    force_refresh: bool = False,
) -> dict:
    normalized = normalize_dashboard_ticker(ticker)
    if not is_taiwan_ticker(normalized):
        return {
            "version": TAIWAN_OFFICIAL_SNAPSHOT_VERSION,
            "snapshot_kind": "ticker",
            "ticker": str(normalized or ticker or "").upper().strip(),
            "fetched_at": pd.Timestamp.now(tz=TW_TZ).isoformat(),
            "status": "missing",
            "valuation": {},
            "flow": {},
            "revenue": {},
            "macro": {},
            "derivatives": {},
            "errors": {"ticker": "Unsupported or empty Taiwan ticker."},
        }
    if force_refresh:
        for cached_func in (
            fetch_taiwan_official_dashboard_snapshot,
            fetch_twse_valuation_snapshot,
            fetch_twse_stock_institutional_flow,
            fetch_twse_foreign_shareholding_snapshot,
            fetch_tpex_snapshot_bundle,
            fetch_monthly_revenue_snapshot,
            fetch_twse_etf_institutional_flow,
        ):
            try:
                cached_func.clear()
            except Exception:
                pass
    payload = _build_taiwan_official_dashboard_payload(normalized, macro_snapshot=macro_snapshot)
    snapshot = dict(payload or {})
    snapshot["version"] = TAIWAN_OFFICIAL_SNAPSHOT_VERSION
    snapshot["snapshot_kind"] = "ticker"
    snapshot["ticker"] = str(snapshot.get("ticker", normalized) or normalized).upper().strip()
    snapshot["fetched_at"] = pd.Timestamp.now(tz=TW_TZ).isoformat()
    snapshot["status"] = "ready" if snapshot else "missing"
    market_fetched_at = str((macro_snapshot or {}).get("fetched_at", "") or "")
    if market_fetched_at:
        snapshot["market_fetched_at"] = market_fetched_at
    return _json_request_safe(snapshot)


def _persist_taiwan_official_snapshot(snapshot: dict) -> dict:
    snapshot_kind = str((snapshot or {}).get("snapshot_kind", "ticker") or "ticker").strip().lower()
    target = _taiwan_official_snapshot_target(snapshot_kind, str((snapshot or {}).get("ticker", "") or ""))
    if not snapshot_kind or not target:
        return snapshot
    safe_snapshot = _json_request_safe(snapshot)
    if not isinstance(safe_snapshot, dict):
        safe_snapshot = dict(snapshot or {})
    safe_snapshot["version"] = int(safe_snapshot.get("version", TAIWAN_OFFICIAL_SNAPSHOT_VERSION) or TAIWAN_OFFICIAL_SNAPSHOT_VERSION)
    safe_snapshot["snapshot_kind"] = snapshot_kind
    safe_snapshot["ticker"] = target if snapshot_kind == "macro" else str(safe_snapshot.get("ticker", target) or target).upper().strip()
    store = _taiwan_official_snapshot_store()
    items = dict(store.get("items", {}) or {})
    items[_taiwan_official_snapshot_key(snapshot_kind, target)] = safe_snapshot
    store["items"] = items
    _write_taiwan_official_snapshot_store(store)
    _upsert_supabase_taiwan_official_snapshot(safe_snapshot)
    return safe_snapshot


def peek_taiwan_official_macro_snapshot() -> dict | None:
    remote_snapshot = _load_supabase_taiwan_official_snapshot("macro", TAIWAN_OFFICIAL_SNAPSHOT_MARKET_KEY)
    if _taiwan_official_snapshot_ready(remote_snapshot):
        return remote_snapshot
    store = _taiwan_official_snapshot_store()
    snapshot = (store.get("items", {}) or {}).get(_taiwan_official_snapshot_key("macro", TAIWAN_OFFICIAL_SNAPSHOT_MARKET_KEY))
    if not _taiwan_official_snapshot_ready(snapshot):
        return None
    return snapshot


def get_taiwan_official_macro_snapshot(*, force_refresh: bool = False) -> dict:
    if not force_refresh:
        existing = peek_taiwan_official_macro_snapshot()
        if _taiwan_official_snapshot_ready(existing):
            return existing
    snapshot = _build_taiwan_official_macro_snapshot(force_refresh=force_refresh)
    return _persist_taiwan_official_snapshot(snapshot)


def peek_taiwan_official_ticker_snapshot(ticker: str) -> dict | None:
    normalized = normalize_dashboard_ticker(ticker)
    if not is_taiwan_ticker(normalized):
        return None
    remote_snapshot = _load_supabase_taiwan_official_snapshot("ticker", normalized)
    if _taiwan_official_snapshot_ready(remote_snapshot):
        return remote_snapshot
    store = _taiwan_official_snapshot_store()
    snapshot = (store.get("items", {}) or {}).get(_taiwan_official_snapshot_key("ticker", normalized))
    if not _taiwan_official_snapshot_ready(snapshot):
        return None
    return snapshot


def get_taiwan_official_ticker_snapshot(
    ticker: str,
    *,
    force_refresh: bool = False,
    macro_snapshot: dict | None = None,
) -> dict:
    normalized = normalize_dashboard_ticker(ticker)
    if not is_taiwan_ticker(normalized):
        return {}
    if not force_refresh:
        existing = peek_taiwan_official_ticker_snapshot(normalized)
        if _taiwan_official_snapshot_ready(existing):
            return existing
    resolved_macro_snapshot = macro_snapshot
    if resolved_macro_snapshot is None:
        resolved_macro_snapshot = get_taiwan_official_macro_snapshot(force_refresh=force_refresh)
    snapshot = _build_taiwan_official_ticker_snapshot(
        normalized,
        macro_snapshot=resolved_macro_snapshot,
        force_refresh=force_refresh,
    )
    return _persist_taiwan_official_snapshot(snapshot)


def load_taiwan_official_dashboard_snapshot(ticker: str, *, force_refresh: bool = False) -> dict:
    normalized = normalize_dashboard_ticker(ticker)
    if not is_taiwan_ticker(normalized):
        return {}
    return get_taiwan_official_ticker_snapshot(normalized, force_refresh=force_refresh)


def default_taiwan_official_prefetch_tickers() -> list[str]:
    preferred_groups = [
        "Taiwan Semiconductors",
        "Taiwan AI Supply Chain",
        "ABF 載板四雄",
        "記憶體供應鏈",
        "封裝測試產業鏈",
        "機器人供應鏈",
        "Taiwan ETFs",
    ]
    collected: list[str] = []
    market_groups = globals().get("WATCHLIST_PRESETS", {}) or {}
    for group_name in preferred_groups:
        group_tickers = market_groups.get(group_name, []) if isinstance(market_groups, dict) else []
        if isinstance(group_tickers, list):
            collected.extend(group_tickers)
    collected.extend(normalize_dashboard_ticker(ticker) for ticker in ACTIVE_ETF_QUICK_PICK_SYMBOLS)
    normalized_defaults = [normalize_dashboard_ticker(ticker) for ticker in DEFAULT_TICKERS if is_taiwan_ticker(ticker)]
    normalized_collected = [normalize_dashboard_ticker(ticker) for ticker in collected if str(ticker).strip()]
    fallback = dedupe_keep_order(normalized_collected + normalized_defaults)
    return [ticker for ticker in fallback if is_taiwan_ticker(ticker)]


def parse_taiwan_official_snapshot_tickers(raw_value: str | None = None) -> list[str]:
    explicit_value = str(raw_value or "").strip()
    if explicit_value:
        tokens = re.split(r"[\s,;|]+", explicit_value)
        parsed = [normalize_dashboard_ticker(token) for token in tokens if str(token).strip()]
        return [ticker for ticker in dedupe_keep_order(parsed) if is_taiwan_ticker(ticker)]

    env_value = str(os.environ.get("TAIWAN_OFFICIAL_SNAPSHOT_TICKERS", "")).strip()
    default_prefetch = default_taiwan_official_prefetch_tickers()
    if env_value:
        tokens = re.split(r"[\s,;|]+", env_value)
        parsed = [normalize_dashboard_ticker(token) for token in tokens if str(token).strip()]
        merged = dedupe_keep_order(parsed + default_prefetch)
        return [ticker for ticker in merged if is_taiwan_ticker(ticker)]
    return default_prefetch


def _taiwan_official_snapshot_is_fresh_for_today(snapshot: dict | None) -> bool:
    if not _taiwan_official_snapshot_ready(snapshot):
        return False
    if _taiwan_official_snapshot_has_retryable_errors(snapshot):
        return False
    fetched_ts = _normalize_tw_timestamp((snapshot or {}).get("fetched_at"))
    if fetched_ts is None:
        return False
    return fetched_ts.date() == datetime.now(TW_TZ).date()


def prefetch_taiwan_official_snapshots_job(
    tickers: list[str] | None = None,
    *,
    force_refresh: bool = False,
    shard_index: int | None = None,
    shard_count: int | None = None,
    include_macro: bool = True,
    include_tickers: bool = True,
) -> dict:
    requested_tickers = [
        ticker for ticker in dedupe_keep_order(tickers or parse_taiwan_official_snapshot_tickers())
        if is_taiwan_ticker(ticker)
    ]
    if not include_macro and not include_tickers:
        return {"status": "skipped", "reason": "No Taiwan official snapshot scope selected.", "tickers": []}

    resolved_shard_count = _normalize_prefetch_shard_value(
        shard_count if shard_count is not None else os.environ.get("PREFETCH_SHARD_COUNT", ""),
        1,
    )
    resolved_shard_index = _normalize_prefetch_shard_value(
        shard_index if shard_index is not None else os.environ.get("PREFETCH_SHARD_INDEX", ""),
        0,
    )

    selected_tickers = _slice_prefetch_shard(requested_tickers, shard_index=shard_index, shard_count=shard_count)
    if include_tickers and resolved_shard_count > 1 and not selected_tickers:
        return {
            "status": "skipped",
            "reason": "No Taiwan official tickers assigned to this shard.",
            "tickers": [],
            "requested_tickers": requested_tickers,
            "shard_index": resolved_shard_index,
            "shard_count": resolved_shard_count,
            "include_macro": include_macro,
            "include_tickers": include_tickers,
        }

    if force_refresh:
        _clear_taiwan_official_refresh_caches()

    market_snapshot = {}
    if include_macro:
        market_snapshot = get_taiwan_official_macro_snapshot(force_refresh=force_refresh)
    elif not force_refresh:
        market_snapshot = peek_taiwan_official_macro_snapshot() or {}

    built_rows: list[dict] = []
    fresh_skipped_rows: list[dict] = []
    build_tickers: list[str] = []
    if include_tickers:
        for ticker in selected_tickers:
            existing_snapshot = peek_taiwan_official_ticker_snapshot(ticker)
            if not force_refresh and _taiwan_official_snapshot_is_fresh_for_today(existing_snapshot):
                fresh_skipped_rows.append(
                    {
                        "ticker": str((existing_snapshot or {}).get("ticker", ticker) or ticker),
                        "status": "fresh_skip",
                        "fetched_at": str((existing_snapshot or {}).get("fetched_at", "") or ""),
                    }
                )
                continue
            build_tickers.append(ticker)

    for row in fresh_skipped_rows:
        built_rows.append(row)

    for ticker in build_tickers:
        snapshot = get_taiwan_official_ticker_snapshot(
            ticker,
            force_refresh=force_refresh,
            macro_snapshot=market_snapshot or None,
        )
        built_rows.append(
            {
                "ticker": str(snapshot.get("ticker", ticker) or ticker),
                "status": str(snapshot.get("status", "missing") or "missing"),
                "fetched_at": str(snapshot.get("fetched_at", "") or ""),
            }
        )
    return {
        "status": "ok",
        "tickers": selected_tickers,
        "requested_tickers": requested_tickers,
        "rows": built_rows,
        "market_status": str((market_snapshot or {}).get("status", "missing") or "missing"),
        "market_fetched_at": str((market_snapshot or {}).get("fetched_at", "") or ""),
        "fetched_at": pd.Timestamp.now(tz=TW_TZ).isoformat(),
        "fresh_skipped_tickers": [row["ticker"] for row in fresh_skipped_rows],
        "built_tickers": build_tickers,
        "shard_index": resolved_shard_index,
        "shard_count": resolved_shard_count,
        "include_macro": include_macro,
        "include_tickers": include_tickers,
    }



