def coerce_float(value):
    if value is None or value is pd.NA:
        return pd.NA
    try:
        number = float(value)
    except (TypeError, ValueError):
        return pd.NA
    return pd.NA if pd.isna(number) else number

def format_local_price(value, ticker: str | None = None):
    value = coerce_float(value)
    if pd.isna(value):
        return "N/A"
    prefix = "NT$" if ticker and is_taiwan_ticker(ticker) else "$"
    return f"{prefix}{value:,.2f}"

def analyst_bias_label(summary: dict) -> str:
    buy_votes = int(summary.get("strong_buy", 0)) + int(summary.get("buy", 0))
    hold_votes = int(summary.get("hold", 0))
    sell_votes = int(summary.get("sell", 0)) + int(summary.get("strong_sell", 0))
    total = buy_votes + hold_votes + sell_votes
    if total <= 0:
        return t("bias_mixed")
    if buy_votes >= max(hold_votes, sell_votes) and buy_votes >= sell_votes + 2:
        return t("bias_bullish")
    if sell_votes >= max(hold_votes, buy_votes) and sell_votes >= buy_votes + 2:
        return t("bias_bearish")
    return t("bias_mixed")

def extract_target_headlines(news_items: list[dict], max_items: int = 3) -> list[dict]:
    ranked = []
    for item in news_items:
        title = str(item.get("title", "") or "")
        summary = str(item.get("summary", "") or "")
        text = f"{title} {summary}".lower()
        score = sum(1 for keyword in TARGET_REFERENCE_KEYWORDS if keyword.lower() in text)
        if score <= 0:
            continue
        score += min(int(item.get("relevance", 0)), 4)
        ranked.append({
            "title": title,
            "url": item.get("url"),
            "provider": item.get("provider", ""),
            "score": score,
            "published": item.get("published", pd.NaT),
        })
    ranked.sort(
        key=lambda row: (
            row["score"],
            pd.Timestamp.min.tz_localize("UTC") if pd.isna(row["published"]) else row["published"],
        ),
        reverse=True,
    )
    return ranked[:max_items]

@st.cache_data(ttl=1800)
def fetch_analyst_target_snapshot(ticker: str) -> dict:
    snapshot = {
        "mean_target": pd.NA,
        "high_target": pd.NA,
        "low_target": pd.NA,
        "current_price": pd.NA,
        "analyst_count": None,
        "bias": t("bias_mixed"),
        "latest_revision": "",
        "error": None,
    }
    try:
        tk = yf.Ticker(ticker)
    except Exception as exc:
        snapshot["error"] = str(exc)
        return snapshot

    try:
        raw_targets = getattr(tk, "analyst_price_targets", {}) or {}
        if hasattr(raw_targets, "to_dict"):
            raw_targets = raw_targets.to_dict()
        if isinstance(raw_targets, dict):
            snapshot["mean_target"] = coerce_float(raw_targets.get("mean") or raw_targets.get("targetMeanPrice"))
            snapshot["high_target"] = coerce_float(raw_targets.get("high") or raw_targets.get("targetHighPrice"))
            snapshot["low_target"] = coerce_float(raw_targets.get("low") or raw_targets.get("targetLowPrice"))
            snapshot["current_price"] = coerce_float(raw_targets.get("current") or raw_targets.get("currentPrice"))
    except Exception:
        pass

    try:
        summary = getattr(tk, "recommendations_summary", None)
        if summary is not None and hasattr(summary, "empty") and not summary.empty:
            row = summary.iloc[-1]
            recommendation_summary = {
                "strong_buy": int(row.get("strongBuy", 0) or 0),
                "buy": int(row.get("buy", 0) or 0),
                "hold": int(row.get("hold", 0) or 0),
                "sell": int(row.get("sell", 0) or 0),
                "strong_sell": int(row.get("strongSell", 0) or 0),
            }
            snapshot["analyst_count"] = sum(recommendation_summary.values()) or snapshot["analyst_count"]
            snapshot["bias"] = analyst_bias_label(recommendation_summary)
    except Exception:
        pass

    try:
        upgrades = getattr(tk, "upgrades_downgrades", None)
        if upgrades is not None and hasattr(upgrades, "empty") and not upgrades.empty:
            latest = upgrades.dropna(how="all").tail(1)
            if not latest.empty:
                row = latest.iloc[0]
                action_bits = [str(row.get("Firm", "") or "").strip()]
                action = str(row.get("Action", "") or "").strip()
                to_grade = str(row.get("ToGrade", "") or "").strip()
                if action:
                    action_bits.append(action)
                if to_grade:
                    action_bits.append(to_grade)
                snapshot["latest_revision"] = " · ".join(bit for bit in action_bits if bit)
    except Exception:
        pass

    if pd.isna(snapshot["current_price"]):
        try:
            fast_info = getattr(tk, "fast_info", {}) or {}
            if hasattr(fast_info, "get"):
                snapshot["current_price"] = coerce_float(
                    fast_info.get("lastPrice") or fast_info.get("regularMarketPrice") or fast_info.get("previousClose")
                )
        except Exception:
            pass

    return snapshot

def build_target_watch_context(ticker: str, price_series: pd.Series, news_items: list[dict], timeframe: str = "6m") -> dict:
    timeframe = normalize_planner_timeframe(timeframe)
    snapshot = fetch_analyst_target_snapshot(ticker)
    current_price = coerce_float(snapshot.get("current_price"))
    if pd.isna(current_price) and price_series is not None and not price_series.empty:
        current_price = coerce_float(price_series.iloc[-1])

    mean_target = coerce_float(snapshot.get("mean_target"))
    high_target = coerce_float(snapshot.get("high_target"))
    low_target = coerce_float(snapshot.get("low_target"))
    analyst_count = snapshot.get("analyst_count")
    target_headlines = extract_target_headlines(news_items)

    progress = PLANNER_TARGET_PROGRESS.get(timeframe, PLANNER_TARGET_PROGRESS["6m"])

    def _project_target(level):
        level = coerce_float(level)
        if pd.isna(level) or pd.isna(current_price):
            return level
        return float(current_price + (level - current_price) * progress)

    projected_mean_target = _project_target(mean_target)
    projected_high_target = _project_target(high_target)
    projected_low_target = _project_target(low_target)

    upside_to_mean = pd.NA
    downside_to_low = pd.NA
    if pd.notna(current_price) and current_price != 0:
        if pd.notna(projected_mean_target):
            upside_to_mean = ((projected_mean_target / current_price) - 1) * 100
        if pd.notna(projected_low_target):
            downside_to_low = ((projected_low_target / current_price) - 1) * 100

    band_text = (
        f"{format_local_price(projected_low_target, ticker)} → {format_local_price(projected_high_target, ticker)}"
        if pd.notna(projected_low_target) or pd.notna(projected_high_target)
        else "N/A"
    )

    if get_language() == "zh_TW":
        horizon_note = f"已按 {planner_timeframe_label(timeframe)} 投資期限調整目標價區間。"
    else:
        horizon_note = f"Target band scaled to a {planner_timeframe_label(timeframe)} investment horizon."

    return {
        "available": pd.notna(projected_mean_target) or bool(target_headlines) or bool(snapshot.get("latest_revision")),
        "timeframe": timeframe,
        "timeframe_label": planner_timeframe_label(timeframe),
        "current_price": current_price,
        "mean_target": projected_mean_target,
        "high_target": projected_high_target,
        "low_target": projected_low_target,
        "full_mean_target": mean_target,
        "full_high_target": high_target,
        "full_low_target": low_target,
        "upside_to_mean": upside_to_mean,
        "downside_to_low": downside_to_low,
        "band_text": band_text,
        "bias": snapshot.get("bias", t("bias_mixed")),
        "analyst_count_text": str(int(analyst_count)) if analyst_count else "N/A",
        "latest_revision": str(snapshot.get("latest_revision", "") or "").strip(),
        "target_headlines": target_headlines,
        "source_note": t("target_reference_source"),
        "warning": t("no_structured_target") if not pd.notna(projected_mean_target) else "",
        "horizon_note": horizon_note,
    }
def build_news_helper_text(item: dict, ticker: str, probability: int) -> str:
    direction_text, _, _ = article_direction_meta(item)
    confidence = tr_confidence(item.get("confidence", "N/A"))
    relevance = relevance_label(int(item.get("relevance", 0)))
    helper = t(
        "news_helper_template",
        ticker=display_ticker_label(ticker),
        direction=direction_text,
        probability=probability,
        confidence=confidence,
        relevance=relevance,
    )
    reason = str(item.get("impact_reason", "") or "").strip()
    if reason:
        helper += f" {t('news_reason_label')}: {tr_reason_text(reason)}"
    return helper

def build_news_summary_html(item: dict, ticker: str, probability: int, block_class: str = "story-row-summary") -> str:
    source_summary = str(item.get("summary") or item.get("impact_reason") or "").strip()
    mode = get_news_mode()
    source_html = f'<div class="{block_class}"><strong>{t("source_summary_label")}</strong> {escape(source_summary or t("no_source_summary"))}</div>'
    if mode == "Original source":
        return f'<div class="{block_class}">{escape(source_summary or t("no_source_summary"))}</div>'
    helper_html = f'<div class="{block_class}"><strong>{t("news_helper_label")}</strong> {escape(build_news_helper_text(item, ticker, probability))}</div>'
    if news_mode_prefers_chinese_first():
        return helper_html + source_html
    return source_html + helper_html

def build_compact_summary_text(item: dict, ticker: str, probability: int, limit: int = 180) -> str:
    source_summary = str(item.get("summary") or item.get("impact_reason") or "").strip()
    if get_news_mode() == "Original source":
        return source_summary[:limit] or t("no_source_summary")
    return build_news_helper_text(item, ticker, probability)[:limit]


def html_block(markup: str) -> str:
    return textwrap.dedent(markup).strip()


def contains_cjk(text: str) -> bool:
    return bool(re.search(r"[\u4e00-\u9fff]", str(text or "")))


def build_news_aliases(ticker: str) -> set[str]:
    ticker_upper = str(ticker).upper()
    base_code = ticker_base_code(ticker_upper)
    aliases = {ticker_upper, base_code}
    meta = TAIWAN_TICKER_METADATA.get(ticker_upper)
    if meta:
        aliases.update(
            {
                meta.get("code", "").upper(),
                meta.get("en", "").upper(),
                meta.get("zh", "").upper(),
            }
        )
    return {alias for alias in aliases if alias}


def score_news_relevance(title: str, summary: str, related: list[str], aliases: set[str]) -> int:
    text_blob = f"{title} {summary}".upper()
    related_set = {str(value).upper() for value in related or []}
    relevance = 0
    if aliases & related_set:
        relevance += 4
    if any(alias in text_blob for alias in aliases if alias):
        relevance += 2
    if any(keyword in text_blob for keyword in ("EARNINGS", "GUIDANCE", "AI", "CHIPS", "DEMAND", "REVENUE", "EXPORT", "TARIFF", "財報", "AI", "晶片", "需求", "營收", "出口", "關稅")):
        relevance += 1
    return relevance


def normalize_google_news_url(url: str) -> str:
    return unescape(str(url or "")).strip()


def split_google_title(title: str) -> tuple[str, str]:
    clean = unescape(str(title or "")).strip()
    if " - " in clean:
        head, tail = clean.rsplit(" - ", 1)
        return head.strip(), tail.strip()
    return clean, "Google News"


def clean_google_description(description: str) -> str:
    raw = unescape(str(description or ""))
    raw = re.sub(r"<[^>]+>", " ", raw)
    raw = re.sub(r"\s+", " ", raw).strip()
    return raw


def parse_google_news_rss(query: str, max_items: int = 10) -> list[dict]:
    feed_url = (
        "https://news.google.com/rss/search?"
        f"q={quote_plus(query)}&hl=zh-TW&gl=TW&ceid=TW:zh-Hant"
    )
    req = Request(feed_url, headers={"User-Agent": "Mozilla/5.0"})
    try:
        xml_bytes, _ = _read_request_bytes(req, timeout=8)
    except Exception:
        return []

    try:
        root = ET.fromstring(xml_bytes)
    except ET.ParseError:
        return []

    items: list[dict] = []
    for node in root.findall(".//item")[:max_items]:
        raw_title = node.findtext("title", default="").strip()
        title, provider = split_google_title(raw_title)
        link = normalize_google_news_url(node.findtext("link", default="").strip())
        description = clean_google_description(node.findtext("description", default="").strip())
        pub_date = pd.to_datetime(node.findtext("pubDate", default=""), utc=True, errors="coerce")
        items.append(
            {
                "title": title or "Untitled",
                "summary": description,
                "provider": provider or "Google News",
                "url": link,
                "published": pub_date,
                "related": [],
            }
        )
    return items


def fetch_taiwan_local_news(ticker: str, max_items: int = 12) -> list[dict]:
    if not is_taiwan_ticker(ticker):
        return []

    meta = TAIWAN_TICKER_METADATA.get(str(ticker).upper(), {})
    code = meta.get("code", ticker_base_code(ticker))
    zh_name = meta.get("zh", code)
    en_name = meta.get("en", code)
    aliases = build_news_aliases(ticker)

    query_parts = [zh_name]
    if en_name and en_name.upper() != zh_name.upper():
        query_parts.append(f'"{en_name}"')
    if code:
        query_parts.append(code)
    query = " OR ".join(part for part in query_parts if part)

    items = []
    for item in parse_google_news_rss(query, max_items=max_items * 2):
        relevance = score_news_relevance(item["title"], item["summary"], item.get("related", []), aliases)
        if contains_cjk(item["title"]):
            relevance += 2
        impact_label, impact_score, impact_reason = infer_news_impact(item["title"], item["summary"])
        confidence = infer_news_confidence(relevance, impact_score)
        item.update(
            {
                "related": [str(ticker).upper()],
                "relevance": relevance,
                "impact_label": impact_label,
                "impact_score": impact_score,
                "impact_reason": impact_reason,
                "confidence": confidence,
                "source_origin": "tw_local",
            }
        )
        items.append(item)

    items.sort(
        key=lambda x: (
            x.get("relevance", 0),
            1 if contains_cjk(x.get("title", "")) else 0,
            pd.Timestamp.min.tz_localize("UTC") if pd.isna(x.get("published")) else x.get("published"),
        ),
        reverse=True,
    )
    return items[:max_items]


def dedupe_news_items(items: list[dict], max_items: int = 12) -> list[dict]:
    deduped = []
    seen: set[str] = set()
    for item in items:
        title_key = re.sub(r"\s+", " ", str(item.get("title", "")).strip().lower())
        url_key = str(item.get("url", "")).strip().lower()
        key = url_key or title_key
        if not key or key in seen:
            continue
        seen.add(key)
        deduped.append(item)

    deduped.sort(
        key=lambda x: (
            x.get("relevance", 0),
            1 if x.get("source_origin") == "tw_local" else 0,
            1 if contains_cjk(x.get("title", "")) else 0,
            pd.Timestamp.min.tz_localize("UTC") if pd.isna(x.get("published")) else x.get("published"),
        ),
        reverse=True,
    )
    return deduped[:max_items]


def ticker_base_code(ticker: str) -> str:
    return str(ticker).split(".", 1)[0].upper()


def is_taiwan_ticker(ticker: str) -> bool:
    ticker_upper = str(ticker).upper()
    return (
        ticker_upper.endswith(".TW")
        or ticker_upper.endswith(".TWO")
        or ticker_upper in TAIWAN_TICKER_METADATA
        or bool(ACTIVE_ETF_SYMBOL_PATTERN.fullmatch(ticker_upper))
    )


def _normalize_symbol_lookup_token(value: str) -> str:
    return "".join(str(value or "").upper().split())


def build_taiwan_alias_index() -> dict[str, str]:
    alias_map: dict[str, str] = {}
    for ticker, meta in TAIWAN_TICKER_METADATA.items():
        normalized_ticker = str(ticker).upper()
        alias_candidates = {
            normalized_ticker,
            ticker_base_code(normalized_ticker),
            meta.get("zh", ""),
            meta.get("en", ""),
        }
        alias_candidates.update(meta.get("aliases", []))
        for alias in alias_candidates:
            token = _normalize_symbol_lookup_token(alias)
            if token:
                alias_map[token] = normalized_ticker
    return alias_map


TAIWAN_ALIAS_INDEX = build_taiwan_alias_index()


RUNTIME_SYMBOL_METADATA_KEY = "dashboard_runtime_symbol_metadata"


def runtime_symbol_metadata() -> dict[str, dict]:
    return st.session_state.setdefault(RUNTIME_SYMBOL_METADATA_KEY, {})


def register_runtime_symbol_metadata(symbol: str, *, name: str = "", exchange: str = "", market: str = "") -> None:
    normalized_symbol = str(symbol or "").upper().strip()
    if not normalized_symbol:
        return
    metadata = runtime_symbol_metadata()
    current = dict(metadata.get(normalized_symbol, {}))
    if name:
        current["name"] = str(name).strip()
    if exchange:
        current["exchange"] = str(exchange).strip()
    if market:
        current["market"] = str(market).strip()
    metadata[normalized_symbol] = current
    st.session_state[RUNTIME_SYMBOL_METADATA_KEY] = metadata


def get_runtime_symbol_metadata(symbol: str) -> dict:
    return runtime_symbol_metadata().get(str(symbol or "").upper().strip(), {})


def scope_allows_ticker(scope: str, ticker: str) -> bool:
    normalized_ticker = str(ticker or "").upper().strip()
    if not normalized_ticker:
        return False
    if scope == "Taiwan only":
        return is_taiwan_ticker(normalized_ticker)
    if scope == "U.S. only":
        return not is_taiwan_ticker(normalized_ticker)
    return True


@st.cache_data(ttl=86400, show_spinner=False)
def yahoo_symbol_has_history(symbol: str) -> bool:
    sink = io.StringIO()
    try:
        with contextlib.redirect_stdout(sink), contextlib.redirect_stderr(sink):
            history = yf.Ticker(symbol).history(period="1mo", interval="1d", auto_adjust=False)
        return history is not None and not history.empty
    except Exception:
        return False


def resolve_taiwan_numeric_symbol(symbol: str) -> str:
    numeric_code = str(symbol or "").strip()
    if not numeric_code:
        return ""
    for suffix in (".TW", ".TWO"):
        candidate = f"{numeric_code}{suffix}"
        if candidate in TAIWAN_TICKER_METADATA:
            return candidate
    for suffix in (".TW", ".TWO"):
        candidate = f"{numeric_code}{suffix}"
        if yahoo_symbol_has_history(candidate):
            return candidate
    return f"{numeric_code}.TW"


@st.cache_data(ttl=21600, show_spinner=False)
def fetch_remote_symbol_search(query: str, max_results: int = 12) -> list[dict]:
    search_query = str(query or "").strip()
    if len(search_query) < 1:
        return []

    url = (
        "https://query1.finance.yahoo.com/v1/finance/search"
        f"?q={quote_plus(search_query)}&quotesCount={max_results * 3}&newsCount=0&listsCount=0&enableFuzzyQuery=true"
    )
    request = Request(
        url,
        headers={
            "User-Agent": "Mozilla/5.0",
            "Accept": "application/json, text/plain, */*",
        },
    )
    try:
        raw_bytes, _ = _read_request_bytes(request, timeout=6)
        payload = json.loads(raw_bytes.decode("utf-8"))
    except (HTTPError, URLError, TimeoutError, ValueError, json.JSONDecodeError):
        return []
    except Exception:
        return []

    results: list[dict] = []
    for quote in payload.get("quotes", []):
        raw_symbol = str(quote.get("symbol", "") or "").upper().strip()
        if not raw_symbol:
            continue

        quote_type = str(quote.get("quoteType", "") or quote.get("typeDisp", "")).upper()
        if quote_type and not any(token in quote_type for token in ("EQUITY", "ETF", "FUND")):
            continue

        display_name = (
            quote.get("shortname")
            or quote.get("longname")
            or quote.get("dispSecIndFlag")
            or raw_symbol
        )
        exchange = " / ".join(
            str(value).strip()
            for value in (
                quote.get("exchange"),
                quote.get("exchDisp"),
            )
            if str(value or "").strip()
        )

        normalized_symbol = normalize_dashboard_ticker(raw_symbol)
        if not normalized_symbol:
            continue

        results.append(
            {
                "symbol": normalized_symbol,
                "name": str(display_name).strip(),
                "exchange": exchange,
            }
        )

    return results


def build_symbol_search_text(symbol: str) -> str:
    normalized_symbol = str(symbol or "").upper().strip()
    meta = TAIWAN_TICKER_METADATA.get(normalized_symbol, {})
    runtime_meta = get_runtime_symbol_metadata(normalized_symbol)
    fallback_name = SUPPLY_CHAIN_RUNTIME_NAME_MAP.get(normalized_symbol, "")
    parts = [
        normalized_symbol,
        ticker_base_code(normalized_symbol),
        meta.get("zh", ""),
        meta.get("en", ""),
        runtime_meta.get("name", ""),
        fallback_name,
        runtime_meta.get("exchange", ""),
    ]
    parts.extend(meta.get("aliases", []))
    return " ".join(str(part) for part in parts if str(part).strip())


def _search_match_score(query_token: str, symbol: str, haystack: str) -> int:
    normalized_symbol = _normalize_symbol_lookup_token(symbol)
    normalized_text = _normalize_symbol_lookup_token(haystack)
    if not query_token or not normalized_text:
        return 0
    if query_token == normalized_symbol:
        return 140
    if query_token == normalized_text:
        return 120
    if normalized_symbol.startswith(query_token):
        return 100
    if query_token in normalized_symbol:
        return 80
    if query_token in normalized_text:
        return 60
    return 0


def build_scope_search_universe(scope: str) -> list[str]:
    symbols = set(DEFAULT_WATCHLIST_UNIVERSE)
    symbols.update(TAIWAN_TICKER_METADATA.keys())
    symbols.update(runtime_symbol_metadata().keys())
    return sorted(symbol for symbol in symbols if scope_allows_ticker(scope, symbol))


def build_symbol_search_results(query: str, scope: str, max_results: int = 12) -> list[str]:
    query_text = str(query or "").strip()
    if not query_text:
        return []

    query_token = _normalize_symbol_lookup_token(query_text)
    scored: list[tuple[int, str]] = []
    seen: set[str] = set()

    local_universe = build_scope_search_universe(scope)
    for symbol in local_universe:
        score = _search_match_score(query_token, symbol, build_symbol_search_text(symbol))
        if score > 0:
            scored.append((score, symbol))
            seen.add(symbol)

    for item in fetch_remote_symbol_search(query_text, max_results=max_results):
        symbol = normalize_dashboard_ticker(item.get("symbol", ""))
        if not symbol or not scope_allows_ticker(scope, symbol):
            continue
        register_runtime_symbol_metadata(symbol, name=item.get("name", ""), exchange=item.get("exchange", ""))
        haystack = " ".join([symbol, item.get("name", ""), item.get("exchange", "")])
        score = _search_match_score(query_token, symbol, haystack) + 10
        scored.append((score, symbol))
        seen.add(symbol)

    if query_text.isdigit() and len(query_text) in {4, 5, 6}:
        numeric_symbol = resolve_taiwan_numeric_symbol(query_text)
        if numeric_symbol and scope_allows_ticker(scope, numeric_symbol):
            scored.append((160, numeric_symbol))
            seen.add(numeric_symbol)

    scored.sort(key=lambda item: (item[0], item[1]), reverse=True)

    results: list[str] = []
    for _, symbol in scored:
        if symbol not in results:
            results.append(symbol)
        if len(results) >= max_results:
            break
    return results


ACTIVE_ETF_SYMBOL_PATTERN = re.compile(r"^\d{5}A(?:\.(?:TW|TWO))?$", re.IGNORECASE)


def normalize_taiwan_active_etf_symbol(raw_symbol: str) -> str:
    symbol = str(raw_symbol or "").upper().replace(" ", "").strip()
    if not symbol:
        return ""
    if not ACTIVE_ETF_SYMBOL_PATTERN.fullmatch(symbol):
        return ""
    base = symbol.split(".", 1)[0]
    if symbol.endswith(".TW") or symbol.endswith(".TWO"):
        return symbol
    for suffix in (".TW", ".TWO"):
        candidate = f"{base}{suffix}"
        if candidate in ACTIVE_ETF_METADATA:
            return candidate
    for suffix in (".TW", ".TWO"):
        candidate = f"{base}{suffix}"
        if yahoo_symbol_has_history(candidate):
            return candidate
    return f"{base}.TW"


def active_etf_catalog_tickers() -> list[str]:
    return sorted(
        ACTIVE_ETF_METADATA.keys(),
        key=lambda ticker: str(ACTIVE_ETF_METADATA.get(ticker, {}).get("code", ticker)),
    )


def get_active_etf_metadata(ticker: str) -> dict:
    normalized = normalize_taiwan_active_etf_symbol(ticker) or str(ticker or "").upper().strip()
    candidates = [normalized]
    if normalized.endswith(".TW"):
        candidates.append(f"{normalized[:-3]}.TWO")
    elif normalized.endswith(".TWO"):
        candidates.append(f"{normalized[:-4]}.TW")
    elif normalized:
        candidates.extend([f"{normalized}.TW", f"{normalized}.TWO"])
    for candidate in candidates:
        meta = ACTIVE_ETF_METADATA.get(candidate)
        if isinstance(meta, dict):
            return meta
    return {}


def active_etf_group_key(ticker: str) -> str:
    return str(get_active_etf_metadata(ticker).get("group_key", "taiwan-core"))


def _active_etf_ui_is_zh() -> bool:
    try:
        return get_language() == "zh_TW" or get_lang() == "繁體中文"
    except Exception:
        return get_lang() == "繁體中文"


def active_etf_group_label(group_key: str) -> str:
    meta = ACTIVE_ETF_GROUP_METADATA.get(group_key, {})
    return str(meta.get("zh" if _active_etf_ui_is_zh() else "en", group_key))


def active_etf_group_note(group_key: str) -> str:
    meta = ACTIVE_ETF_GROUP_METADATA.get(group_key, {})
    return str(meta.get("note_zh" if _active_etf_ui_is_zh() else "note_en", ""))


def active_etf_selector_label(ticker: str) -> str:
    base_label = display_ticker_label(ticker)
    meta = get_active_etf_metadata(ticker)
    if not meta:
        return base_label
    is_zh = _active_etf_ui_is_zh()
    style = str(meta.get("style_zh" if is_zh else "style_en", "")).strip()
    direction = str(meta.get("direction_zh" if is_zh else "direction_en", "")).strip()
    detail_parts = [part for part in [style, direction] if part]
    if not detail_parts:
        return base_label
    return f"{base_label} · {' · '.join(detail_parts)}"


def active_etf_grouped_tickers(tickers: list[str]) -> dict[str, list[str]]:
    grouped: dict[str, list[str]] = {group_key: [] for group_key in ACTIVE_ETF_GROUP_METADATA}
    for ticker in filter_active_etf_tickers(tickers):
        group_key = active_etf_group_key(ticker)
        grouped.setdefault(group_key, []).append(ticker)
    return {group_key: values for group_key, values in grouped.items() if values}


def _active_etf_group_button_key(state_key: str, group_key: str) -> str:
    safe_state = re.sub(r"[^A-Za-z0-9_]+", "_", str(state_key or "").lower()).strip("_") or "active_etf_group"
    safe_group = re.sub(r"[^A-Za-z0-9_]+", "_", str(group_key or "").lower()).strip("_") or "group"
    return f"{safe_state}_{safe_group}_button"


def inject_active_etf_group_button_css(state_key: str, group_keys: list[str], active_key: str) -> None:
    button_keys = [_active_etf_group_button_key(state_key, group_key) for group_key in group_keys]
    if not button_keys:
        return
    base_selectors = ",\n".join(f".st-key-{button_key} button" for button_key in button_keys)
    active_selector = f".st-key-{_active_etf_group_button_key(state_key, active_key)} button"
    render_html_block(
        f"""
        <style>
        {base_selectors} {{
            min-height: 3.05rem !important;
            border-radius: 999px !important;
            border: 1px solid color-mix(in srgb, var(--brand-2, #38bdf8) 36%, transparent) !important;
            background:
                linear-gradient(135deg, color-mix(in srgb, var(--card-soft, rgba(10,18,34,0.82)) 94%, transparent) 0%, color-mix(in srgb, var(--card, rgba(8,16,28,0.92)) 99%, transparent) 100%) !important;
            color: #f2d18b !important;
            box-shadow:
                inset 0 1px 0 rgba(255,255,255,0.04),
                0 12px 26px rgba(3, 10, 20, 0.12) !important;
            font-weight: 850 !important;
            white-space: normal !important;
            transition: transform 140ms ease, border-color 140ms ease, box-shadow 140ms ease, background 140ms ease !important;
        }}
        {base_selectors}:hover {{
            transform: translateY(-1px);
            border-color: color-mix(in srgb, var(--brand-2, #38bdf8) 76%, transparent) !important;
            color: #ffe5aa !important;
            box-shadow:
                inset 0 1px 0 rgba(255,255,255,0.06),
                0 16px 34px rgba(56, 189, 248, 0.16) !important;
        }}
        {active_selector} {{
            background:
                linear-gradient(135deg, color-mix(in srgb, var(--brand-2, #38bdf8) 30%, var(--card, rgba(8,16,28,0.92))) 0%, color-mix(in srgb, var(--brand, #818cf8) 18%, var(--card, rgba(8,16,28,0.92))) 100%) !important;
            border-color: color-mix(in srgb, var(--brand-2, #38bdf8) 90%, transparent) !important;
            color: #fff7df !important;
            box-shadow:
                0 0 0 1px color-mix(in srgb, var(--brand-2, #38bdf8) 24%, transparent),
                0 18px 38px rgba(56, 189, 248, 0.22),
                inset 0 1px 0 rgba(255,255,255,0.08) !important;
        }}
        </style>
        """
    )


def render_active_etf_group_buttons(tickers: list[str], *, state_key: str) -> str | None:
    grouped = active_etf_grouped_tickers(tickers)
    group_keys = list(grouped.keys())
    if not group_keys:
        return None
    active_key = st.session_state.get(state_key, group_keys[0])
    if active_key not in group_keys:
        active_key = group_keys[0]
    st.session_state[state_key] = active_key

    inject_active_etf_group_button_css(state_key, group_keys, active_key)
    cols_per_row = 3
    for row_start in range(0, len(group_keys), cols_per_row):
        cols = st.columns(cols_per_row)
        for idx, group_key in enumerate(group_keys[row_start: row_start + cols_per_row]):
            count = len(grouped.get(group_key, []))
            label = (
                f"{active_etf_group_label(group_key)} · {count} 檔"
                if _active_etf_ui_is_zh()
                else f"{active_etf_group_label(group_key)} · {count} ETFs"
            )
            with cols[idx]:
                if st.button(
                    label,
                    key=_active_etf_group_button_key(state_key, group_key),
                    use_container_width=True,
                ):
                    st.session_state[state_key] = group_key
                    st.rerun()
    note = active_etf_group_note(st.session_state.get(state_key, active_key))
    if note:
        st.caption(note)
    return str(st.session_state.get(state_key, active_key))


def filter_active_etf_tickers(tickers: list[str]) -> list[str]:
    filtered: list[str] = []
    for ticker in tickers:
        normalized = normalize_taiwan_active_etf_symbol(ticker) or normalize_dashboard_ticker(ticker)
        if not normalized or not is_taiwan_active_etf(normalized):
            continue
        filtered.append(normalized)
    return dedupe_keep_order(filtered)


def build_active_etf_search_results(query: str, max_results: int = 12) -> list[str]:
    query_text = str(query or "").strip()
    if not query_text:
        return []

    results: list[str] = []
    direct_symbol = normalize_taiwan_active_etf_symbol(query_text)
    if direct_symbol:
        results.append(direct_symbol)

    query_token = _normalize_holding_alias_text(query_text)
    if query_token:
        for ticker, meta in ACTIVE_ETF_METADATA.items():
            candidates = [
                meta.get("code", ""),
                meta.get("zh", ""),
                meta.get("en", ""),
                meta.get("issuer_zh", ""),
                meta.get("issuer_en", ""),
                meta.get("style_zh", ""),
                meta.get("style_en", ""),
                meta.get("direction_zh", ""),
                meta.get("direction_en", ""),
                active_etf_group_label(str(meta.get("group_key", ""))),
            ]
            candidates.extend(meta.get("aliases", []) or [])
            if any(query_token in _normalize_holding_alias_text(candidate) for candidate in candidates if candidate):
                results.append(ticker)

    for item in fetch_remote_symbol_search(query_text, max_results=max_results):
        symbol = normalize_taiwan_active_etf_symbol(item.get("symbol", ""))
        if not symbol or not is_taiwan_active_etf(symbol):
            continue
        register_runtime_symbol_metadata(symbol, name=item.get("name", ""), exchange=item.get("exchange", ""), market="TW")
        results.append(symbol)

    return sort_ticker_options(dedupe_keep_order(results)[:max_results])


def normalize_dashboard_ticker(raw_symbol: str) -> str:
    symbol_raw = str(raw_symbol).strip()
    symbol = symbol_raw.upper().replace(" ", "")
    if not symbol:
        return ""
    active_etf_symbol = normalize_taiwan_active_etf_symbol(symbol_raw)
    if active_etf_symbol:
        return active_etf_symbol
    alias_hit = TAIWAN_ALIAS_INDEX.get(_normalize_symbol_lookup_token(symbol_raw))
    if alias_hit:
        return alias_hit
    if symbol in TAIWAN_TICKER_METADATA:
        return symbol
    if symbol.endswith(".TW") or symbol.endswith(".TWO"):
        return symbol
    if symbol.isdigit() and len(symbol) in {4, 5, 6}:
        return resolve_taiwan_numeric_symbol(symbol)
    return symbol


def market_scope_group_options(scope: str) -> list[str]:
    if scope == "U.S. only":
        return US_WATCHLIST_GROUPS
    if scope == "Taiwan only":
        return TAIWAN_WATCHLIST_GROUPS
    return US_WATCHLIST_GROUPS + TAIWAN_WATCHLIST_GROUPS


def display_ticker_label(ticker: str) -> str:
    ticker_upper = str(ticker).upper()
    meta = TAIWAN_TICKER_METADATA.get(ticker_upper)
    runtime_meta = get_runtime_symbol_metadata(ticker_upper)
    fallback_name = SUPPLY_CHAIN_RUNTIME_NAME_MAP.get(ticker_upper, "")

    if meta:
        company = meta["zh"] if get_lang() == "繁體中文" else meta["en"]
        return f"{meta['code']} {company}"

    # v1.13.49: 台股若不在預建 metadata, 優先查 TWSE/TPEx 中文公司名對照表
    # (fetch_taiwan_company_name_map, 含全上市櫃 + @cache), 避免顯示 yfinance
    # 英文名。繁中介面下台股本應顯示中文。
    if is_taiwan_ticker(ticker_upper) and get_lang() == "繁體中文":
        try:
            zh_map = fetch_taiwan_company_name_map()
            zh_name = str(zh_map.get(normalize_dashboard_ticker(ticker_upper), "") or "").strip()
            if zh_name:
                return f"{ticker_base_code(ticker_upper)} {zh_name}"
        except Exception:
            pass

    runtime_name = str(runtime_meta.get("name", "")).strip()
    if runtime_name:
        if is_taiwan_ticker(ticker_upper):
            return f"{ticker_base_code(ticker_upper)} {runtime_name}"
        return f"{ticker_upper} {runtime_name}"
    if fallback_name:
        if is_taiwan_ticker(ticker_upper):
            return f"{ticker_base_code(ticker_upper)} {fallback_name}"
        return f"{ticker_upper} {fallback_name}"

    if is_taiwan_ticker(ticker_upper):
        base = ticker_base_code(ticker_upper)
        return f"{base} 台股" if get_lang() == "繁體中文" else f"{base} Taiwan"
    return str(ticker).upper()


def market_scope_label(scope: str) -> str:
    return {
        "Mixed (U.S. + Taiwan)": t("market_scope_mixed"),
        "U.S. only": t("market_scope_us"),
        "Taiwan only": t("market_scope_tw"),
    }.get(scope, scope)


# v1.3.9: Top-of-page selector bar.
# Surfaces Language / Dashboard mode / Market scope right under the
# "David Lau Designed AI Stock Market Vision" title so users can switch context without
# opening the sidebar. This used to live in the sidebar; the same widgets
# have been REMOVED from there to avoid Streamlit duplicate-key warnings.
# Other sidebar settings (theme mode, layout mode, device control, watchlist
# editor, refresh button) stay where they are.
def _inject_top_selector_bar_css() -> None:
    """Inject scoped styles for the top Hero Bar (v1.5.0 redesign).

    The Hero Bar replaces the old Top Selector Bar and adds:
      * Visual experience-level cards (新手 / 初級 / 進階 / 資深) instead of
        a plain Layout-mode selectbox -- with emoji + 1-line guidance copy.
      * Larger Dashboard-mode and Language pickers in matching dark-horizon
        gradient style.
      * Fully responsive: 3 columns on desktop, stacks on mobile.

    Streamlit dedupes identical <style> blocks server-side so this is safe
    to call on every rerun (which is required because the placeholder is
    cleared between paints).
    """
    st.markdown(
        """
        <style>
        /* ===== v1.5.0 Hero Bar ===== */
        .hero-bar-shell {
            background: linear-gradient(135deg, rgba(15,28,52,0.78) 0%, rgba(8,14,28,0.65) 60%, rgba(20,24,48,0.7) 100%);
            border: 1px solid rgba(94,234,212,0.18);
            border-radius: 18px;
            padding: 1.4rem 1.6rem 1rem 1.6rem;
            margin: 0.3rem 0 1.2rem 0;
            position: relative;
            overflow: hidden;
        }
        .hero-bar-shell::before {
            content: "";
            position: absolute; inset: 0;
            background: radial-gradient(circle at 0% 0%, rgba(94,234,212,0.08), transparent 40%),
                        radial-gradient(circle at 100% 100%, rgba(168,85,247,0.06), transparent 45%);
            pointer-events: none;
        }
        .hero-bar-shell > * { position: relative; z-index: 1; }
        .hero-bar-kicker {
            display: inline-flex;
            align-items: center;
            gap: 0.5rem;
            font-size: 0.78rem;
            font-weight: 600;
            color: #5eead4;
            letter-spacing: 0.08em;
            text-transform: uppercase;
            margin-bottom: 0.3rem;
        }
        .hero-bar-kicker-dot {
            width: 8px; height: 8px;
            background: #5eead4;
            border-radius: 50%;
            box-shadow: 0 0 10px #5eead4;
        }
        .hero-bar-title {
            font-size: 1.35rem;
            font-weight: 700;
            color: #fff;
            margin-bottom: 0.15rem;
        }
        .hero-bar-sub {
            font-size: 0.92rem;
            color: rgba(255,255,255,0.6);
            margin-bottom: 1.05rem;
            line-height: 1.5;
        }
        /* Each Streamlit column inside hero-bar gets a column-label */
        .hero-bar-col-label {
            font-size: 0.74rem;
            font-weight: 600;
            color: rgba(255,255,255,0.55);
            text-transform: uppercase;
            letter-spacing: 0.06em;
            margin-bottom: 0.4rem;
            display: flex;
            align-items: center;
            gap: 0.35rem;
        }
        .hero-bar-shell [data-testid="stSelectbox"] > label {
            display: none !important;  /* we render our own column label above */
        }
        .hero-bar-shell [data-testid="stSelectbox"] > div > div {
            background: rgba(11,18,32,0.6) !important;
            border: 1px solid rgba(94,234,212,0.22) !important;
            border-radius: 10px !important;
            font-size: 0.98rem !important;
            color: #fff !important;
        }
        .hero-bar-shell [data-testid="stSelectbox"] > div > div:hover {
            border-color: rgba(94,234,212,0.42) !important;
        }
        /* Experience-level segmented-button group */
        .hero-bar-exp-group {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: 0.5rem;
        }
        .hero-bar-shell .stButton > button {
            background: rgba(11,18,32,0.55);
            border: 1px solid rgba(94,234,212,0.18);
            color: rgba(255,255,255,0.78);
            border-radius: 12px;
            padding: 0.7rem 0.5rem;
            font-size: 0.95rem;
            font-weight: 600;
            line-height: 1.3;
            min-height: 50px;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
            transition: background 0.15s ease, border-color 0.15s ease, transform 0.08s ease;
            width: 100%;
        }
        .hero-bar-shell .stButton > button:hover {
            background: rgba(94,234,212,0.12);
            border-color: rgba(94,234,212,0.45);
            color: #fff;
        }
        .hero-bar-shell .stButton > button:focus:not(:active) {
            border-color: rgba(94,234,212,0.45);
            box-shadow: 0 0 0 2px rgba(94,234,212,0.12);
        }
        /* v1.5.2: Active experience-level button.
           Marker pattern: the active button's label ends with "  ★" so CSS
           can target it via [aria-label$="★"]. The previous approach used a
           wrapper <div class="hero-exp-active"> rendered via st.markdown,
           but Streamlit treats each markdown call as its own widget slot
           -- which silently added ~20px height to the active column only,
           breaking alignment. The marker-character approach has zero
           layout side-effects.

           The literal ★ in the visible label IS the active indicator --
           paired with the green border + glow it reads cleanly as "this
           one is selected" without needing additional pseudo-element art. */
        .hero-bar-shell .stButton > button[aria-label$="★"] {
            background: linear-gradient(135deg, rgba(94,234,212,0.22), rgba(94,234,212,0.08));
            border: 1.5px solid rgba(94,234,212,0.65);
            color: #5eead4;
            box-shadow: 0 0 0 1px rgba(94,234,212,0.18), 0 4px 18px rgba(94,234,212,0.08);
        }
        /* v1.5.1: per-button hint caption below each experience-level button */
        .hero-exp-hint {
            font-size: 0.78rem;
            color: rgba(255,255,255,0.5);
            text-align: center;
            margin-top: 0.35rem;
            line-height: 1.35;
            min-height: 1.5em;
        }
        .hero-bar-tip {
            font-size: 0.85rem;
            color: rgba(255,255,255,0.6);
            margin-top: 0.7rem;
            padding: 0.55rem 0.85rem;
            background: rgba(94,234,212,0.06);
            border-left: 3px solid rgba(94,234,212,0.42);
            border-radius: 6px;
            line-height: 1.5;
        }
        @media (max-width: 1100px) {
            .hero-bar-exp-group { grid-template-columns: repeat(2, 1fr); }
        }
        /* v1.10.18 — Tablet breakpoint (768-1024px) */
        @media (min-width: 720px) and (max-width: 1024px) {
            .hero-bar-shell { padding: 1.2rem 1.1rem 0.9rem 1.1rem; }
            .hero-bar-title { font-size: 1.25rem; }
            .hero-bar-exp-group { grid-template-columns: repeat(4, 1fr); gap: 0.5rem; }
            .hero-bar-shell .stButton > button {
                font-size: 0.88rem;
                min-height: 44px;
                padding: 0.55rem 0.5rem;
            }
        }
        @media (max-width: 720px) {
            .hero-bar-shell { padding: 1.1rem 1rem 0.85rem 1rem; }
            .hero-bar-title { font-size: 1.15rem; }
            .hero-bar-sub { font-size: 0.82rem; }
            .hero-bar-kicker { font-size: 0.7rem; }
            .hero-bar-exp-group { grid-template-columns: 1fr 1fr; }
            .hero-bar-shell .stButton > button {
                font-size: 0.85rem;
                min-height: 44px;  /* iOS tap-target minimum */
                padding: 0.55rem 0.4rem;
            }
            .hero-bar-tip { font-size: 0.78rem; padding: 0.5rem 0.7rem; }
            .hero-bar-shell [data-testid="stSelectbox"] > div > div {
                font-size: 0.88rem !important;
            }
            /* v1.10.18: long pill labels truncate gracefully on mobile */
            .hero-bar-shell .stButton > button > div {
                white-space: nowrap;
                overflow: hidden;
                text-overflow: ellipsis;
            }
        }
        /* v1.8.0: Fold device (~280px wide). Stack experience-level buttons
           into a single column so labels don't truncate. */
        @media (max-width: 480px) {
            .hero-bar-shell { padding: 0.9rem 0.7rem 0.75rem 0.7rem; }
            .hero-bar-title { font-size: 1rem; }
            .hero-bar-sub { font-size: 0.76rem; line-height: 1.4; }
            .hero-bar-exp-group { grid-template-columns: 1fr; gap: 0.4rem; }
            .hero-exp-hint { font-size: 0.7rem; min-height: 1.2em; }
        }
        /* ===== end v1.5.0 Hero Bar ===== */
        </style>
        """,
        unsafe_allow_html=True,
    )


# ---------------------------------------------------------------------------
# v1.5.0 Experience-level metadata. This is a UI-only relabel of the existing
# Layout mode (Standard / Advanced / Expert) plus a new "Beginner" entry that
# maps to Standard. NO downstream code knows about "experience_level" -- we
# always translate back to dashboard_layout_mode session_state. This keeps
# all existing Standard/Advanced/Expert layout switches working unchanged.
# ---------------------------------------------------------------------------
EXPERIENCE_LEVEL_TO_LAYOUT = {
    "beginner": "Standard",
    "overview": "Standard",      # v1.12.6: overview state — layout doesn't matter
                                  # (focal/momentum hook UI takes over before layout dispatch)
    "intermediate": "Standard",
    "advanced": "Advanced",
    "expert": "Expert",
}


def _experience_level_options(lang_zh: bool) -> list[dict]:
    """Return list of (key, emoji, label, hint) tuples for the user-level buttons.

    v1.9.9: The "beginner" key is preserved internally (no session-state
    migration needed) but its visual identity changed from "🌱 新手 /
    先看大方向" to "🤖 AI 分析分享 / 論點驗證". When this level is selected
    on General Market mode, the dispatch routes to
    render_ai_analysis_share_dashboard() instead of the standard layout.

    v1.12.5 (2026-05-12): User-requested rename — the 3 non-beginner
    levels now show feature-oriented labels ("投資規劃" / "股票比較" /
    "股票研究") instead of skill-tier labels ("初級" / "進階" / "資深").
    Internal keys (intermediate / advanced / expert) are unchanged, so
    EXPERIENCE_LEVEL_TO_LAYOUT mapping, session_state persistence, and
    every existing dispatch path keep working without migration.
    The click handler additionally auto-jumps the layout's sub-section
    selector to the matching tab (planning / compare / workspace).

    v1.12.6 (2026-05-12): Added new "overview" key as the DEFAULT entry
    point. Overview state shows focal points + momentum pulse only
    (the subscription product's discovery hook), without rendering the
    layout-mode dispatch. The 4 feature buttons (AI / 投資規劃 / 股票
    比較 / 股票研究) hide focal+momentum and show their dedicated
    function. Layout: 5 buttons total now, "總覽" sits in position 2
    (right after AI 分析分享) to make it the natural "home" button.
    """
    if lang_zh:
        return [
            {"key": "beginner",     "emoji": "🤖", "label": "AI 分析分享", "hint": "AI 幫你看門道"},
            {"key": "overview",     "emoji": "🏠", "label": "總覽",         "hint": "一眼看懂今天怎麼動"},
            {"key": "intermediate", "emoji": "📋", "label": "投資規劃",     "hint": "進場前先想清楚"},
            {"key": "advanced",     "emoji": "🔄", "label": "股票比較",     "hint": "PK 一下誰最強"},
            {"key": "expert",       "emoji": "🔬", "label": "股票研究",     "hint": "挖掘獨家深度"},
        ]
    return [
        {"key": "beginner",     "emoji": "🤖", "label": "AI Analysis",     "hint": "AI cracks the playbook"},
        {"key": "overview",     "emoji": "🏠", "label": "Overview",        "hint": "Today's market at a glance"},
        {"key": "intermediate", "emoji": "📋", "label": "Investment Plan", "hint": "Think before you enter"},
        {"key": "advanced",     "emoji": "🔄", "label": "Stock Compare",   "hint": "Find the strongest pick"},
        {"key": "expert",       "emoji": "🔬", "label": "Stock Research",  "hint": "Dig deeper, find the edge"},
    ]


def _layout_to_experience_level(layout_mode: str, *, current_level: str | None = None) -> str:
    """Reverse-map the persisted layout_mode back to an experience_level key.

    Layout 'Standard' is shared between 'beginner' and 'intermediate'. When we
    can't tell them apart (fresh session), prefer the one already chosen.
    """
    if current_level and current_level in EXPERIENCE_LEVEL_TO_LAYOUT:
        if EXPERIENCE_LEVEL_TO_LAYOUT[current_level] == layout_mode:
            return current_level
    if layout_mode == "Advanced":
        return "advanced"
    if layout_mode == "Expert":
        return "expert"
    return "intermediate"  # default for Standard


def _hint_copy_for_dashboard_mode(dashboard_mode: str, lang_zh: bool) -> str:
    """One-line tip below the hero-bar selectors, mode-aware."""
    if not lang_zh:
        if dashboard_mode == "Active ETF Lab":
            return "🎯 Active ETF Lab — pair compare and underlying-flow research."
        if dashboard_mode == "Supply Chain Lab":
            return "⚡ Supply Chain Lab — Memory / LEO / ABF / Robotics / Packaging-Test."
        if dashboard_mode == "Taiwan Futures Lab":
            return "📈 Taiwan Futures Lab — break-even and direction-aware planning."
        return "🏆 Main Dashboard — full Decision Cockpit + cross-market view."
    if dashboard_mode == "Active ETF Lab":
        return "🎯 主動式 ETF Lab — 比較雙 ETF 與底層流向研究。"
    if dashboard_mode == "Supply Chain Lab":
        return "⚡ 供應鏈 Lab — 記憶體 / 低軌衛星 / ABF / 機器人 / 封測五大鏈。"
    if dashboard_mode == "Taiwan Futures Lab":
        return "📈 台指期 Lab — 回本價與方向感規劃。"
    return "🏆 主 Dashboard — 完整決策主線 + 跨市場視角。"


def render_top_dashboard_selectors() -> None:
    """Render the v1.5.0 Hero Bar at the top of the page.

    Three columns:
      [Dashboard Mode (4 options)]  [Experience Level (4 buttons)]  [Language]

    All three write to existing session_state keys so downstream code that
    reads dashboard_mode / dashboard_layout_mode / dashboard_language is
    unchanged. The Theme Mode picker (previously in sidebar) has been removed
    -- the dashboard now always uses Dark Horizon.
    """
    _inject_top_selector_bar_css()
    lang_zh = st.session_state.get("dashboard_language", "繁體中文") == "繁體中文"

    # ---- Hero Bar shell open ----
    st.markdown('<div class="hero-bar-shell">', unsafe_allow_html=True)
    st.markdown(
        f'<div class="hero-bar-kicker"><span class="hero-bar-kicker-dot"></span>'
        f'{escape("控制中心" if lang_zh else "CONTROL CENTER")}</div>',
        unsafe_allow_html=True,
    )
    st.markdown(
        f'<div class="hero-bar-title">{escape("選擇你今天的工作場景" if lang_zh else "Choose your workspace")}</div>',
        unsafe_allow_html=True,
    )
    st.markdown(
        f'<div class="hero-bar-sub">{escape("先選 Dashboard 模式 ➜ 再選你的使用者層級。設定即時生效，不用按確定。" if lang_zh else "Pick a dashboard mode, then your experience level. Changes apply instantly.")}</div>',
        unsafe_allow_html=True,
    )

    # ---- Row 1: 3 selectboxes (Dashboard / Market Scope / Language) ----
    # v1.5.1: re-added Market Scope (was lost in v1.5.0 rewrite). All three
    # selectors are equal-weight columns so they line up cleanly.
    col_dashboard, col_scope, col_lang = st.columns([1.2, 1.2, 1], gap="medium")

    # === Column 1: Dashboard Mode ===
    with col_dashboard:
        st.markdown(
            f'<div class="hero-bar-col-label">📍 {escape("DASHBOARD 模式" if lang_zh else "DASHBOARD MODE")}</div>',
            unsafe_allow_html=True,
        )
        current_mode = st.session_state.get("dashboard_mode", "General Market")
        if current_mode not in DASHBOARD_MODE_OPTIONS:
            current_mode = "General Market"
        # Dashboard-mode label that includes a leading emoji per option.
        def _mode_label(value: str) -> str:
            base = dashboard_mode_label(value)
            emoji_map = {
                "General Market":     "🏆",
                "Active ETF Lab":     "🎯",
                "Supply Chain Lab":   "⚡",
                "Taiwan Futures Lab": "📈",
                "Stock Comparison":   "📊",
            }
            return f"{emoji_map.get(value, '•')}  {base}"
        selected_mode = st.selectbox(
            "_dashboard_mode_label",
            options=DASHBOARD_MODE_OPTIONS,
            index=DASHBOARD_MODE_OPTIONS.index(current_mode),
            format_func=_mode_label,
            key="top_selector_dashboard_mode",
            label_visibility="collapsed",
        )
        st.session_state["dashboard_mode"] = selected_mode

    # === Column 2: Market Scope (RESTORED in v1.5.1) ===
    # The user can pick US-only / Taiwan-only / Mixed. v1.5.0 accidentally
    # dropped this widget; the session_state key is read by 13+ downstream
    # places so it MUST exist. Removing the "Mixed" option is階段 B work --
    # not done here; we keep the existing 3 options and let the user pick.
    with col_scope:
        st.markdown(
            f'<div class="hero-bar-col-label">🌍 {escape("市場範圍" if lang_zh else "MARKET SCOPE")}</div>',
            unsafe_allow_html=True,
        )
        current_scope = st.session_state.get("dashboard_market_scope", "Taiwan only")
        if current_scope not in MARKET_SCOPE_OPTIONS:
            current_scope = "Taiwan only"
        # Scope label with leading flag/globe emoji.
        def _scope_label(value: str) -> str:
            base = market_scope_label(value)
            emoji_map = {
                "Mixed (U.S. + Taiwan)": "🌐",
                "U.S. only":             "🇺🇸",
                "Taiwan only":           "🇹🇼",
            }
            return f"{emoji_map.get(value, '•')}  {base}"
        selected_scope = st.selectbox(
            "_scope_label",
            options=list(MARKET_SCOPE_OPTIONS.keys()),
            index=list(MARKET_SCOPE_OPTIONS.keys()).index(current_scope),
            format_func=_scope_label,
            key="top_selector_market_scope",
            label_visibility="collapsed",
        )
        st.session_state["dashboard_market_scope"] = selected_scope

    # === Column 3: Language ===
    with col_lang:
        st.markdown(
            f'<div class="hero-bar-col-label">🌐 {escape("語言" if lang_zh else "LANGUAGE")}</div>',
            unsafe_allow_html=True,
        )
        current_lang = st.session_state.get("dashboard_language", "繁體中文")
        if current_lang not in LANGUAGE_OPTIONS:
            current_lang = "繁體中文"
        selected_lang = st.selectbox(
            "_lang_label",
            options=list(LANGUAGE_OPTIONS.keys()),
            index=list(LANGUAGE_OPTIONS.keys()).index(current_lang),
            key="top_selector_language",
            label_visibility="collapsed",
        )
        # v1.5.3: Force rerun on language change so the rest of the Hero Bar
        # text (and the entire page) immediately switches. Without this, the
        # user sees stale English copy until the next interaction.
        if selected_lang != current_lang:
            st.session_state["dashboard_language"] = selected_lang
            st.rerun()
        st.session_state["dashboard_language"] = selected_lang

    # ---- Row 2: Experience Level (4 equal-width buttons across full width) ----
    # v1.5.1: moved out of being a sub-column inside row 1. Putting all 4
    # buttons across the full hero-bar width gives every button equal column
    # width, equal min-height, and lets us shorten the labels (one short line
    # instead of "label\nhint") so they don't wrap awkwardly.
    st.markdown(
        f'<div class="hero-bar-col-label" style="margin-top: 0.85rem;">👤 {escape("使用者層級" if lang_zh else "EXPERIENCE LEVEL")}</div>',
        unsafe_allow_html=True,
    )
    persisted_layout = st.session_state.get("dashboard_layout_mode", "Advanced")
    # v1.12.6: Default to "overview" for new sessions so users see the
    # focal-points + momentum-pulse hook on first visit. If the user has
    # already been navigating, their explicit experience_level choice is
    # preserved (via session_state). _layout_to_experience_level acts as
    # a tertiary fallback only when neither is available.
    current_level = st.session_state.get(
        "dashboard_experience_level",
        "overview",
    )
    # Backstop: if a stale session has a layout but no experience_level,
    # still resolve through the legacy mapping.
    if not current_level:
        current_level = _layout_to_experience_level(persisted_layout) or "overview"
    levels = _experience_level_options(lang_zh)
    # v1.12.6: 5 buttons now (was 4). Columns auto-adapt to len(levels).
    btn_cols = st.columns(len(levels), gap="small")
    for idx, level in enumerate(levels):
        with btn_cols[idx]:
            is_active = level["key"] == current_level
            # v1.5.2: REMOVED the previous st.markdown('<div ...>') wrapper
            # approach. Streamlit treats each markdown call as its own widget
            # slot, so the wrapper div was silently adding ~20px of height to
            # the active column ONLY -- which pushed that one button + its
            # caption down and broke alignment. We now distinguish active
            # state via a marker character in the button label that CSS can
            # target with [aria-label*=" ★"]. Invisible to the eye, equal
            # height for all 4 buttons.
            base_label = f"{level['emoji']}  {level['label']}"
            btn_label = base_label + ("  ★" if is_active else "")
            if st.button(
                btn_label,
                key=f"hero_exp_{level['key']}",
                use_container_width=True,
            ):
                st.session_state["dashboard_experience_level"] = level["key"]
                st.session_state["dashboard_layout_mode"] = EXPERIENCE_LEVEL_TO_LAYOUT[level["key"]]
                # v1.12.5: Auto-jump the layout's sub-section selector to the
                # matching feature tab so the user lands DIRECTLY on the
                # function the button name implies (投資規劃 → planning tab,
                # 股票比較 → compare tab, 股票研究 → workspace tab). Beginner
                # / AI Analysis routes to its own full-page mode so no jump
                # needed there.
                if level["key"] == "intermediate":
                    # Standard layout → step navigator → jump to plan/compare tab
                    st.session_state["dashboard_standard_general_section"] = "layout_standard_compare_plan_tab"
                elif level["key"] == "advanced":
                    # v1.13.57: 「股票比較」直接進 Stock Comparison 獨立模式 (全頁比較),
                    # 而非 General Market 的比較 tab。Stock Comparison 是 full-page
                    # takeover, 不會顯示台灣市場指標/風險溫度計/動能脈搏等上方區塊。
                    st.session_state["dashboard_mode"] = "Stock Comparison"
                elif level["key"] == "expert":
                    # Expert layout → lightweight selector → jump to ticker desks (個股工作台)
                    st.session_state["dashboard_expert_general_section"] = "layout_ticker_desks_tab"
                    st.session_state["dashboard_expert_general_section__selector"] = "layout_ticker_desks_tab"
                st.rerun()
            # Per-button hint caption below the button
            st.markdown(
                f'<div class="hero-exp-hint">{escape(level["hint"])}</div>',
                unsafe_allow_html=True,
            )

    # ---- Hint copy below selectors ----
    hint = _hint_copy_for_dashboard_mode(st.session_state.get("dashboard_mode", "General Market"), lang_zh)
    st.markdown(f'<div class="hero-bar-tip">{escape(hint)}</div>', unsafe_allow_html=True)

    # ---- Hero Bar shell close ----
    st.markdown('</div>', unsafe_allow_html=True)



def sort_ticker_options(options) -> list[str]:
    seen: set[str] = set()
    cleaned: list[str] = []
    for value in options:
        normalized = normalize_dashboard_ticker(value)
        if not normalized or normalized in seen:
            continue
        seen.add(normalized)
        cleaned.append(normalized)
    return sorted(cleaned, key=lambda ticker: display_ticker_label(ticker).casefold())


def sync_multiselect_state(
    state_key: str,
    valid_options: list[str],
    fallback: list[str] | None = None,
    normalizer=None,
) -> list[str]:
    normalize = normalizer or (lambda value: value)
    normalized_to_option: dict[str, str] = {}
    for option in valid_options:
        normalized = normalize(option)
        if normalized and normalized not in normalized_to_option:
            normalized_to_option[normalized] = option

    current = []
    for value in st.session_state.get(state_key, []):
        normalized = normalize(value)
        if normalized in normalized_to_option:
            current.append(normalized_to_option[normalized])

    if not current and fallback:
        for value in fallback:
            normalized = normalize(value)
            if normalized in normalized_to_option:
                current.append(normalized_to_option[normalized])

    deduped_current = list(dict.fromkeys(current))
    st.session_state[state_key] = deduped_current
    return deduped_current



def dedupe_keep_order(values: list[str]) -> list[str]:
    return list(dict.fromkeys(str(value) for value in values if str(value).strip()))


def filter_tickers_for_market_scope(tickers: list[str], market_scope: str) -> list[str]:
    filtered: list[str] = []
    for ticker in tickers:
        normalized = normalize_dashboard_ticker(ticker)
        if not normalized:
            continue
        if market_scope == "Taiwan only" and not is_taiwan_ticker(normalized):
            continue
        if market_scope == "U.S. only" and is_taiwan_ticker(normalized):
            continue
        filtered.append(normalized)
    return dedupe_keep_order(filtered)


def default_tickers_for_market_scope(market_scope: str) -> list[str]:
    # v1.5.3: Mixed scope removed; legacy values get normalized to Taiwan only.
    market_scope = _normalize_market_scope(market_scope)
    return [
        ticker
        for ticker in DEFAULT_TICKERS
        if (market_scope == "Taiwan only" and is_taiwan_ticker(ticker))
        or (market_scope == "U.S. only" and not is_taiwan_ticker(ticker))
    ]


def merge_ticker_selection(existing: list[str], additions: list[str], market_scope: str) -> list[str]:
    merged = dedupe_keep_order(filter_tickers_for_market_scope(existing + additions, market_scope))
    return merged


