def _utc_now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()



def init_auth_db() -> None:
    return


def normalize_auth_email(email: str) -> str:
    return str(email or "").strip().lower()


def _supabase_is_configured() -> bool:
    return bool(SUPABASE_URL and SUPABASE_PUBLISHABLE_KEY)


def _supabase_headers(*, include_auth: bool = False, extra: dict[str, str] | None = None) -> dict[str, str]:
    headers = {
        "apikey": SUPABASE_PUBLISHABLE_KEY,
        "Content-Type": "application/json",
        "Accept": "application/json",
    }
    if include_auth:
        token = st.session_state.get("auth_access_token")
        if token:
            headers["Authorization"] = f"Bearer {token}"
    if extra:
        headers.update(extra)
    return headers


def _json_request_safe(value):
    if value is None or value is pd.NA:
        return None
    if isinstance(value, (pd.Timestamp, datetime)):
        return value.isoformat()
    if isinstance(value, Path):
        return str(value)
    if isinstance(value, pd.DataFrame):
        if value.empty:
            return []
        try:
            return json.loads(value.to_json(orient="records", date_format="iso"))
        except Exception:
            return [
                {
                    str(column): _json_request_safe(cell)
                    for column, cell in row.items()
                }
                for row in value.to_dict(orient="records")
            ]
    if isinstance(value, pd.Series):
        if value.empty:
            return {}
        return {
            str(key): _json_request_safe(item)
            for key, item in value.to_dict().items()
        }
    if isinstance(value, np.ndarray):
        return [_json_request_safe(item) for item in value.tolist()]
    if isinstance(value, np.generic):
        return _json_request_safe(value.item())
    if isinstance(value, dict):
        return {
            str(key): _json_request_safe(item)
            for key, item in value.items()
        }
    if isinstance(value, (list, tuple, set)):
        return [_json_request_safe(item) for item in value]
    try:
        if pd.isna(value):
            return None
    except Exception:
        pass
    return value


def _supabase_request(
    method: str,
    path: str,
    *,
    payload: dict | list | None = None,
    include_auth: bool = False,
    extra_headers: dict[str, str] | None = None,
) -> tuple[int, dict | list | str]:
    # v1.13.31: 未設定就立刻回 — 否則用空 SUPABASE_URL 組出壞 URL 仍會嘗試連線,
    # 卡到 20s timeout 才 fallback 本地檔 (這是 Supabase 沒設時 loading 慢的主因)。
    if not _supabase_is_configured():
        return 0, {"message": "Supabase is not configured."}
    url = f"{SUPABASE_URL}{path}"
    safe_payload = None if payload is None else _json_request_safe(payload)
    data = None if safe_payload is None else json.dumps(safe_payload).encode("utf-8")
    request = Request(
        url,
        data=data,
        headers=_supabase_headers(include_auth=include_auth, extra=extra_headers),
        method=method.upper(),
    )
    try:
        raw_bytes, status_code = _read_request_bytes(request, timeout=8)
        raw = raw_bytes.decode("utf-8")
        if not raw:
            return status_code, {}
        try:
            return status_code, json.loads(raw)
        except Exception:
            return status_code, raw
    except HTTPError as exc:
        raw = exc.read().decode("utf-8", errors="replace")
        try:
            payload = json.loads(raw)
        except Exception:
            payload = raw or str(exc)
        return exc.code, payload
    except URLError as exc:
        return 0, {"message": f"Supabase connection error: {exc.reason}"}
    except Exception as exc:
        return 0, {"message": f"Supabase request failed: {exc}"}


def _supabase_service_is_configured() -> bool:
    return bool(SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY)


def _supabase_service_headers(*, extra: dict[str, str] | None = None) -> dict[str, str]:
    headers = {
        "apikey": SUPABASE_SERVICE_ROLE_KEY,
        "Authorization": f"Bearer {SUPABASE_SERVICE_ROLE_KEY}",
        "Content-Type": "application/json",
        "Accept": "application/json",
    }
    if extra:
        headers.update(extra)
    return headers


def _supabase_service_request(
    method: str,
    path: str,
    *,
    payload: dict | list | None = None,
    extra_headers: dict[str, str] | None = None,
) -> tuple[int, dict | list | str]:
    if not _supabase_service_is_configured():
        return 0, {"message": "Supabase service role is not configured."}
    url = f"{SUPABASE_URL}{path}"
    safe_payload = None if payload is None else _json_request_safe(payload)
    data = None if safe_payload is None else json.dumps(safe_payload).encode("utf-8")
    request = Request(
        url,
        data=data,
        headers=_supabase_service_headers(extra=extra_headers),
        method=method.upper(),
    )
    try:
        raw_bytes, status_code = _read_request_bytes(request, timeout=10)
        raw = raw_bytes.decode("utf-8")
        if not raw:
            return status_code, {}
        try:
            return status_code, json.loads(raw)
        except Exception:
            return status_code, raw
    except HTTPError as exc:
        raw = exc.read().decode("utf-8", errors="replace")
        try:
            payload = json.loads(raw)
        except Exception:
            payload = raw or str(exc)
        return exc.code, payload
    except URLError as exc:
        return 0, {"message": f"Supabase connection error: {exc.reason}"}
    except Exception as exc:
        return 0, {"message": f"Supabase service request failed: {exc}"}


def _auth_response_error(payload: dict | list | str, fallback: str) -> str:
    if isinstance(payload, dict):
        for key in ("msg", "message", "error_description", "error"):
            value = payload.get(key)
            if value:
                return str(value)
    if isinstance(payload, str) and payload.strip():
        return payload.strip()
    return fallback


def _store_authenticated_session(payload: dict) -> None:
    user = payload.get("user") if isinstance(payload.get("user"), dict) else {}
    access_token = payload.get("access_token") or payload.get("session", {}).get("access_token")
    refresh_token = payload.get("refresh_token") or payload.get("session", {}).get("refresh_token")
    expires_in = payload.get("expires_in") or payload.get("session", {}).get("expires_in")
    email = normalize_auth_email(user.get("email") or payload.get("email"))
    user_id = str(user.get("id") or "")

    if access_token:
        st.session_state["auth_access_token"] = str(access_token)
    if refresh_token:
        st.session_state["auth_refresh_token"] = str(refresh_token)
    if expires_in:
        try:
            st.session_state["auth_expires_at"] = int(datetime.now(timezone.utc).timestamp()) + int(expires_in)
        except Exception:
            st.session_state.pop("auth_expires_at", None)
    if email:
        st.session_state["auth_user_email"] = email
    if user_id:
        st.session_state["auth_user_id"] = user_id


def _ensure_active_supabase_session() -> bool:
    if not is_authenticated():
        return False

    expires_at = st.session_state.get("auth_expires_at")
    try:
        expires_at_int = int(expires_at) if expires_at is not None else None
    except Exception:
        expires_at_int = None

    now_ts = int(datetime.now(timezone.utc).timestamp())
    if expires_at_int and now_ts < max(expires_at_int - 60, 0):
        return True

    refresh_token = st.session_state.get("auth_refresh_token")
    if not refresh_token:
        return bool(st.session_state.get("auth_access_token"))

    status, payload = _supabase_request(
        "POST",
        "/auth/v1/token?grant_type=refresh_token",
        payload={"refresh_token": refresh_token},
    )
    if 200 <= status < 300 and isinstance(payload, dict):
        _store_authenticated_session(payload)
        return True

    logout_authenticated_user()
    return False


def register_auth_user(email: str, password: str) -> tuple[bool, str]:
    if not _supabase_is_configured():
        return False, "Supabase is not configured."
    email_normalized = normalize_auth_email(email)
    password_value = str(password or "")

    if not email_normalized or "@" not in email_normalized:
        return False, "Please enter a valid email address."
    if len(password_value) < AUTH_MIN_PASSWORD_LENGTH:
        return False, f"Password must be at least {AUTH_MIN_PASSWORD_LENGTH} characters."

    status, payload = _supabase_request(
        "POST",
        "/auth/v1/signup",
        payload={"email": email_normalized, "password": password_value},
    )
    if not (200 <= status < 300):
        return False, _auth_response_error(payload, "Unable to create account.")

    if isinstance(payload, dict):
        if payload.get("access_token") or payload.get("session"):
            _store_authenticated_session(payload)
            return True, "Account created and signed in."
        return True, "Account created. Please confirm your email if confirmation is enabled, then sign in."

    return True, "Account created."


def authenticate_auth_user(email: str, password: str) -> tuple[bool, str]:
    if not _supabase_is_configured():
        return False, "Supabase is not configured."
    email_normalized = normalize_auth_email(email)
    status, payload = _supabase_request(
        "POST",
        "/auth/v1/token?grant_type=password",
        payload={"email": email_normalized, "password": str(password or "")},
    )
    if not (200 <= status < 300) or not isinstance(payload, dict):
        return False, _auth_response_error(payload, "Incorrect email or password.")

    _store_authenticated_session(payload)
    return True, normalize_auth_email(st.session_state.get("auth_user_email", email_normalized))


def load_user_profile(email: str) -> dict[str, str]:
    email_normalized = normalize_auth_email(email)
    user_id = str(st.session_state.get("auth_user_id", "")).strip()
    if not email_normalized or not user_id:
        return {}
    if not _ensure_active_supabase_session():
        return {}

    select_query = quote_plus("user_id,email,preferences,updated_at")
    path = f"/rest/v1/{SUPABASE_PROFILE_TABLE}?select={select_query}&user_id=eq.{quote_plus(user_id)}&limit=1"
    status, payload = _supabase_request("GET", path, include_auth=True)
    if not (200 <= status < 300) or not isinstance(payload, list) or not payload:
        return {}

    row = payload[0] if isinstance(payload[0], dict) else {}
    preferences = row.get("preferences", {})
    if isinstance(preferences, str):
        try:
            preferences = json.loads(preferences)
        except Exception:
            preferences = {}
    if not isinstance(preferences, dict):
        preferences = {}

    clean = {str(key): str(value) for key, value in preferences.items() if value is not None}
    st.session_state["_auth_last_saved_profile_payload"] = clean
    return clean


def save_user_profile(email: str, params: dict[str, str]) -> None:
    email_normalized = normalize_auth_email(email)
    user_id = str(st.session_state.get("auth_user_id", "")).strip()
    if not email_normalized or not user_id:
        return
    if not _ensure_active_supabase_session():
        return

    clean = {str(key): str(value) for key, value in params.items() if value not in (None, "")}
    last_saved = st.session_state.get("_auth_last_saved_profile_payload")
    if clean == last_saved:
        return

    row = {
        "user_id": user_id,
        "email": email_normalized,
        "preferences": clean,
        "updated_at": _utc_now_iso(),
    }
    path = f"/rest/v1/{SUPABASE_PROFILE_TABLE}?on_conflict=user_id"
    status, payload = _supabase_request(
        "POST",
        path,
        payload=row,
        include_auth=True,
        extra_headers={"Prefer": "resolution=merge-duplicates,return=representation"},
    )
    if 200 <= status < 300:
        st.session_state["_auth_last_saved_profile_payload"] = clean
        return

    error_message = _auth_response_error(
        payload,
        f"Unable to save profile to `{SUPABASE_PROFILE_TABLE}`. Please create the table and RLS policies in Supabase.",
    )
    st.session_state["auth_profile_save_error"] = error_message


def is_authenticated() -> bool:
    return bool(normalize_auth_email(st.session_state.get("auth_user_email", ""))) and bool(st.session_state.get("auth_access_token"))


def get_authenticated_email() -> str:
    return normalize_auth_email(st.session_state.get("auth_user_email", ""))


def logout_authenticated_user() -> None:
    for key in [
        "auth_user_email",
        "auth_user_id",
        "auth_access_token",
        "auth_refresh_token",
        "auth_expires_at",
        "_auth_last_saved_profile_payload",
        "_dashboard_prefs_loaded",
        "auth_profile_save_error",
    ]:
        st.session_state.pop(key, None)


def auth_label(en_text: str, zh_text: str) -> str:
    return zh_text if st.session_state.get("dashboard_language") == "繁體中文" else en_text


def render_auth_sidebar() -> None:
    render_html_block(f'<div class="side-group-label">{auth_label("Account", "帳號")}</div>')
    render_html_block(
        f'''
        <div class="sidebar-auth-shell">
            <div class="sidebar-auth-title">{escape(auth_label("Member access", "會員登入"))}</div>
            <div class="sidebar-auth-copy">{escape(auth_label("Sign in to keep your personal dashboard selections, language, watchlists, and device preferences in sync.", "登入後可保留你的儀表板選擇、語言、觀察清單與裝置偏好設定。"))}</div>
        </div>
        '''
    )
    if not _supabase_is_configured():
        st.warning(auth_label("Supabase is not configured yet.", "Supabase 尚未設定完成。"))
        return

    profile_error = st.session_state.get("auth_profile_save_error")
    if profile_error and not is_authenticated():
        st.session_state.pop("auth_profile_save_error", None)

    if is_authenticated():
        _ensure_active_supabase_session()
        email = get_authenticated_email()
        st.success(auth_label(f"Signed in as {email}", f"已登入：{email}"))
        st.caption(auth_label("Your dashboard selections are saved to your Supabase profile automatically.", "你的儀表板選擇會自動儲存到 Supabase 個人設定。"))
        if profile_error:
            st.warning(profile_error)
        col_save, col_logout = st.columns(2)
        with col_save:
            if st.button(auth_label("Reload profile", "重新載入設定"), use_container_width=True, key="auth_reload_profile_button"):
                st.session_state["_dashboard_prefs_loaded"] = False
                st.rerun()
        with col_logout:
            if st.button(auth_label("Log out", "登出"), use_container_width=True, key="auth_logout_button"):
                logout_authenticated_user()
                st.rerun()
        return

    login_tab, register_tab = st.tabs(
        [
            auth_label("Sign in", "登入"),
            auth_label("Register", "註冊"),
        ]
    )

    with login_tab:
        login_email = st.text_input(
            auth_label("Email", "電子郵件"),
            key="auth_login_email",
            placeholder="name@example.com",
        )
        login_password = st.text_input(
            auth_label("Password", "密碼"),
            type="password",
            key="auth_login_password",
        )
        if st.button(auth_label("Sign in", "登入"), use_container_width=True, key="auth_login_submit"):
            ok, payload = authenticate_auth_user(login_email, login_password)
            if ok:
                st.session_state["_auth_last_saved_profile_payload"] = load_user_profile(payload)
                st.session_state["_dashboard_prefs_loaded"] = False
                st.rerun()
            st.error(payload)

    with register_tab:
        register_email = st.text_input(
            auth_label("Email", "電子郵件"),
            key="auth_register_email",
            placeholder="name@example.com",
        )
        register_password = st.text_input(
            auth_label("Password", "密碼"),
            type="password",
            key="auth_register_password",
        )
        if st.button(auth_label("Create account", "建立帳號"), use_container_width=True, key="auth_register_submit"):
            ok, payload = register_auth_user(register_email, register_password)
            if ok:
                st.success(payload)
                if is_authenticated():
                    st.session_state["_dashboard_prefs_loaded"] = False
                    st.rerun()
            else:
                st.error(payload)


def save_dashboard_preferences(params: dict[str, str]) -> None:
    clean = {key: str(value) for key, value in params.items() if value not in (None, "")}
    if is_authenticated():
        save_user_profile(get_authenticated_email(), clean)
    if clean == _current_query_param_map():
        return
    try:
        query_params = st.query_params
        if hasattr(query_params, "clear"):
            query_params.clear()
        for key, value in clean.items():
            query_params[key] = value
        return
    except Exception:
        pass
    try:
        st.experimental_set_query_params(**clean)
    except Exception:
        return


def load_dashboard_preferences() -> None:
    if st.session_state.get("_dashboard_prefs_loaded"):
        return

    user_profile = load_user_profile(get_authenticated_email()) if is_authenticated() else {}

    def _profile_value(key: str) -> str:
        return str(user_profile.get(key, "")) if key in user_profile else ""

    dashboard_mode = _query_param_first("mode") or _profile_value("mode") or st.session_state.get("dashboard_mode", "General Market")
    if dashboard_mode not in DASHBOARD_MODE_OPTIONS:
        dashboard_mode = "General Market"

    language = _query_param_first("lang") or _profile_value("lang") or st.session_state.get("dashboard_language", "繁體中文")
    if language not in LANGUAGE_OPTIONS:
        language = "English"

    news_mode = _query_param_first("news") or _profile_value("news") or st.session_state.get("dashboard_news_mode", "Original source")
    if news_mode not in NEWS_DISPLAY_OPTIONS:
        news_mode = "Original source"

    device_control_mode = _query_param_first("devicectl") or _profile_value("devicectl") or st.session_state.get("dashboard_device_control_mode", "Auto detect")
    if device_control_mode not in DEVICE_CONTROL_OPTIONS:
        device_control_mode = "Auto detect"

    device_mode = normalize_device_mode(_query_param_first("device") or _profile_value("device") or st.session_state.get("dashboard_device_mode", "Desktop"))

    theme_mode = _query_param_first("theme") or _profile_value("theme") or st.session_state.get("dashboard_theme_mode", "Dark Horizon")
    if theme_mode not in THEME_MODE_OPTIONS:
        theme_mode = "Dark Horizon"

    layout_mode = _query_param_first("layout") or _profile_value("layout") or st.session_state.get("dashboard_layout_mode", "Advanced")
    if layout_mode not in DASHBOARD_LAYOUT_OPTIONS:
        layout_mode = "Advanced"

    market_scope = _query_param_first("scope") or _profile_value("scope") or st.session_state.get("dashboard_market_scope", "Taiwan only")
    if market_scope not in MARKET_SCOPE_OPTIONS:
        market_scope = "Taiwan only"

    groups = _csv_decode(_query_param_first("groups") or _profile_value("groups"))
    groups = [group for group in groups if group in market_scope_group_options(market_scope)]
    if not groups:
        groups = list(MARKET_SCOPE_DEFAULT_GROUPS[market_scope])

    picks_param_present = _query_param_exists("picks") or bool(_profile_value("picks"))
    picks = [
        normalize_dashboard_ticker(value)
        for value in _csv_decode(_query_param_first("picks") or _profile_value("picks"), empty_sentinel=EMPTY_SELECTION_SENTINEL)
    ]
    picks = filter_tickers_for_market_scope(picks, market_scope)
    custom_symbols = _query_param_first("custom") or _profile_value("custom") or st.session_state.get("dashboard_custom_symbols", "")
    symbol_search = _query_param_first("search") or _profile_value("search") or st.session_state.get("dashboard_symbol_search", "")

    active_etf_picks_param_present = _query_param_exists("etfpicks") or bool(_profile_value("etfpicks"))
    active_etf_picks = filter_active_etf_tickers(
        _csv_decode(_query_param_first("etfpicks") or _profile_value("etfpicks"), empty_sentinel=EMPTY_SELECTION_SENTINEL)
    )
    # v1.13.33: Active ETF Lab 預設帶入 quick-pick — 若使用者從未指定 ETF
    # (URL 無 etfpicks 參數、偏好無儲存值, 且非「明確清空」的 __none__ 哨符),
    # 預設帶入 ACTIVE_ETF_QUICK_PICK_SYMBOLS, 讓一進 Lab 就有內容可看, 而非
    # 顯示「請先在左側加入」空畫面。明確清空 (etfpicks=__none__) 仍會被尊重。
    _etfpicks_raw = _query_param_first("etfpicks") or _profile_value("etfpicks") or ""
    _etfpicks_explicitly_empty = str(_etfpicks_raw).strip() == EMPTY_SELECTION_SENTINEL
    _etfpicks_specified = _query_param_exists("etfpicks") or bool(_profile_value("etfpicks"))
    # v1.13.53: 自動帶入只在 Active ETF Lab 模式生效。原本無條件填充, 導致
    # 使用者在其他模式 (如股票研究) 移除 ETF 後, 下次 rerun 又被全部加回來
    # (「移除還會回來」的 bug)。限定 ETF Lab 才預設帶入。
    if (not active_etf_picks and not _etfpicks_specified and not _etfpicks_explicitly_empty
            and dashboard_mode == "Active ETF Lab"):
        active_etf_picks = filter_active_etf_tickers(list(ACTIVE_ETF_QUICK_PICK_SYMBOLS))
    active_etf_custom_symbols = _query_param_first("etfcustom") or _profile_value("etfcustom") or st.session_state.get("dashboard_active_etf_custom_symbols", "")
    active_etf_symbol_search = _query_param_first("etfsearch") or _profile_value("etfsearch") or st.session_state.get("dashboard_active_etf_symbol_search", "")

    supply_chain_groups_param_present = _query_param_exists("scgroups") or bool(_profile_value("scgroups"))
    supply_chain_groups = [
        key
        for key in _csv_decode(_query_param_first("scgroups") or _profile_value("scgroups"), empty_sentinel=EMPTY_SELECTION_SENTINEL)
        if key in SUPPLY_CHAIN_FOCUS_CONFIGS
    ]
    if not supply_chain_groups and not supply_chain_groups_param_present:
        supply_chain_groups = [key for key in SUPPLY_CHAIN_FOCUS_ORDER if key in SUPPLY_CHAIN_FOCUS_CONFIGS]

    lens_name = _query_param_first("lens") or _profile_value("lens") or st.session_state.get("dashboard_lens_name", DEFAULT_TREND_LENS)
    if lens_name not in TREND_LENSES:
        lens_name = DEFAULT_TREND_LENS

    manual_override = ((_query_param_first("manual") or _profile_value("manual") or "0") == "1")
    manual_period = _query_param_first("period") or _profile_value("period") or st.session_state.get("dashboard_manual_period", DEFAULT_PERIOD)
    if manual_period not in SUPPORTED_PERIODS:
        manual_period = DEFAULT_PERIOD
    manual_interval = _query_param_first("interval") or _profile_value("interval") or st.session_state.get("dashboard_manual_interval", DEFAULT_INTERVAL)
    if manual_interval not in SUPPORTED_INTERVALS:
        manual_interval = DEFAULT_INTERVAL

    tx_entry_price = _safe_float(_query_param_first("txentry") or _profile_value("txentry") or st.session_state.get("dashboard_txf_entry_price", 0.0), default=0.0)
    if pd.isna(tx_entry_price):
        tx_entry_price = 0.0
    tx_days_window = int(_safe_float(_query_param_first("txdays") or _profile_value("txdays") or st.session_state.get("dashboard_txf_days_window", 3), default=3))
    tx_days_window = max(1, min(30, tx_days_window))
    tx_position_side = str(_query_param_first("txside") or _profile_value("txside") or st.session_state.get("dashboard_txf_position_side", "Call")).strip() or "Call"
    if tx_position_side not in {"Call", "Put"}:
        tx_position_side = "Call"
    tx_premium_points = _safe_float(_query_param_first("txpremium") or _profile_value("txpremium") or st.session_state.get("dashboard_txf_premium_points", 0.0), default=0.0)
    if pd.isna(tx_premium_points):
        tx_premium_points = 0.0
    tx_target_points = _safe_float(_query_param_first("txtarget") or _profile_value("txtarget") or st.session_state.get("dashboard_txf_target_points", 0.0), default=0.0)
    if pd.isna(tx_target_points):
        tx_target_points = 0.0
    tx_delta_assumption = _safe_float(_query_param_first("txdelta") or _profile_value("txdelta") or st.session_state.get("dashboard_txf_delta_assumption", 0.05), default=0.05)
    if pd.isna(tx_delta_assumption):
        tx_delta_assumption = 0.05
    tx_delta_assumption = max(0.01, min(1.0, float(tx_delta_assumption)))

    st.session_state["dashboard_mode"] = dashboard_mode
    st.session_state["dashboard_language"] = language
    st.session_state["dashboard_news_mode"] = news_mode
    st.session_state["dashboard_device_control_mode"] = device_control_mode
    st.session_state["dashboard_device_mode"] = device_mode
    st.session_state["dashboard_theme_mode"] = theme_mode
    st.session_state["dashboard_layout_mode"] = layout_mode
    st.session_state["dashboard_detected_device_mode"] = detect_device_mode_from_user_agent()
    st.session_state["dashboard_market_scope"] = market_scope
    st.session_state["dashboard_selected_groups"] = groups
    st.session_state["dashboard_selected_tickers"] = picks
    st.session_state["dashboard_selected_tickers_initialized"] = picks_param_present or bool(picks)
    st.session_state["dashboard_custom_symbols"] = custom_symbols
    st.session_state["dashboard_symbol_search"] = symbol_search
    st.session_state["dashboard_active_etf_tickers"] = active_etf_picks
    st.session_state["dashboard_active_etf_tickers_initialized"] = active_etf_picks_param_present or bool(active_etf_picks)
    st.session_state["dashboard_active_etf_custom_symbols"] = active_etf_custom_symbols
    st.session_state["dashboard_active_etf_symbol_search"] = active_etf_symbol_search
    st.session_state["dashboard_supply_chain_groups"] = supply_chain_groups
    st.session_state["dashboard_lens_name"] = lens_name
    st.session_state["dashboard_manual_override"] = manual_override
    st.session_state["dashboard_manual_period"] = manual_period
    st.session_state["dashboard_manual_interval"] = manual_interval
    st.session_state["dashboard_txf_entry_price"] = float(tx_entry_price)
    st.session_state["dashboard_txf_days_window"] = int(tx_days_window)
    st.session_state["dashboard_txf_position_side"] = tx_position_side
    st.session_state["dashboard_txf_premium_points"] = float(tx_premium_points)
    st.session_state["dashboard_txf_target_points"] = float(tx_target_points)
    st.session_state["dashboard_txf_delta_assumption"] = float(tx_delta_assumption)

    # v1.8.6: Restore the radar smart-routing queue from URL. The radar's
    # <a href> links replace all query params on click; if session_state
    # also got reset by the navigation (some Streamlit hosting + browser
    # combos do this), the queue would be lost without this URL-backed
    # fallback. We always re-publish to session_state on every loader run
    # so the queue survives both warm reruns and cold session re-inits.
    radar_picks_csv = _query_param_first("radar_picks") or _profile_value("radar_picks") or ""
    radar_picks_restored: list[str] = []
    seen_radar_picks: set[str] = set()
    valid_us_radar_tickers: set[str] = set()
    for theme in US_THEME_GROUPS:
        for tk in (theme.get("tickers") or []):
            valid_us_radar_tickers.add(str(tk).strip().upper())
    for raw_pick in _csv_decode(radar_picks_csv):
        pk = str(raw_pick).strip().upper()
        if not pk or pk in seen_radar_picks:
            continue
        # Drop unknown tickers (defensive against URL tampering).
        if pk not in valid_us_radar_tickers:
            continue
        seen_radar_picks.add(pk)
        radar_picks_restored.append(pk)
    # Cap to the same size as the live consumer's cap so URL-restored
    # state never blows past the consumer's invariants.
    if len(radar_picks_restored) > _US_RADAR_PICK_QUEUE_CAP:
        radar_picks_restored = radar_picks_restored[-_US_RADAR_PICK_QUEUE_CAP:]
    st.session_state["_us_radar_picks"] = radar_picks_restored

    st.session_state["_dashboard_prefs_loaded"] = True


def taiwan_sector_group(ticker: str) -> str:
    ticker_upper = str(ticker).upper()
    for group in TAIWAN_WATCHLIST_GROUPS:
        if ticker_upper in {symbol.upper() for symbol in WATCHLIST_PRESETS.get(group, [])}:
            return group
    return "Taiwan Semiconductors"


def taiwan_sector_peers(ticker: str, limit: int = 6) -> list[str]:
    group = taiwan_sector_group(ticker)
    ticker_upper = str(ticker).upper()
    peers = [symbol for symbol in WATCHLIST_PRESETS.get(group, []) if str(symbol).upper() != ticker_upper]
    return peers[:limit]


def compute_window_return_pct(series: pd.Series | None) -> float:
    if series is None:
        return float("nan")
    clean = ensure_datetime_index(series).dropna()
    if len(clean) < 2:
        return float("nan")
    start = clean.iloc[0]
    end = clean.iloc[-1]
    if pd.isna(start) or pd.isna(end) or start == 0:
        return float("nan")
    return float(((end / start) - 1) * 100)


def compute_recent_return_pct(series: pd.Series | None, window: int = 20) -> float:
    if series is None:
        return float("nan")
    clean = ensure_datetime_index(series).dropna()
    if len(clean) < 2:
        return float("nan")
    tail = clean.tail(min(window, len(clean)))
    return compute_window_return_pct(tail)


def percent_spread(left: float, right: float) -> float:
    if pd.isna(left) or pd.isna(right):
        return float("nan")
    return float(left - right)


def taiwan_relative_state_label(score: float) -> str:
    if pd.isna(score):
        return t("tw_in_line")
    if score >= 12:
        return t("tw_strong_leader")
    if score >= 4:
        return t("tw_mild_leader")
    if score <= -12:
        return t("tw_clear_laggard")
    if score <= -4:
        return t("tw_mild_laggard")
    return t("tw_in_line")


def taiwan_relative_state_note(score: float) -> str:
    if pd.isna(score):
        return t("tw_benchmark_note_in_line")
    if score >= 12:
        return t("tw_benchmark_note_strong_leader")
    if score >= 4:
        return t("tw_benchmark_note_mild_leader")
    if score <= -12:
        return t("tw_benchmark_note_clear_laggard")
    if score <= -4:
        return t("tw_benchmark_note_mild_laggard")
    return t("tw_benchmark_note_in_line")


def benchmark_delta_label(value: float) -> str:
    if pd.isna(value):
        return "N/A"
    direction = t("tw_outperforming") if value >= 0 else t("tw_lagging")
    return f"{direction} {format_percent(value)}"



@st.cache_data(ttl=300)
def fetch_global_reference_data(period: str, interval: str):
    # v1.5.3-1.5.5: yfinance fetch for all real tickers; skip TWSE sentinels.
    # IX0126.TW (台指期 Yahoo index) IS yfinance-fetchable so it stays in.
    yfinance_tickers = [
        item["ticker"] for item in GLOBAL_REFERENCE_INDICES
        if not item["ticker"].startswith("__")
    ]
    return fetch_daily_data(yfinance_tickers, period, interval)


# ============================================================================
# v1.6.0  Main Dashboard Snapshot — Supabase prefetch / restore
# ============================================================================
# Daily prefetch job (.github/workflows/prefetch-daily.yml +
# prefetch_main_dashboard_job.py) writes a JSON snapshot of the global
# indicator + cockpit Q1-Q4 to the Supabase main_dashboard_snapshot table
# every weekday at 06:00 Taiwan time. On page entry, generate_dashboard()
# tries to load the snapshot and render instantly. The user sees a
# "📅 資料 YYYY-MM-DD" badge + a "🔄 抓今天最新" button to force a live
# refetch when they want fresh numbers.
SUPABASE_MAIN_DASHBOARD_SNAPSHOT_TABLE = "main_dashboard_snapshot"


def _supabase_main_dashboard_snapshot_enabled() -> bool:
    """We require the URL + a service role key to do anything."""
    return bool(SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY)


@st.cache_data(ttl=600, show_spinner=False)
def load_main_dashboard_snapshot(market_scope: str) -> dict | None:
    """Load the most recent snapshot for the given market_scope.

    Returns the row as a dict (with payload columns parsed from JSON), or
    None when:
      - Supabase is not configured (no URL / key)
      - No row exists for this scope yet
      - Network / parse failure (silently degrades to live fetch)

    Cached 10 min: refreshing the page repeatedly within 10 min hits cache,
    but the user-driven "🔄 抓今天最新" button bypasses by clearing cache.
    """
    if not _supabase_main_dashboard_snapshot_enabled():
        return None
    market_scope = _normalize_market_scope(market_scope)
    url = (
        f"{SUPABASE_URL}/rest/v1/{SUPABASE_MAIN_DASHBOARD_SNAPSHOT_TABLE}"
        f"?market_scope=eq.{quote_plus(market_scope)}"
        f"&order=snapshot_at.desc&limit=1"
    )
    headers = {
        "apikey": SUPABASE_SERVICE_ROLE_KEY,
        "Authorization": f"Bearer {SUPABASE_SERVICE_ROLE_KEY}",
        "Accept": "application/json",
    }
    try:
        req = Request(url, headers=headers, method="GET")
        with urlopen(req, timeout=8) as resp:
            data = json.loads(resp.read().decode("utf-8"))
        if not data or not isinstance(data, list):
            return None
        row = data[0]
        # Each *_payload column comes back as already-parsed JSON (PostgREST).
        return row
    except Exception:
        return None


def _format_snapshot_age_label(snapshot_at_iso: str | None, lang_zh: bool) -> str:
    """Friendly age label: '今天 06:00' / '昨天 06:00' / '5/5 06:00'."""
    if not snapshot_at_iso:
        return ""
    try:
        # snapshot_at is ISO 8601 with TZ; reduce to TW timezone for display
        dt = datetime.fromisoformat(snapshot_at_iso.replace("Z", "+00:00"))
        dt_tw = dt.astimezone(TW_TZ)
        today_tw = datetime.now(TW_TZ).date()
        delta_days = (today_tw - dt_tw.date()).days
        time_str = dt_tw.strftime("%H:%M")
        if delta_days == 0:
            prefix = "今天" if lang_zh else "Today"
        elif delta_days == 1:
            prefix = "昨天" if lang_zh else "Yesterday"
        else:
            prefix = dt_tw.strftime("%-m/%-d") if hasattr(dt_tw, "strftime") else dt_tw.strftime("%m/%d")
            try:
                # %-m / %-d not on Windows; fall back manually
                prefix = f"{dt_tw.month}/{dt_tw.day}"
            except Exception:
                pass
        return f"{prefix} {time_str}"
    except Exception:
        return snapshot_at_iso[:16]


def render_snapshot_freshness_bar(snapshot_row: dict | None, lang_zh: bool) -> None:
    """Render the '📅 資料日期' badge + '🔄 抓今天最新' button between the
    Hero Bar and the Global Market Indicator. v1.6.0."""
    inject_snapshot_freshness_bar_css()
    cols = st.columns([3, 1], gap="small")
    with cols[0]:
        if snapshot_row:
            age_label = _format_snapshot_age_label(
                snapshot_row.get("snapshot_at"), lang_zh
            )
            errors = (snapshot_row.get("fetch_metadata") or {}).get("errors") or []
            err_chip = ""
            if errors:
                # Minor visual chip if any builder failed during prefetch
                err_chip = (
                    f' <span class="snapshot-freshness-err-chip">'
                    f'{escape("部分資料抓取失敗" if lang_zh else "Some data missing")}'
                    f'</span>'
                )
            label = "📅 " + (
                f"資料 {age_label}（自動抓取）" if lang_zh
                else f"Data {age_label} (auto-fetched)"
            )
            st.markdown(
                f'<div class="snapshot-freshness-badge">{escape(label)}{err_chip}</div>',
                unsafe_allow_html=True,
            )
        else:
            st.markdown(
                f'<div class="snapshot-freshness-badge snapshot-freshness-badge-live">'
                f'{escape("⚡ 即時抓取" if lang_zh else "⚡ Live fetch")}'
                f'</div>',
                unsafe_allow_html=True,
            )
    with cols[1]:
        btn_label = "🔄 抓今天最新" if lang_zh else "🔄 Refresh now"
        if st.button(btn_label, key="snapshot_refresh_btn", use_container_width=True):
            # Clear caches that feed the cockpit/global indicator so the
            # live path runs on the next rerun.
            try:
                load_main_dashboard_snapshot.clear()
            except Exception:
                pass
            try:
                fetch_global_reference_data.clear()
                fetch_live_reference_quotes.clear()
                fetch_taiwan_market_aggregates.clear()
                fetch_taifex_futures_quote.clear()
                fetch_daily_data.clear()
                fetch_intraday_data.clear()
            except Exception:
                pass
            st.session_state["_force_live_main_dashboard"] = True
            st.rerun()


def inject_snapshot_freshness_bar_css() -> None:
    st.markdown(
        """
        <style>
        .snapshot-freshness-badge {
            background: rgba(11,18,32,0.62);
            border: 1px solid rgba(94,234,212,0.22);
            border-radius: 10px;
            padding: 0.65rem 1.1rem;
            font-size: 0.92rem;
            color: rgba(255,255,255,0.85);
            display: flex; align-items: center; gap: 0.7rem;
            min-height: 42px;
        }
        .snapshot-freshness-badge-live {
            border-color: rgba(250,204,21,0.32);
            color: rgba(250,204,21,0.9);
        }
        .snapshot-freshness-err-chip {
            font-size: 0.78rem;
            padding: 0.18rem 0.5rem;
            border-radius: 6px;
            background: rgba(245,158,11,0.18);
            color: rgba(245,158,11,0.92);
            margin-left: 0.4rem;
        }
        /* v1.8.0: mobile responsive for freshness bar. Streamlit's st.columns
           does NOT auto-stack reliably below ~640px in some browsers, but
           we shrink padding + font so the [3,1] layout still fits. */
        @media (max-width: 720px) {
            .snapshot-freshness-badge {
                padding: 0.55rem 0.85rem;
                font-size: 0.85rem;
                min-height: 40px;
                gap: 0.4rem;
            }
            .snapshot-freshness-err-chip {
                font-size: 0.7rem;
                padding: 0.15rem 0.4rem;
            }
        }
        @media (max-width: 480px) {
            .snapshot-freshness-badge {
                padding: 0.5rem 0.7rem;
                font-size: 0.78rem;
                min-height: 36px;
            }
            /* On Fold/very narrow, hide the err-chip text and keep just the
               warning color rim on the badge — saves precious horizontal space. */
            .snapshot-freshness-err-chip {
                display: none;
            }
        }
        </style>
        """,
        unsafe_allow_html=True,
    )


# v1.5.3: Taiwan-specific market aggregates (total turnover + foreign-net total)
# fetched via TWSE BWIBBU/MI_INDEX endpoints. These are the underlying
# datasets behind the "台股交易量" and "外資合計" indicator cards.
#
# v1.5.4: Now also returns the most recent 3 trading days of values
# (D-0 latest, D-1 prior, D-2 two days back) so the indicator cards can
# show "前一日 / 前兩日" mini-stats next to today's reading.
#
# Cached 30 min by default. TTL is intentionally generous because TWSE
# publishes T86 (institutional flow) ~2 hours after market close, so the
# value usually doesn't change during a session anyway. The cache key
# includes today's TW date so we get a fresh fetch on the next trading day.
@st.cache_data(ttl=1800, show_spinner=False)
def _fetch_taiwan_market_aggregates_raw(_cache_key: str) -> dict:
    """v1.12.1: RAW fetcher — calls TWSE FMTQIK + BFI82U directly.
    Returns dict with None values if fetch fails (used to be the public
    fetch_taiwan_market_aggregates function in v1.12.0d and earlier).

    The PUBLIC entry point is now fetch_taiwan_market_aggregates() below,
    which wraps this in a 4-layer persistent fallback (memory cache →
    session_state last-good → disk JSON → seed value) so the UI NEVER
    shows "資料準備中" when TWSE is unreachable.
    """
    result: dict = {
        "turnover_value": None, "turnover_d1": None, "turnover_d2": None,
        "turnover_change_pct": None,
        # v1.6.0: now tracks all 3 institutional investors with D-1/D-2.
        "foreign_net": None, "foreign_net_d1": None, "foreign_net_d2": None,
        "trust_net": None, "trust_net_d1": None, "trust_net_d2": None,
        "dealer_net": None, "dealer_net_d1": None, "dealer_net_d2": None,
        "data_date": None, "data_date_d1": None, "data_date_d2": None,
        "is_today": False,
        "error": None,
    }

    today_tw = datetime.now(TW_TZ).date()

    def _roc_to_iso(roc_str: str) -> str | None:
        """Convert "114/05/06" ROC date string -> "2025-05-06" gregorian."""
        if not roc_str or "/" not in roc_str:
            return None
        try:
            parts = roc_str.split("/")
            if len(parts) != 3:
                return None
            return f"{int(parts[0]) + 1911}-{int(parts[1]):02d}-{int(parts[2]):02d}"
        except (ValueError, IndexError):
            return None

    # --- 1. Total turnover from TWSE FMTQIK endpoint (~20 trading days) ---
    try:
        date_yyyymmdd = today_tw.strftime("%Y%m%d")
        url = f"https://www.twse.com.tw/exchangeReport/FMTQIK?response=json&date={date_yyyymmdd}"
        payload = _twse_request_json(url)
        rows = payload.get("data") or []
        # Rows are oldest-first; we want the last 3.
        if rows:
            recent = rows[-3:] if len(rows) >= 3 else rows
            # Last (most recent)
            try:
                last_row = recent[-1]
                value_ntd = float(str(last_row[2] or "").replace(",", "").strip())
                result["turnover_value"] = value_ntd / 1_0000_0000  # 元 -> 億
                result["data_date"] = _roc_to_iso(str(last_row[0] or "").strip())
                result["is_today"] = result["data_date"] == today_tw.strftime("%Y-%m-%d")
            except (ValueError, IndexError):
                pass
            # D-1
            if len(recent) >= 2:
                try:
                    d1_row = recent[-2]
                    result["turnover_d1"] = float(
                        str(d1_row[2] or "").replace(",", "").strip()
                    ) / 1_0000_0000
                    result["data_date_d1"] = _roc_to_iso(str(d1_row[0] or "").strip())
                except (ValueError, IndexError):
                    pass
            # D-2
            if len(recent) >= 3:
                try:
                    d2_row = recent[-3]
                    result["turnover_d2"] = float(
                        str(d2_row[2] or "").replace(",", "").strip()
                    ) / 1_0000_0000
                    result["data_date_d2"] = _roc_to_iso(str(d2_row[0] or "").strip())
                except (ValueError, IndexError):
                    pass
            # Change % vs previous day
            if result.get("turnover_value") and result.get("turnover_d1"):
                prev = result["turnover_d1"]
                cur = result["turnover_value"]
                if prev > 0:
                    result["turnover_change_pct"] = ((cur - prev) / prev) * 100.0
    except Exception as exc:
        result["error"] = f"turnover: {type(exc).__name__}"

    # --- 2. Institutional flows from TWSE BFI82U for the latest 3 trading days ---
    # v1.6.0: Now extracts ALL three institutional investors:
    #   - 外資及陸資 (foreign + China)
    #   - 投信 (investment trusts / domestic mutual funds)
    #   - 自營商 (proprietary dealers, both regular + hedging combined)
    #
    # BFI82U returns ~7 rows per day. The 自營商 has 3 sub-rows (合計, 自行
    # 買賣, 避險); we use the first one which is the aggregate total.
    # Walk back until we have 3 days of data (or run out of probes).
    try:
        probe_days = 0
        probe_date = today_tw
        d_index = 0  # 0 = today/D-0, 1 = D-1, 2 = D-2
        while probe_days < 7 and d_index < 3:
            yyyymmdd = probe_date.strftime("%Y%m%d")
            url = (
                f"https://www.twse.com.tw/fund/BFI82U?response=json"
                f"&dayDate={yyyymmdd}&weekDate=&monthDate=&type=day"
            )
            try:
                payload = _twse_request_json(url)
                rows = payload.get("data") or []
                # v1.12.1c: CRITICAL FIX — v1.12.1b accidentally wrote to
                # st.session_state INSIDE this @st.cache_data-decorated
                # function, which is forbidden and broke the entire fetch.
                # Now we stash debug rows in the RESULT dict; the outer
                # wrapper fetch_taiwan_market_aggregates() will extract them
                # and write to session_state (allowed since wrapper isn't cached).
                try:
                    debug_rows = []
                    for r in rows:
                        if r and len(r) >= 4:
                            debug_rows.append({
                                "investor": str(r[0] or "").strip(),
                                "buy": str(r[1] if len(r) > 1 else ""),
                                "sell": str(r[2] if len(r) > 2 else ""),
                                "net": str(r[3] if len(r) > 3 else ""),
                            })
                    # Only store the FIRST successful day's rows (most recent).
                    if "_debug_rows" not in result:
                        result["_debug_rows"] = {
                            "date_probed": yyyymmdd,
                            "row_count": len(rows),
                            "rows": debug_rows,
                        }
                except Exception:
                    pass
                # v1.12.1d: REAL row parser based on actual TWSE BFI82U dump.
                # Actual TWSE row structure observed (2026-05-12):
                #   row[01]  '自營商(自行買賣)'           → dealer sub-row
                #   row[02]  '自營商(避險)'               → dealer sub-row
                #   row[03]  '投信'                       → trust single
                #   row[04]  '外資及陸資(不含外資自營商)' → foreign main
                #   row[05]  '外資自營商'                 → foreign sub-row
                #   row[06]  '合計'                       → grand total (skip)
                #
                # CRITICAL MATCHER ORDER: row[04] string contains '外資自營商'
                # as a substring (inside the parenthetical), so we must check
                # for the row[04] pattern '外資及陸資' BEFORE the plain '外資自營商'.
                #
                # NO standalone aggregate row for 自營商 or 外資 exists.
                # We MUST sum the sub-rows ourselves.
                dealer_self: float | None = None    # 自營商(自行買賣)
                dealer_hedge: float | None = None   # 自營商(避險)
                trust_value: float | None = None    # 投信
                foreign_main: float | None = None   # 外資及陸資(不含外資自營商)
                foreign_sub: float | None = None    # 外資自營商
                for row in rows:
                    investor = str(row[0] or "").strip() if row else ""
                    if not investor:
                        continue
                    try:
                        net_str = str(row[3] if len(row) > 3 else "0").replace(",", "").strip()
                        net_val = float(net_str) / 1_0000_0000  # 元 -> 億
                    except (ValueError, IndexError):
                        continue
                    # Normalize: strip both ASCII + full-width spaces
                    investor_norm = investor.replace(" ", "").replace("　", "")
                    # Skip the grand-total row explicitly
                    if investor_norm == "合計" or investor_norm == "總計":
                        continue
                    # === 自營商 sub-rows ===
                    # Note: check sub-rows BEFORE generic 自營商 match.
                    if "自營商" in investor_norm and ("自行買賣" in investor_norm or "自買" in investor_norm):
                        dealer_self = net_val
                        continue
                    if "自營商" in investor_norm and "避險" in investor_norm:
                        dealer_hedge = net_val
                        continue
                    # === 外資及陸資 main row ===
                    # CRITICAL: must check BEFORE plain '外資自營商' because
                    # row[04] ='外資及陸資(不含外資自營商)' contains '外資自營商'
                    # as a substring inside the parens.
                    if "外資及陸資" in investor_norm or (
                        "外資" in investor_norm and "陸資" in investor_norm
                    ):
                        foreign_main = net_val
                        continue
                    # === 外資自營商 (foreign dealer sub-row, standalone) ===
                    # Now safe to match: '外資及陸資' was handled above.
                    if investor_norm == "外資自營商" or (
                        "外資自營商" in investor_norm and "陸資" not in investor_norm
                    ):
                        foreign_sub = net_val
                        continue
                    # === 投信 ===
                    if "投信" in investor_norm:
                        trust_value = net_val
                        continue
                    # === Fallback aggregate 自營商 row (in case TWSE adds one) ===
                    # Only matches plain "自營商" or "自營商合計" (no sub-keywords),
                    # which we'd then prefer over our sum.
                    if investor_norm.startswith("自營商"):
                        # No sub-keyword matched above → this is some unexpected
                        # aggregate. Stash it as a sentinel.
                        # (Currently TWSE doesn't emit this, but we're defensive.)
                        if dealer_self is None and dealer_hedge is None:
                            dealer_self = net_val  # treat as the "everything" row
                        continue
                # === Aggregate sub-rows into final values ===
                # 自營商合計 = 自行買賣 + 避險
                if dealer_self is not None or dealer_hedge is not None:
                    dealer_value = (dealer_self or 0.0) + (dealer_hedge or 0.0)
                else:
                    dealer_value = None
                # 外資合計 = 外資及陸資(不含外資自營商) + 外資自營商
                if foreign_main is not None or foreign_sub is not None:
                    foreign_value = (foreign_main or 0.0) + (foreign_sub or 0.0)
                else:
                    foreign_value = None
                # If we got at least one value for this day, count it as a successful probe.
                if any(v is not None for v in (foreign_value, trust_value, dealer_value)):
                    if d_index == 0:
                        result["foreign_net"] = foreign_value
                        result["trust_net"] = trust_value
                        result["dealer_net"] = dealer_value
                    elif d_index == 1:
                        result["foreign_net_d1"] = foreign_value
                        result["trust_net_d1"] = trust_value
                        result["dealer_net_d1"] = dealer_value
                    elif d_index == 2:
                        result["foreign_net_d2"] = foreign_value
                        result["trust_net_d2"] = trust_value
                        result["dealer_net_d2"] = dealer_value
                    d_index += 1
            except Exception:
                pass  # this probe day failed, try previous day
            # Walk back one calendar day; skip weekends
            probe_date -= timedelta(days=1)
            while probe_date.weekday() >= 5:
                probe_date -= timedelta(days=1)
            probe_days += 1
    except Exception as exc:
        if result.get("error"):
            result["error"] += f"; foreign: {type(exc).__name__}"
        else:
            result["error"] = f"foreign: {type(exc).__name__}"

    return result


# v1.12.1: Persistent fallback stack for Taiwan market aggregates.
# TWSE FMTQIK + BFI82U occasionally return 403/SSL failures (especially
# from non-TW infrastructure like Streamlit Cloud). Rather than show
# "資料準備中" to the user, we cascade through 4 fallback layers:
#   L1: Streamlit memory cache (handled by @st.cache_data on _raw)
#   L2: session_state["_tw_market_aggregates_last_good"] — in-session
#   L3: disk JSON /tmp/dashboard_tw_market_cache.json — cross-cache
#   L4: hardcoded seed value — last resort
# Each fallback hit sets result["stale"] = True so the UI can show the
# data date (which will be D-1, D-2, etc).

_TW_MARKET_CACHE_FILE = "/tmp/dashboard_tw_market_cache.json"

# L4: seed value — ALL FIELDS NONE (v1.12.1a per user choice "C2").
# Previously v1.12.1 had fake numbers (3500.0 turnover etc.) which would
# mislead users into thinking those were real values. We now return None
# for all fields and let the UI render "--" + a "資料連線異常" disconnect
# chip so the user can clearly see the data layer failed.
_TW_MARKET_SEED_VALUE: dict = {
    "turnover_value": None,
    "turnover_d1": None,
    "turnover_d2": None,
    "turnover_change_pct": None,
    "foreign_net": None,
    "foreign_net_d1": None,
    "foreign_net_d2": None,
    "trust_net": None,
    "trust_net_d1": None,
    "trust_net_d2": None,
    "dealer_net": None,
    "dealer_net_d1": None,
    "dealer_net_d2": None,
    "data_date": None,
    "data_date_d1": None,
    "data_date_d2": None,
    "is_today": False,
    "error": "all_fallbacks_failed",
    "stale": True,
    "stale_source": "seed_value_L4",
}


def _is_aggregates_dict_useful(data: dict | None) -> bool:
    """Check if an aggregates dict has at least the turnover_value populated.
    Returns False if dict is None, empty, or all critical values are None."""
    if not data or not isinstance(data, dict):
        return False
    # At minimum we want turnover_value OR foreign_net to be a real number
    if data.get("turnover_value") is not None:
        return True
    if data.get("foreign_net") is not None:
        return True
    return False


def _write_tw_market_cache_to_disk(data: dict) -> None:
    """L3 write: persist last-good aggregates to /tmp JSON.
    Silently swallows write errors (Streamlit Cloud disk may be ephemeral).
    """
    try:
        import json
        # Strip 'stale' flag before writing (we want fresh-marked when read back
        # to act as 'previously fresh data, now stale')
        snapshot = {k: v for k, v in data.items() if k != "stale" and k != "stale_source"}
        with open(_TW_MARKET_CACHE_FILE, "w", encoding="utf-8") as f:
            json.dump(snapshot, f, ensure_ascii=False, indent=2)
    except Exception:
        pass  # best-effort; never break the flow


def _read_tw_market_cache_from_disk() -> dict | None:
    """L3 read: load last-good aggregates from /tmp JSON.
    Returns None on any error (file missing, corrupt, permission denied).
    """
    try:
        import json
        import os
        if not os.path.exists(_TW_MARKET_CACHE_FILE):
            return None
        with open(_TW_MARKET_CACHE_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
        if not _is_aggregates_dict_useful(data):
            return None
        return data
    except Exception:
        return None


def fetch_taiwan_market_aggregates(_cache_key: str) -> dict:
    """v1.12.1: Public entry — fetch TWSE market-wide aggregates with
    4-layer persistent fallback. Never returns all-None.

    Returns a dict like (same shape as _fetch_taiwan_market_aggregates_raw):
        {
            "turnover_value":     float | None,   # latest day, in 億 NTD
            "turnover_d1":        float | None,
            "turnover_d2":        float | None,
            "turnover_change_pct": float | None,
            "foreign_net":        float | None,
            "foreign_net_d1":     float | None,
            "foreign_net_d2":     float | None,
            "trust_net":          float | None,
            "trust_net_d1":       float | None,
            "trust_net_d2":       float | None,
            "dealer_net":         float | None,
            "dealer_net_d1":      float | None,
            "dealer_net_d2":      float | None,
            "data_date":          "YYYY-MM-DD" | None,
            "data_date_d1":       "YYYY-MM-DD" | None,
            "data_date_d2":       "YYYY-MM-DD" | None,
            "is_today":           bool,
            "error":              str | None,
            "stale":              bool,  # NEW v1.12.1
            "stale_source":       str | None,  # NEW v1.12.1: "L2"/"L3"/"L4"
        }
    """
    SESSION_KEY = "_tw_market_aggregates_last_good"

    # L1: try the real fetch (memory-cached via @st.cache_data on _raw).
    try:
        result = _fetch_taiwan_market_aggregates_raw(_cache_key)
    except Exception as exc:
        result = {"error": f"raw_fetch_exception: {type(exc).__name__}"}

    # v1.12.1c: Extract diagnostic _debug_rows that _raw stashed in the
    # result dict (since _raw can't write session_state directly while cached).
    # This must run OUTSIDE the cache function — wrapper isn't cached.
    if isinstance(result, dict) and "_debug_rows" in result:
        try:
            st.session_state["_bfi82u_last_payload_debug"] = result["_debug_rows"]
        except Exception:
            pass
        # Strip from result so downstream logic doesn't see it
        result = {k: v for k, v in result.items() if k != "_debug_rows"}

    # Path A: SUCCESS — store to L2 + L3, return fresh
    if _is_aggregates_dict_useful(result):
        result["stale"] = False
        result["stale_source"] = None
        # Save to L2 (session) + L3 (disk) for next-time fallback.
        try:
            st.session_state[SESSION_KEY] = dict(result)
        except Exception:
            pass
        _write_tw_market_cache_to_disk(result)
        return result

    # Path B: FAIL — cascade through L2 → L3 → L4
    # L2: in-session last-good
    try:
        cached_l2 = st.session_state.get(SESSION_KEY)
    except Exception:
        cached_l2 = None
    if _is_aggregates_dict_useful(cached_l2):
        out = dict(cached_l2)
        out["stale"] = True
        out["stale_source"] = "L2_session"
        if not out.get("error"):
            out["error"] = result.get("error") if result else None
        return out

    # L3: cross-eviction disk cache
    cached_l3 = _read_tw_market_cache_from_disk()
    if _is_aggregates_dict_useful(cached_l3):
        out = dict(cached_l3)
        out["stale"] = True
        out["stale_source"] = "L3_disk"
        if not out.get("error"):
            out["error"] = result.get("error") if result else None
        # Re-populate L2 so future calls in this session don't hit disk again
        try:
            st.session_state[SESSION_KEY] = dict(out)
        except Exception:
            pass
        return out

    # L4: last-resort seed value
    out = dict(_TW_MARKET_SEED_VALUE)
    out["error"] = (result.get("error") if result else None) or "all_fallbacks_failed"
    return out


# v1.5.4: TAIFEX (Taiwan Futures Exchange) fetcher for 台指期 daily report.
# yfinance ticker TX=F is unreliable; the official TAIFEX OpenAPI publishes
# daily futures market reports at:
#   https://openapi.taifex.com.tw/v1/DailyMarketReportFut
# Each row includes Trading Date, Contract, ExpirationMonth, Open, High,
# Low, LastPrice, ChangePrice, ChangePercent, Volume.
# We pull the "TX" contract's "near-month" row (smallest contract month) for
# D-0, D-1, D-2 by walking back trading days when a probe returns no data.
#
# Graceful: any fetch failure returns None values; the indicator card will
# render "資料準備中" without breaking page render.
@st.cache_data(ttl=900, show_spinner=False)
def fetch_taifex_futures_quote(_cache_key: str) -> dict:
    """Fetch TAIFEX 台指期 (TX) near-month quote for the latest 3 trading days.

    Returns a dict like:
        {
            "last_price":   float | None,   # latest close
            "last_price_d1": float | None,   # prior trading day close
            "last_price_d2": float | None,   # two days back close
            "change_pct":   float | None,   # latest day's % change
            "change_pct_d1": float | None,
            "data_date":    "YYYY-MM-DD" | None,
            "data_date_d1": "YYYY-MM-DD" | None,
            "data_date_d2": "YYYY-MM-DD" | None,
            "is_today":     bool,
            "error":        str | None,
        }
    """
    result: dict = {
        "last_price": None, "last_price_d1": None, "last_price_d2": None,
        "change_pct": None, "change_pct_d1": None,
        "data_date": None, "data_date_d1": None, "data_date_d2": None,
        "is_today": False,
        "error": None,
    }
    today_tw = datetime.now(TW_TZ).date()

    def _pick_near_month_tx_row(rows: list) -> dict | None:
        """From the day's daily report, pick the near-month TX contract row.

        TAIFEX returns rows with 'Contract' = "TX" (台指期), "MTX" (小台),
        "TE" (電子), "TF" (金融) etc., plus various contract months. We want
        the TX with the earliest expiration month (= near-month/active).
        """
        tx_rows = [r for r in rows if r and str(r.get("Contract", "")).strip().upper() == "TX"]
        if not tx_rows:
            return None
        # Sort by ContractMonth (e.g. "202505" "202506") ascending.
        try:
            tx_rows.sort(key=lambda r: str(r.get("ContractMonth", "999999")))
        except Exception:
            pass
        # Filter out 一般交易時段 vs 盤後交易時段 if 'TradingSession' present;
        # prefer the 一般 (regular) session if it exists.
        regular = [r for r in tx_rows if "一般" in str(r.get("TradingSession", ""))]
        return regular[0] if regular else tx_rows[0]

    try:
        probe_days = 0
        probe_date = today_tw
        d_index = 0
        while probe_days < 7 and d_index < 3:
            yyyymmdd = probe_date.strftime("%Y/%m/%d")
            # TAIFEX OpenAPI accepts a date param; if no date the endpoint
            # returns the latest available day. We always pass a date so the
            # walk-back logic works.
            url = (
                f"https://openapi.taifex.com.tw/v1/DailyMarketReportFut"
                f"?date={probe_date.strftime('%Y%m%d')}"
            )
            try:
                payload = _twse_request_json(url)
                # TAIFEX returns a list directly, not {"data": [...]}.
                # Our generic _twse_request_json wraps non-list payloads --
                # account for both shapes.
                if isinstance(payload, list):
                    rows = payload
                elif isinstance(payload, dict):
                    rows = payload.get("data") or payload.get("Data") or []
                else:
                    rows = []
                row = _pick_near_month_tx_row(rows) if rows else None
                if row:
                    last_price_str = str(row.get("LastPrice", "")).replace(",", "").strip()
                    change_pct_str = str(row.get("ChangePercent", "")).replace(",", "").strip()
                    iso_date = probe_date.strftime("%Y-%m-%d")
                    try:
                        last_price = float(last_price_str)
                    except ValueError:
                        last_price = None
                    try:
                        change_pct = float(change_pct_str)
                    except ValueError:
                        change_pct = None
                    if last_price is not None:
                        if d_index == 0:
                            result["last_price"] = last_price
                            result["change_pct"] = change_pct
                            result["data_date"] = iso_date
                            result["is_today"] = iso_date == today_tw.strftime("%Y-%m-%d")
                        elif d_index == 1:
                            result["last_price_d1"] = last_price
                            result["change_pct_d1"] = change_pct
                            result["data_date_d1"] = iso_date
                        elif d_index == 2:
                            result["last_price_d2"] = last_price
                            result["data_date_d2"] = iso_date
                        d_index += 1
            except Exception:
                pass  # try previous day
            # walk back one biz day
            probe_date -= timedelta(days=1)
            while probe_date.weekday() >= 5:
                probe_date -= timedelta(days=1)
            probe_days += 1
    except Exception as exc:
        result["error"] = f"taifex: {type(exc).__name__}"

    return result


@st.cache_data(ttl=GLOBAL_REFERENCE_QUOTE_TTL_SECONDS)
def fetch_live_reference_quotes(tickers: tuple[str, ...]) -> dict[str, dict]:
    snapshots: dict[str, dict] = {}
    for ticker in tickers:
        snapshot = {"price": pd.NA, "as_of": None}
        try:
            tk = yf.Ticker(ticker)
        except Exception:
            snapshots[ticker] = snapshot
            continue

        try:
            fast_info = getattr(tk, "fast_info", {}) or {}
            if hasattr(fast_info, "get"):
                snapshot["price"] = coerce_float(
                    fast_info.get("lastPrice") or fast_info.get("regularMarketPrice") or fast_info.get("previousClose")
                )
                snapshot["as_of"] = (
                    fast_info.get("lastPriceTime")
                    or fast_info.get("regularMarketTime")
                    or fast_info.get("lastTradeDate")
                )
        except Exception:
            pass

        try:
            history = tk.history(period="2d", interval="1m", auto_adjust=False, prepost=False)
            if history is not None and not history.empty:
                close_field = "Close" if "Close" in history.columns else ("Adj Close" if "Adj Close" in history.columns else None)
                if close_field:
                    recent_close = pd.to_numeric(history[close_field], errors="coerce").dropna()
                    if not recent_close.empty:
                        snapshot["price"] = coerce_float(recent_close.iloc[-1]) if pd.isna(snapshot["price"]) else snapshot["price"]
                snapshot["as_of"] = history.index[-1]
        except Exception:
            pass

        snapshots[ticker] = snapshot
    return snapshots


def global_market_trend_state(window_return: float, recent_return: float) -> str:
    if pd.isna(window_return) or pd.isna(recent_return):
        return t("global_market_pullback")
    if window_return >= 4 and recent_return >= 0:
        return t("global_market_uptrend")
    if window_return <= -4 and recent_return <= 0:
        return t("global_market_downtrend")
    return t("global_market_pullback")


def _trend_emoji_for_state(state: str) -> str:
    """v1.5.4: emoji prefix that matches global_market_trend_state output."""
    if state == t("global_market_uptrend"):
        return "📈"
    if state == t("global_market_downtrend"):
        return "📉"
    return "↔️"


def build_global_market_indicator(
    reference_data: pd.DataFrame | None,
    lens_meta: dict | None = None,
    live_quotes: dict[str, dict] | None = None,
    market_scope: str | None = None,
) -> dict:
    """v1.5.3: scope-aware. Builds a US-cards-only or TW-cards-only indicator
    set depending on market_scope.

    v1.5.4: All cards now carry D-1 (prior trading day) and D-2 (two trading
    days ago) values plus a trend_emoji string. Cards built from yfinance
    history use the closing prices in the series; TWSE/TAIFEX-derived cards
    pull D-1/D-2 from the dedicated fetcher's result dict.
    """
    period = (lens_meta or {}).get("period", DEFAULT_PERIOD)
    interval = (lens_meta or {}).get("interval", DEFAULT_INTERVAL)
    market_scope = _normalize_market_scope(market_scope or "Taiwan only")
    indices_for_scope = get_indices_for_scope(market_scope)

    cards: list[dict] = []
    up = down = 0
    live_quotes = live_quotes or {}
    tw_aggregates: dict | None = None
    taifex_quote: dict | None = None

    def _hist_close_at(series: pd.Series | None, offset_from_end: int) -> float:
        """Return close N positions back from the most recent (0 = latest)."""
        if series is None or series.empty:
            return float("nan")
        try:
            idx = -1 - offset_from_end
            if abs(idx) > len(series):
                return float("nan")
            return float(series.iloc[idx])
        except Exception:
            return float("nan")

    for item in indices_for_scope:
        ticker = item["ticker"]

        # v1.5.5: Removed TX=F special-case branch -- the 台指期 card now uses
        # IX0126.TW (TIP TAIFEX TAIEX Futures Index) which goes through the
        # standard yfinance path at the bottom of this loop. The
        # fetch_taifex_futures_quote() helper is preserved in code for future
        # use but is no longer called here.

        # ============== Sentinel: TWSE turnover ==============
        if ticker == "__TWSE_TURNOVER__":
            if tw_aggregates is None:
                tw_aggregates = fetch_taiwan_market_aggregates(
                    datetime.now(TW_TZ).strftime("%Y-%m-%d")
                )
            value = tw_aggregates.get("turnover_value")
            change_pct = tw_aggregates.get("turnover_change_pct")
            data_date = tw_aggregates.get("data_date")
            # v1.12.1a: stale + disconnect flags from the persistent fallback wrapper.
            is_stale = bool(tw_aggregates.get("stale", False))
            stale_source = tw_aggregates.get("stale_source")
            # is_disconnected: all fallbacks failed (L4 seed_value, all-None).
            is_disconnected = (value is None and stale_source == "seed_value_L4")
            if value is None:
                # Card structure still rendered, but with "--" placeholder values.
                # is_pending=False so the card doesn't render the legacy "資料準備中"
                # treatment; instead is_disconnected flag triggers a "資料連線異常"
                # red chip overlay (added in card-render CSS).
                cards.append({
                    "ticker": ticker,
                    "label": t(item["label_key"]),
                    "last_price": float("nan"),
                    "window_return": float("nan"),
                    "recent_return": float("nan"),
                    "last_price_d1": float("nan"),
                    "last_price_d2": float("nan"),
                    "state": t("global_market_data_disconnected") if is_disconnected else t("global_market_pullback"),
                    "trend_emoji": "⚠️" if is_disconnected else "↔️",
                    "is_pending": False,
                    "is_disconnected": is_disconnected,
                    "is_stale": is_stale,
                    "stale_source": stale_source,
                    "data_date": data_date,
                })
            else:
                # State for turnover: increasing volume = "up" (more activity).
                state = (
                    t("global_market_uptrend") if (change_pct or 0) >= 5
                    else t("global_market_downtrend") if (change_pct or 0) <= -5
                    else t("global_market_pullback")
                )
                cards.append({
                    "ticker": ticker,
                    "label": t(item["label_key"]),
                    "last_price": value,
                    "last_price_unit": "億",
                    "window_return": change_pct if change_pct is not None else float("nan"),
                    "recent_return": float("nan"),  # not applicable
                    "last_price_d1": tw_aggregates.get("turnover_d1") or float("nan"),
                    "last_price_d2": tw_aggregates.get("turnover_d2") or float("nan"),
                    "data_date_d1": tw_aggregates.get("data_date_d1"),
                    "data_date_d2": tw_aggregates.get("data_date_d2"),
                    "state": state,
                    "trend_emoji": _trend_emoji_for_state(state),
                    "is_pending": False,
                    "is_stale": is_stale,
                    "stale_source": stale_source,
                    "data_date": data_date,
                })
            continue

        # ============== Sentinel: TWSE institutional net flows ==============
        # v1.6.0: foreign / trust / dealer all share the same card layout.
        # Map each sentinel ticker to its (value_key, d1_key, d2_key) trio.
        _NET_FLOW_KEYS = {
            "__TWSE_FOREIGN_NET__": ("foreign_net", "foreign_net_d1", "foreign_net_d2"),
            "__TWSE_TRUST_NET__":   ("trust_net",   "trust_net_d1",   "trust_net_d2"),
            "__TWSE_DEALER_NET__":  ("dealer_net",  "dealer_net_d1",  "dealer_net_d2"),
        }
        if ticker in _NET_FLOW_KEYS:
            if tw_aggregates is None:
                tw_aggregates = fetch_taiwan_market_aggregates(
                    datetime.now(TW_TZ).strftime("%Y-%m-%d")
                )
            v_key, d1_key, d2_key = _NET_FLOW_KEYS[ticker]
            value = tw_aggregates.get(v_key)
            data_date = tw_aggregates.get("data_date")
            is_today = bool(tw_aggregates.get("is_today"))
            # v1.12.1a: stale + disconnect flags from persistent fallback wrapper
            is_stale_from_fallback = bool(tw_aggregates.get("stale", False))
            stale_source = tw_aggregates.get("stale_source")
            is_disconnected = (value is None and stale_source == "seed_value_L4")
            # Final is_stale: combine "not today" (existing logic) + fallback layer
            is_stale = (not is_today) or is_stale_from_fallback
            if value is None:
                cards.append({
                    "ticker": ticker,
                    "label": t(item["label_key"]),
                    "last_price": float("nan"),
                    "window_return": float("nan"),
                    "recent_return": float("nan"),
                    "last_price_d1": float("nan"),
                    "last_price_d2": float("nan"),
                    "state": t("global_market_data_disconnected") if is_disconnected else t("global_market_pullback"),
                    "trend_emoji": "⚠️" if is_disconnected else "↔️",
                    "is_pending": False,
                    "is_disconnected": is_disconnected,
                    "data_date": data_date,
                    "is_stale": is_stale,
                    "stale_source": stale_source,
                })
            else:
                if value >= 0:
                    state = t("global_market_uptrend")
                    trend_emoji = "💰"
                    up += 1
                else:
                    state = t("global_market_downtrend")
                    trend_emoji = "💸"
                    down += 1
                cards.append({
                    "ticker": ticker,
                    "label": t(item["label_key"]),
                    "last_price": value,
                    "last_price_unit": "億",
                    "window_return": float("nan"),
                    "recent_return": float("nan"),
                    "last_price_d1": tw_aggregates.get(d1_key) if tw_aggregates.get(d1_key) is not None else float("nan"),
                    "last_price_d2": tw_aggregates.get(d2_key) if tw_aggregates.get(d2_key) is not None else float("nan"),
                    "data_date_d1": tw_aggregates.get("data_date_d1"),
                    "data_date_d2": tw_aggregates.get("data_date_d2"),
                    "state": state,
                    "trend_emoji": trend_emoji,
                    "is_pending": False,
                    "data_date": data_date,
                    "is_stale": is_stale,
                    "stale_source": stale_source,
                })
            continue

        # ============== Standard yfinance path (^TWII / ^IXIC / ^GSPC / ^DJI) ==============
        series, _ = get_price_series(reference_data, ticker)
        quote_snapshot = live_quotes.get(ticker, {}) if isinstance(live_quotes, dict) else {}
        live_price = coerce_float(quote_snapshot.get("price"))
        live_series = merge_live_price_into_series(series, live_price, quote_snapshot.get("as_of"))
        base_series = live_series if live_series is not None and not live_series.empty else series

        window_return = compute_window_return_pct(base_series)
        recent_return = compute_recent_return_pct(base_series, 20)

        if not pd.isna(live_price):
            last_price = live_price
        elif series is not None and not series.empty:
            last_price = series.iloc[-1]
        else:
            last_price = float("nan")

        # v1.5.4: D-1 and D-2 closes pulled from the daily series.
        # When live_price merged a today-bar onto base_series, D-1 = closes[-2]
        # which is yesterday; D-2 = closes[-3]. When live_price is missing,
        # series[-1] IS today's bar, so we shift D-1=series[-2], D-2=series[-3].
        # The _hist_close_at helper handles the offset uniformly.
        if not pd.isna(live_price) and live_series is not None:
            # live merged: latest bar is today (from live), so D-1 is offset 1, D-2 is 2
            last_price_d1 = _hist_close_at(live_series, 1)
            last_price_d2 = _hist_close_at(live_series, 2)
        else:
            # no live bar; series[-1] is the latest available trading day
            last_price_d1 = _hist_close_at(series, 1)
            last_price_d2 = _hist_close_at(series, 2)

        is_pending = pd.isna(last_price) and (series is None or series.empty)

        state = global_market_trend_state(window_return, recent_return)
        if state == t("global_market_uptrend"):
            up += 1
        elif state == t("global_market_downtrend"):
            down += 1
        cards.append({
            "ticker": ticker,
            "label": t(item["label_key"]),
            "last_price": last_price,
            "window_return": window_return,
            "recent_return": recent_return,
            "last_price_d1": last_price_d1,
            "last_price_d2": last_price_d2,
            "state": state,
            "trend_emoji": _trend_emoji_for_state(state),
            "is_pending": is_pending,
        })

    total = len(cards)
    threshold = 2 if total <= 3 else 3
    if up >= threshold:
        breadth_copy = t("global_market_breadth_risk_on", up=up, total=total)
    elif down >= threshold:
        breadth_copy = t("global_market_breadth_risk_off", down=down, total=total)
    else:
        breadth_copy = t("global_market_breadth_mixed")

    return {
        "period": period,
        "interval": interval,
        "cards": cards,
        "up_count": up,
        "down_count": down,
        "breadth_copy": breadth_copy,
    }


def render_global_market_indicator(indicator: dict):
    cards = indicator.get("cards", [])
    if not cards:
        return

    def _format_card_value(card: dict) -> str:
        # v1.12.1a: is_disconnected (all-fallbacks-failed L4 seed) → show "--"
        # with a "資料連線異常" chip via _format_card_footer. Keep is_pending
        # path for legacy callers (e.g. TAIFEX cards which may still set it).
        if card.get("is_disconnected"):
            return '<span class="global-indicator-disconnected">--</span>'
        if card.get("is_pending"):
            return f'<span class="global-indicator-pending">{escape(t("global_market_tw_data_pending"))}</span>'
        # v1.6.0: IX0126.TW special handling removed -- 台指期 cards retired,
        # replaced by 三大法人 net-flow cards. Same render path as other cards.
        unit = card.get("last_price_unit", "")
        last_price = card.get("last_price")
        if pd.isna(last_price):
            return f'<span class="global-indicator-pending">{escape(t("global_market_tw_data_pending"))}</span>'
        if unit:
            try:
                v = float(last_price)
                sign = ""
                # v1.6.0: all three institutional net-flow cards display signed
                if card.get("ticker") in ("__TWSE_FOREIGN_NET__", "__TWSE_TRUST_NET__", "__TWSE_DEALER_NET__"):
                    sign = "+" if v > 0 else ""
                return f"{sign}{v:,.0f} {escape(unit)}"
            except Exception:
                return format_price(last_price)
        return format_price(last_price)

    def _format_historical_value(value, unit: str, signed: bool = False) -> str:
        """Format D-1/D-2 close/value, with same unit handling as the main."""
        if pd.isna(value):
            return "—"
        if unit:
            try:
                v = float(value)
                sign = ("+" if v > 0 else "") if signed else ""
                return f"{sign}{v:,.0f} {escape(unit)}"
            except Exception:
                return format_price(value)
        return format_price(value)

    def _format_card_footer(card: dict) -> str:
        # v1.12.1a: disconnect chip ALWAYS visible when all fallbacks failed.
        # Trumps the stale-date label since there's no date to show.
        if card.get("is_disconnected"):
            return (
                f'<div class="global-indicator-disconnected-chip">'
                f'⚠️ {escape(t("global_market_data_disconnected_hint"))}'
                f'</div>'
            )
        data_date = card.get("data_date")
        # v1.12.1a: stale chip — data exists but is from L2/L3 fallback layer
        # (not today). Different from is_disconnected because we DO have data.
        stale_source = card.get("stale_source")
        if data_date and card.get("is_stale") and stale_source in ("L2_session", "L3_disk"):
            return (
                f'<div class="global-indicator-stale-chip">'
                f'<span class="global-indicator-stale-icon">📅</span> '
                f'<span class="global-indicator-stale-text">'
                f'{escape(t("global_market_tw_as_of", date=data_date))} '
                f'<span class="global-indicator-stale-tag">'
                f'({escape(t("global_market_tw_data_stale"))})</span>'
                f'</span>'
                f'</div>'
            )
        if data_date and card.get("is_stale"):
            return (
                f'<div class="global-indicator-stale-date">'
                f'{escape(t("global_market_tw_as_of", date=data_date))}'
                f'</div>'
            )
        if data_date and card.get("ticker", "").startswith("__"):
            return f'<div class="global-indicator-card-date">{escape(data_date)}</div>'
        return ""

    def _format_card_mini(card: dict, key: str, label_key: str) -> str:
        value = card.get(key)
        if pd.isna(value):
            return ""
        return (
            f'<div>'
            f'  <div class="global-indicator-mini-label">{t(label_key)}</div>'
            f'  <div class="global-indicator-mini-value">{format_percent(value)}</div>'
            f'</div>'
        )

    def _format_history_block(card: dict) -> str:
        """v1.5.4: D-1 + D-2 closes/values shown side-by-side below the
        window-return / recent-return mini stats.

        v1.5.6: For IX0126.TW (台指期 TR 指數) where the headline card value
        is "today's % change", display D-1/D-2 as their own % daily change
        instead of raw values. Computed from the close-to-close ratio of
        the last_price / last_price_d1 / last_price_d2 trio.
        """
        d1 = card.get("last_price_d1")
        d2 = card.get("last_price_d2")
        if pd.isna(d1) and pd.isna(d2):
            return ""
        unit = card.get("last_price_unit", "")
        signed = (card.get("ticker") in ("__TWSE_FOREIGN_NET__", "__TWSE_TRUST_NET__", "__TWSE_DEALER_NET__"))
        d1_label = t("global_market_prev_day_close")
        d2_label = t("global_market_prev2_day_close")
        d1_date = card.get("data_date_d1")
        d2_date = card.get("data_date_d2")
        d1_date_html = (
            f'<div class="global-indicator-history-date">{escape(d1_date)}</div>'
            if d1_date else ""
        )
        d2_date_html = (
            f'<div class="global-indicator-history-date">{escape(d2_date)}</div>'
            if d2_date else ""
        )
        # v1.6.0: IX0126.TW special handling removed (card retired in v1.6.0).
        d1_value = _format_historical_value(d1, unit, signed)
        d2_value = _format_historical_value(d2, unit, signed)
        return (
            f'<div class="global-indicator-history">'
            f'  <div>'
            f'    <div class="global-indicator-history-label">{escape(d1_label)}</div>'
            f'    <div class="global-indicator-history-value">{d1_value}</div>'
            f'    {d1_date_html}'
            f'  </div>'
            f'  <div>'
            f'    <div class="global-indicator-history-label">{escape(d2_label)}</div>'
            f'    <div class="global-indicator-history-value">{d2_value}</div>'
            f'    {d2_date_html}'
            f'  </div>'
            f'</div>'
        )

    card_html_parts = []
    for card in cards:
        mini_window = _format_card_mini(card, "window_return", "global_market_window_return")
        mini_recent = _format_card_mini(card, "recent_return", "global_market_recent")
        grid_html = ""
        if mini_window or mini_recent:
            grid_html = (
                f'<div class="global-indicator-grid">'
                f'  {mini_window}'
                f'  {mini_recent}'
                f'</div>'
            )
        # v1.5.4: state chip now leads with trend emoji.
        if not card.get("is_pending"):
            emoji = card.get("trend_emoji", "")
            emoji_prefix = f"{emoji} " if emoji else ""
            chip_html = (
                f'<div class="global-indicator-state-chip">'
                f'{escape(emoji_prefix)}{escape(card["state"])}'
                f'</div>'
            )
        else:
            chip_html = ""
        history_html = _format_history_block(card)
        card_html_parts.append(
            f'<div class="global-indicator-card">'
            f'  <div class="global-indicator-card-top">'
            f'    <div class="global-indicator-label">{escape(card["label"])}</div>'
            f'    {chip_html}'
            f'  </div>'
            f'  <div class="global-indicator-value">{_format_card_value(card)}</div>'
            f'  {grid_html}'
            f'  {history_html}'
            f'  {_format_card_footer(card)}'
            f'</div>'
        )
    card_html = "".join(card_html_parts)

    indices_summary = " · ".join(card["label"] for card in cards)

    shell_html = textwrap.dedent(
        f"""
        <div class="global-indicator-shell global-indicator-shell-compact">
            <div class="global-indicator-header">
                <div>
                    <div class="section-header" style="margin:0; color:#f5ead8;">{t("global_market_indicator")}</div>
                    <div class="global-indicator-title">{t("global_market_breadth")}</div>
                    <div class="global-indicator-copy">{escape(indicator.get("breadth_copy", ""))}</div>
                </div>
                <div class="global-indicator-side">
                    <div class="global-indicator-pill-row">
                        <span class="global-indicator-pill">{t("sticky_global_note")}</span>
                        <span class="global-indicator-pill">{t("global_market_window")}: {escape(indicator["period"])} / {escape(indicator["interval"])}</span>
                    </div>
                    <div class="global-indicator-pill-row global-indicator-pill-row-tight">
                        <span class="global-indicator-pill">{t("global_market_indicator")}: {escape(indices_summary)}</span>
                    </div>
                </div>
            </div>
            <div class="global-indicator-card-grid">
                {card_html}
            </div>
        </div>
        """
    ).strip()

    render_html_block(shell_html)

    # v1.12.3 (2026-05-12): BFI82U diagnostic toggle REMOVED per user request.
    # The TWSE BFI82U row parser was verified in v1.12.1d (foreign / trust /
    # dealer aggregates match TWSE's own daily figures), so the runtime
    # debug probe is no longer needed in production. If a future TWSE
    # schema change makes the parser break again, restore from git
    # history (v1.12.1b ... v1.12.2f kept the toggle for that).


# ============================================================================
# v1.9.5  Tomorrow Momentum Pulse — top-of-page next-day energy estimator
# ============================================================================
# Compact 5-row table that lives RIGHT BELOW the Hero Bar on the main
# Dashboard. Reads the previous close + recent history to estimate whether
# the next session is likely to:
#   強 (動力持續)        score >= 70
#   中 (震盪盤整)        score 40 - 69
#   弱 (資金進出偏弱)    score < 40
#
# Design choices (per user 2026-05-09):
#   * Taiwan: 60% TSMC + 40% market — TSMC is ~35-40% of TAIEX, so its
#     leadership disproportionately drives the index.
#   * U.S.: 75% Mag7 + 25% VIX — Mag7 is the breadth proxy for tech-led
#     rallies, VIX is the inverse fear gauge.
#
# All scoring is bounded [0, 100]. Each contributing signal contributes a
# pre-budgeted slice (so a single freak number can't dominate). Failed
# fetches degrade gracefully — the row shows "—" + 0 contribution rather
# than crashing the whole table.

# Mag7 universe used for the U.S. score. Equal-weighted within the cohort.
TOMORROW_MOMENTUM_MAG7_TICKERS = [
    "AAPL", "MSFT", "GOOGL", "META", "AMZN", "NVDA", "TSLA",
]

# Pre-budgeted per-signal point caps. Sum of each scope's caps = 100.
TOMORROW_MOMENTUM_TAIWAN_BUDGET = {
    # v1.13.0 (Phase 1): Rebalanced budget — TSMC daily noise reduced
    # from 25→15, momentum lookback extended 5d→10d, RSI overbought
    # correction added. Volume now uses price-volume crossover logic
    # (see _momentum_volume_crossover_score) instead of broken raw ratio
    # buckets that always gave 0 for ratio<0.9.
    #
    # TSMC slice (60 pts total)
    "tsmc_daily":   15,   # was 25 — short-term return is noisy
    "tsmc_10d":     25,   # was tsmc_5d 20 — longer momentum lookback
    "tsmc_volume":  15,   # crossover logic now
    "tsmc_rsi":      5,   # NEW — overbought / oversold correction
    # Market slice (40 pts total)
    "taiex_daily":  10,
    "taiex_10d":    10,   # was taiex_5d 8 — bumped + longer lookback
    "twse_volume":  10,   # was 12 — crossover logic now
    "instl_flow":   10,
}
TOMORROW_MOMENTUM_US_BUDGET = {
    # Mag7 slice (75 pts total)
    "mag7_daily":   25,
    "mag7_5d":      20,
    "mag7_breadth": 15,
    "mag7_volume":  15,
    # VIX slice (25 pts total)
    "vix_level":    25,
    # vix_direction is a penalty (subtract up to 5 from vix_level), not a
    # separate budget line — it's surfaced as its own row but its score
    # contribution is folded into vix_level.
}


def _momentum_extract_close_volume(daily_data, ticker: str) -> tuple[pd.Series, pd.Series] | tuple[None, None]:
    """Pull (close_series, volume_series) for one ticker out of the bulk
    yfinance frame. Returns (None, None) when the ticker isn't present."""
    if daily_data is None:
        return None, None
    try:
        if isinstance(daily_data.columns, pd.MultiIndex):
            # yfinance group_by="column" gives ("Field", "Ticker") MultiIndex
            try:
                close = daily_data[("Close", ticker)]
            except KeyError:
                # Fallback: some yfinance versions swap the order
                try:
                    close = daily_data["Close"][ticker]
                except KeyError:
                    return None, None
            try:
                volume = daily_data[("Volume", ticker)]
            except KeyError:
                try:
                    volume = daily_data["Volume"][ticker]
                except KeyError:
                    volume = None
        else:
            close = daily_data.get("Close")
            volume = daily_data.get("Volume")
        if close is None:
            return None, None
        close = close.dropna()
        if close.empty:
            return None, None
        if volume is not None:
            volume = volume.dropna()
        return close, volume
    except Exception:
        return None, None


def _momentum_pct(curr: float, prev: float) -> float | None:
    """Safe pct-change. Returns None when inputs are unusable."""
    try:
        c = float(curr)
        p = float(prev)
    except (TypeError, ValueError):
        return None
    if not (math.isfinite(c) and math.isfinite(p)) or p == 0:
        return None
    return (c - p) / p * 100.0


def _momentum_linear_score(value: float | None, lo: float, hi: float, max_pts: float) -> float:
    """Map a value linearly from [lo, hi] to [0, max_pts]. Clamped at edges.
    Used for return-style signals where 0% earns the midpoint."""
    if value is None or not math.isfinite(value):
        return 0.0
    if hi == lo:
        return max_pts / 2
    pct = (float(value) - lo) / (hi - lo)
    pct = max(0.0, min(1.0, pct))
    return round(pct * max_pts, 2)


def _momentum_volume_score(latest_vol: float | None, avg_vol: float | None, max_pts: float) -> float:
    """Volume scoring brackets. Latest volume vs the trailing 20-day mean.

    DEPRECATED in v1.13.0 (kept for U.S. side compat). Taiwan side now uses
    _momentum_volume_crossover_score which combines volume + direction
    (量價交叉) — the correct signal-processing approach since:
      量爆 + 漲 = 資金追入(strong bullish)
      量爆 + 跌 = 出貨警訊(strong bearish)
      量縮 + 漲 = 健康籌碼鎖定(mild bullish)
      量縮 + 跌 = 無人接(mild bearish, NOT 0 like before)
    """
    if latest_vol is None or avg_vol is None or avg_vol <= 0:
        return 0.0
    ratio = float(latest_vol) / float(avg_vol)
    if ratio >= 1.5:
        return max_pts
    if ratio >= 1.2:
        return round(max_pts * 0.67, 2)
    if ratio >= 0.9:
        return round(max_pts * 0.33, 2)
    return 0.0


def _momentum_volume_crossover_score(
    latest_vol: float | None,
    avg_vol: float | None,
    daily_return: float | None,
    max_pts: float,
) -> tuple[float, str]:
    """v1.13.0 Phase 1: Price-volume crossover scoring.

    Returns (score, interpretation_zh). The 4-quadrant logic:

        Ratio class \\ Direction   |  Up (≥0.3%)   Flat   Down (≤-0.3%)
        --------------------------|-------------------------------------
        Heavy   (ratio ≥ 1.5)     |  100%    65%       20%
        Above   (ratio ≥ 1.2)     |   80%    55%       30%
        Normal  (0.85 ≤ ratio < 1.2) |  60%    50%       45%
        Light   (ratio < 0.85)     |   55%    40%       25%

    Rationale:
      - 量爆+漲 (100%): 資金強力追入, 明日續強概率最高
      - 量爆+跌 (20%): 出貨 / 恐慌賣壓, 明日恐續弱
      - 量縮+漲 (55%): 籌碼鎖定健康整理, 中性偏多
      - 量縮+跌 (25%): 無人接但也無賣壓, 中性偏空
      - 量持平+任何方向: 給中等分數, 信號不明確

    These percentages are calibrated to give max_pts when ideal
    (heavy + up) and floor at ~20% (heavy + down) so that volume signals
    NEVER zero out the indicator even when ratio is ambiguous.

    Returns (score, interpretation_zh) — interpretation in zh for UI label.
    """
    if latest_vol is None or avg_vol is None or avg_vol <= 0:
        return 0.0, "資料準備中"
    ratio = float(latest_vol) / float(avg_vol)
    direction = daily_return if daily_return is not None else 0.0
    # Direction buckets
    if direction >= 0.3:
        dir_label = "up"
    elif direction <= -0.3:
        dir_label = "down"
    else:
        dir_label = "flat"
    # Ratio buckets
    if ratio >= 1.5:
        ratio_label = "heavy"
        ratio_zh = "爆量"
    elif ratio >= 1.2:
        ratio_label = "above"
        ratio_zh = "增量"
    elif ratio >= 0.85:
        ratio_label = "normal"
        ratio_zh = "量持平"
    else:
        ratio_label = "light"
        ratio_zh = "量縮"
    # Score matrix
    score_pct_table = {
        ("heavy",  "up"):   1.00,
        ("heavy",  "flat"): 0.65,
        ("heavy",  "down"): 0.20,
        ("above",  "up"):   0.80,
        ("above",  "flat"): 0.55,
        ("above",  "down"): 0.30,
        ("normal", "up"):   0.60,
        ("normal", "flat"): 0.50,
        ("normal", "down"): 0.45,
        ("light",  "up"):   0.55,
        ("light",  "flat"): 0.40,
        ("light",  "down"): 0.25,
    }
    score_pct = score_pct_table.get((ratio_label, dir_label), 0.50)
    score = round(score_pct * max_pts, 2)
    # Friendly interpretation combining quadrant
    interp_map_zh = {
        ("heavy",  "up"):   "爆量強漲",
        ("heavy",  "flat"): "爆量震盪",
        ("heavy",  "down"): "爆量殺出",
        ("above",  "up"):   "增量上行",
        ("above",  "flat"): "增量震盪",
        ("above",  "down"): "增量下殺",
        ("normal", "up"):   "量平緩漲",
        ("normal", "flat"): "量平整理",
        ("normal", "down"): "量平緩跌",
        ("light",  "up"):   "量縮緩漲",
        ("light",  "flat"): "量縮觀望",
        ("light",  "down"): "量縮續弱",
    }
    interpretation = interp_map_zh.get((ratio_label, dir_label), ratio_zh)
    return score, interpretation


def _momentum_rsi(close_series, period: int = 14) -> float | None:
    """v1.13.0 Phase 1: Wilder's RSI(14).
    Returns 0-100 or None if insufficient data.

    Formula: RSI = 100 - (100 / (1 + RS))
      where RS = avg gain / avg loss over `period` days using Wilder's
      exponential smoothing (period - 1 prior + current).
    """
    try:
        if close_series is None or len(close_series) < period + 1:
            return None
        deltas = close_series.diff().dropna()
        gains = deltas.clip(lower=0)
        losses = (-deltas).clip(lower=0)
        # Wilder's smoothing: first avg = simple, then EMA-like
        avg_gain = gains.iloc[:period].mean()
        avg_loss = losses.iloc[:period].mean()
        for i in range(period, len(deltas)):
            avg_gain = (avg_gain * (period - 1) + gains.iloc[i]) / period
            avg_loss = (avg_loss * (period - 1) + losses.iloc[i]) / period
        if avg_loss == 0:
            return 100.0
        rs = avg_gain / avg_loss
        rsi = 100 - (100 / (1 + rs))
        return round(float(rsi), 1)
    except Exception:
        return None


def _momentum_rsi_score(rsi: float | None, max_pts: float) -> tuple[float, str, str]:
    """v1.13.0 Phase 1: RSI-based overbought/oversold correction.

    Returns (score, interpretation_zh, tone). Score ranges 0 to max_pts:
      RSI > 75 → 0.0 (overbought, expect mean-reversion penalty)
      RSI 65-75 → 0.5*max (strong but caution)
      RSI 50-65 → max (healthy uptrend, ideal zone)
      RSI 35-50 → 0.6*max (sideways)
      RSI 25-35 → 0.7*max (oversold rebound chance)
      RSI < 25 → 0.5*max (deep oversold, caution)

    The U-shape gives both healthy-uptrend and oversold-rebound chances
    high marks, penalizes only the overbought zone (>75).
    """
    if rsi is None or not math.isfinite(rsi):
        return 0.0, "資料準備中", "neutral"
    if rsi > 75:
        return 0.0, f"超買 ({rsi:.0f}, 回測警訊)", "negative"
    if rsi > 65:
        return round(max_pts * 0.5, 2), f"強勢 ({rsi:.0f}, 接近超買)", "positive"
    if rsi >= 50:
        return max_pts, f"健康上行 ({rsi:.0f})", "positive"
    if rsi >= 35:
        return round(max_pts * 0.6, 2), f"中性整理 ({rsi:.0f})", "neutral"
    if rsi >= 25:
        return round(max_pts * 0.7, 2), f"超賣反彈機會 ({rsi:.0f})", "positive"
    return round(max_pts * 0.5, 2), f"深度超賣 ({rsi:.0f}, 謹慎)", "neutral"


def _momentum_signed_flow_score(value: float | None, max_pts: float, scale: float = 200.0) -> float:
    """Signed-flow scoring: ±scale億 → ±max_pts/2 around midpoint."""
    if value is None or not math.isfinite(value):
        return 0.0
    norm = max(-1.0, min(1.0, float(value) / float(scale)))
    return round((norm + 1) / 2 * max_pts, 2)


def _momentum_verdict_from_score(score: float) -> tuple[str, str, str]:
    """Map total score to (verdict_label, emoji, css_class).
    Localized via t() at render time."""
    if score >= 70:
        return ("strong", "🟢", "momentum-verdict-strong")
    if score >= 40:
        return ("neutral", "🟡", "momentum-verdict-neutral")
    return ("weak", "🔴", "momentum-verdict-weak")


def _momentum_direction_strength(score: float, rows: list[dict]) -> dict:
    """v1.13.1 Phase 2: Decompose 0-100 score into direction + strength.

    Args:
        score: total 0-100 score
        rows: list of signal rows with "tone" field (positive/neutral/negative)

    Returns dict:
        {
            "direction_key": "bullish" | "bearish" | "neutral",
            "direction_zh": "偏多 ↑" | "偏空 ↓" | "中性 →",
            "direction_emoji": "↑" | "↓" | "→",
            "strength_key": "strong" | "medium" | "small" | "flat",
            "strength_zh": "強勢 ±2%+" | "中幅 ±0.5-1%" | ...,
            "expected_pct_range_zh": "+1% ~ +2%",
        }

    Logic:
        - Direction: from net tone count. >+2 net positive → bullish.
        - Strength: from |score - 50| distance.
            ±0-5  → flat / 持平 (≤±0.3%)
            ±5-12 → small / 小幅 (±0.3-0.7%)
            ±12-25 → medium / 中幅 (±0.7-1.5%)
            ±25+ → strong / 強勢 (±1.5%+)
    """
    # Direction: tone count + score sanity check
    pos_count = sum(1 for r in rows if r.get("tone") == "positive")
    neg_count = sum(1 for r in rows if r.get("tone") == "negative")
    net_tone = pos_count - neg_count

    # Sanity: if score skews opposite of tone count, lean to score
    score_lean = score - 50
    if net_tone >= 2 and score_lean >= -3:
        direction_key = "bullish"
    elif net_tone <= -2 and score_lean <= 3:
        direction_key = "bearish"
    elif score_lean >= 8:
        direction_key = "bullish"
    elif score_lean <= -8:
        direction_key = "bearish"
    else:
        direction_key = "neutral"

    direction_map = {
        "bullish": ("偏多 ↑",  "↑"),
        "bearish": ("偏空 ↓",  "↓"),
        "neutral": ("中性 →",  "→"),
    }
    direction_zh, direction_emoji = direction_map[direction_key]

    # Strength from |score - 50|
    distance = abs(score - 50)
    if distance < 5:
        strength_key = "flat"
        strength_zh = "持平整理"
        pct_range_zh = "±0.3% 內"
    elif distance < 12:
        strength_key = "small"
        strength_zh = "小幅波動"
        pct_range_zh = "±0.3-0.7%"
    elif distance < 25:
        strength_key = "medium"
        strength_zh = "中幅波動"
        pct_range_zh = "±0.7-1.5%"
    else:
        strength_key = "strong"
        strength_zh = "強勢突破"
        pct_range_zh = "±1.5% 以上"

    # If direction is bullish/bearish, prepend +/-
    if direction_key == "bullish":
        pct_range_signed = pct_range_zh.replace("±", "+")
        if "內" not in pct_range_signed:
            pct_range_signed = pct_range_signed.split("-")[0] + " ~ +" + pct_range_signed.split("-")[-1] if "-" in pct_range_signed else pct_range_signed
    elif direction_key == "bearish":
        pct_range_signed = pct_range_zh.replace("±", "-")
        if "內" not in pct_range_signed:
            pct_range_signed = pct_range_signed.split("-")[0] + " ~ -" + pct_range_signed.split("-")[-1] if "-" in pct_range_signed else pct_range_signed
    else:
        pct_range_signed = pct_range_zh

    return {
        "direction_key": direction_key,
        "direction_zh": direction_zh,
        "direction_emoji": direction_emoji,
        "strength_key": strength_key,
        "strength_zh": strength_zh,
        "expected_pct_range_zh": pct_range_signed,
    }


def _momentum_confidence(rows: list[dict]) -> dict:
    """v1.13.1 Phase 2: Calculate signal consistency / confidence.

    Args:
        rows: list of signal rows with "tone" + "contribution" + "contribution_max"

    Returns dict:
        {
            "confidence_key": "high" | "medium" | "low",
            "confidence_zh": "高 ●●●" | "中 ●●○" | "低 ●○○",
            "consistency_pct": float (0-100),
            "pos_count": int,
            "neg_count": int,
            "neutral_count": int,
            "data_ready_count": int (signals with non-zero data),
        }

    Confidence formula:
        consistency = max(pos_pts, neg_pts) / (pos_pts + neg_pts) × 100
        adjusted by data_completeness:
            data_ready ≥ 6/8 → full weight
            data_ready 3-5   → ×0.85
            data_ready < 3   → ×0.6

    Bands:
        consistency ≥ 70% AND data_ready ≥ 5 → high
        consistency ≥ 50% AND data_ready ≥ 4 → medium
        else → low
    """
    pos_pts = 0.0
    neg_pts = 0.0
    pos_count = 0
    neg_count = 0
    neutral_count = 0
    data_ready_count = 0

    for r in rows:
        contrib = r.get("contribution", 0.0)
        cmax = r.get("contribution_max", 0.0) or 1.0
        tone = r.get("tone", "neutral")
        # Data-ready check: value_text not "—" and contribution > 0
        # (or it's negative but data did flow through, e.g. tone=negative)
        value_text = str(r.get("value_text", "—"))
        if value_text != "—":
            data_ready_count += 1
        if tone == "positive":
            pos_count += 1
            pos_pts += contrib
        elif tone == "negative":
            neg_count += 1
            # For "negative" tone, the absent points (cmax - contrib) is the
            # negative signal strength
            neg_pts += (cmax - contrib)
        else:
            neutral_count += 1

    # Consistency: how skewed is the signal mix?
    total_directional = pos_pts + neg_pts
    if total_directional > 0:
        consistency_pct = max(pos_pts, neg_pts) / total_directional * 100
    else:
        # All neutral / no data
        consistency_pct = 0.0

    # Data completeness penalty
    if data_ready_count >= 6:
        data_factor = 1.0
    elif data_ready_count >= 3:
        data_factor = 0.85
    else:
        data_factor = 0.6
    adjusted_consistency = consistency_pct * data_factor

    if adjusted_consistency >= 70 and data_ready_count >= 5:
        confidence_key = "high"
        confidence_zh = "高 ●●●"
    elif adjusted_consistency >= 50 and data_ready_count >= 4:
        confidence_key = "medium"
        confidence_zh = "中 ●●○"
    else:
        confidence_key = "low"
        confidence_zh = "低 ●○○"

    return {
        "confidence_key": confidence_key,
        "confidence_zh": confidence_zh,
        "consistency_pct": round(adjusted_consistency, 1),
        "pos_count": pos_count,
        "neg_count": neg_count,
        "neutral_count": neutral_count,
        "data_ready_count": data_ready_count,
    }


def _momentum_key_drivers(rows: list[dict]) -> dict:
    """v1.13.1 Phase 2: Detect key drivers, warnings, and conflicts.

    Args:
        rows: list of signal rows

    Returns dict:
        {
            "top_driver": {"label": str, "value_text": str, "interpretation": str} | None,
            "warning": {"label": str, "value_text": str, "interpretation": str} | None,
            "conflict_note_zh": str | None,
        }

    Logic:
        - top_driver: highest-scoring row with tone=positive (e.g. signal
          giving >=80% of its budget)
        - warning: lowest-scoring row with tone=negative (e.g. signal giving
          <=30% of its budget) — flags as risk
        - conflict_note: if there are ≥2 strong-positive AND ≥2 strong-negative
          signals, flag the divergence
    """
    # Compute per-row signal strength (% of budget)
    def signal_pct(row):
        cmax = row.get("contribution_max", 0) or 1
        return row.get("contribution", 0) / cmax * 100 if cmax else 0

    # Top driver: highest score with tone=positive
    pos_rows = [r for r in rows if r.get("tone") == "positive" and r.get("value_text") != "—"]
    pos_rows_sorted = sorted(pos_rows, key=signal_pct, reverse=True)
    top_driver = None
    if pos_rows_sorted and signal_pct(pos_rows_sorted[0]) >= 70:
        r = pos_rows_sorted[0]
        top_driver = {
            "label": r.get("label_zh", "?"),
            "value_text": r.get("value_text", "?"),
            "interpretation": r.get("interpretation_zh", ""),
            "signal_pct": round(signal_pct(r), 1),
        }

    # Warning: lowest score with tone=negative
    neg_rows = [r for r in rows if r.get("tone") == "negative" and r.get("value_text") != "—"]
    neg_rows_sorted = sorted(neg_rows, key=signal_pct)
    warning = None
    if neg_rows_sorted and signal_pct(neg_rows_sorted[0]) <= 35:
        r = neg_rows_sorted[0]
        warning = {
            "label": r.get("label_zh", "?"),
            "value_text": r.get("value_text", "?"),
            "interpretation": r.get("interpretation_zh", ""),
            "signal_pct": round(signal_pct(r), 1),
        }

    # Conflict: 2+ strong positive AND 2+ strong negative
    strong_pos = [r for r in rows if r.get("tone") == "positive" and signal_pct(r) >= 70 and r.get("value_text") != "—"]
    strong_neg = [r for r in rows if r.get("tone") == "negative" and signal_pct(r) <= 35 and r.get("value_text") != "—"]
    conflict_note_zh = None
    if len(strong_pos) >= 2 and len(strong_neg) >= 2:
        # Pick representative labels
        pos_labels = [r.get("label_zh", "") for r in strong_pos[:2]]
        neg_labels = [r.get("label_zh", "") for r in strong_neg[:2]]
        conflict_note_zh = (
            f"訊號分歧:{', '.join(pos_labels)} 偏多,但 "
            f"{', '.join(neg_labels)} 偏空 — 謹慎觀察"
        )

    return {
        "top_driver": top_driver,
        "warning": warning,
        "conflict_note_zh": conflict_note_zh,
    }


def build_tomorrow_momentum_pulse_taiwan(daily_data, twse_aggs: dict | None) -> dict:
    """Compute the 7-signal Taiwan momentum score from previous-close data.

    Args:
        daily_data: yfinance frame containing at minimum 2330.TW + ^TWII
                    (ideally with ~30 days of history for 20-day vol average)
        twse_aggs: result from fetch_taiwan_market_aggregates(); contains
                   turnover Δ% + foreign/trust/dealer net flows

    Returns dict with shape:
        {
            "score": float,           # 0-100
            "verdict_key": str,       # "strong" | "neutral" | "weak"
            "verdict_emoji": str,
            "verdict_class": str,
            "rows": [
                {"label": "TSMC 收盤漲跌幅", "value_text": "+1.85%",
                 "contribution": 17.3, "contribution_max": 25,
                 "interpretation": "領漲", "tone": "positive"},
                ...
            ],
            "data_date": str | None,  # latest close date
            "ready": bool,            # False = upstream data missing
            "data_source_note": str,
        }
    """
    rows: list[dict] = []
    total_score = 0.0
    budget = TOMORROW_MOMENTUM_TAIWAN_BUDGET
    data_date: str | None = None
    components_with_data = 0  # to detect total fetch failure

    # --- TSMC slice (60 pts total: 15+25+15+5) -----------------------
    tsmc_close, tsmc_volume = _momentum_extract_close_volume(daily_data, "2330.TW")
    if tsmc_close is not None and len(tsmc_close) >= 2:
        components_with_data += 1
        try:
            data_date = tsmc_close.index[-1].strftime("%Y-%m-%d")
        except Exception:
            pass

        # 1. TSMC daily return (v1.13.0: budget 25→15, less noise weight)
        tsmc_daily = _momentum_pct(tsmc_close.iloc[-1], tsmc_close.iloc[-2])
        score_d = _momentum_linear_score(tsmc_daily, -3, 3, budget["tsmc_daily"])
        total_score += score_d
        rows.append({
            "label_zh": "TSMC 收盤漲跌幅",
            "label_en": "TSMC daily return",
            "value_text": f"{tsmc_daily:+.2f}%" if tsmc_daily is not None else "—",
            "contribution": score_d,
            "contribution_max": budget["tsmc_daily"],
            "interpretation_zh": (
                "強勢領漲(+2% 以上)" if (tsmc_daily or 0) >= 2 else
                "穩健上行" if (tsmc_daily or 0) >= 0.5 else
                "持平整理" if (tsmc_daily or 0) > -0.5 else
                "回測偏弱"
            ),
            "tone": (
                "positive" if (tsmc_daily or 0) >= 0.5 else
                "negative" if (tsmc_daily or 0) <= -0.5 else
                "neutral"
            ),
        })

        # 2. TSMC 10-day momentum (v1.13.0: was 5d, longer lookback)
        if len(tsmc_close) >= 11:
            tsmc_10d = _momentum_pct(tsmc_close.iloc[-1], tsmc_close.iloc[-11])
        else:
            tsmc_10d = None
        score_10 = _momentum_linear_score(tsmc_10d, -6, 6, budget["tsmc_10d"])
        total_score += score_10
        rows.append({
            "label_zh": "TSMC 10 日動能",
            "label_en": "TSMC 10d momentum",
            "value_text": f"{tsmc_10d:+.2f}%" if tsmc_10d is not None else "—",
            "contribution": score_10,
            "contribution_max": budget["tsmc_10d"],
            "interpretation_zh": (
                "趨勢明顯偏多" if (tsmc_10d or 0) >= 4 else
                "10 日轉強" if (tsmc_10d or 0) >= 1.5 else
                "區間震盪" if (tsmc_10d or 0) > -1.5 else
                "10 日轉弱"
            ),
            "tone": (
                "positive" if (tsmc_10d or 0) >= 1.5 else
                "negative" if (tsmc_10d or 0) <= -1.5 else
                "neutral"
            ),
        })

        # 3. TSMC volume + price crossover (v1.13.0: replaces broken raw-ratio bucket)
        if tsmc_volume is not None and len(tsmc_volume) >= 21:
            latest_vol = float(tsmc_volume.iloc[-1])
            avg20_vol = float(tsmc_volume.iloc[-21:-1].mean())
            vol_ratio = latest_vol / avg20_vol if avg20_vol > 0 else None
        else:
            latest_vol = None
            avg20_vol = None
            vol_ratio = None
        score_v, interp_v = _momentum_volume_crossover_score(
            latest_vol, avg20_vol, tsmc_daily, budget["tsmc_volume"]
        )
        total_score += score_v
        rows.append({
            "label_zh": "TSMC 量價結構",
            "label_en": "TSMC volume × price crossover",
            "value_text": f"{vol_ratio:.2f}x" if vol_ratio is not None else "—",
            "contribution": score_v,
            "contribution_max": budget["tsmc_volume"],
            "interpretation_zh": interp_v,
            "tone": (
                "positive" if score_v >= budget["tsmc_volume"] * 0.65 else
                "negative" if score_v <= budget["tsmc_volume"] * 0.30 else
                "neutral"
            ),
        })

        # 4. TSMC RSI(14) overbought/oversold correction (v1.13.0: NEW)
        tsmc_rsi = _momentum_rsi(tsmc_close, period=14)
        score_rsi, interp_rsi, tone_rsi = _momentum_rsi_score(tsmc_rsi, budget["tsmc_rsi"])
        total_score += score_rsi
        rows.append({
            "label_zh": "TSMC RSI 校正",
            "label_en": "TSMC RSI(14) correction",
            "value_text": f"{tsmc_rsi:.0f}" if tsmc_rsi is not None else "—",
            "contribution": score_rsi,
            "contribution_max": budget["tsmc_rsi"],
            "interpretation_zh": interp_rsi,
            "tone": tone_rsi,
        })
    else:
        # TSMC data missing — push 4 placeholder rows (was 3 in v1.12.x)
        for label_zh, max_pts in [
            ("TSMC 收盤漲跌幅", budget["tsmc_daily"]),
            ("TSMC 10 日動能", budget["tsmc_10d"]),
            ("TSMC 量價結構", budget["tsmc_volume"]),
            ("TSMC RSI 校正", budget["tsmc_rsi"]),
        ]:
            rows.append({
                "label_zh": label_zh, "label_en": label_zh,
                "value_text": "—", "contribution": 0.0,
                "contribution_max": max_pts,
                "interpretation_zh": "資料準備中", "tone": "neutral",
            })

    # --- TAIEX slice (18 pts daily+5d) --------------------------------
    taiex_close, _ = _momentum_extract_close_volume(daily_data, "^TWII")
    if taiex_close is not None and len(taiex_close) >= 2:
        components_with_data += 1
        # 4. TAIEX daily return
        taiex_daily = _momentum_pct(taiex_close.iloc[-1], taiex_close.iloc[-2])
        score_td = _momentum_linear_score(taiex_daily, -2, 2, budget["taiex_daily"])
        total_score += score_td
        rows.append({
            "label_zh": "加權指數漲跌幅",
            "label_en": "TAIEX daily return",
            "value_text": f"{taiex_daily:+.2f}%" if taiex_daily is not None else "—",
            "contribution": score_td,
            "contribution_max": budget["taiex_daily"],
            "interpretation_zh": (
                "大盤強漲(+1% 以上)" if (taiex_daily or 0) >= 1 else
                "大盤偏多" if (taiex_daily or 0) >= 0.3 else
                "大盤持平" if (taiex_daily or 0) > -0.3 else
                "大盤回測"
            ),
            "tone": (
                "positive" if (taiex_daily or 0) >= 0.3 else
                "negative" if (taiex_daily or 0) <= -0.3 else
                "neutral"
            ),
        })

        # 5. TAIEX 10-day momentum (v1.13.0: was 5d)
        if len(taiex_close) >= 11:
            taiex_10d = _momentum_pct(taiex_close.iloc[-1], taiex_close.iloc[-11])
        else:
            taiex_10d = None
        score_t10 = _momentum_linear_score(taiex_10d, -4, 4, budget["taiex_10d"])
        total_score += score_t10
        rows.append({
            "label_zh": "加權指數 10 日動能",
            "label_en": "TAIEX 10d momentum",
            "value_text": f"{taiex_10d:+.2f}%" if taiex_10d is not None else "—",
            "contribution": score_t10,
            "contribution_max": budget["taiex_10d"],
            "interpretation_zh": (
                "趨勢偏多" if (taiex_10d or 0) >= 2 else
                "近 10 日轉強" if (taiex_10d or 0) >= 0.7 else
                "震盪整理" if (taiex_10d or 0) > -0.7 else
                "趨勢轉弱"
            ),
            "tone": (
                "positive" if (taiex_10d or 0) >= 0.7 else
                "negative" if (taiex_10d or 0) <= -0.7 else
                "neutral"
            ),
        })
    else:
        for label_zh, max_pts in [
            ("加權指數漲跌幅", budget["taiex_daily"]),
            ("加權指數 10 日動能", budget["taiex_10d"]),
        ]:
            rows.append({
                "label_zh": label_zh, "label_en": label_zh,
                "value_text": "—", "contribution": 0.0,
                "contribution_max": max_pts,
                "interpretation_zh": "資料準備中", "tone": "neutral",
            })

    # --- TWSE turnover Δ% (12 pts) ------------------------------------
    if twse_aggs and twse_aggs.get("turnover_change_pct") is not None:
        components_with_data += 1
        turnover_chg = float(twse_aggs["turnover_change_pct"])
        score_tw = _momentum_linear_score(turnover_chg, -15, 15, budget["twse_volume"])
        total_score += score_tw
        rows.append({
            "label_zh": "市場成交量變動",
            "label_en": "TWSE turnover Δ%",
            "value_text": f"{turnover_chg:+.1f}%",
            "contribution": score_tw,
            "contribution_max": budget["twse_volume"],
            "interpretation_zh": (
                "資金明顯進場" if turnover_chg >= 10 else
                "成交量溫和放大" if turnover_chg >= 3 else
                "量能持平" if turnover_chg > -3 else
                "量縮資金退場"
            ),
            "tone": (
                "positive" if turnover_chg >= 3 else
                "negative" if turnover_chg <= -3 else
                "neutral"
            ),
        })
    else:
        rows.append({
            "label_zh": "市場成交量變動",
            "label_en": "TWSE turnover Δ%",
            "value_text": "—", "contribution": 0.0,
            "contribution_max": budget["twse_volume"],
            "interpretation_zh": "資料準備中", "tone": "neutral",
        })

    # --- 三大法人 net flow (10 pts) -----------------------------------
    if twse_aggs and any(twse_aggs.get(k) is not None for k in ("foreign_net", "trust_net", "dealer_net")):
        components_with_data += 1
        flow_sum = sum(
            float(twse_aggs.get(k) or 0)
            for k in ("foreign_net", "trust_net", "dealer_net")
        )
        score_inst = _momentum_signed_flow_score(flow_sum, budget["instl_flow"], scale=200.0)
        total_score += score_inst
        rows.append({
            "label_zh": "三大法人合計買賣超",
            "label_en": "Institutional net flow (3 combined)",
            "value_text": f"{flow_sum:+.1f}億",
            "contribution": score_inst,
            "contribution_max": budget["instl_flow"],
            "interpretation_zh": (
                "法人積極買超" if flow_sum >= 100 else
                "法人小幅買超" if flow_sum >= 20 else
                "法人態度中性" if flow_sum > -20 else
                "法人偏向賣壓"
            ),
            "tone": (
                "positive" if flow_sum >= 20 else
                "negative" if flow_sum <= -20 else
                "neutral"
            ),
        })
    else:
        rows.append({
            "label_zh": "三大法人合計買賣超",
            "label_en": "Institutional net flow (3 combined)",
            "value_text": "—", "contribution": 0.0,
            "contribution_max": budget["instl_flow"],
            "interpretation_zh": "資料準備中", "tone": "neutral",
        })

    # --- Verdict -------------------------------------------------------
    score_clamped = max(0.0, min(100.0, round(total_score, 1)))
    verdict_key, emoji, css_class = _momentum_verdict_from_score(score_clamped)

    # v1.13.1 Phase 2: Direction / strength / confidence / key drivers
    direction_info = _momentum_direction_strength(score_clamped, rows)
    confidence_info = _momentum_confidence(rows)
    drivers_info = _momentum_key_drivers(rows)

    return {
        "score": score_clamped,
        "verdict_key": verdict_key,
        "verdict_emoji": emoji,
        "verdict_class": css_class,
        "rows": rows,
        "data_date": data_date,
        "ready": components_with_data >= 1,
        "data_source_note": "依照昨日收盤價估算明日動能(60% TSMC + 40% 大盤量能 / 法人)",
        "scope": "Taiwan",
        # v1.13.1 Phase 2 fields (used only by Taiwan render — U.S. side
        # still uses legacy 1-score layout)
        "direction": direction_info,
        "confidence": confidence_info,
        "key_drivers": drivers_info,
    }


def build_tomorrow_momentum_pulse_us(daily_data) -> dict:
    """Compute the 5-signal U.S. momentum score from previous-close data.

    Args:
        daily_data: yfinance frame containing the 7 Mag7 tickers + ^VIX
                    with ~30 days of history.
    """
    rows: list[dict] = []
    total_score = 0.0
    budget = TOMORROW_MOMENTUM_US_BUDGET
    data_date: str | None = None
    components_with_data = 0

    # --- Mag7 aggregate ------------------------------------------------
    mag7_daily_returns: list[float] = []
    mag7_5d_returns: list[float] = []
    mag7_vol_ratios: list[float] = []
    mag7_positive_count = 0
    mag7_total_count = 0
    for ticker in TOMORROW_MOMENTUM_MAG7_TICKERS:
        close, volume = _momentum_extract_close_volume(daily_data, ticker)
        if close is None or len(close) < 2:
            continue
        try:
            data_date = close.index[-1].strftime("%Y-%m-%d")
        except Exception:
            pass
        mag7_total_count += 1
        d = _momentum_pct(close.iloc[-1], close.iloc[-2])
        if d is not None:
            mag7_daily_returns.append(d)
            if d > 0:
                mag7_positive_count += 1
        if len(close) >= 6:
            f = _momentum_pct(close.iloc[-1], close.iloc[-6])
            if f is not None:
                mag7_5d_returns.append(f)
        if volume is not None and len(volume) >= 21:
            latest_v = float(volume.iloc[-1])
            avg20_v = float(volume.iloc[-21:-1].mean())
            if avg20_v > 0:
                mag7_vol_ratios.append(latest_v / avg20_v)

    if mag7_total_count > 0:
        components_with_data += 1

    # 1. Mag7 daily avg
    avg_mag7_daily = (sum(mag7_daily_returns) / len(mag7_daily_returns)) if mag7_daily_returns else None
    score_md = _momentum_linear_score(avg_mag7_daily, -3, 3, budget["mag7_daily"])
    total_score += score_md
    rows.append({
        "label_zh": "Mag7 平均漲跌幅",
        "label_en": "Mag7 average daily return",
        "value_text": f"{avg_mag7_daily:+.2f}%" if avg_mag7_daily is not None else "—",
        "contribution": score_md,
        "contribution_max": budget["mag7_daily"],
        "interpretation_zh": (
            "科技股全面強漲" if (avg_mag7_daily or 0) >= 1.5 else
            "科技股偏多" if (avg_mag7_daily or 0) >= 0.3 else
            "整體持平" if (avg_mag7_daily or 0) > -0.3 else
            "科技股回測"
        ),
        "tone": (
            "positive" if (avg_mag7_daily or 0) >= 0.3 else
            "negative" if (avg_mag7_daily or 0) <= -0.3 else
            "neutral"
        ),
    })

    # 2. Mag7 5d avg
    avg_mag7_5d = (sum(mag7_5d_returns) / len(mag7_5d_returns)) if mag7_5d_returns else None
    score_m5 = _momentum_linear_score(avg_mag7_5d, -5, 5, budget["mag7_5d"])
    total_score += score_m5
    rows.append({
        "label_zh": "Mag7 5 日平均動能",
        "label_en": "Mag7 5d momentum",
        "value_text": f"{avg_mag7_5d:+.2f}%" if avg_mag7_5d is not None else "—",
        "contribution": score_m5,
        "contribution_max": budget["mag7_5d"],
        "interpretation_zh": (
            "趨勢明顯偏多" if (avg_mag7_5d or 0) >= 3 else
            "近 5 日轉強" if (avg_mag7_5d or 0) >= 1 else
            "區間震盪" if (avg_mag7_5d or 0) > -1 else
            "近 5 日轉弱"
        ),
        "tone": (
            "positive" if (avg_mag7_5d or 0) >= 1 else
            "negative" if (avg_mag7_5d or 0) <= -1 else
            "neutral"
        ),
    })

    # 3. Mag7 breadth
    if mag7_total_count > 0:
        breadth_pct = mag7_positive_count / mag7_total_count
        if breadth_pct >= 1.0:
            score_b = budget["mag7_breadth"]
        elif breadth_pct >= 5/7:
            score_b = round(budget["mag7_breadth"] * 0.80, 2)
        elif breadth_pct >= 3/7:
            score_b = round(budget["mag7_breadth"] * 0.53, 2)
        elif breadth_pct >= 1/7:
            score_b = round(budget["mag7_breadth"] * 0.27, 2)
        else:
            score_b = 0.0
    else:
        breadth_pct = None
        score_b = 0.0
    total_score += score_b
    rows.append({
        "label_zh": "Mag7 上漲家數比例",
        "label_en": "Mag7 breadth (% closing positive)",
        "value_text": f"{mag7_positive_count}/{mag7_total_count}" if mag7_total_count > 0 else "—",
        "contribution": score_b,
        "contribution_max": budget["mag7_breadth"],
        "interpretation_zh": (
            "全面紅K" if (breadth_pct or 0) >= 1.0 else
            "多數上漲" if (breadth_pct or 0) >= 5/7 else
            "漲跌互見" if (breadth_pct or 0) >= 3/7 else
            "多數下跌"
        ),
        "tone": (
            "positive" if (breadth_pct or 0) >= 5/7 else
            "negative" if (breadth_pct or 0) < 3/7 else
            "neutral"
        ),
    })

    # 4. Mag7 avg volume vs 20d
    avg_vol_ratio = (sum(mag7_vol_ratios) / len(mag7_vol_ratios)) if mag7_vol_ratios else None
    score_v = _momentum_volume_score(avg_vol_ratio, 1.0, budget["mag7_volume"]) if avg_vol_ratio is not None else 0.0
    total_score += score_v
    rows.append({
        "label_zh": "Mag7 平均量能(對 20 日)",
        "label_en": "Mag7 avg volume vs 20d",
        "value_text": f"{avg_vol_ratio:.2f}x" if avg_vol_ratio is not None else "—",
        "contribution": score_v,
        "contribution_max": budget["mag7_volume"],
        "interpretation_zh": (
            "整體放量" if (avg_vol_ratio or 0) >= 1.5 else
            "量能溫和增加" if (avg_vol_ratio or 0) >= 1.2 else
            "量能持平" if (avg_vol_ratio or 0) >= 0.9 else
            "量縮觀望"
        ),
        "tone": (
            "positive" if (avg_vol_ratio or 0) >= 1.2 else
            "negative" if (avg_vol_ratio or 0) < 0.9 else
            "neutral"
        ),
    })

    # 5. VIX level (with direction penalty)
    vix_close, _ = _momentum_extract_close_volume(daily_data, "^VIX")
    if vix_close is not None and len(vix_close) >= 1:
        components_with_data += 1
        vix_now = float(vix_close.iloc[-1])
        if vix_now < 15:
            base_score = budget["vix_level"]
            interp = "風險偏好強(VIX < 15)"
            tone = "positive"
        elif vix_now < 20:
            base_score = round(budget["vix_level"] * 0.72, 2)
            interp = "市場情緒平穩(VIX 15–20)"
            tone = "positive"
        elif vix_now < 25:
            base_score = round(budget["vix_level"] * 0.48, 2)
            interp = "波動度上升(VIX 20–25)"
            tone = "neutral"
        elif vix_now < 30:
            base_score = round(budget["vix_level"] * 0.24, 2)
            interp = "避險情緒升溫(VIX 25–30)"
            tone = "negative"
        else:
            base_score = 0.0
            interp = "高度恐慌(VIX ≥ 30)"
            tone = "negative"

        # Direction penalty: VIX rising fast = even less stable
        if len(vix_close) >= 6:
            vix_5d_change = _momentum_pct(vix_now, float(vix_close.iloc[-6]))
            if vix_5d_change is not None and vix_5d_change > 10:
                # Subtract up to 5 pts proportional to how much it rose
                penalty = min(5.0, (vix_5d_change - 10) / 4)
                base_score = max(0.0, base_score - penalty)
                interp += f" + 5日漲幅 {vix_5d_change:+.1f}% 扣分"

        total_score += base_score
        rows.append({
            "label_zh": "VIX 恐慌指數",
            "label_en": "VIX fear gauge",
            "value_text": f"{vix_now:.2f}",
            "contribution": round(base_score, 2),
            "contribution_max": budget["vix_level"],
            "interpretation_zh": interp,
            "tone": tone,
        })
    else:
        rows.append({
            "label_zh": "VIX 恐慌指數",
            "label_en": "VIX fear gauge",
            "value_text": "—", "contribution": 0.0,
            "contribution_max": budget["vix_level"],
            "interpretation_zh": "資料準備中", "tone": "neutral",
        })

    # --- Verdict -------------------------------------------------------
    score_clamped = max(0.0, min(100.0, round(total_score, 1)))
    verdict_key, emoji, css_class = _momentum_verdict_from_score(score_clamped)

    return {
        "score": score_clamped,
        "verdict_key": verdict_key,
        "verdict_emoji": emoji,
        "verdict_class": css_class,
        "rows": rows,
        "data_date": data_date,
        "ready": components_with_data >= 1,
        "data_source_note": "依照昨日收盤價估算明日動能(75% Mag7 + 25% VIX)",
        "scope": "U.S.",
    }


def _render_tomorrow_momentum_pulse_html(payload: dict, lang_zh: bool) -> str:
    """Build the HTML for the momentum pulse table. Returns "" when not
    ready (caller should hide the block)."""
    if not payload.get("ready"):
        return ""

    score = payload["score"]
    verdict_key = payload["verdict_key"]
    verdict_emoji = payload["verdict_emoji"]
    verdict_class = payload["verdict_class"]
    rows = payload["rows"]
    data_date = payload.get("data_date") or ""
    scope = payload.get("scope", "Taiwan")

    # Localized strings
    if lang_zh:
        title = "明日動能脈搏"
        subtitle_template = "依{scope}最近收盤估算下一個交易日動能 · 數值愈高代表動力愈強"
        scope_text = "台股" if scope == "Taiwan" else "美股"
        col_signal = "訊號"
        col_value = "數值"
        col_contribution = "貢獻分"
        col_interpretation = "解讀"
        verdict_label = {
            "strong":  "強 · 動力持續",
            "neutral": "中 · 震盪盤整",
            "weak":    "弱 · 資金進出偏弱",
        }[verdict_key]
        score_suffix = "分 / 100"
        date_prefix = "資料基準"
        source_note = payload.get("data_source_note", "")
    else:
        title = "Tomorrow Momentum Pulse"
        subtitle_template = "Estimating next-session energy from {scope} previous closes · higher = stronger"
        scope_text = "Taiwan" if scope == "Taiwan" else "U.S."
        col_signal = "Signal"
        col_value = "Value"
        col_contribution = "Score"
        col_interpretation = "Read"
        verdict_label = {
            "strong":  "Strong · momentum continues",
            "neutral": "Neutral · range-bound",
            "weak":    "Weak · liquidity thinning",
        }[verdict_key]
        score_suffix = " / 100"
        date_prefix = "As of"
        source_note = (
            "Computed from previous close (60% TSMC + 40% market)"
            if scope == "Taiwan"
            else "Computed from previous close (75% Mag7 + 25% VIX)"
        )

    # Build row HTML
    row_html_parts: list[str] = []
    for row in rows:
        label = row.get("label_zh") if lang_zh else row.get("label_en", row.get("label_zh", ""))
        value = row.get("value_text", "—")
        contrib = row.get("contribution", 0.0)
        contrib_max = row.get("contribution_max", 0)
        contrib_pct = (float(contrib) / float(contrib_max) * 100) if contrib_max else 0
        contrib_pct = max(0.0, min(100.0, contrib_pct))
        interp = row.get("interpretation_zh") if lang_zh else row.get("interpretation_zh", "")
        tone = row.get("tone", "neutral")
        row_html_parts.append(
            f'<div class="momentum-row momentum-tone-{escape(tone)}">'
            f'  <div class="momentum-cell-label">{escape(str(label))}</div>'
            f'  <div class="momentum-cell-value">{escape(str(value))}</div>'
            f'  <div class="momentum-cell-contribution">'
            f'    <div class="momentum-bar-track">'
            f'      <div class="momentum-bar-fill" style="width:{contrib_pct:.1f}%"></div>'
            f'    </div>'
            f'    <span class="momentum-bar-text">{contrib:.1f} / {contrib_max}</span>'
            f'  </div>'
            f'  <div class="momentum-cell-interpretation">{escape(str(interp))}</div>'
            f'</div>'
        )

    rows_block = "".join(row_html_parts)
    # v1.13.25: 盤中暫估標籤 — 盤中用今日即時價拼接時顯示, 提示數值浮動未定稿。
    provisional_badge = ""
    if payload.get("intraday_provisional"):
        provisional_badge = (
            '<span class="momentum-provisional">'
            + ("⏱ 盤中暫估" if lang_zh else "⏱ Intraday (provisional)")
            + "</span>"
        )
    date_block = (
        f'<span class="momentum-date">· {escape(date_prefix)} {escape(data_date)}</span>{provisional_badge}'
        if data_date else (provisional_badge or "")
    )
    subtitle = subtitle_template.format(scope=scope_text)

    # v1.13.1 Phase 2: Build hook block (direction/strength/confidence/key drivers)
    # Only for Taiwan scope (U.S. side keeps legacy layout for now).
    hook_block_html = ""
    if scope == "Taiwan" and lang_zh:
        direction = payload.get("direction") or {}
        confidence = payload.get("confidence") or {}
        key_drivers = payload.get("key_drivers") or {}
        if direction or confidence or key_drivers:
            dir_zh = direction.get("direction_zh", "")
            dir_key = direction.get("direction_key", "neutral")
            strength_zh = direction.get("strength_zh", "")
            pct_range = direction.get("expected_pct_range_zh", "")
            conf_zh = confidence.get("confidence_zh", "")
            conf_key = confidence.get("confidence_key", "low")
            pos_c = confidence.get("pos_count", 0)
            neg_c = confidence.get("neg_count", 0)
            data_c = confidence.get("data_ready_count", 0)
            total_signals = pos_c + neg_c + confidence.get("neutral_count", 0)

            # CSS classes by direction
            dir_class_map = {
                "bullish": "hook-dir-bullish",
                "bearish": "hook-dir-bearish",
                "neutral": "hook-dir-neutral",
            }
            dir_class = dir_class_map.get(dir_key, "hook-dir-neutral")
            conf_class_map = {
                "high":   "hook-conf-high",
                "medium": "hook-conf-medium",
                "low":    "hook-conf-low",
            }
            conf_class = conf_class_map.get(conf_key, "hook-conf-low")

            # Top driver / warning / conflict sub-block
            top_driver = key_drivers.get("top_driver")
            warning = key_drivers.get("warning")
            conflict = key_drivers.get("conflict_note_zh")

            insight_rows_html = ""
            if top_driver:
                insight_rows_html += textwrap.dedent(f"""
                    <div class="hook-insight-row hook-insight-driver">
                        <span class="hook-insight-icon">🏆</span>
                        <span class="hook-insight-label">最強訊號</span>
                        <span class="hook-insight-text">
                            <strong>{escape(top_driver.get('label', ''))}</strong>
                            ({escape(top_driver.get('value_text', ''))})
                            — {escape(top_driver.get('interpretation', ''))}
                        </span>
                    </div>
                """).strip()
            if warning:
                insight_rows_html += textwrap.dedent(f"""
                    <div class="hook-insight-row hook-insight-warning">
                        <span class="hook-insight-icon">⚠️</span>
                        <span class="hook-insight-label">警示訊號</span>
                        <span class="hook-insight-text">
                            <strong>{escape(warning.get('label', ''))}</strong>
                            ({escape(warning.get('value_text', ''))})
                            — {escape(warning.get('interpretation', ''))}
                        </span>
                    </div>
                """).strip()
            if conflict:
                insight_rows_html += textwrap.dedent(f"""
                    <div class="hook-insight-row hook-insight-conflict">
                        <span class="hook-insight-icon">🤔</span>
                        <span class="hook-insight-label">矛盾警示</span>
                        <span class="hook-insight-text">{escape(conflict)}</span>
                    </div>
                """).strip()

            # If no insights at all, show a placeholder
            if not insight_rows_html:
                insight_rows_html = (
                    '<div class="hook-insight-row hook-insight-empty">'
                    '<span class="hook-insight-icon">💡</span>'
                    '<span class="hook-insight-text">訊號分佈均勻,無突出方向</span>'
                    '</div>'
                )

            hook_block_html = textwrap.dedent(f"""
                <div class="momentum-hook-block">
                    <div class="hook-metrics-row">
                        <div class="hook-metric hook-metric-direction {dir_class}">
                            <div class="hook-metric-label">🎯 預期方向</div>
                            <div class="hook-metric-value">{escape(dir_zh)}</div>
                        </div>
                        <div class="hook-metric hook-metric-strength">
                            <div class="hook-metric-label">⚡ 預期幅度</div>
                            <div class="hook-metric-value">{escape(strength_zh)}</div>
                            <div class="hook-metric-sub">{escape(pct_range)}</div>
                        </div>
                        <div class="hook-metric hook-metric-confidence {conf_class}">
                            <div class="hook-metric-label">💡 信心度</div>
                            <div class="hook-metric-value">{escape(conf_zh)}</div>
                            <div class="hook-metric-sub">{data_c}/{total_signals} 訊號 · {pos_c} 多 / {neg_c} 空</div>
                        </div>
                    </div>
                    <div class="hook-insights">
                        {insight_rows_html}
                    </div>
                </div>
            """).strip()

    return textwrap.dedent(
        f"""
        <div class="momentum-pulse-shell">
            <div class="momentum-pulse-head">
                <div class="momentum-pulse-head-text">
                    <div class="momentum-pulse-title">📊 {escape(title)}</div>
                    <div class="momentum-pulse-subtitle">{escape(subtitle)}{date_block}</div>
                </div>
                <div class="momentum-pulse-verdict {escape(verdict_class)}">
                    <div class="momentum-verdict-emoji">{verdict_emoji}</div>
                    <div class="momentum-verdict-text">
                        <div class="momentum-verdict-label">{escape(verdict_label)}</div>
                        <div class="momentum-verdict-score">{score:.1f}<span class="momentum-verdict-suffix">{escape(score_suffix)}</span></div>
                    </div>
                </div>
            </div>
            {hook_block_html}
            <div class="momentum-pulse-table">
                <div class="momentum-row momentum-row-header">
                    <div class="momentum-cell-label">{escape(col_signal)}</div>
                    <div class="momentum-cell-value">{escape(col_value)}</div>
                    <div class="momentum-cell-contribution">{escape(col_contribution)}</div>
                    <div class="momentum-cell-interpretation">{escape(col_interpretation)}</div>
                </div>
                {rows_block}
            </div>
            <div class="momentum-pulse-foot">{escape(source_note)}</div>
        </div>
        """
    ).strip()


