def _sch_pct(v):
    if v is None or not (isinstance(v, (int, float)) and math.isfinite(v)):
        return "—"
    return f"{'+' if v >= 0 else ''}{v:.2f}%"


def _sch_heat_class(v):
    """族群平均漲幅 → (卡片冷暖 class, 數字色 class)。綠漲紅跌 dashboard 慣例。"""
    if v is None or not (isinstance(v, (int, float)) and math.isfinite(v)):
        return "sch-warm", "sch-flat"
    if v >= 3.0:
        return "sch-hot", "sch-up"
    if v >= 0.3:
        return "sch-cool", "sch-up"
    if v > -0.3:
        return "sch-warm", "sch-flat"
    return "sch-cold", "sch-down"


def _sch_verdict(groups, lang_zh=True):
    """由各族群平均漲幅自動生成一句話總結 + chip 色。"""
    moves = [g.get("average_move") for g in groups
             if isinstance(g.get("average_move"), (int, float)) and math.isfinite(g.get("average_move"))]
    if not moves:
        return ("資料整理中" if lang_zh else "Loading"), "sch-tldr-flat"
    up = sum(1 for m in moves if m > 0.3)
    down = sum(1 for m in moves if m < -0.3)
    n = len(moves)
    if up == n:
        return (f"全面走強 · {n}/{n} 收紅" if lang_zh else f"All up · {n}/{n}"), "sch-tldr-up"
    if down == n:
        return (f"全面走弱 · {n}/{n} 收綠" if lang_zh else f"All down · {n}/{n}"), "sch-tldr-down"
    if up >= down:
        return (f"偏多 · {up} 強 {down} 弱" if lang_zh else f"Risk-on · {up} up {down} dn"), "sch-tldr-up"
    return (f"偏空 · {up} 強 {down} 弱" if lang_zh else f"Risk-off · {up} up {down} dn"), "sch-tldr-down"


def _render_supply_chain_heat_html(groups, lang_zh=True, data_date="") -> str:
    if not groups:
        return ""
    gs = sorted(
        groups,
        key=lambda g: (g.get("average_move") if isinstance(g.get("average_move"), (int, float))
                       and math.isfinite(g.get("average_move")) else -1e9),
        reverse=True,
    )
    verdict_txt, verdict_cls = _sch_verdict(gs, lang_zh)
    P = ['<div class="sch-shell">', '<div class="sch-head"><div>']
    P.append(f'<div class="sch-title">🔥 {"供應鏈族群熱度" if lang_zh else "Supply-Chain Heat"}</div>')
    P.append(f'<div class="sch-sub">{escape("資料基準" if lang_zh else "As of")} '
             f'{escape(str(data_date) or "—")} · {"由強到弱" if lang_zh else "strong→weak"}</div></div>')
    P.append(f'<div class="sch-tldr {verdict_cls}">{escape(verdict_txt)}</div></div>')
    P.append('<div class="sch-grid">')
    for i, g in enumerate(gs, start=1):
        avg = g.get("average_move")
        card_cls, pct_cls = _sch_heat_class(avg)
        rank_lbl = f"#{i}" + ("　最強" if i == 1 and lang_zh else "")
        leader = escape(str(g.get("leader_name") or "—"))
        rising = g.get("rising_count", 0)
        total = g.get("ticker_count", 0)
        P.append(
            f'<div class="sch-card {card_cls}">'
            f'<div class="sch-rank">{escape(rank_lbl)}</div>'
            f'<div class="sch-name">{escape(str(g.get("title") or "—"))}</div>'
            f'<div class="sch-pct {pct_cls}">{_sch_pct(avg)}</div>'
            f'<div class="sch-meta">{"龍頭" if lang_zh else "Leader"} '
            f'<span class="sch-leader-name">{leader}</span>'
            f'<br><span class="sch-breadth">{rising}/{total} {"檔上漲" if lang_zh else "up"}</span></div>'
            f'</div>'
        )
    P.append('</div>')
    P.append(f'<div class="sch-note">{escape("漲幅為族群成分股平均；龍頭為族群內代表強勢股。資料取自供應鏈快照收盤。" if lang_zh else "Group average move; leader = strongest constituent.")}</div>')
    P.append('</div>')
    return "".join(P)


def render_supply_chain_heat(lang_zh: bool = True) -> None:
    """v1.13.21: 供應鏈族群熱度 (強弱光譜卡). 取代隱藏的「今日重點」, 提供
    第一眼 High-Level overview。只用穩定的供應鏈快照資料 (不依賴抓不到的
    Active ETF 來源)。全程防禦: 任何失敗都靜默不顯示, 不影響其餘頁面。"""
    try:
        # v1.13.36: 計時 — 量 loader 耗時並判斷 cache HIT/MISS, 寫進 session_state
        # 供 ?debug_focal=1 的 ⏱ Timing 顯示。(舊計時記在隱藏的今日重點函式,
        # 永遠測不到; 改記在實際在跑的熱度卡。)
        import time as _t
        _t0 = _t.perf_counter()
        groups = _load_focal_supply_chains_from_lab(limit=6)
        _elapsed_ms = (_t.perf_counter() - _t0) * 1000.0
        try:
            # v1.13.37: 保留「首次(冷)」與「最慢」紀錄, 不被後來的熱快取覆蓋。
            # (舊版只存最後一次, 而使用者通常等頁面載完才勾 Debug → 量到的是
            #  熱快取 0ms 假象, 看不到真正痛的第一次。)
            _prev = st.session_state.get("_sch_timing")
            _is_first = not isinstance(_prev, dict)
            _first_ms = _elapsed_ms if _is_first else _prev.get("first_ms", _elapsed_ms)
            _max_ms = _elapsed_ms if _is_first else max(_elapsed_ms, _prev.get("max_ms", 0))
            st.session_state["_sch_timing"] = {
                "loader_ms": _elapsed_ms,          # 本次 (通常熱)
                "first_ms": _first_ms,             # 這個 session 第一次 (冷)
                "max_ms": _max_ms,                 # 至今最慢一次
                "cache_status": ("HIT (cached, fast)" if _elapsed_ms < 80 else "MISS (cold fetch / network)"),
                "group_count": len(groups) if isinstance(groups, list) else 0,
                "measured_at": datetime.now(TW_TZ).strftime("%H:%M:%S"),
            }
        except Exception:
            pass
        if not groups:
            return
        data_date = ""
        for g in groups:
            d = str(g.get("fetched_at") or g.get("as_of_date") or "").strip()
            if d:
                # fetched_at 可能是 ISO timestamp, 只取日期部分
                data_date = d[:10]
                break
        render_html_block(_SUPPLY_CHAIN_HEAT_CSS)
        html = _render_supply_chain_heat_html(groups, lang_zh=lang_zh, data_date=data_date)
        if html:
            render_html_block(html)
    except Exception:
        return


@st.cache_data(ttl=1800, show_spinner=False)
def _build_active_etf_heat(cache_key: str) -> list:
    """v1.13.22: 主動式 ETF 熱度資料 — 繞過抓不到的 Supabase, 直接用
    fetch_daily_data 抓日線 + _active_etf_price_stats_for_overall 算當日漲跌。
    回傳 list[dict{code,name,style,move,volume_ratio}]。cache 300s。

    cache_key 僅用於 @st.cache_data 分桶 (傳日期/時段字串)。"""
    syms = [s if "." in s else f"{s}.TW" for s in ACTIVE_ETF_QUICK_PICK_SYMBOLS]
    try:
        daily = fetch_daily_data(syms, "5d", "1d")
    except Exception:
        return []
    out: list[dict] = []
    for sym in syms:
        try:
            stats = _active_etf_price_stats_for_overall(daily, sym)
        except Exception:
            continue
        move = stats.get("latest_return")
        if move is None or not (isinstance(move, (int, float)) and math.isfinite(move)):
            continue
        code = sym.split(".")[0]
        meta = get_active_etf_metadata(sym)
        out.append({
            "code": code,
            "name": str(meta.get("zh") or active_etf_selector_label(sym) or code),
            "style": str(meta.get("style_zh") or ""),
            "move": float(move),
            "volume_ratio": stats.get("volume_ratio"),
        })
    return out


def _render_active_etf_heat_html(items, lang_zh=True, data_date="") -> str:
    if not items:
        return ""
    its = sorted(
        items,
        key=lambda x: (x.get("move") if isinstance(x.get("move"), (int, float))
                       and math.isfinite(x.get("move")) else -1e9),
        reverse=True,
    )
    # 復用供應鏈熱度的 verdict 邏輯 (改吃 move 欄)
    moves = [x.get("move") for x in its if isinstance(x.get("move"), (int, float)) and math.isfinite(x.get("move"))]
    if not moves:
        verdict_txt, verdict_cls = ("資料整理中" if lang_zh else "Loading"), "sch-tldr-flat"
    else:
        up = sum(1 for m in moves if m > 0.3)
        down = sum(1 for m in moves if m < -0.3)
        n = len(moves)
        if up == n:
            verdict_txt, verdict_cls = (f"全面走強 · {n}/{n} 收紅" if lang_zh else f"All up · {n}/{n}"), "sch-tldr-up"
        elif down == n:
            verdict_txt, verdict_cls = (f"全面走弱 · {n}/{n} 收綠" if lang_zh else f"All down · {n}/{n}"), "sch-tldr-down"
        elif up >= down:
            verdict_txt, verdict_cls = (f"偏多 · {up} 強 {down} 弱" if lang_zh else f"Risk-on · {up}/{down}"), "sch-tldr-up"
        else:
            verdict_txt, verdict_cls = (f"偏空 · {up} 強 {down} 弱" if lang_zh else f"Risk-off · {up}/{down}"), "sch-tldr-down"

    P = ['<div class="sch-shell">', '<div class="sch-head"><div>']
    P.append(f'<div class="sch-title">⚡ {"主動式 ETF 熱度" if lang_zh else "Active ETF Heat"}</div>')
    P.append(f'<div class="sch-sub">{escape("資料基準" if lang_zh else "As of")} '
             f'{escape(str(data_date) or "—")} · {"由強到弱" if lang_zh else "strong→weak"}</div></div>')
    P.append(f'<div class="sch-tldr {verdict_cls}">{escape(verdict_txt)}</div></div>')
    P.append('<div class="sch-grid">')
    for i, x in enumerate(its, start=1):
        mv = x.get("move")
        card_cls, pct_cls = _sch_heat_class(mv)
        rank_lbl = f"#{i}" + ("　最強" if i == 1 and lang_zh else "")
        name = escape(str(x.get("name") or "—"))
        code = escape(str(x.get("code") or ""))
        style = escape(str(x.get("style") or ""))
        vr = x.get("volume_ratio")
        vol_txt = ""
        if isinstance(vr, (int, float)) and math.isfinite(vr) and vr > 0:
            vol_txt = (f"量能 {vr:.1f}×" if lang_zh else f"vol {vr:.1f}×")
        meta_line = (f'{"風格" if lang_zh else "Style"} <span class="sch-leader-name">{style}</span>'
                     if style else f'<span class="sch-leader-name">{code}</span>')
        breadth = f'<br><span class="sch-breadth">{vol_txt}</span>' if vol_txt else ""
        P.append(
            f'<div class="sch-card {card_cls}">'
            f'<div class="sch-rank">{escape(rank_lbl)}</div>'
            f'<div class="sch-name">{name} <span style="font-size:12px;color:#8b95ad;font-weight:600;">{code}</span></div>'
            f'<div class="sch-pct {pct_cls}">{_sch_pct(mv)}</div>'
            f'<div class="sch-meta">{meta_line}{breadth}</div>'
            f'</div>'
        )
    P.append('</div>')
    P.append(f'<div class="sch-note">{escape("漲跌幅為當日收盤；量能為相對20日均量倍數。資料取自即時日線。" if lang_zh else "Daily close move; vol = ratio to 20d avg.")}</div>')
    P.append('</div>')
    return "".join(P)


def render_active_etf_heat(lang_zh: bool = True) -> None:
    """v1.13.22: 主動式 ETF 熱度 (強弱光譜卡, 與供應鏈同風格)。直接用 yfinance
    日線計算, 不依賴抓不到的 Supabase active_etf_snapshots。全程防禦。"""
    try:
        try:
            _key = datetime.now(TW_TZ).strftime("%Y%m%d-%H")
        except Exception:
            _key = "nodate"
        # v1.13.36: 計時 (同供應鏈熱度)。
        import time as _t
        _t0 = _t.perf_counter()
        items = _build_active_etf_heat(_key)
        _elapsed_ms = (_t.perf_counter() - _t0) * 1000.0
        try:
            # v1.13.37: 保留首次(冷)+最慢, 不被熱快取覆蓋 (同供應鏈)。
            _prev = st.session_state.get("_etfheat_timing")
            _is_first = not isinstance(_prev, dict)
            _first_ms = _elapsed_ms if _is_first else _prev.get("first_ms", _elapsed_ms)
            _max_ms = _elapsed_ms if _is_first else max(_elapsed_ms, _prev.get("max_ms", 0))
            st.session_state["_etfheat_timing"] = {
                "loader_ms": _elapsed_ms,
                "first_ms": _first_ms,
                "max_ms": _max_ms,
                "cache_status": ("HIT (cached, fast)" if _elapsed_ms < 80 else "MISS (cold fetch / network)"),
                "item_count": len(items) if isinstance(items, list) else 0,
                "measured_at": datetime.now(TW_TZ).strftime("%H:%M:%S"),
            }
        except Exception:
            pass
        if not items:
            return
        try:
            data_date = datetime.now(TW_TZ).strftime("%Y-%m-%d")
        except Exception:
            data_date = ""
        render_html_block(_SUPPLY_CHAIN_HEAT_CSS)  # 共用同一套 CSS
        html = _render_active_etf_heat_html(items, lang_zh=lang_zh, data_date=data_date)
        if html:
            render_html_block(html)
    except Exception:
        return


