SAFE_HTML_WRAPPER_EXACT = {
    '</div>',
    '<div></div>',
    '<div class="planner-stack-spacer"></div>',
    '<div class="candlestick-section-spacer"></div>',
    '<div class="group-stack-divider"></div>',
}

SAFE_HTML_WRAPPER_PREFIXES = (
    '<div class="section-expander-wrap',
    '<div class="planner-expander-wrap',
)

SAFE_HTML_LEADING_STRIP_CLASSES = (
    'lead-story-board',
    'target-watch-board',
    'brief-grid',
    'compare-table-body',
    'planner-expander-badge-row',
)

def _is_wrapper_only_html(fragment: str) -> bool:
    probe = textwrap.dedent(str(fragment)).strip()
    if not probe:
        return True
    if probe in SAFE_HTML_WRAPPER_EXACT:
        return True
    if any(probe.startswith(prefix) and probe.endswith('>') and '</div>' not in probe for prefix in SAFE_HTML_WRAPPER_PREFIXES):
        return True
    return False

def _strip_known_wrapper_tokens(html: str) -> str:
    cleaned = textwrap.dedent(str(html)).strip()
    if not cleaned:
        return ""

    lines = [line.rstrip() for line in cleaned.splitlines()]
    while lines and _is_wrapper_only_html(lines[0]):
        lines.pop(0)
    while lines and _is_wrapper_only_html(lines[-1]):
        lines.pop()

    cleaned = "\n".join(lines).strip()
    if not cleaned:
        return ""

    # Only strip unmatched leading closing tags when the real block is one of our known safe roots.
    safe_root_pattern = "|".join(re.escape(cls) for cls in SAFE_HTML_LEADING_STRIP_CLASSES)
    cleaned = re.sub(
        rf"^(?:\s*</div>\s*)+(?=<div class=\"(?:{safe_root_pattern})\")",
        "",
        cleaned,
        flags=re.DOTALL,
    ).strip()

    # Strip standalone opening wrappers only when they are the entire remaining fragment.
    if any(cleaned.startswith(prefix) and cleaned.endswith('>') and '</div>' not in cleaned for prefix in SAFE_HTML_WRAPPER_PREFIXES):
        return ""

    return cleaned

def render_html_block(html: str):
    if html is None:
        return

    cleaned = _strip_known_wrapper_tokens(html)
    if not cleaned:
        return

    if hasattr(st, "html"):
        st.html(cleaned)
    else:
        st.markdown(cleaned, unsafe_allow_html=True)


def render_expander_meta(section: str, item_count: int | None, helper_base: str):
    helper_text = planner_expander_helper(helper_base, section, item_count)
    meta_html = (
        '<div class="planner-expander-meta">'
        + planner_expander_badges(section, item_count)
        + f'<div class="planner-expander-helper">{escape(helper_text)}</div>'
        + '</div>'
    )
    render_html_block(meta_html)

# ============================================================================
# § 10. YFINANCE DATA FETCHERS
# ============================================================================
# Two cached fetchers feed the rest of the dashboard. fetch_daily_data is the
# 1Y/1D backbone for trend lens charts; fetch_intraday_data is the 1D/1m feed
# for live-quote refresh.
#
# v1.4.1: bumped TTL from 300s -> 1800s (30 min) for daily and 120s -> 600s
# (10 min) for intraday. Rationale: yfinance bulk download for 30-80 tickers
# costs 5-12 seconds cold; the previous TTL meant nearly every re-entry to
# the dashboard re-paid that cost. 30 min is short enough that intraday
# moves are still tracked via the intraday endpoint, but long enough that
# typical reload patterns hit cache. Users can force-refresh via the
# sidebar "Refresh live data" button when needed.
@st.cache_data(ttl=1800)
def fetch_daily_data(tickers: list[str], period: str, interval: str):
    sink = io.StringIO()
    with contextlib.redirect_stdout(sink), contextlib.redirect_stderr(sink):
        return yf.download(
            tickers=tickers,
            period=period,
            interval=interval,
            progress=False,
            auto_adjust=False,
            group_by="column",
            threads=True,
            prepost=False,
        )


@st.cache_data(ttl=600)
def fetch_intraday_data(tickers: list[str]):
    sink = io.StringIO()
    with contextlib.redirect_stdout(sink), contextlib.redirect_stderr(sink):
        return yf.download(
            tickers=tickers,
            period=INTRADAY_PERIOD,
            interval=INTRADAY_INTERVAL,
            progress=False,
            auto_adjust=False,
            group_by="column",
            threads=True,
            prepost=True,
        )


@st.cache_data(ttl=600)
def fetch_ticker_news(ticker: str, max_items: int = 12):
    raw_news = []
    last_error = None
    news_candidates = [ticker]
    base_code = ticker_base_code(ticker)
    if is_taiwan_ticker(ticker) and base_code != str(ticker).upper():
        news_candidates.append(base_code)

    for candidate in news_candidates:
        try:
            tk = yf.Ticker(candidate)
            try:
                raw_news = tk.news or []
            except Exception:
                raw_news = tk.get_news() or []
            if raw_news:
                break
        except Exception as e:
            last_error = e

    if raw_news is None:
        raw_news = []

    items = []
    ticker_upper = str(ticker).upper()
    news_aliases = build_news_aliases(ticker_upper)

    for item in raw_news:
        if not isinstance(item, dict):
            continue

        content = item.get("content") if isinstance(item.get("content"), dict) else {}
        title = content.get("title") or item.get("title") or "Untitled"
        summary = content.get("summary") or item.get("summary") or ""
        provider_dict = content.get("provider") if isinstance(content.get("provider"), dict) else {}
        provider = provider_dict.get("displayName") or item.get("publisher") or item.get("provider") or "Unknown source"

        canonical = content.get("canonicalUrl") if isinstance(content.get("canonicalUrl"), dict) else {}
        clickthrough = content.get("clickThroughUrl") if isinstance(content.get("clickThroughUrl"), dict) else {}
        url = canonical.get("url") or clickthrough.get("url") or item.get("link") or item.get("url")

        published_raw = content.get("pubDate") or item.get("providerPublishTime") or item.get("published")
        published_ts = pd.NaT
        if published_raw is not None:
            try:
                if isinstance(published_raw, (int, float)):
                    published_ts = pd.to_datetime(published_raw, unit="s", utc=True)
                else:
                    published_ts = pd.to_datetime(published_raw, utc=True)
            except Exception:
                published_ts = pd.NaT

        related = []
        for key in ("relatedTickers", "tickers", "symbols"):
            candidate = content.get(key) if key in content else item.get(key)
            if isinstance(candidate, list):
                related.extend([str(x).upper() for x in candidate])

        relevance = score_news_relevance(title, summary, related, news_aliases)
        impact_label, impact_score, impact_reason = infer_news_impact(title, summary)
        confidence = infer_news_confidence(relevance, impact_score)

        items.append({
            "title": title,
            "summary": summary,
            "provider": provider,
            "url": url,
            "published": published_ts,
            "related": related,
            "relevance": relevance,
            "impact_label": impact_label,
            "impact_score": impact_score,
            "impact_reason": impact_reason,
            "confidence": confidence,
            "source_origin": "yahoo",
        })

    local_tw_items = fetch_taiwan_local_news(ticker, max_items=max_items * 2) if is_taiwan_ticker(ticker) else []
    merged_items = dedupe_news_items(local_tw_items + items, max_items=max_items * 3)
    filtered_items = [x for x in merged_items if x.get("relevance", 0) > 0]

    if last_error and not merged_items:
        return [], f"News unavailable for {display_ticker_label(ticker)}: {last_error}"
    return (filtered_items or merged_items)[:max_items], None


# ---------------------------
# Helpers
# ---------------------------
def get_series(data: pd.DataFrame | None, field: str, ticker: str):
    if data is None or data.empty:
        return None
    try:
        if isinstance(data.columns, pd.MultiIndex):
            if (field, ticker) in data.columns:
                return data[(field, ticker)].dropna()
            if (ticker, field) in data.columns:
                return data[(ticker, field)].dropna()
            if field in data.columns.get_level_values(0):
                sub = data[field]
                if isinstance(sub, pd.DataFrame) and ticker in sub.columns:
                    return sub[ticker].dropna()
            if ticker in data.columns.get_level_values(0):
                sub = data[ticker]
                if isinstance(sub, pd.DataFrame) and field in sub.columns:
                    return sub[field].dropna()
            return None
        if field in data.columns:
            series = data[field]
            if isinstance(series, pd.DataFrame):
                if ticker in series.columns:
                    return series[ticker].dropna()
                return None
            return series.dropna()
        return None
    except Exception:
        return None


def get_price_series(data: pd.DataFrame | None, ticker: str):
    fields = ["Close", "Adj Close"] if is_index_symbol(ticker) else PRICE_FIELDS_PRIORITY
    for field in fields:
        s = get_series(data, field, ticker)
        if s is not None and not s.empty:
            return ensure_datetime_index(s), field
    return None, None


def _normalize_quote_timestamp(ts):
    if ts is None or pd.isna(ts):
        return None
    try:
        stamp = pd.Timestamp(ts)
    except Exception:
        return None
    if stamp.tzinfo is not None:
        try:
            stamp = stamp.tz_convert(None)
        except Exception:
            stamp = stamp.tz_localize(None)
    return stamp


def merge_live_price_into_series(series: pd.Series | None, live_price, as_of=None):
    live_price = coerce_float(live_price)
    if series is None or series.empty or pd.isna(live_price):
        return series

    merged = ensure_datetime_index(series).copy()
    as_of_ts = _normalize_quote_timestamp(as_of) or pd.Timestamp.utcnow().tz_localize(None)

    try:
        last_ts = pd.Timestamp(merged.index[-1])
        if last_ts.tzinfo is not None:
            last_ts = last_ts.tz_convert(None)
    except Exception:
        last_ts = None

    if last_ts is not None and last_ts.normalize() == as_of_ts.normalize():
        merged.iloc[-1] = float(live_price)
        return merged

    if last_ts is not None and as_of_ts <= last_ts:
        merged.iloc[-1] = float(live_price)
        return merged

    merged.loc[as_of_ts] = float(live_price)
    return merged.sort_index()


def ensure_datetime_index(series: pd.Series | None):
    if series is None or series.empty:
        return series
    s = series.copy()
    s.index = pd.to_datetime(s.index)
    return s


def localize_timestamp(ts):
    ts = pd.Timestamp(ts)
    if ts.tzinfo is None:
        return ts.tz_localize(US_TZ)
    return ts.tz_convert(US_TZ)


def format_us_timestamp(ts) -> str:
    if ts is None or pd.isna(ts):
        return "N/A"
    return localize_timestamp(ts).strftime("%Y-%m-%d %H:%M %Z")


def format_tw_timestamp(ts) -> str:
    if ts is None or pd.isna(ts):
        return "N/A"
    return localize_timestamp(ts).tz_convert(TW_TZ).strftime("%Y-%m-%d %H:%M %Z")


def format_price(value):
    if pd.isna(value):
        return "N/A"
    return f"${value:,.2f}"


def format_percent(value):
    if pd.isna(value):
        return "N/A"
    return f"{value:+.2f}%"


def rsi_signal(rsi_value):
    if pd.isna(rsi_value):
        return "N/A"
    if rsi_value >= 70:
        return "Overbought"
    if rsi_value <= 30:
        return "Oversold"
    if rsi_value >= 55:
        return "Bullish Momentum"
    if rsi_value <= 45:
        return "Weak Momentum"
    return "Neutral"


def trend_label(one_year_return):
    if pd.isna(one_year_return):
        return "N/A"
    if one_year_return >= 25:
        return "Strong Uptrend"
    if one_year_return > 0:
        return "Moderate Uptrend"
    if one_year_return <= -20:
        return "Strong Downtrend"
    if one_year_return < 0:
        return "Mild Downtrend"
    return "Flat"



def to_numeric_series(series: pd.Series | None, *, keep_index: bool = True):
    if series is None:
        return pd.Series(dtype="float64")
    s = series.copy() if isinstance(series, pd.Series) else pd.Series(series)
    if keep_index:
        try:
            s = ensure_datetime_index(s)
        except Exception:
            pass
    return pd.to_numeric(s, errors="coerce")


def empty_analysis_payload(ticker: str, indicators: pd.DataFrame | None = None, news_items: list[dict] | None = None):
    indicators = indicators if indicators is not None else pd.DataFrame()
    news_pulse = build_news_pulse(news_items or [])
    return {
        "signal": "HOLD",
        "confidence": "Low",
        "score": 0,
        "summary": "Data is limited right now, so the dashboard is staying neutral until cleaner price history is available.",
        "reasons": ["Price history is incomplete or non-numeric, so advanced indicators were safely skipped."],
        "trend": "N/A",
        "one_year_return": pd.NA,
        "rsi14": pd.NA,
        "rsi_status": "N/A",
        "last_price": pd.NA,
        "sma20": pd.NA,
        "sma50": pd.NA,
        "sma200": pd.NA,
        "indicators": indicators,
        "latest_daily_ts": indicators.index[-1] if not indicators.empty else None,
        "volume_status": "N/A",
        "news_pulse": news_pulse,
        "ticker": ticker,
    }


def calculate_rsi(series: pd.Series, period: int = 14):
    price = to_numeric_series(series).dropna()
    if price.empty or len(price) < period + 1:
        return pd.Series(dtype="float64")

    delta = price.diff()
    gain = delta.clip(lower=0.0)
    loss = -delta.clip(upper=0.0)

    avg_gain = gain.rolling(window=period, min_periods=period).mean()
    avg_loss = loss.rolling(window=period, min_periods=period).mean()

    zero_gain = avg_gain.eq(0)
    zero_loss = avg_loss.eq(0)

    rs = avg_gain / avg_loss.replace(0, np.nan)
    rsi = 100.0 - (100.0 / (1.0 + rs))

    rsi = rsi.mask(zero_loss & ~zero_gain, 100.0)
    rsi = rsi.mask(zero_gain & ~zero_loss, 0.0)
    rsi = rsi.mask(zero_gain & zero_loss, 50.0)

    return pd.to_numeric(rsi, errors="coerce")

def build_indicator_frame(price_series: pd.Series):
    price_series = to_numeric_series(price_series)
    if price_series.empty:
        return pd.DataFrame(columns=["Price", "SMA 20", "SMA 50", "SMA 200", "RSI 14", "1Y Return %"])

    df = pd.DataFrame({"Price": price_series.copy()})
    df["SMA 20"] = price_series.rolling(20, min_periods=20).mean()
    df["SMA 50"] = price_series.rolling(50, min_periods=50).mean()
    df["SMA 200"] = price_series.rolling(200, min_periods=200).mean()
    df["RSI 14"] = calculate_rsi(price_series)

    valid_price = price_series.dropna()
    base_price = valid_price.iloc[0] if not valid_price.empty else np.nan
    if pd.notna(base_price) and base_price != 0:
        df["1Y Return %"] = ((price_series / base_price) - 1.0) * 100.0
    else:
        df["1Y Return %"] = np.nan

    return df

def get_ohlc_frame(data: pd.DataFrame | None, ticker: str, tail: int | None = None):
    open_series = get_series(data, "Open", ticker)
    high_series = get_series(data, "High", ticker)
    low_series = get_series(data, "Low", ticker)
    close_series, _ = get_price_series(data, ticker)

    if open_series is None or high_series is None or low_series is None or close_series is None:
        return pd.DataFrame()

    frame = pd.concat(
        [
            ensure_datetime_index(open_series),
            ensure_datetime_index(high_series),
            ensure_datetime_index(low_series),
            ensure_datetime_index(close_series),
        ],
        axis=1,
    )
    frame.columns = ["Open", "High", "Low", "Close"]
    frame = frame.dropna()

    if frame.empty:
        return pd.DataFrame(columns=["Date", "Open", "High", "Low", "Close"])

    frame = frame.reset_index()

    # The index column can be named Date, Datetime, index, or something else.
    first_col = frame.columns[0]
    if first_col != "Date":
        frame = frame.rename(columns={first_col: "Date"})

    frame["Date"] = pd.to_datetime(frame["Date"], errors="coerce")
    frame = frame.dropna(subset=["Date"])

    if tail is not None:
        frame = frame.tail(tail).copy()

    return frame


def wave_default_bar_count(ohlc: pd.DataFrame | None, interval_hint: str = "") -> int:
    hint = str(interval_hint or "").strip().lower()
    if hint == "1wk":
        return 26
    if ohlc is not None and not ohlc.empty and "Date" in ohlc.columns:
        dates = pd.to_datetime(ohlc["Date"], errors="coerce").dropna()
        if len(dates) >= 3:
            median_gap = dates.sort_values().diff().dropna().median()
            if pd.notna(median_gap) and median_gap >= pd.Timedelta(days=5):
                return 26
    return 126


def wave_year_bar_count(ohlc: pd.DataFrame | None, interval_hint: str = "") -> int:
    hint = str(interval_hint or "").strip().lower()
    if hint == "1wk":
        return 52
    if ohlc is not None and not ohlc.empty and "Date" in ohlc.columns:
        dates = pd.to_datetime(ohlc["Date"], errors="coerce").dropna()
        if len(dates) >= 3:
            median_gap = dates.sort_values().diff().dropna().median()
            if pd.notna(median_gap) and median_gap >= pd.Timedelta(days=5):
                return 52
    return 252


def _wave_span_days(ohlc: pd.DataFrame | None) -> float:
    if ohlc is None or ohlc.empty or "Date" not in ohlc.columns:
        return 0.0
    dates = pd.to_datetime(ohlc["Date"], errors="coerce").dropna()
    if len(dates) < 2:
        return 0.0
    return float((dates.max() - dates.min()).days)


def resolve_wave_ohlc_window(
    base_ohlc: pd.DataFrame | None,
    ticker: str,
    period: str,
    interval_hint: str,
    bar_count: int,
    min_span_days: int,
) -> pd.DataFrame:
    window = base_ohlc.tail(bar_count).copy() if base_ohlc is not None and not base_ohlc.empty else pd.DataFrame()
    if _wave_span_days(window) >= float(min_span_days):
        return window
    if not str(ticker or "").strip():
        return window
    fetched = fetch_daily_data([ticker], str(period or DEFAULT_PERIOD or "1y"), str(interval_hint or DEFAULT_INTERVAL or "1d"))
    fetched_ohlc = get_ohlc_frame(fetched, ticker, tail=bar_count)
    if fetched_ohlc is not None and not fetched_ohlc.empty:
        return fetched_ohlc
    return window


def _wave_lang_zh() -> bool:
    return get_language() == "zh_TW" or get_lang() == "繁體中文"


def _wave_window_label(interval_hint: str = "") -> str:
    zh = _wave_lang_zh()
    if str(interval_hint or "").strip().lower() == "1wk":
        return "近 6 個月週線" if zh else "6-month weekly lens"
    return "近 6 個月日線" if zh else "6-month daily lens"


def _wave_year_window_label(interval_hint: str = "") -> str:
    zh = _wave_lang_zh()
    if str(interval_hint or "").strip().lower() == "1wk":
        return "近 1 年週線" if zh else "1-year weekly lens"
    return "近 1 年日線" if zh else "1-year daily lens"


def _extract_wave_turning_points(ohlc: pd.DataFrame) -> list[dict]:
    if ohlc is None or ohlc.empty or len(ohlc) < 14:
        return []

    frame = ohlc.copy().reset_index(drop=True)
    frame["Date"] = pd.to_datetime(frame["Date"], errors="coerce")
    frame = frame.dropna(subset=["Date", "Open", "High", "Low", "Close"]).reset_index(drop=True)
    if len(frame) < 14:
        return []

    closes = pd.to_numeric(frame["Close"], errors="coerce").to_numpy(dtype=float)
    highs = pd.to_numeric(frame["High"], errors="coerce").to_numpy(dtype=float)
    lows = pd.to_numeric(frame["Low"], errors="coerce").to_numpy(dtype=float)
    valid_moves = pd.Series(closes).pct_change().abs().dropna()
    move_threshold = float(np.clip(valid_moves.median() * 100 * 8 if not valid_moves.empty else 5.0, 3.5, 13.0))
    window = int(np.clip(len(frame) // 18, 2, 6))

    points: list[dict] = []
    overall_up = bool(closes[-1] >= closes[0])
    points.append(
        {
            "index": 0,
            "Date": frame.at[0, "Date"],
            "Price": float(lows[0] if overall_up else highs[0]),
            "kind": "low" if overall_up else "high",
        }
    )

    for idx in range(window, len(frame) - window):
        segment = closes[idx - window : idx + window + 1]
        if np.isnan(segment).any():
            continue
        if closes[idx] >= float(segment.max()):
            points.append(
                {
                    "index": idx,
                    "Date": frame.at[idx, "Date"],
                    "Price": float(highs[idx]),
                    "kind": "high",
                }
            )
        if closes[idx] <= float(segment.min()):
            points.append(
                {
                    "index": idx,
                    "Date": frame.at[idx, "Date"],
                    "Price": float(lows[idx]),
                    "kind": "low",
                }
            )

    last_kind = "high" if closes[-1] >= closes[-2] else "low"
    points.append(
        {
            "index": len(frame) - 1,
            "Date": frame.at[len(frame) - 1, "Date"],
            "Price": float(highs[-1] if last_kind == "high" else lows[-1]),
            "kind": last_kind,
        }
    )

    points = sorted(points, key=lambda item: (int(item["index"]), 0 if item["kind"] == "low" else 1))
    compressed: list[dict] = []
    for point in points:
        if not compressed:
            compressed.append(point)
            continue
        last = compressed[-1]
        if point["kind"] == last["kind"]:
            if point["kind"] == "high" and point["Price"] >= last["Price"]:
                compressed[-1] = point
            elif point["kind"] == "low" and point["Price"] <= last["Price"]:
                compressed[-1] = point
            continue
        compressed.append(point)

    filtered: list[dict] = []
    for idx, point in enumerate(compressed):
        if not filtered:
            filtered.append(point)
            continue
        last = filtered[-1]
        if point["kind"] == last["kind"]:
            if point["kind"] == "high" and point["Price"] >= last["Price"]:
                filtered[-1] = point
            elif point["kind"] == "low" and point["Price"] <= last["Price"]:
                filtered[-1] = point
            continue
        move_pct = abs((float(point["Price"]) - float(last["Price"])) / float(last["Price"])) * 100 if float(last["Price"]) else 0.0
        if move_pct >= move_threshold or idx == len(compressed) - 1:
            filtered.append(point)

    return filtered[-9:] if len(filtered) > 9 else filtered


def build_wave_snapshot(ohlc: pd.DataFrame | None, interval_hint: str = "") -> dict:
    if ohlc is None or ohlc.empty:
        return {}

    frame = ohlc.copy().reset_index(drop=True)
    if len(frame) < 12:
        return {}

    points = _extract_wave_turning_points(frame)
    if len(points) < 4:
        return {}

    trend_up = bool(pd.to_numeric(frame["Close"], errors="coerce").iloc[-1] >= pd.to_numeric(frame["Close"], errors="coerce").iloc[0])
    desired_start = "low" if trend_up else "high"
    while len(points) >= 4 and points[0]["kind"] != desired_start:
        points = points[1:]
    if len(points) > 9:
        points = points[-9:]
    if len(points) < 4:
        return {}

    labels = ["0", "1", "2", "3", "4", "5", "A", "B", "C"][: len(points)]
    points_df = pd.DataFrame(points).copy()
    points_df["Label"] = labels
    points_df["Date"] = pd.to_datetime(points_df["Date"], errors="coerce")
    points_df["Phase"] = points_df["Label"].map(
        {
            "0": "Origin",
            "1": "Wave 1",
            "2": "Wave 2",
            "3": "Wave 3",
            "4": "Wave 4",
            "5": "Wave 5",
            "A": "Wave A",
            "B": "Wave B",
            "C": "Wave C",
        }
    )

    zh = _wave_lang_zh()
    current_label = labels[-1]
    current_phase = (
        {
            "0": "起漲原點",
            "1": "Wave 1 啟動",
            "2": "Wave 2 回撤",
            "3": "Wave 3 推進",
            "4": "Wave 4 整理",
            "5": "Wave 5 末段",
            "A": "A 浪修正",
            "B": "B 浪反彈",
            "C": "C 浪確認",
        }.get(current_label, "波段推進")
        if zh else
        {
            "0": "origin build",
            "1": "Wave 1 launch",
            "2": "Wave 2 retracement",
            "3": "Wave 3 expansion",
            "4": "Wave 4 consolidation",
            "5": "Wave 5 extension",
            "A": "Wave A correction",
            "B": "Wave B rebound",
            "C": "Wave C confirmation",
        }.get(current_label, "wave structure")
    )

    def _swing(start_idx: int, end_idx: int) -> float:
        if max(start_idx, end_idx) >= len(points_df):
            return float("nan")
        return float(points_df.iloc[end_idx]["Price"] - points_df.iloc[start_idx]["Price"])

    notes: list[str] = []
    rule_badges: list[str] = []

    wave1 = abs(_swing(0, 1))
    wave2 = abs(_swing(1, 2))
    wave3 = abs(_swing(2, 3))
    wave4 = abs(_swing(3, 4))

    if len(points_df) >= 3 and wave1 > 0:
        retrace = wave2 / wave1 if not pd.isna(wave2) else float("nan")
        if pd.notna(retrace):
            if 0.5 <= retrace <= 0.75:
                notes.append(
                    f"Wave 2 回撤約 {retrace:.2f} 倍，接近 0.618 常見區。" if zh else
                    f"Wave 2 retraced about {retrace:.2f}x, close to the common 0.618 zone."
                )
            else:
                notes.append(
                    f"Wave 2 回撤約 {retrace:.2f} 倍，屬於可觀察的修正幅度。" if zh else
                    f"Wave 2 retraced about {retrace:.2f}x, which gives us a readable corrective depth."
                )
        invalid_wave2 = points_df.iloc[2]["Price"] < points_df.iloc[0]["Price"] if trend_up else points_df.iloc[2]["Price"] > points_df.iloc[0]["Price"]
        rule_badges.append("Wave 2 未跌破原點" if zh else "Wave 2 origin intact") if not invalid_wave2 else rule_badges.append("Wave 2 跌破原點" if zh else "Wave 2 broke origin")

    if len(points_df) >= 4 and wave1 > 0 and pd.notna(wave3):
        wave3_ratio = wave3 / wave1
        if wave3_ratio >= 1.5:
            notes.append(
                f"Wave 3 延伸約 {wave3_ratio:.2f} 倍，接近強勢推動波特徵。" if zh else
                f"Wave 3 is extending at roughly {wave3_ratio:.2f}x Wave 1, which fits a stronger impulse profile."
            )
            rule_badges.append("Wave 3 延伸" if zh else "Wave 3 extended")
        else:
            notes.append(
                f"Wave 3 約為 Wave 1 的 {wave3_ratio:.2f} 倍，暫時沒有極端延伸。" if zh else
                f"Wave 3 is about {wave3_ratio:.2f}x Wave 1, so extension is present but not extreme."
            )

    if len(points_df) >= 5 and pd.notna(wave4):
        invalid_wave4 = points_df.iloc[4]["Price"] <= points_df.iloc[1]["Price"] if trend_up else points_df.iloc[4]["Price"] >= points_df.iloc[1]["Price"]
        rule_badges.append("Wave 4 未重疊 Wave 1" if zh else "Wave 4 avoids Wave 1 overlap") if not invalid_wave4 else rule_badges.append("Wave 4 重疊 Wave 1" if zh else "Wave 4 overlaps Wave 1")
        if current_label in {"4", "5", "A", "B", "C"}:
            notes.append(
                "Wave 4 偏整理，適合搭配量能與均線看延續。" if zh else
                "Wave 4 looks more sideways, so volume and moving averages matter more for the next confirmation."
            )

    headline = (
        f"{_wave_window_label(interval_hint)}波浪結構偏向{'上升推動' if trend_up else '下降推動'}，目前落在 {current_phase}。"
        if zh else
        f"The {_wave_window_label(interval_hint)} wave map leans {'upward impulse' if trend_up else 'downward impulse'}, with price currently sitting in {current_phase}."
    )
    if current_label in {"A", "B", "C"}:
        headline = (
            f"{_wave_window_label(interval_hint)}已進入修正段，現在較像 {current_phase}。"
            if zh else
            f"The {_wave_window_label(interval_hint)} structure has moved into correction, and the current read is closer to {current_phase}."
        )

    guidance = (
        "這是依近 6 個月主要轉折點做的波浪標註，適合拿來判讀結構，不適合單獨當成精準進出場訊號；請搭配均線、MACD、量能一起看。"
        if zh else
        "These labels are heuristic wave annotations built from the main turning points in the last six months. They are useful for structure, but should still be paired with moving averages, MACD, and volume."
    )

    return {
        "points": points_df,
        "headline": headline,
        "notes": notes[:3],
        "rule_badges": rule_badges[:3],
        "guidance": guidance,
        "current_label": current_label,
        "trend_up": trend_up,
        "window_label": _wave_window_label(interval_hint),
    }


def render_candlestick_chart(
    ohlc: pd.DataFrame,
    title: str,
    subtitle: str = "",
    height: int = 420,
    show_ma: bool = False,
    wave_snapshot: dict | None = None,
    window_label: str = "",
    show_wave: bool = True,
):
    if ohlc is None or ohlc.empty:
        st.info("Chart data is not available.")
        return

    chart_df = ohlc.copy()
    chart_df["Date"] = pd.to_datetime(chart_df["Date"])
    chart_df["Up"] = chart_df["Close"] >= chart_df["Open"]
    chart_df["Color"] = chart_df["Up"].map({True: "#19c37d", False: "#ff5b5b"})

    if show_ma:
        chart_df["SMA 20"] = chart_df["Close"].rolling(20).mean()
        chart_df["SMA 50"] = chart_df["Close"].rolling(50).mean()

    wave_snapshot = (wave_snapshot or build_wave_snapshot(chart_df)) if show_wave else {}
    rule_badges = wave_snapshot.get("rule_badges", []) if isinstance(wave_snapshot, dict) else []
    badge_html = "".join(
        f'<span style="display:inline-flex;align-items:center;justify-content:center;padding:7px 12px;border-radius:999px;background:rgba(84,214,255,.12);border:1px solid rgba(84,214,255,.20);color:#9ae9ff;font-size:11px;font-weight:900;letter-spacing:.06em;text-transform:uppercase;">{escape(str(item))}</span>'
        for item in rule_badges
        if str(item).strip()
    )
    top_meta = []
    if window_label:
        top_meta.append(window_label)
    if isinstance(wave_snapshot, dict) and wave_snapshot.get("window_label"):
        top_meta.append(str(wave_snapshot.get("window_label")))
    meta_text = " · ".join(dict.fromkeys([item for item in top_meta if item]))

    st.markdown(
        f"""
        <div class="chart-shell">
            <div style="display:flex; gap:16px; justify-content:space-between; align-items:flex-start; flex-wrap:wrap;">
                <div>
                    <div class="chart-title">{escape(title)}</div>
                    <div class="chart-copy">{escape(subtitle)}</div>
                </div>
                <div style="display:flex; flex-wrap:wrap; gap:8px; justify-content:flex-end;">
                    {f'<span style="display:inline-flex;align-items:center;justify-content:center;padding:7px 12px;border-radius:999px;background:rgba(188,120,255,.13);border:1px solid rgba(188,120,255,.18);color:#e7c8ff;font-size:11px;font-weight:900;letter-spacing:.06em;text-transform:uppercase;">{escape(meta_text)}</span>' if meta_text else ''}
                    {badge_html}
                </div>
            </div>
        </div>
        """,
        unsafe_allow_html=True,
    )

    base = alt.Chart(chart_df).encode(
        x=alt.X(
            "Date:T",
            axis=alt.Axis(
                title=None,
                labelColor="#c9d4f0",
                grid=False,
                tickColor="#334155",
                domainColor="rgba(201,212,240,0.18)",
                labelPadding=10,
            ),
        ),
        tooltip=[
            alt.Tooltip("Date:T", title="Date"),
            alt.Tooltip("Open:Q", format=",.2f"),
            alt.Tooltip("High:Q", format=",.2f"),
            alt.Tooltip("Low:Q", format=",.2f"),
            alt.Tooltip("Close:Q", format=",.2f"),
        ],
    )

    close_curve = base.mark_line(color="rgba(111,203,255,0.34)", strokeWidth=1.5, interpolate="monotone").encode(
        y=alt.Y(
            "Close:Q",
            axis=alt.Axis(
                title=None,
                labelColor="#c9d4f0",
                gridColor="rgba(201,212,240,0.12)",
                domain=False,
                tickColor="#334155",
            ),
        )
    )

    wick = base.mark_rule(strokeWidth=1.3).encode(
        y=alt.Y(
            "Low:Q",
            axis=alt.Axis(
                title=None,
                labelColor="#c9d4f0",
                gridColor="rgba(201,212,240,0.12)",
                domain=False,
                tickColor="#334155",
            ),
        ),
        y2="High:Q",
        color=alt.Color("Color:N", scale=None, legend=None),
    )

    body = base.mark_bar(size=7).encode(
        y=alt.Y(
            "Open:Q",
            axis=alt.Axis(
                title=None,
                labelColor="#c9d4f0",
                gridColor="rgba(201,212,240,0.12)",
                domain=False,
                tickColor="#334155",
            ),
        ),
        y2="Close:Q",
        color=alt.Color("Color:N", scale=None, legend=None),
    )

    layers = [close_curve, wick, body]

    if show_ma:
        sma20 = base.mark_line(color="#7cc7ff", strokeWidth=1.6).encode(y="SMA 20:Q")
        sma50 = base.mark_line(color="#f3b94d", strokeWidth=1.6).encode(y="SMA 50:Q")
        layers.extend([sma20, sma50])

    if isinstance(wave_snapshot, dict):
        wave_points = wave_snapshot.get("points")
        if isinstance(wave_points, pd.DataFrame) and not wave_points.empty:
            wave_base = alt.Chart(wave_points).encode(
                x=alt.X("Date:T"),
                y=alt.Y("Price:Q"),
                tooltip=[
                    alt.Tooltip("Date:T", title="Date"),
                    alt.Tooltip("Phase:N", title="Wave"),
                    alt.Tooltip("Price:Q", format=",.2f"),
                ],
            )
            wave_line = wave_base.mark_line(color="#63e6ff", strokeWidth=3.0, interpolate="monotone").encode()
            wave_points_layer = wave_base.mark_point(
                filled=True,
                size=100,
                color="#86efff",
                stroke="#081220",
                strokeWidth=1.5,
            ).encode()
            wave_labels = wave_base.mark_text(
                dy=-14,
                fontSize=13,
                fontWeight="bold",
                color="#f5f1ff",
            ).encode(text="Label:N")
            layers.extend([wave_line, wave_points_layer, wave_labels])

    chart = (
        alt.layer(*layers)
        .resolve_scale(y="shared")
        .properties(height=height)
        .configure(background="#0f172a")
        .configure_view(stroke=None, fill="#0f172a")
        .configure_axis(
            domain=False,
            labelFont="Inter",
            titleFont="Inter",
            labelColor="#c9d4f0",
            gridColor="rgba(201,212,240,0.12)",
        )
    )

    st.altair_chart(chart, use_container_width=True)

    if isinstance(wave_snapshot, dict) and wave_snapshot:
        notes = wave_snapshot.get("notes", []) or []
        note_html = "".join(
            f'<li style="margin:0 0 8px 18px; color:rgba(229,236,255,.84); line-height:1.62;">{escape(str(item))}</li>'
            for item in notes
            if str(item).strip()
        )
        st.markdown(
            f"""
            <div style="margin-top:14px; padding:18px 20px; border-radius:20px; border:1px solid rgba(84,214,255,.14); background:
                radial-gradient(circle at top left, rgba(84,214,255,.10) 0%, rgba(84,214,255,0) 30%),
                linear-gradient(180deg, rgba(9,18,34,.96) 0%, rgba(11,20,38,.98) 100%);
                box-shadow: inset 0 1px 0 rgba(255,255,255,.03), 0 14px 34px rgba(0,0,0,.16);">
                <div style="font-size:12px; font-weight:900; letter-spacing:.14em; text-transform:uppercase; color:#63e6ff;">Wave Lens</div>
                <div style="font-size:26px; font-weight:900; line-height:1.18; color:#f7fbff; margin-top:6px;">{escape(str(wave_snapshot.get("headline", "")))}</div>
                {f'<ul style="margin:14px 0 0 0; padding:0;">{note_html}</ul>' if note_html else ''}
                <div style="margin-top:12px; color:rgba(201,212,240,.74); line-height:1.62;">{escape(str(wave_snapshot.get("guidance", "")))}</div>
            </div>
            """,
            unsafe_allow_html=True,
        )


def get_intraday_snapshot(intraday_data: pd.DataFrame | None, ticker: str):
    price_series, field_name = get_price_series(intraday_data, ticker)
    volume_series = get_series(intraday_data, "Volume", ticker)
    if price_series is None or price_series.empty:
        return {
            "available": False,
            "last_price": pd.NA,
            "change_pct": pd.NA,
            "timestamp": None,
            "field_name": "N/A",
            "volume": pd.NA,
            "chart": pd.DataFrame(),
        }
    latest_ts = price_series.index[-1]
    last_price = price_series.iloc[-1]
    prev_price = price_series.iloc[-2] if len(price_series) >= 2 else pd.NA
    change_pct = ((last_price / prev_price) - 1) * 100 if pd.notna(prev_price) and prev_price != 0 else pd.NA
    chart = pd.DataFrame({"Intraday Price": price_series.tail(78)})
    return {
        "available": True,
        "last_price": last_price,
        "change_pct": change_pct,
        "timestamp": latest_ts,
        "field_name": field_name,
        "volume": volume_series.iloc[-1] if volume_series is not None and not volume_series.empty else pd.NA,
        "chart": chart,
    }


def infer_news_impact(title: str, summary: str = ""):
    text = f"{title} {summary}".lower()
    pos = sum(1 for kw in POSITIVE_NEWS_KEYWORDS if kw in text)
    neg = sum(1 for kw in NEGATIVE_NEWS_KEYWORDS if kw in text)
    score = pos - neg

    if score >= 2:
        return "Likely bullish", score, "Headline language leans positive for demand, margins, upgrades, or growth."
    if score <= -2:
        return "Likely bearish", score, "Headline language leans negative for guidance, regulation, demand, or execution risk."
    if score > 0:
        return "Mildly bullish", score, "Some positive wording is present, but the signal is not strong."
    if score < 0:
        return "Mildly bearish", score, "Some negative wording is present, but the signal is not strong."
    return "Neutral / mixed", score, "The headline is informational or the signals conflict."


def infer_news_confidence(relevance: int, impact_score: int):
    strength = abs(impact_score)
    total = relevance + strength
    if total >= 6:
        return "High"
    if total >= 3:
        return "Medium"
    return "Low"


def build_news_pulse(news_items: list[dict]):
    if not news_items:
        return {"score": 0.0, "label": "Flat", "up": 0, "down": 0, "neutral": 0}
    weighted = 0.0
    up = down = neutral = 0
    for item in news_items:
        weight = 1 + min(item.get("relevance", 0), 4) * 0.25
        score = item.get("impact_score", 0)
        weighted += score * weight
        label = item.get("impact_label", "Neutral / mixed")
        if "bullish" in label.lower():
            up += 1
        elif "bearish" in label.lower():
            down += 1
        else:
            neutral += 1
    avg = weighted / max(len(news_items), 1)
    if avg >= 1.4:
        label = "News tilt: bullish"
    elif avg <= -1.4:
        label = "News tilt: bearish"
    else:
        label = "News tilt: mixed"
    return {"score": avg, "label": label, "up": up, "down": down, "neutral": neutral}




CATALYST_KEYWORDS = {
    "Earnings": {"earnings", "revenue", "guidance", "eps", "beat", "miss", "forecast", "quarter", "margin"},
    "AI Demand": {"ai", "gpu", "data center", "chips", "accelerator", "server", "inference", "training", "demand"},
    "Regulation": {"regulation", "regulator", "antitrust", "probe", "ban", "export", "tariff", "lawsuit", "fine"},
    "Macro": {"inflation", "rates", "fed", "economy", "macro", "cpi", "ppi", "jobs", "treasury", "recession"},
    "Analyst Action": {"upgrade", "downgrade", "price target", "outperform", "underperform", "buy rating", "sell rating"},
    "Supply Chain": {"supply", "shipment", "capacity", "factory", "shortage", "inventory", "lead time", "wafer", "production"},
}


def classify_catalyst(item: dict) -> str:
    text = f"{item.get('title','')} {item.get('summary','')} {item.get('impact_reason','')}".lower()
    scores = {}
    for category, keywords in CATALYST_KEYWORDS.items():
        scores[category] = sum(1 for kw in keywords if kw in text)
    best = max(scores, key=scores.get) if scores else "Macro"
    return best if scores.get(best, 0) > 0 else "Macro"


def build_catalyst_engine(news_items: list[dict]) -> dict:
    categories = {name: {"count": 0, "score": 0.0} for name in CATALYST_KEYWORDS}
    if not news_items:
        return {
            "dominant": "Macro",
            "net_score": 0.0,
            "rows": [],
            "headline": "Catalysts are light and mixed.",
            "turning_point": "No strong category is dominating current news flow.",
        }

    for item in news_items:
        category = classify_catalyst(item)
        weight = 1 + min(int(item.get("relevance", 0)), 4) * 0.25
        impact = float(item.get("impact_score", 0))
        categories[category]["count"] += 1
        categories[category]["score"] += impact * weight

    rows = []
    for category, values in categories.items():
        count = values["count"]
        score = values["score"]
        bias = "Bullish" if score > 0.4 else "Bearish" if score < -0.4 else "Mixed"
        intensity = min(100, int(abs(score) * 18 + count * 10)) if count else 8
        rows.append({
            "category": category,
            "count": count,
            "score": score,
            "bias": bias,
            "intensity": intensity,
        })

    rows.sort(key=lambda row: (row["count"], abs(row["score"])), reverse=True)
    dominant = rows[0]["category"] if rows else "Macro"
    net_score = sum(row["score"] for row in rows)

    if net_score >= 2:
        headline = f"{dominant} is the main upside catalyst right now."
    elif net_score <= -2:
        headline = f"{dominant} is the main pressure point right now."
    else:
        headline = f"{dominant} is active, but the broader catalyst mix is still balanced."

    turning_point = {
        "Earnings": "Watch whether the next report confirms or breaks the current narrative.",
        "AI Demand": "Demand commentary can quickly accelerate momentum in semis and infrastructure names.",
        "Regulation": "Policy or legal headlines can shift valuation fast even without a change in operations.",
        "Macro": "Rate and inflation sensitivity can overpower stock-specific news in the short term.",
        "Analyst Action": "Analyst revisions often act as short, sharp catalyst bursts rather than long trends.",
        "Supply Chain": "Shipment, inventory, and capacity updates often show up in margins before price follows.",
    }.get(dominant, "The catalyst picture is mixed.")

    return {
        "dominant": dominant,
        "net_score": net_score,
        "rows": rows,
        "headline": headline,
        "turning_point": turning_point,
    }


def calculate_macd(series: pd.Series):
    s = to_numeric_series(series).dropna()
    if s.empty:
        empty = pd.Series(dtype="float64")
        return empty, empty, empty

    ema12 = s.ewm(span=12, adjust=False, min_periods=12).mean()
    ema26 = s.ewm(span=26, adjust=False, min_periods=26).mean()
    macd_line = ema12 - ema26
    signal_line = macd_line.ewm(span=9, adjust=False, min_periods=9).mean()
    hist = macd_line - signal_line

    return (
        pd.to_numeric(macd_line, errors="coerce"),
        pd.to_numeric(signal_line, errors="coerce"),
        pd.to_numeric(hist, errors="coerce"),
    )

def build_trading_lab(price_series: pd.Series, volume_series: pd.Series | None) -> dict:
    series = to_numeric_series(price_series).dropna()
    if series.empty:
        return {}

    macd_line, signal_line, hist = calculate_macd(series)
    sma20 = series.rolling(20, min_periods=20).mean()
    std20 = series.rolling(20, min_periods=20).std()
    upper = sma20 + 2 * std20
    lower = sma20 - 2 * std20

    last_price = series.iloc[-1]
    tail20 = series.tail(20)
    support = tail20.nsmallest(min(3, len(tail20))).mean() if not tail20.empty else np.nan
    resistance = tail20.nlargest(min(3, len(tail20))).mean() if not tail20.empty else np.nan

    tags = []
    if not upper.empty and pd.notna(upper.iloc[-1]) and last_price > upper.iloc[-1]:
        tags.append("Breakout stretch")
    elif not lower.empty and pd.notna(lower.iloc[-1]) and last_price < lower.iloc[-1]:
        tags.append("Breakdown risk")
    elif not sma20.empty and pd.notna(sma20.iloc[-1]) and pd.notna(support) and last_price < sma20.iloc[-1] and last_price > support:
        tags.append("Pullback zone")
    else:
        tags.append("Trend continuation")

    hist_valid = hist.dropna()
    if len(hist_valid) >= 2:
        if hist_valid.iloc[-1] > 0 and hist_valid.iloc[-1] > hist_valid.iloc[-2]:
            tags.append("MACD improving")
        elif hist_valid.iloc[-1] < 0 and hist_valid.iloc[-1] < hist_valid.iloc[-2]:
            tags.append("MACD weakening")

    volume_ratio = pd.NA
    if volume_series is not None and not volume_series.empty:
        vol = to_numeric_series(volume_series).dropna()
        if not vol.empty:
            avg50 = vol.tail(50).mean()
            if pd.notna(avg50) and avg50 != 0:
                volume_ratio = vol.iloc[-1] / avg50
                if volume_ratio >= 1.3:
                    tags.append("Volume confirmation")
                elif volume_ratio <= 0.8:
                    tags.append("Light volume")

    setup = "Balanced"
    if len([t for t in tags if t in ("Trend continuation", "MACD improving", "Volume confirmation")]) >= 2:
        setup = "Momentum-led"
    elif "Pullback zone" in tags:
        setup = "Pullback watch"
    elif "Breakdown risk" in tags or "MACD weakening" in tags:
        setup = "Risk-off"

    bb_upper = upper.iloc[-1] if not upper.empty else pd.NA
    bb_mid = sma20.iloc[-1] if not sma20.empty else pd.NA
    bb_lower = lower.iloc[-1] if not lower.empty else pd.NA
    macd_last = macd_line.dropna().iloc[-1] if not macd_line.dropna().empty else pd.NA
    signal_last = signal_line.dropna().iloc[-1] if not signal_line.dropna().empty else pd.NA
    hist_last = hist_valid.iloc[-1] if not hist_valid.empty else pd.NA

    return {
        "macd": macd_last,
        "macd_signal": signal_last,
        "macd_hist": hist_last,
        "bb_upper": bb_upper,
        "bb_mid": bb_mid,
        "bb_lower": bb_lower,
        "support": support,
        "resistance": resistance,
        "volume_ratio": volume_ratio,
        "setup": setup,
        "tags": tags,
    }

def enrich_pro_analysis(analysis: dict, price_series: pd.Series, volume_series: pd.Series | None, news_items: list[dict], active_lens_title: str | None = None, intraday: dict | None = None) -> dict:
    catalyst = build_catalyst_engine(news_items)
    trading_lab = build_trading_lab(price_series, volume_series)

    pro_score = analysis["score"]
    if catalyst["net_score"] >= 2:
        pro_score += 1
    elif catalyst["net_score"] <= -2:
        pro_score -= 1

    tags = []
    for tag in trading_lab.get("tags", []):
        if "Breakout" in tag or "improving" in tag or "confirmation" in tag:
            tags.append(("up", tag))
        elif "Breakdown" in tag or "weakening" in tag:
            tags.append(("down", tag))
        else:
            tags.append(("neutral", tag))

    alerts = []
    if analysis["signal"] == "HOLD" and pro_score >= 4:
        alerts.append("Setup is close to flipping from HOLD to BUY.")
    if analysis["signal"] == "BUY" and catalyst["net_score"] < -1.5:
        alerts.append("News pulse is deteriorating against the bullish trend.")
    if analysis["signal"] == "SELL" and trading_lab.get("setup") == "Pullback watch":
        alerts.append("Selling pressure is still present, but a reactive bounce zone is forming.")
    if abs(catalyst["net_score"]) >= 3:
        alerts.append(f"{catalyst['dominant']} headlines are now a major directional driver.")

    analysis["catalyst_engine"] = catalyst
    analysis["trading_lab"] = trading_lab
    analysis["pro_tags"] = tags
    analysis["alerts"] = alerts
    analysis["pro_score"] = pro_score
    analysis["active_lens_title"] = active_lens_title or "Position View"
    analysis["lens_alerts"] = build_lens_alerts(analysis, intraday or {})
    return analysis


