def _extract_tpex_field(row: dict, keywords: tuple[str, ...]) -> str:
    for key, value in row.items():
        key_text = str(key or "")
        if any(token in key_text for token in keywords):
            value_text = str(value or "").strip()
            if value_text:
                return value_text
    return ""


@st.cache_data(ttl=1800, show_spinner=False)
def fetch_tpex_snapshot_bundle(code: str) -> dict:
    code = _extract_security_code(code)
    if not code:
        return {}

    endpoints = {
        "quotes": "https://www.tpex.org.tw/openapi/v1/tpex_mainboard_quotes",
        "valuation": "https://www.tpex.org.tw/openapi/v1/tpex_mainboard_peratio_analysis",
        "flow": "https://www.tpex.org.tw/openapi/v1/tpex_3insti_trading",
    }

    result: dict[str, dict] = {}
    for key, url in endpoints.items():
        try:
            payload = _fetch_json_url(url, timeout=20)
        except Exception as exc:
            result[key] = {"source": url, "error": str(exc)}
            continue
        rows = payload if isinstance(payload, list) else payload.get("data", []) if isinstance(payload, dict) else []
        row = _match_row_by_security_code(rows, code)
        if not row:
            result[key] = {"source": url, "error": "No matching code."}
            continue
        result[key] = {"source": url, "row": row}

    valuation_row = result.get("valuation", {}).get("row", {}) or {}
    flow_row = result.get("flow", {}).get("row", {}) or {}
    quote_row = result.get("quotes", {}).get("row", {}) or {}

    return {
        "source": "TPEx OpenAPI",
        "date": _find_value_by_keywords(
            valuation_row or quote_row or flow_row,
            ("日期", "Date"),
        ),
        "valuation_date": _find_value_by_keywords(valuation_row, ("日期", "Date")),
        "quote_date": _find_value_by_keywords(quote_row, ("日期", "Date")),
        "flow_date": _find_value_by_keywords(flow_row, ("日期", "Date")),
        "pe": _find_value_by_keywords(valuation_row, ("本益比", "PE")),
        "yield": _find_value_by_keywords(valuation_row, ("殖利率", "Yield")),
        "pb": _find_value_by_keywords(valuation_row, ("股價淨值比", "P/B", "PB")),
        "foreign_net": _find_value_by_keywords(flow_row, ("外資及陸資買賣超", "外資買賣超")),
        "trust_net": _find_value_by_keywords(flow_row, ("投信買賣超",)),
        "dealer_net": _find_value_by_keywords(flow_row, ("自營商買賣超",)),
        "close": _find_value_by_keywords(quote_row, ("收盤", "Close")),
        "valuation_error": str(result.get("valuation", {}).get("error", "") or ""),
        "quote_error": str(result.get("quotes", {}).get("error", "") or ""),
        "flow_error": str(result.get("flow", {}).get("error", "") or ""),
        "error": str(result.get("flow", {}).get("error", "") or result.get("valuation", {}).get("error", "") or result.get("quotes", {}).get("error", "") or ""),
    }


@st.cache_data(ttl=21600, show_spinner=False)
def fetch_monthly_revenue_snapshot(ticker: str) -> dict:
    code = ticker_base_code(ticker)
    if not code or is_taiwan_active_etf(ticker):
        return {}

    is_otc = str(ticker or "").upper().endswith(".TWO")
    url = (
        "https://www.tpex.org.tw/openapi/v1/mopsfin_t187ap05_O"
        if is_otc
        else "https://openapi.twse.com.tw/v1/opendata/t187ap05_L"
    )

    try:
        payload = _fetch_json_url(url, timeout=25)
    except Exception as exc:
        return {"source": url, "error": str(exc)}

    rows = payload if isinstance(payload, list) else payload.get("data", []) if isinstance(payload, dict) else []
    candidates = [row for row in rows if _extract_row_code(row) == code]
    if not candidates:
        return {"source": url, "error": "No revenue row matched."}

    candidates.sort(key=_row_sortable_timestamp, reverse=True)
    row = candidates[0]

    return {
        "source": url,
        "period": _find_value_by_keywords(row, ("資料年月", "年月", "年/月", "Month")),
        "revenue": _find_value_by_keywords(
            row,
            ("當月營收", "本月營收", "營業收入-當月營收", "CurrentMonthRevenue"),
        ),
        "mom": _find_value_by_keywords(
            row,
            ("上月比較增減", "較上月增減", "MoM"),
        ),
        "yoy": _find_value_by_keywords(
            row,
            ("去年同月增減", "去年同月增減(%)", "YoY"),
        ),
        "acc_yoy": _find_value_by_keywords(
            row,
            ("前期比較增減", "累計營收增減", "AccumulatedYoY"),
        ),
    }


def _flatten_leaf_dicts(value: object) -> list[dict]:
    if isinstance(value, dict):
        direct_rows: list[dict] = []
        nested_rows: list[dict] = []
        for key, child in value.items():
            if isinstance(child, dict):
                rows = _flatten_leaf_dicts(child)
                if not rows and child:
                    rows = [child]
                nested_rows.extend(rows)
            elif isinstance(child, list):
                if child and all(not isinstance(item, (dict, list)) for item in child):
                    direct_rows.append({str(key): ", ".join(str(item) for item in child if str(item).strip())})
                else:
                    nested_rows.extend(_flatten_leaf_dicts(child))
        if direct_rows:
            return direct_rows + nested_rows
        if value and all(not isinstance(v, (dict, list)) for v in value.values()):
            return [value]
        return nested_rows
    if isinstance(value, list):
        rows: list[dict] = []
        for child in value:
            rows.extend(_flatten_leaf_dicts(child))
        return rows
    return []


def _iter_cbc_dataset_rows(payload: object) -> list[dict]:
    rows = _flatten_leaf_dicts(payload)
    normalized: list[dict] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        flattened = {str(key): value for key, value in row.items() if not isinstance(value, (dict, list))}
        if flattened:
            normalized.append(flattened)
    return normalized


def _extract_best_numeric_value(row: dict, *keyword_groups: tuple[str, ...]) -> str:
    if not isinstance(row, dict) or not row:
        return ""

    normalized_groups = [
        [str(keyword or "").strip().lower() for keyword in group if str(keyword or "").strip()]
        for group in keyword_groups
    ]

    def _compact(text: object) -> str:
        return re.sub(r"[^a-z0-9\u4e00-\u9fff]+", "", str(text or "").lower())

    def _key_matches(key_text: str, keywords: list[str]) -> bool:
        compact_key = _compact(key_text)
        return any(
            keyword in key_text
            or (_compact(keyword) and _compact(keyword) in compact_key)
            for keyword in keywords
        )

    def _numeric_text(value: object) -> str:
        numeric = _safe_float(value)
        if pd.isna(numeric):
            return ""
        raw = str(value or "").strip()
        match = re.search(r"[-+]?(?:\d+\.\d+|\d+)", raw.replace(",", ""))
        if match:
            return match.group(0)
        return str(float(numeric))

    for keywords in normalized_groups:
        for key, value in row.items():
            key_text = str(key or "").strip().lower()
            if not key_text or not _key_matches(key_text, keywords):
                continue
            text_value = _numeric_text(value)
            if text_value:
                return text_value

    excluded_tokens = {
        "日期", "年月", "年季", "date", "month", "day", "year", "代號", "code",
        "幣別", "名稱", "name", "label", "項目", "item", "序號", "index",
    }

    numeric_candidates: list[tuple[int, str]] = []
    for key, value in row.items():
        key_text = str(key or "").strip().lower()
        if any(token in key_text for token in excluded_tokens):
            continue
        text_value = _numeric_text(value)
        if not text_value:
            continue
        priority = 1 if any(token in key_text for token in ("value", "數值", "資料值", "rate", "匯率", "利率")) else 2
        numeric_candidates.append((priority, text_value))

    if not numeric_candidates:
        return ""

    numeric_candidates.sort(key=lambda item: item[0])
    return numeric_candidates[0][1]


def _select_cbc_fx_row(rows: list[dict]) -> dict:
    preferred = ("usd/twd", "usd per twd", "美金", "美元", "新台幣", "us dollar")
    fallback: dict = {}
    for row in rows:
        joined = " ".join([str(k) for k in row.keys()] + [str(v) for v in row.values()]).lower()
        if not fallback:
            fallback = row
        if any(token in joined for token in preferred):
            return row
    return fallback


def _select_cbc_policy_rate_row(rows: list[dict]) -> dict:
    preferred = ("重貼現率", "政策利率", "基準利率", "discount rate", "policy rate")
    fallback: dict = {}
    for row in rows:
        joined = " ".join([str(k) for k in row.keys()] + [str(v) for v in row.values()]).lower()
        if not fallback:
            fallback = row
        if any(token in joined for token in preferred):
            return row
    return fallback



@st.cache_data(ttl=21600, show_spinner=False)
def fetch_cbc_macro_snapshot() -> dict:
    result: dict[str, dict] = {}

    for key, file_name in {
        "fx": "BP01D01",
        "policy_rate": "EG28D01",
    }.items():
        url = f"https://cpx.cbc.gov.tw/API/DataAPI/Get?FileName={file_name}"
        try:
            payload = _fetch_json_url(url, timeout=25)
        except Exception as exc:
            result[key] = {"source": url, "error": str(exc)}
            continue

        rows = _iter_cbc_dataset_rows(payload)
        rows.sort(key=_row_sortable_timestamp, reverse=True)
        if not rows:
            result[key] = {"source": url, "error": "CBC payload had no usable rows."}
            continue

        selected = _select_cbc_fx_row(rows) if key == "fx" else _select_cbc_policy_rate_row(rows)
        value = _extract_best_numeric_value(
            selected,
            ("數值", "Value", "資料值", "數據", "rate", "匯率", "利率"),
        )
        label = _find_value_by_keywords(
            selected,
            ("幣別", "項目", "名稱", "Label", "資料項目", "項目別"),
        )

        if key == "fx":
            label = label or "USD/TWD"
        else:
            label = label or "Policy rate"

        result[key] = {
            "source": url,
            "date": _find_value_by_keywords(selected, ("日期", "Date", "年月日", "資料日期", "統計期")) or str(_row_sortable_timestamp(selected).date()),
            "value": value,
            "label": label,
            "error": "" if value else f"CBC row matched but numeric value could not be parsed. keys={list(selected.keys())[:8]}",
        }

    return result



@st.cache_data(ttl=3600, show_spinner=False)
def fetch_taifex_put_call_snapshot() -> dict:
    url = "https://www.taifex.com.tw/cht/3/pcRatio"
    try:
        html = _fetch_text_url(url, timeout=25, accept="text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")
    except Exception as exc:
        return {"source": url, "error": str(exc)}

    tables: list[pd.DataFrame] = []
    parse_errors: list[str] = []
    for html_source in (html, html.replace("<br>", "<br/>")):
        try:
            tables = pd.read_html(io.StringIO(html_source))
            if tables:
                break
        except Exception as exc:
            parse_errors.append(str(exc))

    for table in tables:
        columns = [str(col) for col in table.columns]
        joined_cols = " ".join(columns).lower()
        if not any(token in joined_cols for token in ("put", "call", "ratio", "賣權", "買權", "比率")):
            continue
        cleaned = table.copy()
        cleaned.columns = [str(col).strip() for col in cleaned.columns]
        cleaned = cleaned.dropna(how="all")
        if cleaned.empty:
            continue
        row = cleaned.iloc[0].to_dict()
        ratio_value = _find_value_by_keywords(row, ("比率", "ratio"))
        if not ratio_value:
            for key, value in row.items():
                key_text = str(key).lower()
                if "比率" in key_text or "ratio" in key_text:
                    ratio_value = str(value)
                    break
        if not ratio_value:
            numeric_values = []
            for value in row.values():
                numeric = _safe_float(value)
                if not pd.isna(numeric) and 0 < numeric < 300:
                    numeric_values.append(float(numeric))
            if numeric_values:
                ratio_value = str(numeric_values[-1])
        if ratio_value:
            return {
                "source": url,
                "date": _find_value_by_keywords(row, ("日期", "Date")),
                "ratio": ratio_value,
                "put_volume": _find_value_by_keywords(row, ("賣權成交量", "Put")),
                "call_volume": _find_value_by_keywords(row, ("買權成交量", "Call")),
                "error": "",
            }

    regex_match = re.search(r"(20\d{2}/\d{1,2}/\d{1,2})\s+([\d,]+)\s+([\d,]+)\s+([\d.]+)", html)
    if regex_match:
        return {
            "source": url,
            "date": regex_match.group(1),
            "put_volume": regex_match.group(2),
            "call_volume": regex_match.group(3),
            "ratio": regex_match.group(4),
            "error": "",
        }

    error_text = parse_errors[-1] if parse_errors else "No usable put/call table found."
    return {"source": url, "error": error_text}



def _build_taiwan_official_dashboard_payload(ticker: str, *, macro_snapshot: dict | None = None) -> dict:
    ticker = str(ticker or "").upper().strip()
    if not is_taiwan_ticker(ticker):
        return {}

    code = ticker_base_code(ticker)
    resolved_macro = dict(macro_snapshot or {})
    macro_payload = _json_request_safe(resolved_macro.get("macro")) if isinstance(resolved_macro.get("macro"), dict) else None
    derivatives_payload = _json_request_safe(resolved_macro.get("derivatives")) if isinstance(resolved_macro.get("derivatives"), dict) else None
    payload = {
        "ticker": ticker,
        "code": code,
        "is_active_etf": is_taiwan_active_etf(ticker),
        "valuation": {},
        "flow": {},
        "foreign_ownership": {},
        "revenue": {},
        "macro": macro_payload if isinstance(macro_payload, dict) else fetch_cbc_macro_snapshot(),
        "derivatives": derivatives_payload if isinstance(derivatives_payload, dict) else fetch_taifex_put_call_snapshot(),
        "errors": {},
    }

    if ticker.endswith(".TWO"):
        tpex = fetch_tpex_snapshot_bundle(code)
        payload["valuation"] = {
            "source": tpex.get("source", "TPEx OpenAPI"),
            "date": tpex.get("date", ""),
            "pe": tpex.get("pe", ""),
            "yield": tpex.get("yield", ""),
            "pb": tpex.get("pb", ""),
            "error": tpex.get("error", ""),
        }
        payload["flow"] = {
            "source": tpex.get("source", "TPEx OpenAPI"),
            "date": tpex.get("flow_date", ""),
            "foreign_net": tpex.get("foreign_net", ""),
            "trust_net": tpex.get("trust_net", ""),
            "dealer_net": tpex.get("dealer_net", ""),
            "error": tpex.get("flow_error", "") or tpex.get("error", ""),
        }
    elif is_taiwan_active_etf(ticker):
        flow_payload = fetch_twse_etf_institutional_flow(ticker)
        record = flow_payload.get("record", {}) or {}
        payload["flow"] = {
            "source": flow_payload.get("source", "TWSE T86 ETF"),
            "date": flow_payload.get("date", ""),
            "foreign_net": record.get("foreign_net", ""),
            "trust_net": record.get("trust_net", ""),
            "dealer_net": record.get("dealer_net", ""),
            "error": flow_payload.get("error", ""),
        }
    else:
        payload["valuation"] = fetch_twse_valuation_snapshot(code)
        payload["flow"] = fetch_twse_stock_institutional_flow(code)
        payload["foreign_ownership"] = fetch_twse_foreign_shareholding_snapshot(code)

    payload["revenue"] = fetch_monthly_revenue_snapshot(ticker)
    payload["errors"] = {
        "valuation": str(payload["valuation"].get("error", "")),
        "flow": str(payload["flow"].get("error", "")),
        "foreign_ownership": str(payload["foreign_ownership"].get("error", "")),
        "revenue": str(payload["revenue"].get("error", "")),
        "cbc_fx": str((payload["macro"].get("fx", {}) or {}).get("error", "")),
        "cbc_rate": str((payload["macro"].get("policy_rate", {}) or {}).get("error", "")),
        "taifex_pcr": str((payload["derivatives"] or {}).get("error", "")),
    }
    return _json_request_safe(payload)


@st.cache_data(ttl=1800, show_spinner=False)
def fetch_taiwan_official_dashboard_snapshot(ticker: str) -> dict:
    return _build_taiwan_official_dashboard_payload(ticker)



def _official_card_html(label: str, value: str, sub: str = "") -> str:
    sub_html = f'<div class="benchmark-sub">{escape(sub)}</div>' if sub else ""
    return (
        '<div class="benchmark-box">'
        f'<div class="benchmark-label">{escape(label)}</div>'
        f'<div class="benchmark-value">{escape(value)}</div>'
        f'{sub_html}'
        '</div>'
    )


def _format_taiwan_lot_text(value: object, lang_zh: bool, signed: bool = False) -> str:
    numeric = _safe_float(value)
    if pd.isna(numeric):
        return "—"
    lots = numeric / 1000.0
    abs_lots = abs(lots)
    if abs_lots >= 100:
        text = f"{abs_lots:,.0f}"
    else:
        text = f"{abs_lots:,.1f}".rstrip("0").rstrip(".")
    if signed:
        sign = "+" if lots > 0 else "-" if lots < 0 else ""
        text = f"{sign}{text}"
    return f"{text} 張" if lang_zh else f"{text} lots"


def _format_signed_percent_text(value: object, digits: int = 2) -> str:
    numeric = _safe_float(value)
    if pd.isna(numeric):
        return "—"
    return f"{numeric:+.{digits}f}%"


def _official_story_box_html(title: str, headline: str, detail: str) -> str:
    return (
        '<div class="benchmark-box">'
        f'<div class="benchmark-label">{escape(title)}</div>'
        f'<div style="margin-top:8px;font-size:1.02rem;font-weight:700;line-height:1.45;color:var(--text-primary);">{escape(headline)}</div>'
        f'<div class="benchmark-sub" style="margin-top:8px;white-space:normal;line-height:1.65;">{escape(detail)}</div>'
        '</div>'
    )


def _official_actor_label(actor_key: str, lang_zh: bool) -> str:
    zh_map = {
        "foreign": "外資",
        "trust": "投信",
        "dealer": "自營商",
    }
    en_map = {
        "foreign": "Foreign",
        "trust": "Trust",
        "dealer": "Dealer",
    }
    return (zh_map if lang_zh else en_map).get(actor_key, actor_key)


def _official_flow_diagnostics(flow: dict | None, lang_zh: bool) -> dict[str, str]:
    payload = dict(flow or {})
    error_text = str(payload.get("error", "") or "").strip()
    source_text = str(payload.get("source", "") or "").strip()
    date_text = str(payload.get("date", "") or "").strip()

    def _flow_value(raw: object) -> float:
        if isinstance(raw, str):
            normalized = (
                raw.strip()
                .replace(",", "")
                .replace("%", "")
                .replace("％", "")
                .replace("＋", "")
                .replace("+", "")
                .replace("−", "-")
                .replace("－", "-")
            )
            if normalized.lower() in {"", "-", "nan", "none", "null", "n/a"}:
                return float("nan")
            match = re.search(r"[-+]?(?:\d+\.\d+|\d+)", normalized)
            return float(match.group(0)) if match else float("nan")
        return _safe_float(raw)

    foreign_value = _flow_value(payload.get("foreign_net"))
    trust_value = _flow_value(payload.get("trust_net"))
    dealer_value = _flow_value(payload.get("dealer_net"))
    valid_values = [value for value in (foreign_value, trust_value, dealer_value) if not pd.isna(value)]
    error_key = error_text.casefold()

    if error_text:
        if "no matching code" in error_key or "no institutional flow found" in error_key or "no flow row matched" in error_key:
            status = "official_blank"
        else:
            status = "source_error"
    elif not valid_values:
        status = "official_blank" if source_text or date_text else "missing"
    elif all(abs(value) < 0.5 for value in valid_values):
        status = "all_zero"
    elif pd.isna(foreign_value):
        status = "partial_missing"
    elif abs(foreign_value) < 0.5:
        status = "foreign_zero"
    else:
        status = "available"

    if status == "official_blank":
        return {
            "status": status,
            "headline": "官方外資欄位空白" if lang_zh else "Official foreign-flow row is blank",
            "short": "官方空白" if lang_zh else "Official blank",
            "detail": (
                "這代表官方來源有回應，但這檔在當日法人資料裡沒有對應列或沒有揭露值。先不要直接解讀成外資完全沒參與，也不是程式抓取失敗。"
                if lang_zh else
                "The official source responded, but this ticker had no matching institutional row or no disclosed value for the day. Do not read it as proof that foreign investors were absent, and it is not a fetch failure."
            ),
        }
    if status == "source_error":
        return {
            "status": status,
            "headline": "外資資料抓取失敗" if lang_zh else "Foreign-flow fetch failed",
            "short": "抓取失敗" if lang_zh else "Fetch failed",
            "detail": (
                "這次是來源請求或解析失敗，不能解讀成中性、零買賣超，或外資沒有操作。"
                if lang_zh else
                "This run failed at the source or parsing layer, so it should not be read as neutral, zero-flow, or no foreign activity."
            ),
        }
    if status == "missing":
        return {
            "status": status,
            "headline": "外資資料尚未建立" if lang_zh else "Foreign-flow snapshot not built yet",
            "short": "尚未建立" if lang_zh else "Not built",
            "detail": (
                "目前還沒有可用的官方外資快照，先刷新一次再看。"
                if lang_zh else
                "No official foreign-flow snapshot is available yet. Refresh once before reading too much into it."
            ),
        }
    if status == "all_zero":
        return {
            "status": status,
            "headline": "官方明確顯示零買賣超" if lang_zh else "Official flow is explicitly zero",
            "short": "零買賣超" if lang_zh else "Zero net flow",
            "detail": (
                "這和抓不到資料不同，代表官方欄位有值，而且三大法人在這筆資料上沒有明顯淨買賣超。"
                if lang_zh else
                "This is different from missing data. The official fields are present and the institutions show no meaningful net buying or selling in this snapshot."
            ),
        }
    if status == "foreign_zero":
        return {
            "status": status,
            "headline": "外資當日近乎中性" if lang_zh else "Foreign flow is near flat today",
            "short": "外資中性" if lang_zh else "Foreign flat",
            "detail": (
                "外資欄位有回值且接近 0，代表今天沒有明顯表態；可搭配持股比率與後續兩三天延續性一起看。"
                if lang_zh else
                "The foreign field is present and close to zero, so there is no strong daily stance. Pair it with ownership ratio and the next few sessions for context."
            ),
        }
    if status == "partial_missing":
        return {
            "status": status,
            "headline": "外資暫缺，先看其餘法人" if lang_zh else "Foreign flow missing, read the other institutions first",
            "short": "部分缺值" if lang_zh else "Partial gap",
            "detail": (
                "投信或自營商仍有值，但外資欄位本身未揭露，這時候不要把空白誤認成外資中性。"
                if lang_zh else
                "Trust or dealer values are present, but the foreign field itself is undisclosed. Do not mistake the blank for a neutral foreign read."
            ),
        }
    return {
        "status": status,
        "headline": "外資資料可解讀" if lang_zh else "Foreign-flow data is usable",
        "short": "可解讀" if lang_zh else "Usable",
        "detail": (
            "這筆外資數字來自官方日資料，可以和持股比率、營收與後續延續性一起交叉判讀。"
            if lang_zh else
            "This foreign-flow reading comes from an official daily source and can be read alongside ownership ratio, revenue, and follow-through."
        ),
    }


def _official_flow_story(ticker_label: str, foreign_net: object, trust_net: object, dealer_net: object, lang_zh: bool) -> tuple[str, str]:
    flows = {
        "foreign": _safe_float(foreign_net),
        "trust": _safe_float(trust_net),
        "dealer": _safe_float(dealer_net),
    }
    valid_flows = {key: value for key, value in flows.items() if not pd.isna(value)}
    foreign_value = flows["foreign"]
    if pd.isna(foreign_value) and not valid_flows:
        if lang_zh:
            return (
                "法人買賣超資料暫缺",
                f"{ticker_label} 目前缺少官方法人買賣超，先不要只憑感覺判斷強弱，較適合等資料補齊後再看。",
            )
        return (
            "Institutional flow data is missing",
            f"Official institutional flow for {ticker_label} is unavailable right now, so avoid drawing a strong read from this section alone.",
        )

    positive_count = sum(1 for value in valid_flows.values() if value > 0)
    negative_count = sum(1 for value in valid_flows.values() if value < 0)
    dominant_actor = max(valid_flows, key=lambda key: abs(valid_flows[key])) if valid_flows else "foreign"
    dominant_value = valid_flows.get(dominant_actor, float("nan"))
    dominant_lots = _format_taiwan_lot_text(dominant_value, lang_zh)

    if pd.isna(foreign_value):
        headline = "外資資料暫缺，先看其餘法人方向" if lang_zh else "Foreign flow is missing, so read the other institutions first"
        lead_text = (
            f"目前以{_official_actor_label(dominant_actor, lang_zh)}的動作最明顯，方向約 {dominant_lots}。"
            if lang_zh else
            f"The clearest move so far comes from {_official_actor_label(dominant_actor, lang_zh)} at about {dominant_lots}."
        )
    elif foreign_value > 0:
        headline = "外資偏買，短線籌碼加分" if lang_zh else "Foreign investors are net buyers, which helps short-term positioning"
        lead_text = (
            f"外資今天對 {ticker_label} 買超約 {_format_taiwan_lot_text(foreign_value, lang_zh)}，代表短線資金態度偏友善。"
            if lang_zh else
            f"Foreign investors bought about {_format_taiwan_lot_text(foreign_value, lang_zh)} of {ticker_label} today, a friendlier short-term signal."
        )
    elif foreign_value < 0:
        headline = "外資偏賣，短線籌碼扣分" if lang_zh else "Foreign investors are net sellers, which is a short-term headwind"
        lead_text = (
            f"外資今天對 {ticker_label} 賣超約 {_format_taiwan_lot_text(foreign_value, lang_zh)}，代表短線資金先站在保守那一邊。"
            if lang_zh else
            f"Foreign investors sold about {_format_taiwan_lot_text(foreign_value, lang_zh)} of {ticker_label} today, which points to a more cautious short-term tone."
        )
    else:
        headline = "外資近乎中性，短線方向未明" if lang_zh else "Foreign flow is roughly flat, so the short-term read is still neutral"
        lead_text = (
            f"外資今天對 {ticker_label} 幾乎沒有明顯偏向，代表這筆資料本身還不能當成明確買賣訊號。"
            if lang_zh else
            f"Foreign flow for {ticker_label} is close to flat today, so this datapoint alone is not a strong buy or sell signal."
        )

    if valid_flows and positive_count == len(valid_flows):
        consensus_text = (
            "三大法人方向一致偏買，籌碼面相對整齊。"
            if lang_zh else
            "All reported institutional groups are net buyers, so positioning is relatively aligned."
        )
    elif valid_flows and negative_count == len(valid_flows):
        consensus_text = (
            "三大法人同步偏賣，短線賣壓通常會比較明顯。"
            if lang_zh else
            "All reported institutional groups are net sellers, which usually means heavier near-term pressure."
        )
    elif positive_count and negative_count:
        consensus_text = (
            "不同法人看法分歧，代表市場還在找共識，不適合把單日買賣超當成絕對答案。"
            if lang_zh else
            "Institutional views are split, so the market is still searching for consensus and one day of flow should not be treated as the answer."
        )
    else:
        consensus_text = (
            f"今天最主導的是{_official_actor_label(dominant_actor, lang_zh)}，方向約 {dominant_lots}。"
            if lang_zh else
            f"The biggest single driver today is {_official_actor_label(dominant_actor, lang_zh)} at about {dominant_lots}."
        )

    practical_text = (
        "對新手來說，這一欄先看方向，再看是否連續兩到三天延續，不要只因為一天買超就追高，也不要只因一天賣超就完全否定公司。"
        if lang_zh else
        "For newer investors, read the direction first and then watch whether it persists for two or three sessions instead of reacting to a single day."
    )
    return headline, " ".join(part for part in (lead_text, consensus_text, practical_text) if part)


def _official_revenue_story(ticker_label: str, yoy: object, mom: object, lang_zh: bool) -> tuple[str, str]:
    yoy_value = _safe_float(yoy)
    mom_value = _safe_float(mom)
    yoy_text = _format_signed_percent_text(yoy)
    mom_text = _format_signed_percent_text(mom)

    if pd.isna(yoy_value) and pd.isna(mom_value):
        if lang_zh:
            return (
                "月營收資料暫缺",
                f"{ticker_label} 暫時沒有可解讀的月營收數字，這時不要只靠股價波動做基本面判斷。",
            )
        return (
            "Monthly revenue data is missing",
            f"Monthly revenue for {ticker_label} is unavailable right now, so avoid using price movement alone as a fundamental read.",
        )

    if not pd.isna(yoy_value) and yoy_value > 0 and not pd.isna(mom_value) and mom_value > 0:
        headline = "營收雙增，基本面動能偏正向" if lang_zh else "Both YoY and MoM revenue are up, which supports the fundamental trend"
        tone_text = (
            f"YoY {yoy_text}、MoM {mom_text}，代表 {ticker_label} 跟去年同期、跟上個月相比都在成長。"
            if lang_zh else
            f"Revenue is {yoy_text} YoY and {mom_text} MoM, meaning {ticker_label} is growing against both last year and last month."
        )
    elif not pd.isna(yoy_value) and yoy_value > 0 and not pd.isna(mom_value) and mom_value < 0:
        headline = "年增還在，但短線月增降溫" if lang_zh else "YoY growth is still there, but MoM momentum cooled"
        tone_text = (
            f"YoY {yoy_text} 代表長一點的趨勢仍有撐，但 MoM {mom_text} 表示最近一個月開始降溫。"
            if lang_zh else
            f"YoY growth at {yoy_text} keeps the longer trend intact, while MoM at {mom_text} suggests the latest month cooled."
        )
    elif not pd.isna(yoy_value) and yoy_value < 0 and not pd.isna(mom_value) and mom_value > 0:
        headline = "短線月增回升，但年增仍偏弱" if lang_zh else "MoM improved, but YoY is still soft"
        tone_text = (
            f"MoM {mom_text} 表示最近一個月有回溫，不過 YoY {yoy_text} 仍提醒 {ticker_label} 的年對年基礎還沒有完全轉強。"
            if lang_zh else
            f"MoM at {mom_text} shows a short-term rebound, but YoY at {yoy_text} says the year-on-year base is still not fully strong for {ticker_label}."
        )
    elif not pd.isna(yoy_value) and yoy_value < 0 and not pd.isna(mom_value) and mom_value < 0:
        headline = "營收雙弱，基本面要更保守" if lang_zh else "Both YoY and MoM revenue are weak, so fundamentals need more caution"
        tone_text = (
            f"YoY {yoy_text}、MoM {mom_text}，代表 {ticker_label} 的營收動能同時弱於去年同期與上個月。"
            if lang_zh else
            f"Revenue is {yoy_text} YoY and {mom_text} MoM, showing weaker momentum versus both last year and last month."
        )
    else:
        headline = "營收訊號偏中性，還需要再觀察" if lang_zh else "Revenue signals are mixed, so more confirmation is needed"
        tone_text = (
            f"目前看到的營收讀數是 YoY {yoy_text}、MoM {mom_text}，方向還不夠一致。"
            if lang_zh else
            f"The current revenue reads are YoY {yoy_text} and MoM {mom_text}, which are not aligned enough yet."
        )

    practical_text = (
        "月營收比較像公司基本面溫度計，適合拿來確認趨勢，不適合直接拿來預測明天一定漲或一定跌。"
        if lang_zh else
        "Monthly revenue is more of a temperature check on fundamentals than a promise about tomorrow's price move."
    )
    return headline, " ".join(part for part in (tone_text, practical_text) if part)


def _official_valuation_story(pe: object, pb: object, cash_yield: object, lang_zh: bool) -> tuple[str, str, bool, bool]:
    pe_value = _safe_float(pe)
    pb_value = _safe_float(pb)
    yield_value = _safe_float(cash_yield)

    notes: list[str] = []
    score = 0.0
    valuation_rich = False
    valuation_supportive = False

    if not pd.isna(pe_value):
        if pe_value <= 0:
            notes.append(
                f"PE {pe_value:.2f} 不適合直接拿來估值，通常要回頭確認獲利是否失真或處於轉折期。"
                if lang_zh else
                f"PE at {pe_value:.2f} is not a clean valuation read, so earnings quality needs a closer look."
            )
            score -= 0.4
        elif pe_value <= 15:
            notes.append(
                f"PE {pe_value:.2f} 不算高，估值壓力相對小。"
                if lang_zh else
                f"PE at {pe_value:.2f} is not especially high, so valuation pressure is lighter."
            )
            score += 1.0
        elif pe_value >= 25:
            notes.append(
                f"PE {pe_value:.2f} 偏高，市場已經先反映不少期待。"
                if lang_zh else
                f"PE at {pe_value:.2f} is elevated, so the market is already pricing in a fair amount of optimism."
            )
            score -= 1.0
            valuation_rich = True
        else:
            notes.append(
                f"PE {pe_value:.2f} 大致落在中性區。"
                if lang_zh else
                f"PE at {pe_value:.2f} sits in a more neutral range."
            )

    if not pd.isna(pb_value):
        if 0 < pb_value <= 1.5:
            notes.append(
                f"PB {pb_value:.2f} 偏低，資產價格相對有支撐。"
                if lang_zh else
                f"PB at {pb_value:.2f} is on the lower side, which gives asset valuation more support."
            )
            score += 0.3
        elif pb_value >= 3.5:
            notes.append(
                f"PB {pb_value:.2f} 偏高，代表市場願意給較高溢價。"
                if lang_zh else
                f"PB at {pb_value:.2f} is high, meaning the market is paying a larger premium."
            )
            score -= 0.4
            valuation_rich = True

    if not pd.isna(yield_value):
        if yield_value >= 4:
            notes.append(
                f"殖利率 {yield_value:.2f}% 對保守型投資人比較友善。"
                if lang_zh else
                f"Yield at {yield_value:.2f}% is more supportive for conservative investors."
            )
            score += 0.5
        elif 0 < yield_value < 2:
            notes.append(
                f"殖利率 {yield_value:.2f}% 偏低，股價容錯率通常較小。"
                if lang_zh else
                f"Yield at {yield_value:.2f}% is low, which often means less margin for error in the price."
            )
            score -= 0.3
            valuation_rich = True

    if score >= 0.8:
        headline = "估值相對友善" if lang_zh else "Valuation looks relatively supportive"
        valuation_supportive = True
    elif score <= -0.8:
        headline = "估值偏貴，追價要更小心" if lang_zh else "Valuation looks rich, so chasing needs more caution"
    elif notes:
        headline = "估值大致中性" if lang_zh else "Valuation looks broadly neutral"
    else:
        headline = "估值資料有限，先別只看本益比" if lang_zh else "Valuation data is limited, so do not rely on PE alone"

    detail = " ".join(notes) if notes else (
        "這檔目前缺少完整估值資料，最好搭配產業位置與獲利趨勢一起看。"
        if lang_zh else
        "Valuation data is incomplete here, so it should be read together with sector position and earnings trend."
    )
    if lang_zh:
        detail += " 估值要和同產業比較才更有意義，所以這一欄適合拿來提醒風險，不適合單獨當買點。"
    else:
        detail += " Valuation is most useful when compared with peers, so this is better as a risk reminder than a standalone buy signal."
    return headline, detail, valuation_rich, valuation_supportive


def _official_buy_angle_story(
    ticker_label: str,
    foreign_net: object,
    yoy: object,
    mom: object,
    valuation_rich: bool,
    valuation_supportive: bool,
    lang_zh: bool,
) -> tuple[str, str]:
    foreign_value = _safe_float(foreign_net)
    yoy_value = _safe_float(yoy)
    mom_value = _safe_float(mom)

    foreign_positive = not pd.isna(foreign_value) and foreign_value > 0
    foreign_negative = not pd.isna(foreign_value) and foreign_value < 0
    revenue_positive = not pd.isna(yoy_value) and yoy_value > 0 and (pd.isna(mom_value) or mom_value >= 0)
    revenue_negative = not pd.isna(yoy_value) and yoy_value < 0 and (pd.isna(mom_value) or mom_value <= 0)

    if foreign_negative and revenue_negative:
        if lang_zh:
            return (
                "偏保守：先觀察，不建議急著接",
                f"{ticker_label} 目前同時面臨外資賣壓與營收偏弱，對不熟悉風險控管的人來說，先等止賣或下一期營收回穩會比較穩健。",
            )
        return (
            "More cautious: wait rather than rush in",
            f"{ticker_label} is dealing with both foreign selling and soft revenue, so waiting for selling pressure to ease or the next revenue release to stabilize is usually safer.",
        )

    if foreign_negative and revenue_positive:
        if lang_zh:
            return (
                "基本面不差，但先等賣壓緩和",
                f"{ticker_label} 的公司面不算差，可是短線籌碼還在被外資調節。若真的想布局，通常比較適合等連續賣超收斂或拉回後再分批。",
            )
        return (
            "Fundamentals are holding up, but wait for selling pressure to cool",
            f"{ticker_label} is holding up fundamentally, but foreign investors are still selling. If you want exposure, a pullback or a slowdown in selling is usually a cleaner entry.",
        )

    if foreign_positive and revenue_negative:
        if lang_zh:
            return (
                "有資金撐盤，但基本面還要再確認",
                f"{ticker_label} 目前比較像資金先行，不一定代表公司獲利已同步改善。這種情況對新手來說，不要只因買超就追價。",
            )
        return (
            "Money is stepping in, but fundamentals still need work",
            f"{ticker_label} looks more like a flow-led move for now, which does not necessarily mean earnings have already improved. Newer investors should avoid chasing just because institutions bought.",
        )

    if foreign_positive and revenue_positive and valuation_rich:
        if lang_zh:
            return (
                "結構偏正向，但估值不低",
                f"{ticker_label} 同時有外資支持和營收動能，不過估值已不便宜。比較好的做法通常是等拉回、分批，而不是看到強就一次追高。",
            )
        return (
            "The setup is constructive, but valuation is not cheap",
            f"{ticker_label} has both foreign support and revenue momentum, but valuation is already rich. Waiting for a pullback and scaling in is usually healthier than chasing strength.",
        )

    if foreign_positive and revenue_positive and valuation_supportive:
        if lang_zh:
            return (
                "結構偏正向，可列入分批觀察",
                f"{ticker_label} 的資金面、基本面與估值都沒有明顯拖後腿。若技術面沒有過熱，這種型態比較接近可以分批觀察的候選名單。",
            )
        return (
            "Constructive setup and worth watching for staged entry",
            f"{ticker_label} is not being held back by capital flow, fundamentals, or valuation right now. If the chart is not overstretched, this is closer to a staged-entry candidate.",
        )

    if valuation_rich:
        if lang_zh:
            return (
                "中性偏觀察：好公司也要注意買價",
                f"{ticker_label} 就算題材不錯，若估值已經偏高，報酬往往更依賴未來驚喜。對大多數投資人來說，等價格更舒服通常比硬追更重要。",
            )
        return (
            "Neutral-to-watch: even good companies need the right price",
            f"Even if {ticker_label} has a good story, rich valuation means returns depend more on future upside surprises. For most investors, price discipline matters more than speed.",
        )

    if lang_zh:
        return (
            "中性：先看下一個確認訊號",
            f"{ticker_label} 目前官方資料沒有形成很一致的買點，比較適合再看後續外資方向、下一期營收，或股價是否出現止跌訊號。",
        )
    return (
        "Neutral: wait for the next confirmation signal",
        f"The official data for {ticker_label} does not yet form a strong entry case, so watching the next round of foreign flow, revenue, or price stabilization makes sense.",
    )


def _official_status_pill_html(text: str, tone: str = "flat") -> str:
    tone_class = {
        "up": "etf-tracker-status-up",
        "down": "etf-tracker-status-down",
        "flat": "etf-tracker-status-flat",
    }.get(str(tone or "flat").lower(), "etf-tracker-status-flat")
    return f'<span class="etf-tracker-status-pill {tone_class}">{escape(text)}</span>'


def _official_source_story_html(
    source: str,
    dataset: str,
    stamp: str,
    headline: str,
    detail: str = "",
    note: str = "",
    *,
    pill_text: str = "",
    tone: str = "flat",
) -> str:
    pill_html = _official_status_pill_html(pill_text, tone) if pill_text else ""
    stamp_html = f'<div class="benchmark-sub" style="margin-top:4px;">{escape(stamp)}</div>' if stamp else ""
    detail_html = f'<div class="benchmark-sub" style="margin-top:8px;white-space:normal;line-height:1.6;">{escape(detail)}</div>' if detail else ""
    note_html = (
        f'<div class="benchmark-sub" style="margin-top:2px;white-space:normal;line-height:1.68;color:rgba(248, 241, 229, 0.78);">{escape(note)}</div>'
        if note else ""
    )
    return (
        '<div class="benchmark-box" style="padding:16px 16px 14px 16px; display:flex; flex-direction:column; gap:12px; min-height:220px;">'
        '<div style="display:flex; justify-content:space-between; align-items:flex-start; gap:10px; flex-wrap:wrap;">'
        '<div>'
        f'<div class="benchmark-label" style="margin:0;">{escape(source)}</div>'
        f'<div style="margin-top:6px; font-size:18px; font-weight:850; line-height:1.32; color:#fff8ee;">{escape(dataset)}</div>'
        f'{stamp_html}'
        '</div>'
        f'{pill_html}'
        '</div>'
        '<div style="padding:12px 14px; border-radius:16px; border:1px solid rgba(255,255,255,0.08); '
        'background:linear-gradient(135deg, rgba(12, 24, 43, 0.72) 0%, rgba(255,255,255,0.03) 100%);">'
        '<div class="benchmark-label" style="font-size:10px; color:rgba(248, 241, 229, 0.52);">Highlight</div>'
        f'<div style="margin-top:7px; font-size:17px; font-weight:820; line-height:1.48; color:#fffaf0; white-space:normal;">{escape(headline)}</div>'
        f'{detail_html}'
        '</div>'
        f'{note_html}'
        '</div>'
    )


def render_taiwan_market_macro_strip(force_show: bool = False) -> None:
    # v1.13.53: 用 list concat 而非 += (原 += 會 mutate session_state 的 list
    # reference, 把 active_etf_tickers 永久併進 selected_tickers)。
    selected = list(st.session_state.get("dashboard_selected_tickers", []) or [])
    selected = selected + list(st.session_state.get("dashboard_active_etf_tickers", []) or [])
    has_tw = force_show or any(is_taiwan_ticker(ticker) for ticker in selected)
    if not has_tw:
        return

    lang_zh = get_language() == "zh_TW"
    macro = fetch_cbc_macro_snapshot()
    derivatives = fetch_taifex_put_call_snapshot()

    cards: list[str] = []

    fx = macro.get("fx", {}) or {}
    fx_value = _safe_number_text(fx.get("value"), digits=4)
    if fx_value == "—":
        fx_value = str(fx.get("value") or "—")
    cards.append(
        _official_card_html(
            "CBC FX" if not lang_zh else "央行匯率",
            fx_value,
            f"{fx.get('label', 'USD/TWD')} · {fx.get('date', '')}".strip(" ·"),
        )
    )

    rate = macro.get("policy_rate", {}) or {}
    rate_value = _safe_percent_text(rate.get("value"))
    if rate_value == "—":
        rate_value = str(rate.get("value") or "—")
    cards.append(
        _official_card_html(
            "CBC Rate" if not lang_zh else "央行利率",
            rate_value,
            f"{rate.get('label', 'Policy rate')} · {rate.get('date', '')}".strip(" ·"),
        )
    )

    pcr = derivatives or {}
    pcr_value = _safe_number_text(pcr.get("ratio"), digits=2)
    if pcr_value == "—":
        pcr_value = str(pcr.get("ratio") or "—")
    cards.append(
        _official_card_html(
            "TAIFEX PCR" if not lang_zh else "期交所 PCR",
            pcr_value,
            f"{pcr.get('date', '')}".strip(),
        )
    )

    render_html_block(
        f"""
        <div class="global-indicator-shell global-indicator-shell-compact" style="margin-top:14px;">
            <div class="global-indicator-header">
                <div>
                    <div class="section-header" style="margin:0; color:#f5ead8;">{'Taiwan macro overlay' if not lang_zh else '台股總經覆蓋'}</div>
                    <div class="global-indicator-title">{'CBC + TAIFEX official layer' if not lang_zh else '央行 + 期交所官方層'}</div>
                    <div class="global-indicator-copy">{'Adds official Taiwan macro and derivatives context on top of the cross-market dashboard.' if not lang_zh else '把台灣官方總經與衍生性商品脈絡補到原本 Dashboard 之上。'}</div>
                </div>
            </div>
            <div class="benchmark-grid">
                {''.join(cards)}
            </div>
        </div>
        """
    )


