def us_theme_label(theme_key: str, lang_zh: bool) -> str:
    """Return the localized theme label, including emoji prefix."""
    for theme in US_THEME_GROUPS:
        if theme["key"] == theme_key:
            label = theme["label_zh"] if lang_zh else theme["label_en"]
            return f"{theme['emoji']}  {label}"
    return theme_key


def all_us_theme_tickers() -> list[str]:
    """Flat list of all US theme tickers (for fetch_daily_data warm-up)."""
    out: list[str] = []
    for theme in US_THEME_GROUPS:
        out.extend(theme["tickers"])
    return dedupe_keep_order(out)


def build_us_theme_radar(
    daily_data: pd.DataFrame | None,
    intraday_data: pd.DataFrame | None,
    *,
    top_n_per_theme: int = 0,
    lang_zh: bool = True,
    auto_fetch: bool = True,
) -> list[dict]:
    """Build the 5-theme US market radar bundle.

    Returns a list of theme dicts:
        [
          {
            "key": "mag7",
            "emoji": "🌟",
            "label": "MAG 7 科技七雄",
            "leaders": [
                {"ticker": "NVDA", "move_pct": 2.1, "last_price": 142.3},
                {"ticker": "META", "move_pct": 1.5, "last_price": 615.0},
                ...
            ],
            "rising_count": 5,
            "total_count": 7,
          },
          ...
        ]

    "leaders" are the top_n_per_theme tickers sorted by today's % move
    descending.

    v1.7.1: When auto_fetch=True (default), if the provided daily_data
    doesn't already contain the US theme tickers (common case: dashboard
    is in TW watchlist mode but user switched scope to U.S. only), this
    function will call fetch_daily_data() with all 28 US theme tickers to
    get fresh data. This makes US-only mode work even when the snapshot
    isn't available (Streamlit cache-cold startup, refresh button pressed,
    etc.). Set auto_fetch=False to keep the v1.7.0 behavior of relying
    purely on the caller-provided dataframe.
    """
    # v1.7.1: detect "no US tickers in daily_data" and auto-fetch.
    # Cheap probe: try to get_price_series for one MAG 7 ticker.
    if auto_fetch:
        probe_ticker = US_THEME_GROUPS[0]["tickers"][0]  # NVDA
        probe_series, _ = get_price_series(daily_data, probe_ticker)
        if probe_series is None or probe_series.empty:
            # daily_data missing US tickers; fetch our own slice.
            us_tickers = all_us_theme_tickers()
            try:
                fetched_daily = fetch_daily_data(us_tickers, "3mo", "1d")
                if fetched_daily is not None and not fetched_daily.empty:
                    daily_data = fetched_daily
                # intraday is optional; skip auto-fetch for simplicity.
            except Exception:
                pass  # graceful: keep going with whatever daily_data we had

    radar: list[dict] = []
    for theme in US_THEME_GROUPS:
        rows: list[dict] = []
        rising = 0
        total = 0
        for ticker in theme["tickers"]:
            series, _ = get_price_series(daily_data, ticker)
            if series is None or series.empty:
                continue
            total += 1
            # Today's % move = (last - prev_close) / prev_close * 100
            last_price = float(series.iloc[-1])
            prev_close = float(series.iloc[-2]) if len(series) >= 2 else last_price
            move_pct = ((last_price - prev_close) / prev_close * 100.0) if prev_close > 0 else 0.0
            # Try intraday for fresher last price if available
            try:
                if intraday_data is not None and not intraday_data.empty:
                    intra_series, _ = get_price_series(intraday_data, ticker)
                    if intra_series is not None and not intra_series.empty:
                        intra_last = float(intra_series.iloc[-1])
                        if not pd.isna(intra_last) and prev_close > 0:
                            last_price = intra_last
                            move_pct = ((intra_last - prev_close) / prev_close * 100.0)
            except Exception:
                pass
            if move_pct > 0:
                rising += 1
            rows.append({
                "ticker": ticker,
                "last_price": last_price,
                "move_pct": move_pct,
                "prev_close": prev_close,
            })
        # Sort by move_pct descending, take top N
        rows.sort(key=lambda r: r["move_pct"], reverse=True)
        # v1.7.2: top_n_per_theme=0 means show all tickers in the theme.
        # Otherwise slice to top N. The user selected "show all" so each
        # theme card lists every ticker the theme defines (not just top 3).
        leaders = rows if top_n_per_theme <= 0 else rows[:top_n_per_theme]
        radar.append({
            "key": theme["key"],
            "emoji": theme["emoji"],
            "label": theme["label_zh"] if lang_zh else theme["label_en"],
            "leaders": leaders,
            "rising_count": rising,
            "total_count": total,
        })
    return radar


# ---------------------------------------------------------------------------
# v1.8.3: US Theme Radar — per-theme Catalyst Engine pulse
# ---------------------------------------------------------------------------
# For each of the 5 themes in US_THEME_GROUPS, fetch news for every ticker
# in the theme, aggregate into one news pool per theme, run the existing
# build_catalyst_engine() over the pool, and surface AI Demand + Earnings
# + dominant rows. Returned shape is keyed by theme["key"] so the renderer
# can look up the right catalyst for each card.
#
# Performance:
#   - 28 cached fetch_ticker_news calls run through ThreadPoolExecutor with
#     max_workers=8 and an overall timeout. fetch_ticker_news is itself
#     cached at TTL 600s, and this outer build wraps another @cache_data
#     at TTL 600s, so warm-cache reruns are <50ms.
#   - Cold cache: ~2-3s for the 28 yfinance news calls in parallel.
#   - If the timeout fires, partial data is returned (cached); the renderer
#     still works -- themes without data simply don't show chips.
#
# Why we don't use @st.cache_data on the outer:
#   - Streamlit warns when @st.cache_data fns are called from threads
#     (it's the documented pattern but the warning is noisy). Since the
#     inner fetch_ticker_news IS cached, the outer build's overhead is
#     just dict iteration + classify_catalyst (keyword counting). Total
#     warm-cache rebuild cost is ~10ms — acceptable without outer cache.
#   - Update v1.8.3.1: actually we DO outer-cache because the threading
#     overhead (executor spinup, futures dict construction) adds up over
#     many reruns.  We use @st.cache_data with show_spinner=False; the
#     thread-cache warning is harmless and only fires on cold cache.
@st.cache_data(ttl=600, show_spinner=False)
def build_us_theme_catalysts(
    news_per_ticker: int = 6,
    max_workers: int = 8,
    overall_timeout_sec: float = 4.0,
) -> dict[str, dict]:
    """Compute per-theme catalyst engine summary for the US Theme Radar.

    Returns a dict keyed by theme["key"]:
        {
            "mag7": {
                "dominant": "AI Demand",
                "net_score": 5.0,
                "story_count": 24,
                "headline": "AI Demand is the main upside catalyst right now.",
                "rows": [
                    {"category": "AI Demand", "count": 4, "score": 2.5,
                     "bias": "Bullish", "intensity": 86},
                    ...
                ],
                "ai_demand": <row dict or None>,
                "earnings": <row dict or None>,
            },
            "oil_stocks": {...},
            ...
        }

    Themes with no news return a stub with story_count=0 and dominant=None
    so the caller can render a "no catalyst data" chip rather than crashing.
    """
    import concurrent.futures

    # Build ticker → theme key map and theme key → ticker list map.
    ticker_to_theme: dict[str, str] = {}
    theme_tickers: dict[str, list[str]] = {}
    for theme in US_THEME_GROUPS:
        theme_tickers[theme["key"]] = list(theme["tickers"])
        for tk in theme["tickers"]:
            ticker_to_theme[str(tk).upper()] = theme["key"]

    all_tickers = list(ticker_to_theme.keys())
    ticker_news: dict[str, list[dict]] = {tk: [] for tk in all_tickers}

    # Parallel news fetch. Each fetch_ticker_news is cached at TTL 600s, so
    # warm-cache the executor returns nearly instantly. On cold cache,
    # parallelism keeps the wall-clock to ~2-3s for 28 calls instead of
    # ~10s+ if we did them sequentially.
    try:
        with concurrent.futures.ThreadPoolExecutor(max_workers=max_workers) as executor:
            future_to_tk = {
                executor.submit(fetch_ticker_news, tk, news_per_ticker): tk
                for tk in all_tickers
            }
            done, _ = concurrent.futures.wait(
                future_to_tk.keys(), timeout=overall_timeout_sec
            )
            for fut in done:
                tk = future_to_tk[fut]
                try:
                    items, _err = fut.result(timeout=0.05)
                    ticker_news[tk] = list(items or [])
                except Exception:
                    ticker_news[tk] = []
            # Futures still running after timeout: don't cancel — they'll
            # finish in the background and warm fetch_ticker_news's cache
            # so the next render of this builder gets a complete dataset.
    except Exception:
        # Catastrophic executor failure: return empty so the radar still
        # renders (just without chips).
        return {key: {"dominant": None, "net_score": 0.0, "story_count": 0,
                      "headline": "", "rows": [], "ai_demand": None,
                      "earnings": None}
                for key in theme_tickers.keys()}

    # Per-theme aggregate + catalyst engine pass.
    out: dict[str, dict] = {}
    for theme_key, tks in theme_tickers.items():
        theme_news_pool: list[dict] = []
        for tk in tks:
            theme_news_pool.extend(ticker_news.get(tk, []))
        if not theme_news_pool:
            out[theme_key] = {
                "dominant": None,
                "net_score": 0.0,
                "story_count": 0,
                "headline": "",
                "rows": [],
                "ai_demand": None,
                "earnings": None,
            }
            continue
        catalyst = build_catalyst_engine(theme_news_pool)
        rows = list(catalyst.get("rows") or [])
        ai_row = next((r for r in rows if r.get("category") == "AI Demand"), None)
        eps_row = next((r for r in rows if r.get("category") == "Earnings"), None)
        out[theme_key] = {
            "dominant": catalyst.get("dominant"),
            "net_score": float(catalyst.get("net_score", 0.0) or 0.0),
            "story_count": len(theme_news_pool),
            "headline": str(catalyst.get("headline", "") or ""),
            "rows": rows,
            "ai_demand": ai_row,
            "earnings": eps_row,
        }
    return out


def build_us_theme_catalyst_aggregate(
    theme_catalysts: dict[str, dict] | None,
) -> dict:
    """Compute a radar-wide catalyst pulse summary across all themes.

    Used by the Theme Pulse banner above the grid. Returns:
        {
            "dominant": "AI Demand",      # most-impactful category overall
            "net_score": 5.0,             # sum of net scores across themes
            "themes_bullish": 3,          # # themes with net_score > 0.5
            "themes_bearish": 1,          # # themes with net_score < -0.5
            "themes_mixed": 1,            # the rest
            "themes_total": 5,
            "story_count": 87,            # total stories aggregated
            "tilt": "Bullish" | "Bearish" | "Mixed",
        }
    """
    if not theme_catalysts:
        return {
            "dominant": None, "net_score": 0.0,
            "themes_bullish": 0, "themes_bearish": 0, "themes_mixed": 0,
            "themes_total": 0, "story_count": 0, "tilt": "Mixed",
        }
    # Aggregate category scores and counts across all themes.
    category_totals: dict[str, dict] = {}
    net_score_sum = 0.0
    story_total = 0
    bull_count = bear_count = mixed_count = 0
    themes_total = 0
    for _key, catalyst in theme_catalysts.items():
        if not isinstance(catalyst, dict):
            continue
        themes_total += 1
        story_total += int(catalyst.get("story_count", 0) or 0)
        net = float(catalyst.get("net_score", 0.0) or 0.0)
        net_score_sum += net
        if net > 0.5:
            bull_count += 1
        elif net < -0.5:
            bear_count += 1
        else:
            mixed_count += 1
        for row in (catalyst.get("rows") or []):
            cat = str(row.get("category", "")).strip()
            if not cat:
                continue
            slot = category_totals.setdefault(cat, {"count": 0, "score": 0.0})
            slot["count"] += int(row.get("count", 0) or 0)
            slot["score"] += float(row.get("score", 0.0) or 0.0)

    # Pick the dominant category by absolute aggregate impact.
    dominant = None
    if category_totals:
        dominant = max(
            category_totals.items(),
            key=lambda kv: (kv[1]["count"], abs(kv[1]["score"])),
        )[0]
    if dominant is not None and category_totals[dominant]["count"] == 0:
        dominant = None  # all categories are empty -> no dominant

    if net_score_sum >= 1.5:
        tilt = "Bullish"
    elif net_score_sum <= -1.5:
        tilt = "Bearish"
    else:
        tilt = "Mixed"

    return {
        "dominant": dominant,
        "net_score": float(net_score_sum),
        "themes_bullish": bull_count,
        "themes_bearish": bear_count,
        "themes_mixed": mixed_count,
        "themes_total": themes_total,
        "story_count": int(story_total),
        "tilt": tilt,
    }


def build_us_theme_catalysts_safe(
    timeout_sec: float = 4.5,
) -> dict[str, dict]:
    """Wrapper that NEVER raises and always returns within `timeout_sec`.

    Spawns the cached builder inside a single-worker executor (mirrors the
    pattern in _cockpit_underlying_signal_with_timeout, ~L 28250). On
    timeout returns empty dict so the radar still renders without chips.
    The cached inner result populates the cache for subsequent renders.
    """
    import concurrent.futures
    try:
        with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:
            future = executor.submit(build_us_theme_catalysts)
            try:
                return future.result(timeout=timeout_sec) or {}
            except concurrent.futures.TimeoutError:
                return {}
    except Exception:
        return {}


# ---------------------------------------------------------------------------
# v1.8.4: PER-TICKER catalyst pulse for each row of the US Theme Radar
# ---------------------------------------------------------------------------
# Companion to build_us_theme_catalysts (v1.8.3). Where the theme builder
# aggregates news ACROSS all tickers in a theme, this builder runs the
# catalyst engine on each ticker INDIVIDUALLY so the radar can show per-row
# AI Demand / Earnings chips.
#
# Cache strategy:
#   - Inner fetch_ticker_news is the only IO; it's cached at TTL 600s and
#     SHARED with build_us_theme_catalysts. So the second-run cost (after
#     the theme builder has warmed the cache) is just ~28 dict lookups +
#     ~28 classify_catalyst passes ≈ <100ms total.
#   - This outer fn is also @st.cache_data(ttl=600) so reruns within the
#     window skip the executor spinup entirely.
#
# Output shape (dict keyed by upper-case ticker symbol):
#   {
#       "TSLA": {
#           "dominant": "AI Demand",
#           "net_score": 1.5,
#           "story_count": 6,
#           "ai_demand": <row dict or None>,
#           "earnings":  <row dict or None>,
#           "rows": [...],            # full breakdown if caller wants it
#       },
#       "AAPL": {...},
#       ...
#   }
# Tickers with no news return a stub with story_count=0 and dominant=None
# so the renderer can omit chips for that row gracefully.
@st.cache_data(ttl=600, show_spinner=False)
def build_us_ticker_catalysts(
    news_per_ticker: int = 6,
    max_workers: int = 8,
    overall_timeout_sec: float = 4.0,
) -> dict[str, dict]:
    import concurrent.futures

    # Flat list of all 28 US theme tickers.
    all_tickers: list[str] = []
    for theme in US_THEME_GROUPS:
        for tk in (theme.get("tickers") or []):
            all_tickers.append(str(tk).strip().upper())
    all_tickers = dedupe_keep_order(all_tickers)

    ticker_news: dict[str, list[dict]] = {tk: [] for tk in all_tickers}

    # Parallel news fetch (cache-backed; this is essentially free if the
    # v1.8.3 theme builder ran first and warmed fetch_ticker_news's cache).
    try:
        with concurrent.futures.ThreadPoolExecutor(max_workers=max_workers) as executor:
            future_to_tk = {
                executor.submit(fetch_ticker_news, tk, news_per_ticker): tk
                for tk in all_tickers
            }
            done, _ = concurrent.futures.wait(
                future_to_tk.keys(), timeout=overall_timeout_sec
            )
            for fut in done:
                tk = future_to_tk[fut]
                try:
                    items, _err = fut.result(timeout=0.05)
                    ticker_news[tk] = list(items or [])
                except Exception:
                    ticker_news[tk] = []
            # Futures still running after timeout: don't cancel; let them
            # finish and warm the cache for the next render.
    except Exception:
        return {tk: {"dominant": None, "net_score": 0.0, "story_count": 0,
                     "ai_demand": None, "earnings": None, "rows": []}
                for tk in all_tickers}

    out: dict[str, dict] = {}
    for tk in all_tickers:
        items = ticker_news.get(tk) or []
        if not items:
            out[tk] = {
                "dominant": None,
                "net_score": 0.0,
                "story_count": 0,
                "ai_demand": None,
                "earnings": None,
                "rows": [],
            }
            continue
        catalyst = build_catalyst_engine(items)
        rows = list(catalyst.get("rows") or [])
        ai_row = next((r for r in rows if r.get("category") == "AI Demand"), None)
        eps_row = next((r for r in rows if r.get("category") == "Earnings"), None)
        out[tk] = {
            "dominant": catalyst.get("dominant"),
            "net_score": float(catalyst.get("net_score", 0.0) or 0.0),
            "story_count": len(items),
            "ai_demand": ai_row,
            "earnings": eps_row,
            "rows": rows,
        }
    return out


def build_us_ticker_catalysts_safe(
    timeout_sec: float = 4.5,
) -> dict[str, dict]:
    """Wrapper that NEVER raises and always returns within `timeout_sec`.

    Same protective pattern as build_us_theme_catalysts_safe. On timeout
    returns {} so per-row chips are simply omitted (the radar still
    renders the price + move% columns normally).
    """
    import concurrent.futures
    try:
        with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:
            future = executor.submit(build_us_ticker_catalysts)
            try:
                return future.result(timeout=timeout_sec) or {}
            except concurrent.futures.TimeoutError:
                return {}
    except Exception:
        return {}


def build_home_news_active_etf_spotlight(
    daily_data: pd.DataFrame | None,
    intraday_data: pd.DataFrame | None,
    tickers: list[str],
    lens_meta: dict | None,
    dashboard_mode: str,
    *,
    limit: int = 3,
) -> list[dict]:
    etf_tickers = dedupe_keep_order(_home_news_active_etf_candidates(dashboard_mode, tickers))[:8]
    if not etf_tickers:
        return []

    period = str((lens_meta or {}).get("period", DEFAULT_PERIOD) or DEFAULT_PERIOD)
    interval = str((lens_meta or {}).get("interval", DEFAULT_INTERVAL) or DEFAULT_INTERVAL)
    etf_daily_data = daily_data
    etf_intraday_data = intraday_data if dashboard_mode == "Active ETF Lab" else None
    if dashboard_mode != "Active ETF Lab":
        try:
            etf_daily_data = fetch_daily_data(etf_tickers, period, interval)
        except Exception:
            etf_daily_data = None

    rows: list[dict] = []
    for ticker in etf_tickers:
        item = _ticker_move_from_data(etf_daily_data, etf_intraday_data, ticker)
        move = _safe_float(item.get("move"))
        price_series = item.get("price_series")
        volume_series = item.get("volume_series")
        if price_series is None or price_series.empty:
            continue
        analysis = analyze_market_sentinel(price_series, volume_series, [], ticker)
        volume_ratio = _safe_float(item.get("volume_ratio"))
        volume_score = min(max(volume_ratio, 0.0), 5.0) * 3.0 if pd.notna(volume_ratio) else 0.0
        move_score = abs(float(move)) * 1.6 if pd.notna(move) else 0.0
        positive_bonus = max(float(move), 0.0) * 0.8 if pd.notna(move) else 0.0
        trend_score = max(float(_safe_float(analysis.get("score"), default=0.0)), 0.0)
        attention_score = move_score + positive_bonus + volume_score + trend_score
        rows.append(
            {
                "ticker": ticker,
                "label": active_etf_selector_label(ticker),
                "move": move,
                "volume_ratio": volume_ratio,
                "trend": analysis.get("trend", "N/A"),
                "signal": analysis.get("signal", "HOLD"),
                "attention_score": attention_score,
            }
        )

    rows.sort(key=lambda row: float(row.get("attention_score", 0.0)), reverse=True)
    return rows[:limit]


def load_editor_analysis_items(*, max_items: int = 4) -> list[dict]:
    fallback_items = [
        {
            "title": "AI 供應鏈先看資金續航",
            "summary": "若強勢鏈漲幅擴大但外資沒有同步回補，短線可先用分批與停利帶管理追價風險。",
            "tags": ["AI", "供應鏈", "外資"],
            "priority": "高",
            "stance": "觀察",
        },
        {
            "title": "主動式 ETF 適合看題材純度",
            "summary": "主動式 ETF 的熱度不要只看單日漲幅，還要搭配持股題材、成交量變化與外資是否連續進場。",
            "tags": ["主動式ETF", "題材", "成交量"],
            "priority": "中",
            "stance": "研究",
        },
    ]
    try:
        if EDITOR_ANALYSIS_PATH.exists():
            payload = json.loads(EDITOR_ANALYSIS_PATH.read_text(encoding="utf-8"))
            raw_items = payload.get("items", payload) if isinstance(payload, dict) else payload
            if isinstance(raw_items, list):
                items = [item for item in raw_items if isinstance(item, dict)]
                if items:
                    return items[:max_items]
    except Exception:
        pass
    return fallback_items[:max_items]


@st.cache_data(ttl=20 * 60, show_spinner=False)
def fetch_home_taiex_volume_snapshot() -> dict:
    now_tw = pd.Timestamp.now(tz=TW_TZ)
    try:
        frame = yf.download("^TWII", period="3mo", interval="1d", auto_adjust=False, progress=False, threads=False)
        if frame is None or frame.empty:
            raise ValueError("No TAIEX daily volume data returned.")
        normalized = frame.copy()
        if isinstance(normalized.columns, pd.MultiIndex):
            flattened = []
            for col in normalized.columns:
                if isinstance(col, tuple):
                    flattened.append(str(col[0] or col[-1]))
                else:
                    flattened.append(str(col))
            normalized.columns = flattened
        normalized.columns = [str(col).strip() for col in normalized.columns]
        volume_col = next((col for col in normalized.columns if str(col).strip().lower() == "volume"), None)
        close_col = next((col for col in normalized.columns if str(col).strip().lower() == "close"), None)
        if not volume_col:
            raise ValueError("Volume column was not found for ^TWII.")

        volume_series = pd.to_numeric(normalized[volume_col], errors="coerce").dropna().tail(24)
        if volume_series.empty:
            raise ValueError("No valid TAIEX volume rows were available.")
        close_series = pd.to_numeric(normalized[close_col], errors="coerce").dropna().tail(volume_series.shape[0]) if close_col else pd.Series(dtype=float)

        latest_volume = float(volume_series.iloc[-1])
        avg_20 = float(volume_series.tail(min(20, volume_series.shape[0])).mean())
        latest_ratio = latest_volume / avg_20 if avg_20 else float("nan")
        change_pct = ((latest_volume / float(volume_series.iloc[-2])) - 1.0) * 100.0 if volume_series.shape[0] >= 2 and float(volume_series.iloc[-2]) else float("nan")
        price_change_pct = ((float(close_series.iloc[-1]) / float(close_series.iloc[0])) - 1.0) * 100.0 if close_series.shape[0] >= 2 and float(close_series.iloc[0]) else float("nan")
        as_of = pd.Timestamp(volume_series.index[-1])
        if as_of.tzinfo is None:
            as_of = as_of.tz_localize(TW_TZ)
        else:
            as_of = as_of.tz_convert(TW_TZ)

        return {
            "status": "ready",
            "source": "Yahoo Finance ^TWII daily volume",
            "as_of": as_of.isoformat(),
            "latest_volume": latest_volume,
            "avg_20": avg_20,
            "latest_ratio": latest_ratio,
            "change_pct": change_pct,
            "price_change_pct": price_change_pct,
            "min_volume": float(volume_series.min()),
            "max_volume": float(volume_series.max()),
            "volume_points": [float(value) for value in volume_series.tolist()],
            "labels": [pd.Timestamp(idx).strftime("%m/%d") for idx in volume_series.index.tolist()],
        }
    except Exception as exc:
        return {
            "status": "missing",
            "source": "Yahoo Finance ^TWII daily volume",
            "as_of": now_tw.isoformat(),
            "error": str(exc),
            "latest_volume": pd.NA,
            "avg_20": pd.NA,
            "latest_ratio": pd.NA,
            "change_pct": pd.NA,
            "price_change_pct": pd.NA,
            "volume_points": [],
            "labels": [],
        }


def _render_home_news_taiex_volume_terrain_html(lang_zh: bool) -> str:
    snapshot = fetch_home_taiex_volume_snapshot()
    if str(snapshot.get("status", "")) != "ready":
        missing_title = "加權指數量能地形圖暫時不可用" if lang_zh else "TAIEX volume terrain is temporarily unavailable"
        missing_note = "公開日量資料暫時沒有回來，等下一輪快照後會自動補上。" if lang_zh else "The public daily volume feed is unavailable right now and will return on the next snapshot."
        return f"""
        <div class="home-news-terrain-card">
            <div class="home-news-terrain-head">
                <div>
                    <div class="home-news-terrain-kicker">{"TAIEX VOLUME" if not lang_zh else "加權指數量能"}</div>
                    <div class="home-news-terrain-title">{escape(missing_title)}</div>
                    <div class="home-news-terrain-copy">{escape(missing_note)}</div>
                </div>
            </div>
        </div>
        """

    points = [float(value) for value in (snapshot.get("volume_points", []) or []) if pd.notna(_safe_float(value))]
    labels = list(snapshot.get("labels", []) or [])
    if len(points) < 2:
        return ""

    width = 760.0
    height = 260.0
    left_pad = 30.0
    right_pad = 32.0
    top_pad = 26.0
    bottom_pad = 38.0
    usable_w = width - left_pad - right_pad
    usable_h = height - top_pad - bottom_pad
    vol_min = min(points)
    vol_max = max(points)
    span = max(vol_max - vol_min, 1.0)

    def _xy(index: int, value: float, depth: float = 0.0) -> tuple[float, float]:
        x = left_pad + (usable_w * index / max(len(points) - 1, 1))
        normalized = (value - vol_min) / span
        y = top_pad + (1.0 - normalized) * usable_h + depth
        return x, y

    main_coords = [_xy(i, value, 0.0) for i, value in enumerate(points)]
    front_path = " ".join(f"{x:.1f},{y:.1f}" for x, y in main_coords)
    terrain_lines: list[str] = []
    fill_layers: list[str] = []
    wire_colors = ["#3af4e6", "#3fe7ff", "#50d2ff", "#68aeff", "#818cf8", "#8974ff", "#aa73ff"]
    wire_opacities = [0.34, 0.30, 0.26, 0.23, 0.20, 0.17, 0.14]
    for layer_index in range(7):
        depth = 8.0 * layer_index
        damp = 1.0 - (layer_index * 0.06)
        layer_coords = []
        for i, value in enumerate(points):
            midpoint = vol_min + (value - vol_min) * max(damp, 0.58)
            layer_coords.append(_xy(i, midpoint, depth))
        line_path = " ".join(f"{x:.1f},{y:.1f}" for x, y in layer_coords)
        terrain_lines.append(
            f'<polyline class="terrain-wire terrain-wire-{layer_index}" points="{line_path}" '
            f'fill="none" stroke="{wire_colors[layer_index]}" stroke-opacity="{wire_opacities[layer_index]:.2f}" '
            'stroke-width="1.25" stroke-linecap="round" stroke-linejoin="round" />'
        )
        if layer_index in {1, 3, 5}:
            fill_ref = "terrainFillA" if layer_index != 3 else "terrainFillB"
            fill_opacity = 0.72 if layer_index != 5 else 0.46
            fill_layers.append(
                f'<polygon class="terrain-fill terrain-fill-{layer_index}" points="{line_path} {width-right_pad:.1f},{height-bottom_pad+8:.1f} {left_pad:.1f},{height-bottom_pad+8:.1f}" '
                f'fill="url(#terrainFill{fill_ref[-1]})" opacity="{fill_opacity:.2f}" />'
            )

    column_lines = []
    for idx in range(0, len(points), 3):
        x, y = main_coords[idx]
        column_lines.append(
            f'<line class="terrain-column" x1="{x:.1f}" y1="{y:.1f}" x2="{x:.1f}" y2="{height-bottom_pad+6:.1f}" '
            'stroke="#4ae7ff" stroke-opacity="0.20" stroke-width="1" stroke-dasharray="2 4" />'
        )

    label_indices = sorted({0, len(points)//2, len(points)-1})
    timestamp_marks = []
    for idx in label_indices:
        x, _ = main_coords[idx]
        label = labels[idx] if idx < len(labels) else ""
        timestamp_marks.append(
            f'<g class="terrain-axis-mark"><line x1="{x:.1f}" y1="{height-bottom_pad+8:.1f}" x2="{x:.1f}" y2="{height-bottom_pad+14:.1f}" '
            f'stroke="#b1e4ff" stroke-opacity="0.28" stroke-width="1" /><text x="{x:.1f}" y="{height-bottom_pad+28:.1f}" '
            f'fill="#cfeaff" fill-opacity="0.72" font-size="11" font-weight="700" text-anchor="middle">{escape(label)}</text></g>'
        )

    latest_volume_text = _format_profile_compact_number(snapshot.get("latest_volume"), digits=1)
    avg_volume_text = _format_profile_compact_number(snapshot.get("avg_20"), digits=1)
    ratio_value = _safe_float(snapshot.get("latest_ratio"))
    ratio_text = "—" if pd.isna(ratio_value) else f"{ratio_value:.2f}x"
    change_text = "—" if pd.isna(_safe_float(snapshot.get("change_pct"))) else f"{_safe_float(snapshot.get('change_pct')):+.1f}%"
    price_text = "—" if pd.isna(_safe_float(snapshot.get("price_change_pct"))) else f"{_safe_float(snapshot.get('price_change_pct')):+.1f}%"
    as_of_text = format_taiwan_official_snapshot_fetched_at(snapshot.get("as_of"))
    volume_note = (
        f"近月日量地形顯示最新量能 {latest_volume_text}，約為 20 日均量的 {ratio_text}；最近一筆量能變化 {change_text}。"
        if lang_zh else
        f"The recent daily-volume terrain shows {latest_volume_text} on the latest bar, about {ratio_text} of the 20-day average, with the last session changing {change_text}."
    )

    svg_markup = f"""
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 {int(width)} {int(height)}" preserveAspectRatio="none" aria-label="TAIEX volume terrain">
        <defs>
            <linearGradient id="terrainGlowLeft" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stop-color="#3af4e6" />
                <stop offset="55%" stop-color="#39d8ff" />
                <stop offset="100%" stop-color="#8974ff" />
            </linearGradient>
            <linearGradient id="terrainFillA" x1="0%" y1="0%" x2="0%" y2="100%">
                <stop offset="0%" stop-color="#3af4e6" stop-opacity="0.20" />
                <stop offset="100%" stop-color="#3af4e6" stop-opacity="0.02" />
            </linearGradient>
            <linearGradient id="terrainFillB" x1="0%" y1="0%" x2="0%" y2="100%">
                <stop offset="0%" stop-color="#8974ff" stop-opacity="0.18" />
                <stop offset="100%" stop-color="#8974ff" stop-opacity="0.02" />
            </linearGradient>
            <filter id="terrainBlur" x="-20%" y="-20%" width="140%" height="160%">
                <feGaussianBlur stdDeviation="5.5" />
            </filter>
        </defs>
        <rect x="0" y="0" width="{int(width)}" height="{int(height)}" fill="#050e1e" opacity="0.98" />
        <g>
            <line x1="{left_pad:.1f}" y1="{height-bottom_pad+8:.1f}" x2="{width-right_pad:.1f}" y2="{height-bottom_pad+8:.1f}" stroke="#6ecdff" stroke-opacity="0.10" stroke-width="1" />
            <line x1="{left_pad:.1f}" y1="{top_pad+24:.1f}" x2="{width-right_pad:.1f}" y2="{top_pad+24:.1f}" stroke="#6ecdff" stroke-opacity="0.08" stroke-width="1" />
            <line x1="{left_pad:.1f}" y1="{top_pad+88:.1f}" x2="{width-right_pad:.1f}" y2="{top_pad+88:.1f}" stroke="#6ecdff" stroke-opacity="0.08" stroke-width="1" />
            <line x1="{left_pad:.1f}" y1="{top_pad+152:.1f}" x2="{width-right_pad:.1f}" y2="{top_pad+152:.1f}" stroke="#6ecdff" stroke-opacity="0.08" stroke-width="1" />
        </g>
        <g>{''.join(fill_layers)}{''.join(column_lines)}{''.join(terrain_lines)}</g>
        <polyline points="{front_path}" fill="none" stroke="#3af4e6" stroke-opacity="0.36" stroke-width="10" stroke-linecap="round" stroke-linejoin="round" filter="url(#terrainBlur)" />
        <polyline points="{front_path}" fill="none" stroke="url(#terrainGlowLeft)" stroke-width="3.2" stroke-linecap="round" stroke-linejoin="round" />
        <g>{''.join(f'<circle cx="{x:.1f}" cy="{y:.1f}" r="2.8" fill="#cfffff" opacity="0.94" />' for x, y in main_coords[::2])}</g>
        <g>{''.join(timestamp_marks)}</g>
    </svg>
    """
    terrain_data_uri = base64.b64encode(svg_markup.encode("utf-8")).decode("ascii")

    return f"""
    <div class="home-news-terrain-card">
        <div class="home-news-terrain-head">
            <div>
                <div class="home-news-terrain-kicker">{"TAIEX VOLUME TERRAIN" if not lang_zh else "加權指數成交量地形圖"}</div>
                <div class="home-news-terrain-title">{"3D data terrain map for weighted-index volume" if not lang_zh else "把加權指數量能做成 3D 數據地形流"}</div>
                <div class="home-news-terrain-copy">{escape(volume_note)}</div>
            </div>
            <div class="home-news-terrain-metrics">
                <div class="home-news-terrain-metric"><span>{"Latest" if not lang_zh else "最新量"}</span><strong>{latest_volume_text}</strong></div>
                <div class="home-news-terrain-metric"><span>{"20D Avg" if not lang_zh else "20日均量"}</span><strong>{avg_volume_text}</strong></div>
                <div class="home-news-terrain-metric"><span>{"Volume / Avg" if not lang_zh else "量比"}</span><strong>{ratio_text}</strong></div>
            </div>
        </div>
        <div class="home-news-terrain-stage">
            <img class="home-news-terrain-image" src="data:image/svg+xml;base64,{terrain_data_uri}" alt="TAIEX volume terrain" />
            <div class="terrain-callout terrain-callout-left">
                <div class="terrain-callout-label">{"Volume stream" if not lang_zh else "量能時間流"}</div>
                <div class="terrain-callout-copy">{escape(as_of_text)}</div>
            </div>
            <div class="terrain-callout terrain-callout-right">
                <div class="terrain-callout-label">{"Index trend" if not lang_zh else "指數趨勢"}</div>
                <div class="terrain-callout-copy">{price_text}</div>
            </div>
        </div>
    </div>
    """


